insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (884, '5', '다음 증상이 나타나는 질환으로 옳은 것은?• 숨을 내쉴 때 쌕쌔거리는 호흡음• 만성 염증성 질환으로 기관지 벽의 부종과 기도 협착• 꽃가루, 집먼지진드기, 찬 공기 노출 시 기도의 과민반응', '["천식", "결핵", "후두염", "폐수종", "흉막염"]'::jsonb, 1, NULL, NULL, '{"1": "천식: 주어진 증상과 관련된 주요 특징을 모두 포함하고 있으며, 특히 쌕쌕거리는 호흡음과 기도의 과민반응이 특징입니다.\n[정답]", "2": "결핵: 주로 기침과 가래가 특징이며, 주어진 증상들과는 관련성이 낮습니다.", "3": "후두염: 주로 후두의 염증으로 인한 증상이며, 쌕쌕거리는 호흡음이 일반적이지 않습니다.", "4": "폐수종: 폐에 액체가 고이는 상태로, 호흡곤란을 유발하지만 주어진 증상과는 다릅니다.", "5": "흉막염: 흉막의 염증으로 호흡 시 통증이 주 증상인데, 주어진 증상들과 맞지 않습니다."}'::jsonb, '[{"term_ko": "호흡음", "term_vi": "Chứng âm thở", "def_ko": "소리(소리)", "def_vi": "Âm thanh của hơi thở"}, {"term_ko": "만성", "term_vi": "Mạn tính", "def_ko": "오랜 시간 동안 지속되는(kinh niên)", "def_vi": "Kéo dài lâu"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "신체가 감염이나 손상에 반응하여 발생하는 상태(viêm)", "def_vi": "Trạng thái phát sinh khi cơ thể phản ứng với nhiễm trùng hoặc tổn伤"}, {"term_ko": "부종", "term_vi": "Phù", "def_ko": "부풀어 오르다(swelling)", "def_vi": "Sưng lên"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡에 사용하는 통로(đường hô hấp)", "def_vi": "Cửa đường hô hấp"}, {"term_ko": "과민반응", "term_vi": "Phản ứng quá mẫn", "def_ko": "지나치게 민감하게 반응하는 상태(phản ứng quá mẫn)", "def_vi": "Trạng thái phản ứng quá mức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (883, '5', '천식 대상자의 기도 경련을 유발하거나 악화시키는 요인은?', '["찬 공기 노출", "복식 호흡", "독감 예방접종", "가벼운 실내운동", "뜨거운 물로 침구류 세탁"]'::jsonb, 1, NULL, NULL, '{"1": "찬 공기에 노출되면 기도가 수축되어 천식 증상이 악화될 수 있습니다.\n[정답]", "2": "복식 호흡은 천식 피해자의 기도를 이완시킬 수 있습니다.", "3": "독감 예방접종은 천식 발작과 직접적인 연관이 없습니다.", "4": "가벼운 실내 운동은 천식 환자에게 도움이 될 수 있습니다.", "5": "뜨거운 물로 침구류 세탁은 천식에 영향을 미치지 않습니다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "알레르기나 환경적 요인으로 인해 기도가 좁아지는 질환", "def_vi": "Bệnh khiến đường thở bị thu hẹp do dị ứng hoặc yếu tố môi trường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (882, '5', '기도의 만성 염증성 질환으로 숨을 내쉴 때 쌕쌕거리는 호흡음이 나는 호흡기 질환은?', '["폐렴", "천식", "폐결핵", "만성기관지염", "협심증"]'::jsonb, 2, NULL, NULL, '{"1": "폐렴은 폐에 염증이 생기는 질환으로, 쌕쌕거리는 소리와는 직접적인 연관이 적습니다.\n[정답]", "2": "천식은 기도의 만성 염증성 질환으로, 숨을 내쉴 때 쌕쌕거리는 호흡음이 특징입니다.", "3": "폐결핵은 결핵균에 의한 폐렴의 일종으로, 쌕쌕거림과는 다릅니다.", "4": "만성기관지염은 기도의 만성 염증이지만, 주로 기침과 가래가 특징입니다.", "5": "협심증은 심장의 문제로, 호흡기 질환이 아닙니다."}'::jsonb, '[{"term_ko": "기도", "term_vi": "염증", "def_ko": "기도(상기도와 하기도를 포함) / Đường hô hấp: Đường hô hấp (bao gồm đường hô hấp trên và dưới)", "def_vi": "염증(병리적 상태) / Viêm: Tình trạng bệnh lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (881, '5', '폐렴을 치료하는 방법으로 옳은 것은?', '["치내 혈액의 산소 농도를 적절하게 유지한다.", "수분 섭취를 제한한다.", "실내 습도를 높게 유지한다.", "항생제 사용을 금한다.", "주기적으로 객담 검사를 실시한다."]'::jsonb, 1, NULL, NULL, '{"1": "치내 혈액의 산소 농도를 적절하게 유지하는 것은 폐렴 치료에서 중요한 요소이다.\n[정답]", "2": "수분 섭취를 제한하는 것은 오히려 건강에 해로울 수 있다.", "3": "실내 습도를 높게 유지하는 것은 일부 환자에게 도움이 될 수 있지만, 항상 필요한 것은 아니다.", "4": "항생제 사용을 금하는 것은 오히려 폐렴 치료에 부정적인 영향을 미친다.", "5": "주기적으로 객담 검사를 실시하는 것은 중요하지만, 치료 방법으로 보기에는 적합하지 않다."}'::jsonb, '[{"term_ko": "폐렴", "term_vi": "치료", "def_ko": "폐의 염증(viêm phổi)", "def_vi": "질병 또는 증상을 완화하거나 없애기 위한 방법(điều trị)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (880, '5', '음식물이나 이물질이 기도 내로 넘어가 기관지나 폐에 염증을 일으키는 질환은?', '["식도염", "폐렴", "위경련", "폐기종", "천식"]'::jsonb, 2, NULL, NULL, '{"1": "식도염: 식도가 염증으로 인해 발생하는 질환으로, 기도의 염증과는 관련이 없습니다.\n[정답]", "2": "폐렴: 폐에 염증이 발생하는 질환으로, 음식물이나 이물질이 기도 내로 넘어가면서 발생할 수 있습니다.", "3": "위경련: 위의 근육 경련으로, 기도와는 관계가 없습니다.", "4": "폐기종: 폐 내의 공기주머니가 파괴되는 질환으로, 염증과는 다릅니다.", "5": "천식: 기도가 좁아지면서 나타나는 반응으로, 음식물이나 이물질의 침입과 직접적인 관계가 없습니다."}'::jsonb, '[{"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "기도의 가지 부분", "def_vi": "Phần nhánh của đường thở"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "조직이 부풀고 아픈 상태", "def_vi": "Trạng thái tổ chức sưng và đau"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 질병", "def_vi": "Bệnh tật hoặc tình trạng bệnh lý"}, {"term_ko": "기타", "term_vi": "Khác", "def_ko": "기타라는 것을 포함한 여러 상태", "def_vi": "Bao gồm nhiều tình trạng khác nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (879, '5', '세균, 바이러스에 의한 폐 조직의 염증으로 호흡곤란, 가래, 기침이 나타나는 질병은?', '["폐렴", "폐암", "천식", "폐결핵", "만성기관지염"]'::jsonb, 1, NULL, NULL, '{"1": "폐렴은 세균이나 바이러스에 의해 폐의 염증이 발생하며, 호흡곤란, 가래, 기침 등의 증상이 나타납니다.\n[정답]", "2": "폐암은 폐에 발생하는 악성 종양으로, 주로 기침, 체중 감소 등의 증상을 보이지만 염증은 아닙니다.", "3": "천식은 알레르기 등을 원인으로 하는 염증성 질환이지만, 세균이나 바이러스에 의한 것은 아닙니다.", "4": "폐결핵은 결핵균에 의한 감염병으로 폐에 염증을 일으키지만, 주로 점진적인 증상이 나타납니다.", "5": "만성기관지염은 장기간의 기관지 염증으로 인한 기침, 가래가 특징이나, 감염에 의한 것이 아닙니다."}'::jsonb, '[{"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "박테리아(한국어)", "def_vi": "vi sinh vật đơn bào gây bệnh"}, {"term_ko": "바이러스", "term_vi": "Virus", "def_ko": "바이러스(한국어)", "def_vi": "tác nhân gây bệnh nhỏ hơn vi khuẩn"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "염증(한국어)", "def_vi": "phản ứng của cơ thể với tổn thương"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "호흡 곤란(한국어)", "def_vi": "tình trạng không thể thở bình thường"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "가래(한국어)", "def_vi": "chất nhầy trong đường hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침(한국어)", "def_vi": "hành động đẩy không khí ra khỏi phổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (878, '5', '만성 기관지염으로 기도가 좁아진 대상자를 돕는 방법으로 옳은 것은?', '["자극적인 음식을 섭취한다.", "차가운 물을 자주 마시게 한다.", "탈취제를 사용하여 실내 공기를 정화한다.", "전염성이 강하므로 마스크를 착용하게 한다.", "갑작스러운 온도 변화에 노출되지 않게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "자극적인 음식은 기도를 더 자극하여 증상을 악화시킬 수 있다.\n[정답]", "5": "갑작스러운 온도 변화는 기관지에 부담을 줄 수 있으므로 노출되지 않게 해야 한다.", "2": "차가운 물은 기도를 수축시킬 수 있어 바람직하지 않다.", "3": "탈취제는 화학 성분이 포함되어 있어 호흡기에 좋지 않을 수 있다.", "4": "전염성이 강하다는 것은 정확하지 않으며, 기본적인 예방 조치가 필요하지만 마스크 착용이 주된 방법은 아니다."}'::jsonb, '[{"term_ko": "만성 기관지염", "term_vi": "기도", "def_ko": "만성 bronchitis", "def_vi": "đường thở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (877, '5', '만성기관지염으로 기도가 좁아진 경우 치료 및 예방법으로 옳은 것은?', '["찬 공기에 노출한다.", "뜨거운 음식을 섭취한다.", "흡연자는 금연을 한다.", "차가운 음식을 섭취한다.", "기침을 자제한다."]'::jsonb, 3, NULL, NULL, '{"1": "찬 공기에 노출하면 기도가 더욱 좁아질 수 있으므로 옳지 않다.\n[정답]", "3": "흡연은 만성기관지염을 악화시키기 때문에 금연이 필수적이다.", "2": "뜨거운 음식은 기도에 자극을 줄 수 있어 주의해야 한다.", "4": "차가운 음식 역시 기도를 자극할 수 있으므로 바람직하지 않다.", "5": "기침은 기도에서 이물질을 배출하는 중요한 반사작용이므로 자제하는 것이 좋지 않다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "Bệnh phế quản mãn tính", "def_ko": "만성적으로 기도의 염증이 생기는 질환", "def_vi": "Bệnh viêm mãn tính ở đường thở"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡하는 경로", "def_vi": "Đường dẫn khí"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (876, '5', '만성기관지염을 앓고 있는 대상자의 증상을 완화시키는 방법으로 옳은 것은?', '["해열진통제를 투여한다.", "차고 매ㅐ운 음식을 먹게 한다.", "공기 정화를 위해 방향제를 뿌린다.", "호흡곤란 시에는 뜨거운 차를 마시게 한다.", "심호흡과 기침을 하여 기관지 내 가래를 배출한다."]'::jsonb, 5, NULL, NULL, '{"1": "해열진통제는 주로 통증 조절을 위해 사용되며, 만성기관지염의 증상 완화와는 크게 관련이 없다.\n[정답]", "5": "심호흡과 기침은 기관지 내 가래를 배출하는 데 효과적이며, 만성기관지염 환자에게 도움이 된다.", "2": "차고 매운 음식은 기관지를 자극할 수 있어 권장되지 않는다.", "3": "방향제는 공기를 정화하기보다는 오히려 기관지에 자극을 줄 수 있다.", "4": "뜨거운 차는 호흡곤란 개선에 직접적인 도움이 되지 않고, 오히려 자극을 줄 수 있다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "Viêm phế quản mãn tính", "def_ko": "만성 기침, 가래, 호흡곤란 등의 증상을 동반하는 질병", "def_vi": "Bệnh có triệu chứng như ho mãn tính, đờm và khó thở"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증세 및 시그널", "def_vi": "Biểu hiện và tín hiệu"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "호흡기에서 배출되는 점액", "def_vi": "Chất nhầy được loại bỏ khỏi đường hô hấp"}, {"term_ko": "심호흡", "term_vi": "Hít thở sâu", "def_ko": "깊은 호흡", "def_vi": "Thở sâu"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "호흡기가 자극받을 때 발생하는 반사 작용", "def_vi": "Phản ứng xảy ra khi đường hô hấp bị kích thích"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (875, '5', '다음 증상이 나타나는 질환은?• 체중 감소, 잦은 호흡기 감염• 점진적으로 호흡곤란이 심화• 이른 아침에 발생하는 가래 끓는 기침', '["만성기관지염", "폐렴", "폐결핵", "천식", "심부전"]'::jsonb, 1, NULL, NULL, '{"1": "만성기관지염은 지속적인 기침과 가래가 동반되며 체중 감소와 잦은 호흡기 감염이 나타날 수 있습니다.\n[정답]", "2": "폐렴은 급성 호흡기 감염으로 일반적으로 기침과 가래가 발생하지만 체중 감소와 잦은 감염은 만성적으로 나타나기 어렵습니다.", "3": "폐결핵은 체중 감소와 기침이 있지만, 주로 밤에 땀을 흘리는 증상이 더 두드러집니다.", "4": "천식은 발작적 호흡곤란이 특징이며, 가래는 드물게 나타납니다.", "5": "심부전은 호흡곤란을 유발할 수 있으나, 주로 체중 증가 및 부종이 동반됩니다."}'::jsonb, '[{"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (874, '5', '고열과 함께 기침 등 호흡기 증상을 일으키는 인플루엔자에 대한 설명으로 옳은 것은?', '["혈액으로 감염되는 질병이다.", "치료제로 항바이러스제를 사용한다.", "증상 발현 이후에는 전파 위험이 없다.", "감염자와 접촉한 사람은 증상 유무에 관계없이 치료한다.", "감염 후 회복 중에 발열과 누런 가래가 생기는 것은 정상이다."]'::jsonb, 2, NULL, NULL, '{"1": "인플루엔자는 호흡기 감염으로 혈액으로 전파되지 않습니다.\n[정답]", "2": "인플루엔자의 치료에는 항바이러스제가 사용됩니다.", "3": "증상 발현 이후에도 전파 위험이 존재합니다.", "4": "감염자와 접촉한 사람들은 증상이 나타나지 않아도 예방 차원에서 치료할 수 있습니다.", "5": "회복 중에 발열과 누런 가래가 발생할 수 있지만, 이는 일반적인 경우에 해당하지 않습니다."}'::jsonb, '[{"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "고온(한국어)", "def_vi": "Nhiệt độ cơ thể tăng cao"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침(한국어)", "def_vi": "Hắt hơi"}, {"term_ko": "호흡기", "term_vi": "Đường hô hấp", "def_ko": "호흡기(한국어)", "def_vi": "Đường thở"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "인플루엔자(한국어)", "def_vi": "Cúm"}, {"term_ko": "치료제", "term_vi": "Thuốc điều trị", "def_ko": "치료제(한국어)", "def_vi": "Thuốc điều trị"}, {"term_ko": "항바이러스제", "term_vi": "Thuốc kháng virus", "def_ko": "항바이러스제(한국어)", "def_vi": "Thuốc kháng virus"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (873, '5', '노화에 따라 일반적으로 나타나는 호흡기계 변화는?', '["호흡기계 감염 감소", "폐활량 증가", "호흡근육 근력 감소", "기관지 내 분비물 감소", "신체조직 내 수분 함유량 증가"]'::jsonb, 3, NULL, NULL, '{"1": "노화에 따라 호흡기계 감염이 증가하는 편이다.\n[정답]", "3": "노화에 따라 호흡근육의 근력이 감소하는 것이 일반적이다.", "2": "노화로 인해 폐활량은 감소하는 경향이 있다.", "4": "노화에 따라 기관지의 분비물은 증가할 수 있다.", "5": "신체조직 내 수분 함유량은 노화에 따라 감소하는 경우가 많다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이의 증가에 따라 신체적, 정신적 기능이 저하되는 과정", "def_vi": "Quá trình suy giảm chức năng cơ thể và tâm lý theo sự gia tăng độ tuổi"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "숨을 쉴 때 사용되는 기관과 구조", "def_vi": "Các cơ quan và cấu trúc tham gia vào việc thở"}, {"term_ko": "폐활량", "term_vi": "Dung tích phổi", "def_ko": "폐가 한 번의 호흡으로 흡입 또는 내보낼 수 있는 공기의 총량", "def_vi": "Tổng lượng không khí mà phổi có thể hít vào hoặc thở ra trong một nhịp"}, {"term_ko": "호흡근육", "term_vi": "Cơ hô hấp", "def_ko": "호흡을 담당하는 근육들", "def_vi": "Các cơ chịu trách nhiệm cho việc thở"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "폐로 공기를 운반하는 통로", "def_vi": "Đường dẫn không khí vào phổi"}, {"term_ko": "신체조직", "term_vi": "Mô cơ thể", "def_ko": "신체를 구성하는 조직", "def_vi": "Các mô cấu thành cơ thể"}, {"term_ko": "수분 함유량", "term_vi": "Nồng độ nước", "def_ko": "물이 포함된 양", "def_vi": "Lượng nước có trong mô"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (872, '5', '노화에 따른 호흡기계의 특성으로 옳은 것은?', '["폐순환량 감소", "폐포의 탄력성 증가", "호흡근육의 근력 강화", "기침반사 증가", "섬모운동 증가"]'::jsonb, 1, NULL, NULL, '{"1": "노화로 인해 폐순환량이 감소하는 것은 맞는 설명입니다. 이는 노화로 인해 호흡기계의 구조와 기능이 변화하기 때문입니다.\n[정답]", "2": "노화가 진행됨에 따라 폐포의 탄력성은 감소하는 경향이 있습니다.", "3": "노화에 따라 호흡근육의 근력은 약화될 수 있습니다.", "4": "기침반사는 노화로 인해 감소하는 경우가 많습니다.", "5": "섬모운동은 노화에 따라 일반적으로 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음, 나이듦(성장과 시간의 경과로 인한 변화)", "def_vi": "Sự già hóa, quá trình thay đổi do tuổi tác"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "호흡과 연관된 기관들의 집합체", "def_vi": "Tập hợp các cơ quan liên quan đến hô hấp"}, {"term_ko": "폐순환량", "term_vi": "Lượng tuần hoàn phổi", "def_ko": "폐로 가는 혈액의 양", "def_vi": "Lượng máu chảy đến phổi"}, {"term_ko": "폐포", "term_vi": "Phế nang", "def_ko": "호흡의 기본 단위", "def_vi": "Đơn vị cơ bản của hô hấp"}, {"term_ko": "탄력성", "term_vi": "Tính đàn hồi", "def_ko": "원래 형태로 돌아가려는 성질", "def_vi": "Tính chất trở về hình dạng ban đầu"}, {"term_ko": "호흡근육", "term_vi": "Cơ bắp hô hấp", "def_ko": "호흡에 관여하는 근육", "def_vi": "Cơ bắp tham gia vào hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "호흡기에 자극이 있을 때 나타나는 반응", "def_vi": "Phản ứng khi có kích thích ở đường hô hấp"}, {"term_ko": "반사", "term_vi": "Phản xạ", "def_ko": "자극에 대한 자동적인 반응", "def_vi": "Phản ứng tự động đối với kích thích"}, {"term_ko": "섬모", "term_vi": "Lông niệu", "def_ko": "세포에 붙어있는 미세한 털", "def_vi": "Sợi tóc mịn gắn vào tế bào"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (871, '5', '변비 대상자를 돕는 방법으로 옳은 것은?', '["복부 마사지를 해준다.", "변비약을 주기적으로 권한다.", "하제 사용을 많이 한다.", "수분 섭취를 줄인다.", "음식 섭취량을 줄인다."]'::jsonb, 1, NULL, NULL, '{"1": "복부 마사지는 장의 움직임을 촉진시켜 변비 완화에 도움을 줍니다.\n[정답]", "2": "변비약을 주기적으로 사용하는 것은 의사의 처방에 따라야 하며, 자주 권하는 것은 적절치 않습니다.", "3": "하제 사용은 장기간 사용 시 의존성을 초래할 수 있습니다.", "4": "수분 섭취는 오히려 증가시켜야 하며, 줄이는 것은 바람직하지 않습니다.", "5": "음식 섭취량을 줄이는 것은 변비를 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변을 보기 어렵거나 귀찮은 상태", "def_vi": "Tình trạng khó khăn hoặc phiền phức khi đi đại tiện"}, {"term_ko": "마사지를 하다", "term_vi": "Xoa bóp", "def_ko": "신체의 특정 부위를 문지르거나 눌러서 자극을 주는 것", "def_vi": "Sự chà xát hoặc ấn vào một phần cụ thể của cơ thể để kích thích"}, {"term_ko": "하제", "term_vi": "Thuốc nhuận tràng", "def_ko": "대변을 부드럽게 하는 약물", "def_vi": "Thuốc làm mềm phân"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "체내의 물 성분", "def_vi": "Thành phần nước trong cơ thể"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "섭취하는 모든 물질", "def_vi": "Tất cả các chất được tiêu thụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (870, '5', '변비의 원인이 되는 요인으로 옳은 것은?', '["신체활동 증가", "충분한 수분 섭취", "마약성 진통제 복용", "복부 근육의 힘 강화", "규칙적인 배변 습관"]'::jsonb, 3, NULL, NULL, '{"1": "신체활동이 증가하면 장 운동이 원활해져 변비 예방에 도움을 준다.", "2": "충분한 수분 섭취는 변을 부드럽게 하여 변비를 예방한다.\n[정답]", "3": "마약성 진통제 복용은 장의 기능을 억제하여 변비를 유발할 수 있다.", "4": "복부 근육의 힘 강화는 변비 예방에 도움이 된다.", "5": "규칙적인 배변 습관은 변비를 예방하는 중요한 방법이다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변이 딱딱해지고 배변이 어려운 상태", "def_vi": "Tình trạng phân cứng và khó đi vệ sinh"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "운동이나 활동을 통해 신체를 움직이는 것", "def_vi": "Điều gì đó mà cơ thể được vận động hoặc chuyển động"}, {"term_ko": "마약성 진통제", "term_vi": "Thuốc giảm đau có chứa narcotic", "def_ko": "마약에 해당하는 진통제", "def_vi": "Thuốc giảm đau thuộc loại thuốc phiện"}, {"term_ko": "배변 습관", "term_vi": "Thói quen đi vệ sinh", "def_ko": "대변을 보는 방식이나 패턴", "def_vi": "Cách thức hoặc thói quen đi vệ sinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (869, '5', '변비를 유발하는 식사로 옳은 것은?', '["우유 섭취", "저잔여식이 섭취", "수분이 많은 음식 섭취", "섬유질이 많은 음식 섭취", "유산균이 많이 포함된 음식 섭취"]'::jsonb, 2, NULL, NULL, '{"1": "우유는 변비를 완화시킬 수 있는 성분이 있는 음식입니다.\n[정답]", "2": "저잔여식이는 변비를 유발할 수 있는 식사입니다.", "3": "수분이 많은 음식 섭취는 변비를 예방하는 데 도움이 됩니다.", "4": "섬유질이 많은 음식은 변비를 해결하는 데 효과적입니다.", "5": "유산균이 많이 포함된 음식은 장에 긍정적인 영향을 주어 변비를 완화할 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "변의 배출이 어려운 상태(한국어)", "def_vi": "Trạng thái khó tiêu hóa phân"}, {"term_ko": "저잔여식이", "term_vi": "Chế độ ăn ít cặn", "def_ko": "섬유소가 적은 식사(한국어)", "def_vi": "Bữa ăn ít chất xơ"}, {"term_ko": "유산균", "term_vi": "Probiotic", "def_ko": "장 건강에 좋은 균(한국어)", "def_vi": "Vi khuẩn có lợi cho sức khỏe đường ruột"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (868, '5', '노인에게 변비가 많은 이유로 옳은 것은?', '["과도한 하제 남용", "충분한 수분섭취", "저작능력 증가", "음식물 섭취량 증가", "장근육의 긴장도 증가"]'::jsonb, 1, NULL, NULL, '{"1": "과도한 하제 남용은 변비를 유발할 수 있습니다. 노인들은 약물에 의한 의존성이 있을 수 있으며, 이는 변비를 악화시킵니다.\n[정답]", "2": "충분한 수분섭취는 오히려 변비 예방에 도움이 됩니다. 노인에게 물 섭취가 부족할 경우 변비가 발생할 수 있습니다.", "3": "저작능력 증가가 변비와 관련이 없으며, 이는 오히려 음식 섭취를 촉진합니다.", "4": "음식물 섭취량 증가가 변비를 유발하는 것은 아니며, 적절한 식사가 장 건강에 유익합니다.", "5": "장근육의 긴장도 증가가 변비와 직접적인 관계가 없습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태(한국어)", "def_vi": "Tình trạng khó đi đại tiện (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (867, '5', '변비의 발생 원인으로 옳은 것은?', '["규칙적인 운동", "섬유질이 많은 음식 섭취", "수분섭취 부족", "장운동 증가", "복부 근육의 힘 증가"]'::jsonb, 3, NULL, NULL, '{"1": "규칙적인 운동은 장의 운동을 촉진시켜 변비를 예방합니다.", "2": "섬유질이 많은 음식 섭취는 장의 건강을 돕고 변비 예방에 도움을 줍니다.\n[정답]", "3": "수분섭취 부족은 변비의 주요 원인 중 하나입니다. 수분이 부족하면 대변이 단단해져 배출이 어려워집니다.", "4": "장운동 증가는 변비를 완화하는 요인입니다.", "5": "복부 근육의 힘 증가는 변비 예방에 도움이 됩니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi tiêu"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체 활동", "def_vi": "Hoạt động thể chất"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "몸에 필요한 물", "def_vi": "Nước cần thiết cho cơ thể"}, {"term_ko": "섬유질", "term_vi": "Chất xơ", "def_ko": "식이섬유", "def_vi": "Chất xơ trong thực phẩm"}, {"term_ko": "장운동", "term_vi": "Hoạt động của ruột", "def_ko": "장의 움직임", "def_vi": "Sự di chuyển của ruột"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배 부분", "def_vi": "Phần bụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (866, '5', '잦은 설사로 탈수가 예상되는 대상자에게 우선적으로 돕는 방법은?', '["우유 섭취량을 늘린다.", "식사를 충분히 제공한다.", "물을 충분히 마시게 한다.", "수시로 지사제를 복용시킨다.", "장운동을 증가시키는 음식을 먹게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "우유는 수분을 제공할 수 있지만, 설사 시에는 유제품이 기저에 영향을 줄 수 있다.\n[정답]", "3": "물은 탈수 예방에 가장 기초적인 방법이며, 우선적으로 공급해야 한다.", "2": "식사가 충분하더라도 수분이 부족하면 탈수를 막기 어렵다.", "4": "지사제를 사용하기보다는 수분을 보충하는 것이 우선이다.", "5": "장운동을 증가시키는 음식은 오히려 설사를 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (865, '5', '대상자가 수차례 설사 후에 피부가 건조하고 힘이 없다고 할 때 돕는 방법으로 옳은 것은?', '["지사제를 바로 공급한다.", "녹차나 커피를 제공한다.", "음식량을 늘리낟.", "고지방식을 제공한다.", "몸을 따뜻하게 하고 수분섭취를 해준다."]'::jsonb, 5, NULL, NULL, '{"1": "지사제를 바로 공급하는 것은 지양해야 한다. 장의 자연스러운 회복을 방해할 수 있다.\n[정답]", "5": "몸을 따뜻하게 하고 수분 섭취를 해주는 것이 가장 적절하다. 체온 유지와 수분 보충은 회복에 도움이 된다.", "3": "음식량을 늘리는 것은 GI 트랙에 부담을 줄 수 있다.", "4": "고지방식은 소화에 어려움을 줄 수 있어 피해야 한다.", "2": "녹차나 커피는 이뇨작용을 증가시켜 탈수 상태를 악화할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (864, '5', '대상자가 설사를 할 때 제공하는 음식으로 옳은 것은?', '["우유", "비빔밥, 콜라", "흰죽, 보리차", "사과, 복숭아", "제육볶음, 현미밥"]'::jsonb, 3, NULL, NULL, '{"1": "우유는 소화가 어려워 설사를 악화시킬 수 있습니다.\n[정답]", "3": "흰죽과 보리차는 소화가 잘되고 수분 보충에 도움이 됩니다.", "2": "비빔밥과 콜라는 기름지고 자극적이어서 피해야 합니다.", "4": "사과와 복숭아는 섬유질이 많아 소화에 부담을 줄 수 있습니다.", "5": "제육볶음과 현미밥은 기름지고 소화가 어려운 음식입니다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "증상(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (863, '5', '설사의 발생 원인으로 옳은 것은?', '["뜨거운 음식물 섭취", "균형 잡힌 식사", "식물성 식이섬유 섭취", "하제 등 약물의 남용", "소화기능의 증가"]'::jsonb, 4, NULL, NULL, '{"1": "뜨거운 음식물 섭취는 일반적으로 설사를 유발하지 않습니다.\n[정답]", "4": "하제 등 약물의 남용은 설사의 일반적인 원인입니다.", "2": "균형 잡힌 식사는 설사를 예방하는 데 도움이 됩니다.", "3": "식물성 식이섬유 섭취는 소화를 돕지만 설사를 유발하지 않습니다.", "5": "소화기능의 증가는 설사와 관련이 없습니다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "설사는 화장실을 자주 가고 물 같은 변을 보는 증상입니다.", "def_vi": "Là triệu chứng đi vệ sinh thường xuyên và có phân lỏng."}, {"term_ko": "하제", "term_vi": "Thuốc nhuận tràng", "def_ko": "대변의 배출을 촉진하는 약물입니다.", "def_vi": "Là loại thuốc thúc đẩy việc thải phân."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (862, '5', '대장암 환자의 식이요법으로 옳은 것은?', '["간식을 수시로 섭취한다.", "통곡물로 만든 음식을 섭취한다.", "동물성 식품을 많이 섭취한다.", "염장식품을 섭취한다.", "생채소, 생과일 섭취를 제한한다."]'::jsonb, 2, NULL, NULL, '{"1": "대장암 환자는 간식을 자주 섭취하는 것이 건강에 좋지 않다.\n[정답]", "2": "통곡물로 만든 음식은 식이섬유가 풍부하여 대장 건강에 도움이 된다.", "3": "동물성 식품은 지방이 높아 대장암 환자에게 좋지 않다.", "4": "염장식품은 발암물질이 포함될 수 있어 피하는 것이 좋다.", "5": "생채소와 생과일은 대장 건강에 이로운 식품이므로 섭취를 제한해서는 안 된다."}'::jsonb, '[{"term_ko": "식이요법", "term_vi": "Chế độ ăn uống", "def_ko": "식사 치료법(한국어)", "def_vi": "Phương pháp điều trị bằng ăn uống"}, {"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 생기는 암(한국어)", "def_vi": "Ung thư xảy ra ở đại tràng"}, {"term_ko": "통곡물", "term_vi": "Ngũ cốc nguyên hạt", "def_ko": "곡물을 정제하지 않은 것(한국어)", "def_vi": "Ngũ cốc không được tinh chế"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화되지 않는 섬유소(한국어)", "def_vi": "Chất không tiêu hóa được"}, {"term_ko": "발암물질", "term_vi": "Chất gây ung thư", "def_ko": "암을 유발하는 물질(한국어)", "def_vi": "Chất gây ra bệnh ung thư"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (861, '5', '대장암 환자의 식이요법으로 옳은 것은?', '["정제된 곡물을 섭취한다.", "훈연된 동물성 식품을 섭취한다.", "고칼로리 음식을 섭취한다.", "하루에 6~8잔의 생수를 마신다.", "입맛을 돋우는 자극적인 음식을 섭취한다."]'::jsonb, 4, NULL, NULL, '{"1": "정제된 곡물은 섬유소가 적어 식이요법에 적합하지 않다.\n[정답]", "4": "하루에 6~8잔의 생수는 수분 섭취를 돕고 장 건강에 좋다.", "2": "훈연된 동물성 식품은 발암물질이 포함될 수 있어 대장암 환자에게 바람직하지 않다.", "3": "고칼로리 음식은 비만을 유발할 수 있어 추천되지 않는다.", "5": "자극적인 음식은 대장에 부담을 줄 수 있어 피해야 한다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 발생하는 암", "def_vi": "Ung thư xảy ra ở đại tràng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (860, '5', '대장암 대상자의 식이요법으로 옳은 것은?', '["생채소, 생과일을 충분히 섭취한다.", "육류는 훈연하여 섭취한다.", "간식으로 튀김류를 자주 섭취한다.", "차가운 아이스크림으로 식욕을 돋운다.", "흰죽을 야식으로 섭취한다."]'::jsonb, 1, NULL, NULL, '{"1": "대장암 환자에게는 식이섬유가 풍부한 생채소와 생과일을 섭취하는 것이 좋다.\n[정답]", "2": "육류는 훈연하여 섭취하는 것이 건강에 해로울 수 있다.", "3": "튀김류는 지방이 많아 좋지 않은 선택이다.", "4": "차가운 아이스크림은 대장에 자극을 줄 수 있어 피해야 한다.", "5": "흰죽은 소화가 잘되지만, 충분한 영양소를 포함하지 않아 단독 섭취는 좋지 않다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "식이요법", "def_ko": "결 colon cancer", "def_vi": "chế độ ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (859, '5', '대장암 환자에게 적합한 음식은?', '["현미밥", "라면", "육개장", "명란젓", "피자"]'::jsonb, 1, NULL, NULL, '{"1": "현미밥은 식이섬유가 풍부하여 대장 건강에 도움을 줄 수 있어 대장암 환자에게 적합하다.\n[정답]", "2": "라면은 염분과 첨가물이 많아 대장암 환자에게 좋지 않다.", "3": "육개장은 기름과 염분이 높아 대장암 환자에게 부적합할 수 있다.", "4": "명란젓 역시 염분이 높아 대장암 환자에게 추천되지 않는다.", "5": "피자는 고지방, 고열량 음식으로 대장암 환자에게는 좋지 않다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 생기는 암", "def_vi": "Ung thư xảy ra ở đại tràng"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화할 수 없는 식물성 영양소", "def_vi": "Chất dinh dưỡng thực vật không tiêu hóa được"}, {"term_ko": "염분", "term_vi": "Natri", "def_ko": "소금의 성분", "def_vi": "Thành phần của muối"}, {"term_ko": "고지방", "term_vi": "Chất béo cao", "def_ko": "지방이 많은", "def_vi": "Nhiều chất béo"}, {"term_ko": "고열량", "term_vi": "Nhiều calo", "def_ko": "칼로리가 많은", "def_vi": "Nhiều năng lượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (858, '5', '대상자가 최근 체중감소와 설사, 변비, 점액이 섞인 혈변을 자주 호소할 때 의심되는 질환은?', '["위암", "췌장암", "대장암", "위염", "신부전"]'::jsonb, 3, NULL, NULL, '{"1": "위암은 소화기계의 악성 종양으로 체중 감소가 있을 수 있지만 혈변과 같은 특정 증상은 없습니다.\n[정답]", "2": "췌장암은 소화기계에 영향을 미칠 수 있으나 주된 증상은 아닙니다.", "3": "대장암은 체중 감소, 설사, 변비, 혈변 등과 연관이 있으므로 해당 증상에 가장 적합합니다.", "4": "위염은 위에서 염증이 발생하는 것으로, 혈변이 자주 나타나지 않습니다.", "5": "신부전은 주로 소변에 영향을 주며 체중 변화가 있을 수 있지만, 위의 증상과는 관계가 적습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (857, '5', '위암 환자가 섭취하는 음식으로 옳은 것은?', '["육개장", "녹황색 채소", "치킨", "카레", "베이컨"]'::jsonb, 2, NULL, NULL, '{"1": "육개장은 기름지고 자극적인 음식으로 위암 환자에게 적합하지 않습니다.\n[정답]", "2": "녹황색 채소는 비타민과 미네랄이 풍부하여 위암 환자에게 좋습니다.", "3": "치킨은 기름지고, 조리법에 따라 위암 환자에게 부적합할 수 있습니다.", "4": "카레는 자극적인 향신료가 포함되어 있어 위암 환자에게 좋지 않습니다.", "5": "베이컨은 고지방식으로 소화가 어렵고 위암 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "위암", "term_vi": "Ung thư dạ dày", "def_ko": "위에서 발생하는 암", "def_vi": "Ung thư xảy ra ở dạ dày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (856, '5', '위암에 대한 설명으로 옳은 것은?', '["체중증가가 나타난다.", "증상만으로 조기진단이 가능하다.", "위암은 가족력이 없다.", "단백질 섭취를 피한다.", "치료 후 5년간은 정기검진으로 재발여부를 확인한다."]'::jsonb, 5, NULL, NULL, '{"1": "위암 환자는 일반적으로 체중 감소가 나타난다.\n[정답]", "5": "치료 후 5년간은 정기검진으로 재발여부를 확인하는 것이 중요하다.", "2": "위암은 증상만으로 조기진단하기 어렵다.", "3": "위암은 가족력이 있을 수 있으며, 가족력은 위험 인자 중 하나다.", "4": "단백질 섭취는 환자의 영양 상태를 고려하여 적절히 조절해야 한다."}'::jsonb, '[{"term_ko": "위암", "term_vi": "Ung thư dạ dày", "def_ko": "위장에서 발생하는 악성 종양", "def_vi": "Khối u ác tính phát sinh trong dạ dày"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Khối lượng cơ thể"}, {"term_ko": "정기검진", "term_vi": "Khám định kỳ", "def_ko": "정해진 주기로 건강 상태를 확인하는 검사", "def_vi": "Kiểm tra tình trạng sức khỏe theo một lịch trình nhất định"}, {"term_ko": "가족력", "term_vi": "Tiền sử gia đình", "def_ko": "가족 내에서 발생한 질병의 이력", "def_vi": "Lịch sử bệnh tật trong gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (855, '5', '질병이 서서히 진행되어 증상이 잘 나타나지 않으며 체중감소와 오심, 출혈, 구토나 복부 종양 덩어리가 나타나는 질환은?', '["식도암", "위암", "간암", "대장암", "폐암"]'::jsonb, 2, NULL, NULL, '{"1": "식도에 생기는 악성 종양으로, 초기에는 증상이 없고 진행될수록 연하곤란과 통증이 나타날 수 있다.\n[정답]", "2": "위에서 발생하는 암으로, 초기에는 증상이 거의 없으며 체중 감소와 오심, 구토가 점진적으로 나타난다.", "3": "간에서 발생하는 암이며, 초기에는 증상이 миним한 경우가 많지만, 황달이나 복통 등의 증상이 나올 수 있다.", "4": "대장에서 발생하는 암으로, 초기에는 무증상이 많고 이후 변화가 나타날 수 있다.", "5": "폐에서 생기는 암으로, 초기에는 기침이나 호흡곤란이 나타나며 진행이 되면 다양한 증상이 발생할 수 있다."}'::jsonb, '[{"term_ko": "질병", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (854, '5', '위궤양 대상자를 돕는 방법으로 옳은 것은?', '["훈연한 음식을 먹게 한다.", "흡연자이면 금연하게 한다.", "잠자리에 들기 전에 녹차를 마시게 한다.", "검은색 대변을 보더라도 정상이라고 안심시킨다.", "비스테로이드성 소염진통제를 자주 복용하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "훈연한 음식은 위에 자극을 줄 수 있으므로 좋지 않습니다.\n[정답]", "2": "흡연은 위궤양에 악영향을 미치므로 금연이 필요합니다.", "3": "잠자리에 들기 전에 녹차를 마시는 것은 위에 자극을 줄 수 있습니다.", "4": "검은색 대변은 위장 출혈을 의미할 수 있어 안심시키는 것이 옳지 않습니다.", "5": "비스테로이드성 소염진통제는 위궤양을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 점막에 생기는 염증성 병변", "def_vi": "Vết thương viêm trên niêm mạc dạ dày"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "비스테로이드성 소염진통제", "term_vi": "Thuốc giảm đau chống viêm không steroid", "def_ko": "소염 및 진통 효과가 있는 약물", "def_vi": "Thuốc có tác dụng giảm đau và chống viêm"}, {"term_ko": "검은색 대변", "term_vi": "Phân có màu đen", "def_ko": "소화관 출혈을 의미할 수 있는 징후", "def_vi": "Dấu hiệu có thể chỉ ra chảy máu tiêu hóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (853, '5', '헬리코박터균 감염이 원인이 되어 속쓰림과 상복부 불편감이 나타나는 질환은?', '["췌장염", "협심증", "담석증", "위궤양", "대장암"]'::jsonb, 4, NULL, NULL, '{"1": "췌장염은 췌장에서 염증이 발생하는 질환으로, 헬리코박터균과는 관련이 없습니다.", "2": "협심증은 심장과 관련된 질환으로, 소화기계와는 관련이 없습니다.", "3": "담석증은 담낭에 결석이 생긴 질환으로, 헬리코박터균 감염과는 관련이 없습니다.\n[정답]", "4": "위궤양은 헬리코박터균 감염으로 인해 발생할 수 있는 질환입니다.", "5": "대장암은 대장에서 발생하는 암으로, 헬리코박터균과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "헬리코박터균", "term_vi": "Vi khuẩn Helicobacter", "def_ko": "위염, 위궤양 유발 원인균", "def_vi": "Vi khuẩn gây viêm dạ dày, loét dạ dày"}, {"term_ko": "속쓰림", "term_vi": "Đau dạ dày", "def_ko": "위에서 불편한 느낌", "def_vi": "Cảm giác không thoải mái ở dạ dày"}, {"term_ko": "상복부", "term_vi": "Thượng vị", "def_ko": "배의 상단 부분", "def_vi": "Phần trên của bụng"}, {"term_ko": "불편감", "term_vi": "Cảm giác khó chịu", "def_ko": "괴로운 느낌", "def_vi": "Cảm giác không thoải mái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (852, '5', '다음과 같은 증상이 나타나는 질환은?• 새벽 1~2시에 발생하는 속쓰림과 상복부 불편감 • 심한 경우 위 출혈, 위 천공, 위 협착', '["위암", "위염", "위궤앙", "식도암", "대장암"]'::jsonb, 3, NULL, NULL, '{"1": "위암: 주로 진행된 상태에서 증상이 나타나므로 이 증상과는 일치하지 않습니다.\n[정답]", "3": "위궤양: 새벽에 발생하는 속쓰림과 복부 불편감, 위 출혈 등과 관련이 있습니다.", "2": "위염: 속쓰림이 있지만, 심한 경우는 이 증상에 비해 덜 위험합니다.", "4": "식도암: 증상은 다르게 나타나므로 부합하지 않습니다.", "5": "대장암: 상복부 불편감보다는 하복부 증상이 주로 발생합니다."}'::jsonb, '[{"term_ko": "속쓰림", "term_vi": "Đau dạ dày", "def_ko": "쓰넣음(한국어)", "def_vi": "Đau dạ dày(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (851, '5', '위염으로 명치 부위의 통증과 구토 증상이 있을 때 도움이 되는 방법은?', '["차가운 음료를 마신다.", "양손으로 상복부를 밀어 올린다.", "처방받은 제산제 복용을 중단한다.", "배고프지 않도록 식사를 자주 한다.", "하루 정도 금식하여 위의 부담을 덜어준다."]'::jsonb, 5, NULL, NULL, '{"1": "차가운 음료를 마신 경우 위염 증상이 악화될 수 있으므로 좋지 않다.\n[정답]", "5": "하루 정도 금식하여 위의 부담을 덜어주는 것이 위염 증상 완화에 도움이 된다.", "2": "양손으로 상복부를 밀어 올리는 방법은 통증을 유발할 수 있어 피해야 한다.", "3": "처방받은 제산제 복용을 중단하는 것은 증상을 악화시킬 수 있다.", "4": "배고프지 않도록 식사를 자주 하는 것은 위에 부담을 줄 수 있어 바람직하지 않다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm của dạ dày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (850, '5', '위염의 치료 및 예방법으로 옳은 것은?', '["금식 시 수분 섭취를 줄인다.", "자극적인 음식을 섭취한다.", "금식 후 뜨거운 음식을 섭취한다.", "제산제, 진정제 등의 약물을 사용한다.", "활발하게 신체를 움직여서 위장운동을 촉진한다."]'::jsonb, 4, NULL, NULL, '{"1": "금식을 하더라도 수분 섭취는 충분히 해야 합니다.", "2": "자극적인 음식은 위염을 악화시킬 수 있습니다.", "3": "금식 후 뜨거운 음식은 위에 자극을 줄 수 있습니다.\n[정답]", "4": "제산제와 진정제는 위염 치료에 도움을 줍니다.", "5": "과도한 신체 활동은 위장에 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Sự viêm của dạ dày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (849, '5', '배가 고프기 시작할 때 발생하는 명치 부위와 심한 통증과 식사 후 위가 무겁거나 부푼듯한 느낌을 주는 질환은?', '["위궤양", "당뇨병", "변비", "위염", "대장암"]'::jsonb, 4, NULL, NULL, '{"1": "위궤양은 특정한 복통과 관련이 있지만 통증의 위치와 느낌이 다릅니다.\n[정답]", "4": "위염은 명치 부위의 통증과 식사 후 무겁거나 부풀어 오른 느낌과 관련이 있습니다.", "3": "변비는 주로 배변과 관련된 문제로 통증 위치와는 거리가 있습니다.", "2": "당뇨병은 위의 증상과는 관련이 적습니다.", "5": "대장암도 통증의 위치와 다르며, 이 문제의 증상과는 맞지 않습니다."}'::jsonb, '[{"term_ko": "명치", "term_vi": "Thượng vị", "def_ko": "위쪽 복부의 중앙 부분", "def_vi": "Phần giữa trên bụng"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔, 아프다", "def_vi": "Cảm giác không thoải mái"}, {"term_ko": "무겁다", "term_vi": "Nặng", "def_ko": "재기거나 무겁게 느끼는 것", "def_vi": "Cảm thấy nặng nề"}, {"term_ko": "부풀다", "term_vi": "Sưng phồng", "def_ko": "부풀어 오른 느낌", "def_vi": "Cảm giác đầy bụng"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm ở dạ dày"}, {"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 상처", "def_vi": "Vết thương trong dạ dày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (848, '5', '노화에 따라 일반적으로 나타나는 소화기계 변화는?', '["타액 분비 증가", "위액의 산도 증가", "지방의 흡수력 증가", "쓴맛, 신맛의 미각 감소", "약물 대사능력 감소"]'::jsonb, 5, NULL, NULL, '{"1": "타액 분비 증가는 노화와 관련이 없습니다.\n[정답]", "5": "약물 대사능력이 감소하는 것은 노화로 인해 나타나는 일반적인 변화입니다.", "2": "위액의 산도는 일반적으로 노화에 따라 감소합니다.", "3": "지방의 흡수력은 노화에 따라 감소합니다.", "4": "미각은 노화에 따라 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이로 인해 신체 기능이 저하되는 과정", "def_vi": "Quá trình giảm chức năng cơ thể do tuổi tác"}, {"term_ko": "타액", "term_vi": "Nước bọt", "def_ko": "입에서 나오는 소화액", "def_vi": "Dịch tiêu hóa được tiết ra từ miệng"}, {"term_ko": "위액", "term_vi": "Dịch vị", "def_ko": "위에서 나오는 소화액", "def_vi": "Dịch tiêu hóa được tiết ra từ dạ dày"}, {"term_ko": "미각", "term_vi": "Khả năng nếm vị", "def_ko": "맛을 느끼는 능력", "def_vi": "Khả năng cảm nhận mùi vị"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위해 사용하는 물질", "def_vi": "Chất được sử dụng để điều trị"}, {"term_ko": "대사", "term_vi": "Chuyển hóa", "def_ko": "체내에서 물질이 변환되는 과정", "def_vi": "Quá trình chuyển đổi chất trong cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (847, '5', '노화에 따른 소화기계의 변화로 옳은 것은?', '["당내성 감소", "대장연동운동 증가", "단맛, 짠맛 감각 증가", "췌장의 소화효소 분비 증가", "항문 괄약근 긴장도 증가"]'::jsonb, 1, NULL, NULL, '{"1": "당내성 감소는 노화에 따른 소화기계의 변화로 맞습니다.\n[정답]", "2": "대장연동운동 증가는 노화의 결과가 아닙니다.", "3": "단맛, 짠맛 감각은 노화로 인해 감소합니다.", "4": "췌장의 소화효소 분비는 노화에 따라 감소합니다.", "5": "항문 괄약근 긴장도는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감", "def_vi": "Sự già đi"}, {"term_ko": "소화기계", "term_vi": "Hệ tiêu hóa", "def_ko": "음식물을 소화하는 시스템", "def_vi": "Hệ thống tiêu hóa thức ăn"}, {"term_ko": "당내성", "term_vi": "Khả năng dung nạp đường", "def_ko": "당분을 처리하는 능력", "def_vi": "Khả năng xử lý đường"}, {"term_ko": "대장연동운동", "term_vi": "Vận động đại tràng", "def_ko": "대장의 운동 활동", "def_vi": "Hoạt động vận động của đại tràng"}, {"term_ko": "췌장", "term_vi": "Tụy", "def_ko": "소화 효소를 생성하는 기관", "def_vi": "Cơ quan sản xuất enzyme tiêu hóa"}, {"term_ko": "항문 괄약근", "term_vi": "Cơ vòng hậu môn", "def_ko": "항문을 제어하는 근육", "def_vi": "Cơ kiểm soát hậu môn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (846, '5', '노화에 따른 소화기계의 변화로 옳은 것은?', '["맛을 느끼는 세포수가 증가한다.", "후각기능은 변함이 없고, 미각은 둔화된다.", "타액과 위액분비가 상승하여 소화가 잘 된다.", "의치의 사용으로 음식을 잘 씹게 된다.", "소화능력의 저하로 변비, 설사, 구토 등이 생긴다."]'::jsonb, 5, NULL, NULL, '{"1": "맛을 느끼는 세포수가 증가하지 않고, 오히려 감소한다.\n[정답]", "5": "소화능력이 저하되어 변비, 설사, 구토 등의 증상이 발생할 수 있다.", "2": "후각기능도 대체로 둔화되며, 미각이 둔화되는 경우가 흔하다.", "3": "타액과 위액 분비는 일반적으로 감소하여 소화가 더 어려워진다.", "4": "의치 사용이 모든 사람에게 음식을 잘 씹게 하는 것은 아니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노인 또는 나이가 많음", "def_vi": "Người già hoặc nhiều tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (845, '5', '노화에 따른 소화기계 특성으로 옳은 것은?', '["대장의 활동성 증가", "미각과 후각 기능 둔감", "타액과 위액분비 증가", "직장벽의 탄력성 증가", "지방의 흡수력 증가"]'::jsonb, 2, NULL, NULL, '{"1": "대장의 활동성 증가: 노화가 진행되면서 대장의 활동성은 일반적으로 감소한다. \n[정답]", "2": "미각과 후각 기능 둔감: 노화로 인해 미각과 후각의 기능이 둔감해지는 것이 일반적이다.", "3": "타액과 위액분비 증가: 노화가 진행되면 타액과 위액의 분비가 감소한다.", "4": "직장벽의 탄력성 증가: 노화로 인하여 직장벽의 탄력성은 감소한다.", "5": "지방의 흡수력 증가: 노화는 지방의 흡수력을 감소시킨다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음(한국어)", "def_vi": "Già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (844, '5', '다음 중 소화된 음식물의 수분을 흡수하여 대변 형태로 굳게 만드는 역할을 하는 소화기계 기관은?', '["췌장", "소장", "ㄷ대장", "위", "십이지장"]'::jsonb, 3, NULL, NULL, '{"1": "췌장은 소화 효소를 분비하여 음식을 소화하는 역할을 합니다.\n[정답]", "3": "대장은 소화된 음식물의 수분을 흡수하여 대변 형태로 굳게 만드는 주된 기관입니다.", "2": "소장은 영양소를 흡수하는 주요한 기관입니다.", "4": "위는 음식을 저장하고 소화하는 역할을 합니다.", "5": "십이지장은 소화 효소와 담즙이 섞여 음식을 분해하는 곳입니다."}'::jsonb, '[{"term_ko": "소화기계", "term_vi": "대변", "def_ko": "소화기관의 집합체(소 hệ tiêu hóa)", "def_vi": "체내에서 소화된 음식물의 찌꺼기(phân)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (843, '5', '노인성 질환의 특징으로 옳은 것은?', '["급성질환으로 회복이 느리다.", "만성질환으로 치료가 빠르다.", "혈액순환 저하로 욕창이 잘 발생한다.", "질환의 원인은 명확하나 치료가 어렵다.", "한 가지 질병이 단독으로 발생한다."]'::jsonb, 3, NULL, NULL, '{"1": "노인성 질환은 급성 질환이 아니므로, 이 보기는 부정확하다.\n[정답]", "3": "혈액순환 저하로 욕창이 잘 발생하는 것은 노인성 질환의 특징이다.", "2": "만성질환은 치료가 느리므로, 이 보기도 부정확하다.", "4": "질환의 원인이 명확할지라도 치료가 어려운 경우가 많아 이 보기도 부정확하다.", "5": "노인성 질환은 여러 가지 질병이 동시에 발생할 수 있으므로 이 보기도 부정확하다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Bệnh lý người cao tuổi", "def_ko": "노인이 앓는 병", "def_vi": "Bệnh mà người cao tuổi mắc phải"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (842, '5', '노인성 질환의 특성에 대한 설명으로 옳은 것은?', '["가벼운 질환에도 의식장애가 발생한다.", "초기 진단과 예후 예측이 용이하다.", "원인이 병확한 만성 퇴행성 질병이다.", "증상이 뚜렷하여 기존 질병명으로 구분된다.", "신장의 배설 능력 저하로 약물의 배설이 빠르다."]'::jsonb, 1, NULL, NULL, '{"1": "가벼운 질환에도 의식장애가 발생할 수 있다. 이는 노인에서 뇌 기능이 저하되어 있을 가능성이 증가하기 때문이다.\n[정답]", "2": "초기 진단과 예후 예측이 용이하다고 할 수 없다. 노인성 질환은 특성상 증상이 복잡하고 비특이적이기 때문이다.", "3": "노인성 질환은 반드시 만성 퇴행성 질병이라는 잘못된 인식이다. 다양한 원인에 의해 발생할 수 있다.", "4": "증상이 뚜렷하여 기존 질병명으로 구분된다고 보기 어려운 경우가 많다.", "5": "신장의 배설 능력 저하로 약물의 배설이 느려진다. 이는 노인에서 흔한 상황이다."}'::jsonb, '[{"term_ko": "노인성 질환", "term_vi": "Bệnh tuổi già", "def_ko": "고령자에게 흔한 질병", "def_vi": "Bệnh phổ biến ở người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (841, '5', '노인이 약물에 쉽게 중독되는 이유로 옳은 것은?', '["혈액순환 증가", "간의 대사능력 증가", "약물의 흡수능력 증가", "신장의 배설능력 감소", "위장의 위산분비 증가"]'::jsonb, 4, NULL, NULL, '{"1": "혈액순환이 증가하면 약물의 분포가 빨라질 수 있으나, 노인의 경우 일반적으로 혈액순환이 감소합니다.\n[정답]", "4": "신장의 배설능력이 감소하면 약물이 체내에 더 오래 남아있게 되어 중독 위험이 증가합니다.", "2": "간의 대사능력이 증가하는 것은 노인의 특성과 맞지 않으며, 대신 일반적으로 감소합니다.", "3": "약물의 흡수능력이 증가하는 것도 노인에서 일반적으로 나타나지 않으며, 노화로 인해 흡수 능력이 저하될 수 있습니다.", "5": "위장의 위산 분비가 증가하면 약물의 흡수가 더 잘 될 수 있지만, 노인에서는 위산 분비가 감소하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "독성이 있어 몸에 해로운 상태", "def_vi": "Tình trạng độc hại cho cơ thể"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위해 사용하는 화학물질", "def_vi": "Chất hóa học sử dụng để chữa bệnh"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "배설 기능을 하는 장기", "def_vi": "Cơ quan thực hiện chức năng bài tiết"}, {"term_ko": "대사", "term_vi": "Chuyển hóa", "def_ko": "체내 물질이 변화하는 과정", "def_vi": "Quá trình thay đổi chất trong cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (840, '5', '다음 중 노인성 질환의 특성으로 옳은 것은?', '["질환의 경과가 빠른 급성질환이 대부분이다.", "젊은 사람보다 약물에 둔감하게 반응한다.", "질환이 빈번히 발생하여 회복이 빠르다.", "노화과정과 구분이 어려워 정확한 진단이 어렵다.", "골격근의 수축력 증가로 관절운동이 용이하다."]'::jsonb, 4, NULL, NULL, '{"1": "급성질환은 일반적으로 노인성 질환에 해당하지 않습니다. 노인성 질환은 만성적입니다.\n[정답]", "4": "노인성 질환은 노화 과정과 밀접한 관련이 있어 진단이 어렵습니다.", "3": "노인성 질환은 빈번히 발생하지만 회복이 느린 경향이 있습니다.", "2": "노인의 약물 반응은 젊은 사람에 비해 변화가 있을 수 있으나 둔감하다고 일반화할 수 없습니다.", "5": "노화로 골격근의 수축력이 감소하는 경우가 많아 관절 운동이 용이하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Người cao tuổi", "def_ko": "노화로 인한", "def_vi": "Do quá trình lão hóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (839, '5', '노인성 질환의 특성으로 옳은 것은?', '["노인성 질환은 경과가 짤다.", "합병증이 동반되지 않는다.", "질환이 치유되면 자립생활이 가능하다.", "전형적인 증상이 빈번하게 나타난다.", "다른 질병을 동반하기 쉽다."]'::jsonb, 5, NULL, NULL, '{"1": "노인성 질환은 보통 경과가 길다.\n[정답]", "5": "노인성 질환은 다른 질병을 동반하기 쉬운 경향이 있다.", "2": "노인성 질환은 합병증이 동반되기 쉽다.", "3": "대부분의 경우 자립생활이 어려울 수 있다.", "4": "전형적인 증상이 항상 나타나는 것은 아니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Người già", "def_ko": "나이가 많은", "def_vi": "Người lớn tuổi"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "다른 질병이나 상태에서 생기는 문제", "def_vi": "Vấn đề phát sinh từ bệnh hoặc tình trạng khác"}, {"term_ko": "자립생활", "term_vi": "Sống tự lập", "def_ko": "독립적으로 생활하는 것", "def_vi": "Sống độc lập"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc trưng"}, {"term_ko": "경과", "term_vi": "Quá trình", "def_ko": "병이 진행되는 과정", "def_vi": "Tiến trình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (838, '5', '노인성 질환의 특성으로 옳은 것은?', '["정상적인 노화과정과 구분이 쉬다.", "재발되는 경우는 드물다.", "질환에 대한 민감도가 낮다.", "수분과 전해질의 균형이 깨지기 쉽다.", "약 성분이 체외로 빨리 배출되어 치료가 어렵다."]'::jsonb, 4, NULL, NULL, '{"1": "정상적인 노화과정과 구분이 쉽지 않습니다.\n[정답]", "4": "노인의 경우 수분과 전해질의 균형이 깨지기 쉽습니다.", "2": "재발되는 경우가 많습니다.", "3": "오히려 질환에 대한 민감도가 높습니다.", "5": "약 성분이 체내에 오래 남아 효과적으로 치료할 수 있습니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "질환", "def_ko": "노인과 관련된, bệnh liên quan đến người già", "def_vi": "병, bệnh lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (837, '4', '다음 내용에 해당하는 직무스트레스 해소 방법은?업무 중 상사로부터 꾸지람을 들었을 때"나에게 관심이 있어 야단치는 거야."라고 자신의 상황을 긍정적으로 생각한다.', '["호흡법", "인정요법", "심상훈련", "인지수정", "긴장이완기법"]'::jsonb, 4, NULL, NULL, '{"1": "호흡법: 긴장을 완화하고 집중력을 높이기 위한 방법입니다.", "2": "인정요법: 개인의 감정이나 행동을 수용하는 방법입니다.\n[정답]", "3": "인지수정: 부정적인 사고를 긍정적으로 전환하는 기법으로, 문제에서 제시된 상황을 긍정적으로 해석하는 것을 포함합니다.", "4": "긴장이완기법: 신체의 긴장을 풀어주는 방법입니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Stress công việc", "def_ko": "업무 스트레스(압박감, 부담감)", "def_vi": "áp lực, gánh nặng trong công việc"}, {"term_ko": "긍정적", "term_vi": "Tích cực", "def_ko": "긍정적인, 좋은", "def_vi": "tốt"}, {"term_ko": "상사", "term_vi": "Cấp trên", "def_ko": "직장의 상위 관계자", "def_vi": "người cấp cao trong công việc"}, {"term_ko": "상황", "term_vi": "Tình huống", "def_ko": "특정한 경우나 상황", "def_vi": "trường hợp hay hoàn cảnh cụ thể"}, {"term_ko": "인지", "term_vi": "Nhận thức", "def_ko": "인지, 인식", "def_vi": "sự nhận biết"}, {"term_ko": "해소", "term_vi": "Giải quyết", "def_ko": "문제를 해결하거나 없애다", "def_vi": "giải quyết hoặc loại bỏ vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (836, '4', '다음 설명에 해당하는 직무스트레스 대처 방법은?•과거 편안했던 기억을 떠올린다. •복식호흡을 천천히 하면서 "편해", "쉬어" 등의 단어를 천천히 속으로 반복한다.', '["호흡법", "인정요법", "심상훈련", "인지수정", "긴장이완기법"]'::jsonb, 3, NULL, NULL, '{"1": "호흡법: 호흡을 조절하여 스트레스를 줄이는 방법입니다.\n[정답]", "3": "심상훈련: 과거의 편안한 기억을 떠올리고 긍정적인 단어를 반복하여 마음을 편안하게 만드는 기법입니다.", "2": "인정요법: 자신의 감정을 인식하고 수용하는 방법입니다.", "4": "인지수정: 부정적인 사고를 긍정적인 사고로 바꾸는 방법입니다.", "5": "긴장이완기법: 근육의 긴장을 풀어주는 기법입니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng nghề nghiệp", "def_ko": "직장에서의 스트레스", "def_vi": "Căng thẳng trong công việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (835, '4', '직무스트레스를 예방하기 위한 활동으로 옳은 것은?', '["근로계약 시 근로시간을 유연하게 정한다.", "업무 효율을 위해 동료 간의 만남을 자제한다.", "업무 성과를 위해 근무 중 휴게시간을 반납한다.", "정기회의와 면담을 통해 의사소통 체계를 확보한다.", "업무지침은 상황에 따라 근로자가 판단하고 변경한다."]'::jsonb, 4, NULL, NULL, '{"1": "근로계약 시 근로시간을 유연하게 정하는 것은 직무스트레스를 줄일 수 있지만, 직접적인 예방 활동이라고 보기는 어렵다.\n[정답]", "4": "정기회의와 면담을 통해 의사소통 체계를 확보하는 것은 직원 간의 의견 교환과 스트레스 관리에 매우 중요한 활동이다.", "3": "업무 성과를 위해 근무 중 휴게시간을 반납하는 것은 오히려 직무스트레스를 악화시킬 가능성이 있다.", "2": "업무 효율을 위해 동료 간의 만남을 자제하는 것은 소통의 단절을 초래할 수 있어 부정적 영향을 미칠 수 있다.", "5": "업무지침의 판단과 변경은 근로자의 주관적인 판단에 의존하게 되어 혼란을 초래할 수 있으므로 적절하지 않다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Stress nghề nghiệp", "def_ko": "직장에서 느끼는 스트레스", "def_vi": "Căng thẳng nghề nghiệp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (834, '4', '다음 사례에 해당하느 요양보호사의 직무스트레스 유발 요인은?치매대상자가 커피잔이 없어졌다면서, 요양보호사가 의심스럽다고 아들에게 말한다. "커피잔이 예쁘고 좋은 걸 알고 훔쳐갔어. 손버릇이 아주 나빠." 치매증상을 이해하고 최선을 다하려고 하지만, 도둑 취급당하는 것 같아 자존심도 상하고 기분이 나쁘다.', '["직무요구", "조직체계", "노동강도", "역할모호", "감정노동"]'::jsonb, 5, NULL, NULL, '{"1": "직무요구: 업무의 양이나 질이 높은 경우를 말하며, 해당 사례와는 관련이 없습니다.", "2": "조직체계: 조직에서의 위치나 권한에 따른 문제로, 이번 사례와 직접적인 연관이 없습니다.", "3": "노동강도: 육체적 혹은 정신적 노동의 강함에 대한 것으로, 이 경우와는 관계가 적습니다.", "4": "역할모호: 역할의 경계나 기대가 불확실한 경우를 의미하나, 이 사례는 그와는 거리가 있습니다.\n[정답]", "5": "감정노동: 감정 노동은 타인의 감정을 관리해야 하는 일을 의미하며, 요양보호사가 도둑 취급을 당하는 느낌을 받아 스트레스를 받는 상황이 이에 해당합니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng công việc", "def_ko": "업무에서 오는 스트레스(한국어)", "def_vi": "Căng thẳng đến từ công việc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (833, '4', '다음 내용에 해당하는 요양보호사의 직무스트레스 유발 요인은?대상자:"점심에 딸들이 온다는데, 식사 좀 맛있게 준비해 줘요. 애들 갈 때 싸서 보낼 반찬도 넉넉하게 만들어 줘요." 요양보호사:"(......)', '["조직체계", "직무요구", "역할모호", "노동강도", "성희롱"]'::jsonb, 3, NULL, NULL, '{"1": "조직체계: 요양보호사가 속한 조직의 구조와 운영 방식이 직무 스트레스에 미치는 영향이다.", "2": "직무요구: 요양보호사에게 요구되는 직무의 양과 질을 나타낸다.\n[정답]", "3": "역할모호: 요양보호사가 맡은 역할과 책임이 불명확할 때 발생하는 스트레스를 의미한다.", "4": "노동강도: 직무를 수행하는 데 필요한 육체적 힘의 정도를 나타낸다.", "5": "성희롱: 직장 내 성적인 괴롭힘으로 인한 스트레스 요인이다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng công việc", "def_ko": "업무에서 느끼는 스트레스", "def_vi": "Stress mà nhân viên gặp phải trong công việc"}, {"term_ko": "조직체계", "term_vi": "Hệ thống tổ chức", "def_ko": "조직의 구조와 운영 방식", "def_vi": "Cấu trúc và cách thức hoạt động của tổ chức"}, {"term_ko": "직무요구", "term_vi": "Yêu cầu công việc", "def_ko": "업무의 양과 질", "def_vi": "Khối lượng và chất lượng công việc"}, {"term_ko": "역할모호", "term_vi": "Mơ hồ về vai trò", "def_ko": "역할과 책임의 불확실성", "def_vi": "Sự không rõ ràng về vai trò và trách nhiệm"}, {"term_ko": "노동강도", "term_vi": "Cường độ lao động", "def_ko": "직무에 필요한 육체적 힘의 정도", "def_vi": "Mức độ sức lực cần thiết để thực hiện nhiệm vụ"}, {"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 괴롭힘", "def_vi": "Hành vi quấy rối tình dục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (832, '4', '재가요양보호사가 경험하는 직무스트레스에 대한 설명으로 옳은 것은?', '["역할모호 - 업무범위 밖의 가사노동 요구", "감정노동 - 가족을 대신하여 보호자 역할 수행", "성희롱 - 대상자의 자유로운 의사표현의 권리 존중", "직무요구 - 생활이 어려운 대상자의 생업 지원의 부담감", "조직체계 - 체계적인 관리감독에 따른 근로조건의 일관성"]'::jsonb, 1, NULL, NULL, '{"1": "역할모호 - 업무범위 밖의 가사노동 요구는 재가요양보호사가 직무 구분이 명확하지 않을 때 겪는 스트레스를 설명한다.\n[정답]", "2": "감정노동 - 가족을 대신하여 보호자 역할 수행은 재가요양보호사가 정서적 노동을 하고 있다는 것을 나타낸다. 그러나 직무스트레스의 직접적인 원인은 아니다.", "3": "성희롱 - 대상자의 자유로운 의사표현의 권리 존중은 성희롱을 구분하는 내용이며, 스트레스의 원인으로 보기 어렵다.", "4": "직무요구 - 생활이 어려운 대상자의 생업 지원의 부담감은 직무의 요구를 설명하지만, 이는 스트레스의 원인보다는 응답자의 직무 내 외적인 요구를 나타낸다.", "5": "조직체계 - 체계적인 관리감독에 따른 근로조건의 일관성은 스트레스보다는 조직의 안정성을 의미한다."}'::jsonb, '[{"term_ko": "역할모호", "term_vi": "Vai trò mơ hồ", "def_ko": "역할의 경계가 불명확함(한국어)", "def_vi": "Ranh giới vai trò không rõ ràng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (831, '4', '옴에 감염된 대상자를 안전하게 돕는 방법으로 옳은 것은?', '["공용 체온계를 사용한다.", "맨손으로 가려운 곳을 긁어 준다.", "감염 부위를 만져 보아 열감을 확인한다.", "내의와 침구는 뜨거운 물로 10~20분간 세탁한다.", "대상자와 접촉하여 증상이 나타나면 장갑과 가운을 착용한다."]'::jsonb, 4, NULL, NULL, '{"1": "공용 체온계를 사용하면 감염이 확산될 수 있으므로 안전하지 않습니다.\n[정답]", "4": "내의와 침구를 뜨거운 물로 10~20분간 세탁하면 감염균을 효과적으로 제거할 수 있습니다.", "2": "맨손으로 가려운 곳을 긁어 주는 것은 감염을 악화시킬 수 있어 위험합니다.", "3": "감염 부위를 만져 보아 열감을 확인하는 것은 불필요하며, 손상된 피부를 건드리는 것은 위험할 수 있습니다.", "5": "대상자와 접촉하여 증상이 나타나면 장갑과 가운을 착용하는 것은 사후 조치로 적절하지만, 사전에 예방하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부에 발생하는 기생충 감염", "def_vi": "Nhiễm ký sinh trùng trên da"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원체가 체내에 침투하여 발생하는 질병", "def_vi": "Bệnh xảy ra khi vi khuẩn xâm nhập vào cơ thể"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "오염물질을 제거하기 위한 처리", "def_vi": "Xử lý để loại bỏ chất bẩn"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하기 위한 기구", "def_vi": "Dụng cụ bảo vệ tay"}, {"term_ko": "가운", "term_vi": "Áo choàng", "def_ko": "의료진이 착용하는 보호복", "def_vi": "Trang phục bảo vệ của nhân viên y tế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (830, '4', '옴에 대한 설명으로 옳은 것은?', '["밤보다 낮에 가려움이 더 심하다.", "2~3주 지나면 자연적으로 없어진다.", "다른 사람에게 옮기지 않는다.", "면역이 저하된 노인에게 주로 발생한다.", "약은 밤에 바르고 다음날 아침에 씻어낸다."]'::jsonb, 5, NULL, NULL, '{"1": "낮에 가려움이 심한 것이 아니라, 주로 밤에 가려움이 심해지는 질환입니다.\n[정답]", "2": "일반적으로 옴은 자연적으로 사라지지 않고, 치료가 필요합니다.", "3": "옴은 쉽게 전염되므로 다른 사람에게 옮길 수 있습니다.", "4": "면역이 저하된 노인뿐만 아니라, 모든 연령대에서 발생할 수 있습니다.", "5": "옴 약물은 일반적으로 밤에 바르고 다음날 씻어내는 방법이 효과적입니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부질환으로 가려움증을 유발하는 병", "def_vi": "Bệnh da gây ngứa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (829, '4', '옴에 감염된 편마비 대상자를 돌볼 때 요양보호사의 대처방법은?', '["마스크를 착용한다.", "얼굴을 포함한 전신에 연고를 발라준다.", "2~3일간 요양보호 업무를 중단한다.", "내의 및 침구류를 세탁 후 바로 사용한다.", "세탁이 어려운 것은 3일간 햇볕을 쬐거나 다리미로 다린다."]'::jsonb, 5, NULL, NULL, '{"1": "마스크를 착용하는 것은 일반적인 감염 예방의 방법이지만, 옴은 피부 접촉을 통해 전파되므로 마스크 착용만으로는 충분하지 않습니다.\n[정답]", "5": "세탁이 어려운 것은 3일간 햇볕을 쬐거나 다리미로 다려 소독하는 방법은 옴의 전파를 예방하는데 효과적입니다.", "2": "얼굴을 포함한 전신에 연고를 발라주는 것은 감염 치료에 필요하지만, 요양보호사로서의 대처방법으로는 적절하지 않습니다.", "3": "2~3일간 요양보호 업무를 중단하는 것은 감염이 확인된 후 필요할 수 있으나, 반드시 필요한 대처 방법은 아닙니다.", "4": "내의 및 침구류를 세탁 후 바로 사용하하는 것은 감염 전파의 위험이 있습니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부 질환으로 발생하는 병", "def_vi": "Bệnh về da do ký sinh trùng gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (828, '4', '요양보호사가 옴에 감염된 대상자에게 서비스를 실행한 후 겨드랑이에 물집이 생기고 가려움증이 있을 때 치료방법으로 옳은 것은?', '["24시간 이내에 예방접종을 한다.", "겨드랑이와 팔이 접히는 부분에만 약을 바른다.", "엑스레이를 찍어 감염여부를 확인한다.", "자연 치유되므로 그냥 나둔다.", "요양보호사와 동거하는 가족까지 동시에 치료를 받는다."]'::jsonb, 5, NULL, NULL, '{"1": "예방접종은 옴 감염에 대해 즉각적인 치료 효과가 없습니다.\n[정답]", "5": "옴은 전염성이 강하므로, 요양보호사와 동거하는 가족도 함께 치료를 받아야 합니다.", "2": "겨드랑이와 팔 접히는 부분에만 약을 바르는 것은 부족한 대처법입니다.", "3": "엑스레이는 옴 감염을 확인하는 방법이 아닙니다.", "4": "자연 치료를 기대하는 것은 적절한 치료 방법이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람이란 뜻", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (827, '4', '다음 내용에 해당하는 감염성 질환은?•오염된 음식, 물 등을 섭취할 때 감염된다. •구토, 메스꺼움,오한,복통, 설사 증상이 있다. •감염력이 강하고 전염성이 높다.', '["옴", "결핵", "독감", "머릿니", "노로바이러스 장염"]'::jsonb, 5, NULL, NULL, '{"1": "옴: 피부에 기생하는 기생충에 의해 발생하는 질환으로, 이 문제의 증상과 전파 방식이 다름.", "2": "결핵: 호흡기를 통해 전파되는 세균 감염이며, 문제의 전파 경로와는 관련이 없음.", "3": "독감: 바이러스에 의해 발생하지만, 주로 호흡기로 전파되며 문제의 전파 경로와 맞지 않음.\n[정답]", "5": "노로바이러스 장염: 오염된 음식이나 물을 통해 감염되며, 구토, 메스꺼움, 복통, 설사 등의 증상을 동반하고 전염성이 강함.", "4": "머릿니: 피부 접촉을 통해 전파되지만, 문제의 증상과는 일치하지 않음."}'::jsonb, '[{"term_ko": "감염성", "term_vi": "Nhiễm trùng", "def_ko": "감염을 일으키는 성질(한국어)", "def_vi": "Tính chất gây nhiễm trùng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (826, '4', '요양보호사가 대상자로부터 감염되지 않도록 주의해야 하는 직업성 감염 질환은?', '["옴", "천식", "기관지염", "알레르기성 비염", "갑상선기능 저하증"]'::jsonb, 1, NULL, NULL, '{"1": "옴은 피부 접촉을 통해 전파되는 감염병입니다.\n[정답]", "2": "천식은 알레르기나 환경적 요인에 의해 발생하는 호흡기 질환입니다.", "3": "기관지염은 주로 바이러스나 박테리아에 의해 발생하는 염증입니다.", "4": "알레르기성 비염은 알레르기 반응으로 인한 비염으로 전염성이 없습니다.", "5": "갑상선기능 저하증은 호르몬 분비 문제로 발생하며, 전염성이 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Người chuyên chăm sóc bệnh nhân"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균이 몸에 침투하여 생기는 질병", "def_vi": "Bệnh do vi khuẩn xâm nhập vào cơ thể"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 증세", "def_vi": "Bệnh tật hoặc triệu chứng"}, {"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환", "def_vi": "Bệnh đường hô hấp"}, {"term_ko": "기관지염", "term_vi": "Viêm phế quản", "def_ko": "호흡기 염증", "def_vi": "Viêm đường hô hấp"}, {"term_ko": "알레르기성 비염", "term_vi": "Viêm mũi dị ứng", "def_ko": "비염의 일종", "def_vi": "Một loại viêm mũi"}, {"term_ko": "갑상선기능 저하증", "term_vi": "Suy giáp", "def_ko": "갑상선의 기능 저하", "def_vi": "Giảm chức năng tuyến giáp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (825, '4', '요양보호사가 업무 중 고열과 인후통 증상으로 독감이 의심될 때 우선적으로 해야 할 일은?', '["요양보호 업무를 중단한다.", "독감 예방접종을 한다.", "사용하던 물품을 소독한다.", "가글액으로 입안을 헹군다.", "해열진통제를 복용한다."]'::jsonb, 1, NULL, NULL, '{"1": "요양보호사가 전염병 증상을 보일 때에는 다른 환자에게 전염을 예방하기 위해 업무를 중단해야 합니다.\n[정답]", "2": "예방접종은 사전 예방 조치이지, 증상이 나타난 경우에는 시급하지 않습니다.", "3": "소독은 중요하지만, 가장 우선적으로 해야 할 행동은 아닙니다.", "4": "가글은 증상 완화를 위한 조치이나, 우선시되어야 할 사항은 아닙니다.", "5": "해열진통제 복용도 필요할 수 있으나, 업무 중단이 우선되어야 합니다."}'::jsonb, '[{"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "높은 체온", "def_vi": "Nhiệt độ cơ thể cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (824, '4', '요양보호서비스 제공 시 감염을 예방하는 방법으로 옳은 것은?', '["독감이 걸린 대상자는 즉시 서비스를 중단한다.", "장염에 감염된 경우 손을 잘 씻고 음식조리를 한다.", "독감이 유행하기 시작하면 예방접종을 한다.", "결핵대상자가 사용한 침구류는 일광소독 한다.", "요양보호사가 잠복결핵 상태인 경우 업무를 중단한다."]'::jsonb, 4, NULL, NULL, '{"1": "독감이 걸린 대상자는 즉시 서비스를 중단하는 것은 지나친 조치입니다. 대신 감염 예방을 위한 다른 방법을 취해야 합니다.\n[정답]", "4": "결핵대상자가 사용한 침구류는 일광소독 하는 것이 올바른 감염 예방 방법입니다.", "2": "장염에 감염된 경우 손을 잘 씻고 음식조리를 하는 것은 필요하지만, 감염 예방을 위한 방법으로는 적합하지 않습니다.", "3": "독감이 유행하기 시작하면 예방접종을 하는 것이 권장되지만, 질문의 의도에는 직접적인 감염 예방 방법이 아닙니다.", "5": "요양보호사가 잠복결핵 상태인 경우 업무를 중단하는 것이 적절할 수 있지만, 모든 경우에 해당하는 것은 아닙니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (823, '4', '요양보호사의 직업성 감염질환 중 결핵에 대한 설명으로 옳은 것은?', '["결핵은 폐에만 침범하는 감염성 질환이다.", "식욕증가와 함께 체중이 늘어난다.", "2주 이상의 기침과 피가 섞인 가래가 나온다.", "감염 대상자와 접촉 시에는 즉시 격리치료를 받는다.", "결핵은 유전되는 질환이다."]'::jsonb, 3, NULL, NULL, '{"1": "결핵은 폐에만 침범하는 감염성 질환이 아니며, 다른 장기에도 영향을 미칠 수 있습니다.\n[정답]", "3": "2주 이상의 기침과 피가 섞인 가래는 결핵의 전형적인 증상입니다.", "2": "결핵 환자는 보통 체중이 줄어들며 식욕도 감소합니다.", "4": "감염 대상자와 접촉 시 즉시 격리치료를 받기보다는 적절한 조치를 취하고 관찰하는 것이 중요합니다.", "5": "결핵은 유전되는 질환이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "폐렴 바이러스에 의해 발생하는 감염 질환", "def_vi": "Bệnh gây ra bởi virus phổi"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균이 침투하여 생기는 질병", "def_vi": "Bệnh do vi khuẩn xâm nhập gây ra"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "숨을 쉴 때 공기가 목구멍에서 나오는 과정", "def_vi": "Hành động phát ra âm thanh trong quá trình thở"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "기침을 할 때 나오는 진한 분비물", "def_vi": "Chất nhầy tiết ra khi ho"}, {"term_ko": "격리", "term_vi": "Cách ly", "def_ko": "분리하여 치료하는 절차", "def_vi": "Quy trình tách riêng để điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (822, '4', '결핵이 의심되는 환자를 돌볼 시 감염을 예방하는 방법으로 옳은 것은?', '["항생제 복용", "보호장구 착용", "침구류 그늘에서 말리기", "수액으로 영양보충", "대상자가 입었던 옷 소각"]'::jsonb, 3, NULL, NULL, '{"1": "항생제 복용은 치료에 도움이 되지만 감염 예방과는 관련이 적습니다.\n[정답]", "2": "보호장구 착용은 감염을 예방하는 방법 중 하나입니다.", "3": "침구류 그늘에서 말리기는 위생적으로 처리가치 않지만, 감염 예방으로 직접적인 효과는 없습니다.", "4": "수액으로 영양보충은 직접적인 감염 예방과는 관련이 없습니다.", "5": "대상자가 입었던 옷 소각은 과도한 조치이며 필요하지 않습니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "병균에 의한 폐 질환", "def_vi": "Bệnh do vi khuẩn gây ra ở phổi"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병이나 바이러스가 신체에 침투하는 것", "def_vi": "Sự xâm nhập của bệnh hoặc virus vào cơ thể"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "세균 감염을 치료하는 약물", "def_vi": "Thuốc điều trị nhiễm trùng do vi khuẩn"}, {"term_ko": "보호장구", "term_vi": "Trang bị bảo hộ", "def_ko": "의료진이 감염을 예방하기 위해 착용하는 장비", "def_vi": "Thiết bị được nhân viên y tế sử dụng để phòng ngừa nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (821, '4', '요양보호사의 감염예방 방법으로 옳은 것은?', '["가능하면 손톱을 길게 유지한다.", "분비물 접촉 후에는 휴지로 손을 닦는다.", "주기적으로 스테로이드 약물을 복용한다.", "감염질환이 의심될 때에만 건강검진을 받는다.", "임신한 경우 풍진, 수두 감염 대상자와 접촉을 피한다."]'::jsonb, 5, NULL, NULL, '{"1": "가능하면 손톱을 짧게 관리해야 합니다. 손톱이 길면 세균이 쌓이기 쉽습니다.\n[정답]", "5": "임신한 경우 풍진, 수두 감염 대상자와의 접촉을 피해야 합니다. 감염으로 인한 위험을 예방할 수 있습니다.", "2": "분비물 접촉 후에는 반드시 손을 씻어야 합니다. 휴지로 닦는 것은 불완전합니다.", "3": "주기적으로 스테로이드 약물을 복용하는 것은 면역력을 저하시킬 수 있기 때문에 권장되지 않습니다.", "4": "감염 질환이 의심될 때는 정기적으로 건강검진을 받아야 합니다. 검진을 지연하는 것은 좋지 않습니다."}'::jsonb, '[{"term_ko": "감염예방", "term_vi": "Phòng ngừa nhiễm trùng", "def_ko": "감염을 예방하는 방법", "def_vi": "Các phương pháp ngăn ngừa nhiễm trùng"}, {"term_ko": "손톱", "term_vi": "Móng tay", "def_ko": "손가락 끝의 단단한 부분", "def_vi": "Phần cứng ở đầu ngón tay"}, {"term_ko": "분비물", "term_vi": "Chất tiết", "def_ko": "몸에서 나오는 물질", "def_vi": "Chất từ cơ thể tiết ra"}, {"term_ko": "스테로이드", "term_vi": "Steroid", "def_ko": "호르몬의 일종", "def_vi": "Một loại hormone"}, {"term_ko": "핵검진", "term_vi": "Kiểm tra sức khỏe", "def_ko": "건강을 확인하는 절차", "def_vi": "Quy trình xác nhận sức khỏe"}, {"term_ko": "풍진", "term_vi": "Rubella", "def_ko": "바이러스 감염", "def_vi": "Nhiễm virus"}, {"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "바이러스 감염", "def_vi": "Nhiễm virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (820, '4', '요양보호사의 근골격계 손상을 예방하기 위한 스트레치 방법으로 옳은 것은?', '["통증을 느낄 때까지 한다.", "같은 동작을 2~3회 반복한다.", "동작을 빠르고 신속하게 한다.", "스트레칭 된 자세로 10~15초 정도 유지한다.", "동작과 동작 사이를 쉬지 않고 계속 한다."]'::jsonb, 4, NULL, NULL, '{"1": "통증을 느낄 때까지 하는 것은 부상의 위험이 크므로 올바르지 않다.\n[정답]", "4": "스트레칭 된 자세로 10~15초 정도 유지하는 것은 근육의 이완을 도와주어 안전한 스트레칭 방법이다.", "2": "같은 동작을 2~3회 반복하는 것은 일반적인 스트레칭 방법이나, 너무 반복할 경우 부상의 위험이 높아질 수 있다.", "3": "동작을 빠르고 신속하게 하는 것은 스트레칭의 목적에 맞지 않다.", "5": "동작과 동작 사이를 쉬지 않고 계속하는 것은 근육의 회복 시간을 방해할 수 있다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "신체의 뼈와 근육 시스템", "def_vi": "Hệ thống xương và cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (819, '4', '요양보호사가 전신 스트레칭을 할 때 올바른 방법은?', '["동작을 최대한 빠르고 강하게 한다.", "스트레칭된 자세로 30초이상 유지한다.", "상 하 좌 우 균형있게 교대로 스트레칭한다.", "통증이 느껴질 때까지 동작을 반복한다.", "호흡을 최대한 참고 스트레칭 한다."]'::jsonb, 3, NULL, NULL, '{"1": "동작을 최대한 빠르고 강하게 하면 부상을 초래할 수 있습니다.\n[정답]", "3": "상하좌우 균형 있게 교대로 스트레칭하는 것이 올바른 방법입니다.", "2": "스트레칭된 자세를 30초 이상 유지하는 것은 좋지만 교대로 하는 것이 중요합니다.", "4": "통증이 느껴질 때까지 동작을 반복하는 것은 위험합니다.", "5": "호흡을 최대한 참고 스트레칭하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "전신 스트레칭", "term_vi": "Kéo dài toàn thân", "def_ko": "전신을 늘이고 기르는 동작", "def_vi": "Động tác kéo dài toàn bộ cơ thể"}, {"term_ko": "상하좌우", "term_vi": null, "def_ko": "위아래 그리고 좌우", "def_vi": null}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "같은 정도로 나누어짐", "def_vi": "Chia đều mức độ"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (818, '4', '노인 대상자가 만성관절염으로 어깨와 무릎에 통증을 호소할 때 돕는 방법으로 옳은 것은?', '["냉찜질을 한다.", "온찜질을 한다.", "진통제를 준다.", "심호흡을 하게 한다.", "운동의 강도를 높인다."]'::jsonb, 2, NULL, NULL, '{"1": "냉찜질은 초기 통증이나 염증이 있는 경우 사용하지만 만성관절염에는 적절하지 않습니다.\n[정답]", "2": "온찜질은 혈액순환을 촉진하고 통증 완화에 도움을 주므로 적절한 방법입니다.", "3": "진통제는 통증 완화에 도움이 될 수 있으나 의사의 처방이 필요합니다.", "4": "심호흡은 긴장을 완화할 수 있으나 통증의 직접적인 완화에는 효과적이지 않습니다.", "5": "운동의 강도를 높이는 것은 오히려 통증을 악화시킬 수 있으므로 권장되지 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (817, '4', '침대의 자세를 조절하기 위해서 반복적으로 레버를 돌리다가 손목에 통증과 부종이 생길 경우 초기 대처 방법은?', '["손목 부위에 압박 붕대를 감아준다.", "손목을 가볍게 털어 준다.", "스테로이드 약물을 주입한다.", "손목 부위에 온찜질을 한다.", "심장보다 손상부위를 낮게 내린다."]'::jsonb, 1, NULL, NULL, '{"1": "손목 부위에 압박 붕대를 감아준다: 손목의 부종을 줄이고 통증을 완화하는 데 도움이 된다.\n[정답]", "2": "손목을 가볍게 털어 준다: 통증을 가중시킬 수 있는 방법이다. 효과적이지 않다.", "3": "스테로이드 약물을 주입한다: 급성 상황에서 초기 대처로는 적합하지 않다.", "4": "손목 부위에 온찜질을 한다: 초기에는 찜질보다 냉찜질이 더 효과적이다.", "5": "심장보다 손상부위를 낮게 내린다: 부종을 악화시킬 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (816, '4', '요양보호사가 물건을 들어 올릴 때 허리를 보호하는 자세로 옳은 것은?', '["무릎을 펴고 무게중심을 높인다.", "몸의 무게중심을 낮추고 지지면을 좁힌다.", "물건을 최대한 몸 가까이 위치하여 들어올린다.", "물건을 든 상태에서 허리를 돌려 방향을 전환한다.", "양손으로 물건을 들어 올릴 때는 허리를 구부리고 들어올린다."]'::jsonb, 3, NULL, NULL, '{"1": "무릎을 펴고 무게중심을 높이면 허리에 무리가 갈 수 있습니다.\n[정답]", "3": "물건을 최대한 몸 가까이 위치하여 들어올리면 허리 부담이 줄어듭니다.", "2": "몸의 무게중심을 낮추고 지지면을 좁히면 불안정해질 수 있습니다.", "4": "물건을 든 상태에서 허리를 돌리면 허리 부상을 초래할 수 있습니다.", "5": "양손으로 물건을 들어 올릴 때 허리를 구부리면 허리를 다칠 위험이 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (815, '4', '요양보호사가 무거운 물건을 들어 올릴 때 허리를 보호하는 자세로 옳은 것은?', '["무릎을 굽히고 지지면을 넓힌다.", "허리를 구부리고 들어올린다.", "물건을 든 상태에서 허리를 돌려 방향을 전환한다.", "물체는 몸에서 멀리 놓고 들어올린다.", "순간적인 허리힘을 이용해서 들어올린다."]'::jsonb, 1, NULL, NULL, '{"1": "무릎을 굽히고 지지면을 넓히는 것은 허리를 보호하는 올바른 자세입니다.\n[정답]", "2": "허리를 구부리고 들어올리는 것은 허리에 부담을 줄 수 있어 잘못된 자세입니다.", "3": "물건을 든 상태에서 허리를 돌리는 것은 허리에 과부하를 줄 수 있어 위험합니다.", "4": "물체를 몸에서 멀리 놓고 들어올리는 것은 힘을 더 주게 되어 허리에 부담이 될 수 있습니다.", "5": "순간적인 허리힘을 이용해 들어올리는 것은 부상을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 신체적, 정서적 지지를 제공하는 직업", "def_vi": "Người hỗ trợ về thể chất và tinh thần cho bệnh nhân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "몸의 중심 부위", "def_vi": "Vùng trung tâm của cơ thể"}, {"term_ko": "물건", "term_vi": "Vật", "def_ko": "물질이나 물체", "def_vi": "Vật chất hoặc đồ vật"}, {"term_ko": "지지면", "term_vi": "Mặt tiếp xúc", "def_ko": "무언가를 지지하는 표면", "def_vi": "Bề mặt hỗ trợ một cái gì đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (814, '4', '허리를 오랫동안 반복적으로 구부려서 생기는 디스크를 예방하기 위한 스트레칭 방법은?', '["한 손으로 반대쪽 팔꿈치를 감싸 지그시 눌러준다.", "엎드려 누운 자세에서 위로 다리를 들어 올린다.", "등 뒤에서 수건의 양끝을 잡고 지그시 잡아당긴다.", "두 손을 뒤로하여 깍지 끼고 뒤로 밀어준다.", "양측의 손등을 맞대고 미는 동작을 유지한다."]'::jsonb, 2, NULL, NULL, '{"1": "한 손으로 반대쪽 팔꿈치를 감싸 지그시 눌러주는 자세는 허리 스트레칭에 바람직하지 않습니다.\n[정답]", "2": "엎드려 누운 자세에서 위로 다리를 들어 올리는 것은 허리 근육을 효과적으로 늘려주어 디스크 예방에 도움이 됩니다.", "3": "등 뒤에서 수건의 양끝을 잡고 지그시 잡아당기는 방법은 일반적인 허리 통증 완화에는 좋지만, 디스크 예방에는 적합하지 않습니다.", "4": "두 손을 뒤로하여 깍지 끼고 뒤로 밀어주면 허리 근육에 긴장이 생길 수 있어 조심해야 합니다.", "5": "양측의 손등을 맞대고 미는 동작은 자세 교정에 도움이 되나, 디스크 예방 스트레칭에는 그다지 효과적이지 않습니다."}'::jsonb, '[{"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리(한국어)", "def_vi": "Vùng lưng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (813, '4', '수근관 증후군의 증상에 대한 설명으로 옳은 것은?', '["손목을 손바닥 방향으로 굽히면 통증이 감소된다.", "가운데 손가락의 운동 기능장애가 심하다.", "새끼손가락과 연결된 손바닥 감각이 둔해진다.", "손을 털면 저림과 통증이 완화될 수 있다.", "밤에 통증이 완화되고, 낮에는 심해진다."]'::jsonb, 4, NULL, NULL, '{"1": "손목을 손바닥 방향으로 굽히면 통증이 감소되지 않고 오히려 악화될 수 있습니다.\n[정답]", "2": "가운데 손가락의 운동 기능장애는 있을 수 있으나, 가장 심한 경우는 아닙니다.", "3": "새끼손가락은 수근관 증후군의 주요 증상과 관련이 없습니다.", "4": "손을 털면 저림과 통증이 완화될 수 있습니다.", "5": "수근관 증후군은 밤에 통증이 증가하고 낮에 완화되는 경우가 많습니다."}'::jsonb, '[{"term_ko": "수근관", "term_vi": "Ống cổ tay", "def_ko": "손목의 중간을 지나는 관", "def_vi": "Ống giữa cổ tay"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (812, '4', '요양보호사에게 발생되는 근골격계 질환의 위험요인은?', '["반복적으로 같은 동작을 하는 경우", "안정된 자세에서 작업하는 경우", "힘이 적게 드는 일을 하는 경우", "가벼운 물건을 들어 올릴 경우", "적당한 힘을 가하는 경우"]'::jsonb, 1, NULL, NULL, '{"1": "반복적으로 같은 동작을 하는 경우는 근골격계 질환의 주요 위험 요인으로, 지속적인 스트레스를 유발할 수 있다.\n[정답]", "2": "안정된 자세에서 작업하는 경우는 위험 요인으로 작용하지 않으며, 오히려 건강한 자세를 지원할 수 있다.", "3": "힘이 적게 드는 일을 하는 경우에는 위험도가 낮아 근골격계 질환과 관련이 없다.", "4": "가벼운 물건을 들어 올릴 경우에도 일반적으로 안전한 활동으로 간주된다.", "5": "적당한 힘을 가하는 경우는 근골격계에 부담을 줄이지 않기 때문에 위험 요인이 아니다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "신체의 뼈와 근육 시스템", "def_vi": "Hệ thống xương và cơ bắp của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (811, '4', '치매 대상자가 옷을 입은 채 거실에 서서 대변을 보고 있다. 대상자의 딸이 정말 큰일이네, 치매 증상이 점점 심해지셔서...라고 말할 때 요양보호사의 대처방법은?', '["방으로 데리고 가서 기저귀를 채운다.", "동료 요양보호사에게 업무를 인계한다.", "뒷처리를 해준 후 증상을 기록한다.", "하던 일을 계속하며 개입하지 않는다.", "재가서비스가 어려우므로 시설 입소를 권유한다."]'::jsonb, 3, NULL, NULL, '{"1": "방으로 데리고 가서 기저귀를 채우는 것은 임시방편일 뿐, 근본적인 해결이 아닙니다.\n[정답]", "3": "뒷처리를 해준 후 증상을 기록하는 것은 환자의 안전과 기록 관리 측면에서 적절한 대처입니다.", "2": "동료 요양보호사에게 업무를 인계하는 것은 상황에 따라 필요할 수 있으나, 즉각적인 대처가 요구되는 상황에서는 적절하지 않습니다.", "4": "하던 일을 계속하며 개입하지 않는 것은 환자의 안전과 건강을 고려했을 때 잘못된 접근입니다.", "5": "재가서비스가 어려우므로 시설 입소를 권유하는 것은 심각한 상황에서의 대처보다는 장기적인 해결책을 제안하는 것으로, 즉각적인 대처로는 부적합합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (810, '4', '평소 알고 지내던 요양보호사가 서로의 어머니에게 교차서비스를 제공하는 것으로 처리하여 급여를 더 받자고 할 때 대처방법은?', '["어머니의 의견을 물어보고 알려주겠다고 한다.", "제안을 들어줄 만한 다른 요양보호사를 소개한다.", "마찰이 생길 수 있으니 대응하지 않는다.", "윤리원칙에 어긋난다고 말하며 거부한다.", "어머니에게 교차서비스에 대해 미리 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "어머니의 의견을 물어보는 것은 문제가 될 수 있는 행위를 조장할 수 있습니다.\n[정답]", "4": "윤리원칙에 어긋난다는 점을 강조하며 명확히 거부하는 것이 가장 바람직합니다.", "2": "다른 요양보호사를 소개하는 것은 문제를 악화시킬 수 있습니다.", "3": "마찰을 피하는 것이 아니라 적절한 대응이 필요합니다.", "5": "교차서비스에 대해 설명하는 것은 상황을 오해하게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "교차서비스", "term_vi": "Dịch vụ chéo", "def_ko": "서로 다른 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ khác nhau cho nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (809, '4', '대상자의 보호자가 사용했던 기저귀의 재사용을 강요할 때 대처방법은?', '["재사용이 해로운 이유는 설명하고 새 기저귀를 사용한다.", "소변이 덜 묻은 기저귀는 말려서 재사용한다.", "보호자의 요구 사항을 기록한 후 재사용한다.", "보호자가 방문하는 날에만 재사용한다.", "요양보호사의 사비로 기저귀를 구매하여 사용한다."]'::jsonb, 1, NULL, NULL, '{"1": "재사용이 해로운 이유는 설명하고 새 기저귀를 사용한다. \n[정답] 재사용이 인체에 미치는 해로운 영향을 보호자에게 설명하여, 새로운 기저귀 사용을 권장하는 것이 올바른 대처입니다.", "2": "소변이 덜 묻은 기저귀는 말려서 재사용한다. \n재사용은 감염의 위험이 있어 적절하지 않습니다.", "3": "보호자의 요구 사항을 기록한 후 재사용한다. \n요양보호사는 보호자의 요구 사항보다 안전이 우선입니다.", "4": "보호자가 방문하는 날에만 재사용한다. \n보호자의 방문 여부와 관계없이 안전한 방법을 따라야 합니다.", "5": "요양보호사의 사비로 기저귀를 구매하여 사용한다. \n요양보호사의 사비로 기저귀를 구매하는 것은 바람직하지 않으며, 기관의 기준에 따라야 합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (808, '4', '대상자로부터 본인부담금 면제를 강요 받은 경우 대처방법은?', '["형편이 어려우면 요양보호사가 대신 납부한다.", "불법행위이므로 할 수 없다고 말한다.", "면제해주고 그만큼 서비스 시간을 줄인다.", "수수료를 받고 면제받을 수 있도록 해준다.", "면제받을 수 있는 다른 기관을 소개해준다."]'::jsonb, 2, NULL, NULL, '{"1": "형편이 어려운 경우에도 요양보호사가 그 대신 납부하는 것은 정당하지 않기 때문에 잘못된 선택입니다.\n[정답]", "2": "불법행위이므로 할 수 없다고 말하는 것이 정답입니다. 요양보호사는 부당한 요구를 거절해야 합니다.", "3": "면제해주고 서비스 시간을 줄이는 것은 합법적이지 않으며, 고객의 요구를 잘못 수용하는 것입니다.", "4": "수수료를 받고 면제받을 수 있도록 해주는 것은 명백한 불법행위입니다.", "5": "면제받을 수 있는 다른 기관을 소개해주는 것도 합법적인 방법이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "수혜자(한국어)", "def_vi": "Người nhận dịch vụ chăm sóc (베트남어)"}, {"term_ko": "본인부담금", "term_vi": "Chi phí cá nhân", "def_ko": "개인 부담금(한국어)", "def_vi": "Chi phí mà cá nhân phải chi trả(베트남어)"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "보건 의료 종사자(한국어)", "def_vi": "Người làm trong lĩnh vực chăm sóc sức khỏe (베트남어)"}, {"term_ko": "불법", "term_vi": "Bất hợp pháp", "def_ko": "법에 어긋나는 것(한국어)", "def_vi": "Không đúng theo pháp luật (베트남어)"}, {"term_ko": "면제", "term_vi": "Miễn phí", "def_ko": "면책(한국어)", "def_vi": "Miễn trừ phí tổn (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (807, '4', '시설에서 목욕서비스를 제공하던 중 대상자가 갑자기 가슴을 만지는 경우 대처방법은?', '["화를 내며 목욕을 중단한다.", "대상자에게 정신적 피해보상을 요구한다.", "단호히 거부하고 대상자의 가족과 시설장에게 알리겠다고 말한다.", "대상자의 사생활 보호를 위해 비밀로 한다.", "치매라서 그러는 거라ㅗ 이해하며 넘어간다."]'::jsonb, 3, NULL, NULL, '{"1": "화를 내며 목욕을 중단하는 것은 상황을 악화시킬 수 있습니다.\n[정답]", "3": "단호히 거부하고 대상자의 가족과 시설장에게 알리겠다고 말하는 것이 적절한 대처 방법입니다.", "2": "정신적 피해 보상을 요구하는 것은 적절하지 않습니다.", "4": "비밀로 하는 것은 대상자의 권리를 침해할 우려가 있습니다.", "5": "이해한다는 태도는 문제의 심각성을 간과하는 것입니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 일", "def_vi": "Hoạt động rửa sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (806, '4', '시설에서 대상자가 넘어져 쓰러졌을 때 먼저 해야 할 것으로 옳은 것은?', '["보호자에게 연락한다.", "동료 요양보호사에게 연락한다.", "시설장에게 보고한다.", "침대로 옮긴 후 안정을 시킨다.", "병원으로 이송시킨다."]'::jsonb, 3, NULL, NULL, '{"1": "보호자에게 연락하는 것은 나중에 해야 하는 일입니다.\n[정답]", "3": "시설장에게 보고하는 것이 가장 먼저 해야 할 일입니다.", "2": "동료 요양보호사에게 연락하는 것도 중요하지만 우선적으로 시설장에게 보고해야 합니다.", "4": "침대로 옮기는 것은 상황에 따라 다를 수 있으므로 먼저 보고가 필요합니다.", "5": "병원으로 이송하는 것은 상황이 심각할 경우에 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (805, '4', '다음 사례에서 요양보호사가 지키지 못한 직업적 태도는?대상자 딸: "엄마, 요양보호사 선생님 어디 가셨어요?" 대상자: "점심밥 차려주고 잠깐만 나갔다 온다 했은데, 나간 지 한시간이 됐는데 안 오네..."', '["대상자의 권리를 보호한다.", "대상자의 상태 변화를 세심하게 관찰한다.", "요양보호 업무 중 근무지를 비우지 않는다.", "요양보호사의 판단만으로 서비스를 제공하지 않는다.", "성실한 태도로 책임감을 갖고 업무 활동을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자의 권리를 보호하는 것은 요양보호사가 반드시 지켜야 하는 태도입니다.", "2": "대상자의 상태 변화를 세심하게 관찰하는 것은 중요한 업무입니다.\n[정답]", "3": "요양보호 업무 중 근무지를 비우지 않는 것은 기본적인 직업 태도로서, 규정을 지키지 않은 경우입니다.", "4": "요양보호사의 판단만으로 서비스를 제공하지 않는 것은 적절한 태도입니다.", "5": "성실한 태도로 책임감을 갖고 업무 활동을 하는 것은 필수적입니다."}'::jsonb, '[{"term_ko": "직업적 태도", "term_vi": "Thái độ nghề nghiệp", "def_ko": "직업적으로 가져야 할 자세", "def_vi": "Thái độ cần có trong công việc"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "상태 변화", "term_vi": "Sự thay đổi tình trạng", "def_ko": "상태의 변화", "def_vi": "Sự thay đổi về tình trạng sức khỏe"}, {"term_ko": "근무지", "term_vi": "Nơi làm việc", "def_ko": "근무하는 장소", "def_vi": "Địa điểm làm việc"}, {"term_ko": "판단", "term_vi": "Phán đoán", "def_ko": "결정 내리기", "def_vi": "Ra quyết định"}, {"term_ko": "책임감", "term_vi": "Cảm giác trách nhiệm", "def_ko": "책임 의식", "def_vi": "Ý thức về bổn phận"}, {"term_ko": "성실", "term_vi": "Chân thành", "def_ko": "진정성 있는 태도", "def_vi": "Thái độ chân thành"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (804, '4', '요양보호사의 윤리적 태도로 올바른 것은?', '["사고발생 시 즉시 시설장 및 관리책임자에게 보고한다.", "대상자의 비밀은 필요 시에만 보호한다.", "서비스 내용이 확실하지 않을 시 기록을 뺀다.", "대상자가 학대받는 상황에는 관여하지 않는다.", "서비스 시간 변경 요청 시 조정할 수 없다고 말한다."]'::jsonb, 1, NULL, NULL, '{"1": "사고발생 시 즉시 시설장 및 관리책임자에게 보고한다. [정답] 사고 발생 시 즉시 보고하는 것은 윤리적 책임을 다하는 것입니다.", "2": "대상자의 비밀은 필요 시에만 보호한다. 비밀 보호는 항상 중요합니다.", "3": "서비스 내용이 확실하지 않을 시 기록을 뺀다. 정확한 기록이 중요하며, 빼는 것은 잘못된 행동입니다.", "4": "대상자가 학대받는 상황에는 관여하지 않는다. 학대 상황에 대해 관여해야 하는 의무가 있습니다.", "5": "서비스 시간 변경 요청 시 조정할 수 없다고 말한다. 상황에 따라 조정할 수 있어야 합니다."}'::jsonb, '[{"term_ko": "윤리적 태도", "term_vi": "Thái độ đạo đức", "def_ko": "도덕적 관점에서의 행동 방식", "def_vi": "Cách cư xử từ quan điểm đạo đức"}, {"term_ko": "보고하다", "term_vi": "Báo cáo", "def_ko": "알리다", "def_vi": "Thông báo"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "은밀한 정보", "def_vi": "Thông tin kín"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭행 혹은 일부러 해치다", "def_vi": "Hành vi bạo lực hoặc cố ý làm hại"}, {"term_ko": "조정하다", "term_vi": "Điều chỉnh", "def_ko": "배치 또는 수정하다", "def_vi": "Sắp xếp hoặc sửa đổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (803, '4', '요양보호 업무 중 법적 소송에 휘말리지 않기 위한 방법으로 옳은 것은?', '["서비스내용과 방법이 확실하지 않으면 상식선에서 판단한다.", "서비스계획 수립 시 대상자의 요구는 배제한다.", "대상자의 상태 변화를 세심하게 관찰하여 기록한다.", "시설장이나 간호사에게 보고한 내용은 따로 기록하지 않는다.", "대상자가 학대 받고 있다고 의심되면 동료와 의논하여 해결한다."]'::jsonb, 3, NULL, NULL, '{"1": "서비스의 내용을 확실히 하지 않으면 상식적으로 판단하는 것은 올바른 방법이 아닙니다.\n[정답]", "3": "대상자의 상태 변화를 세심하게 관찰하고 기록하는 것은 법적 문제를 예방하는 중요한 방법입니다.", "2": "서비스 계획에 대상자의 요구를 배제하는 것은 바람직하지 않습니다.", "4": "보고한 내용은 별도로 기록해야 법적 소송에 대비할 수 있습니다.", "5": "학대 의심 시, 동료와 의논하는 것은 필요하지만 반드시 보고하고 기록해야 합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "업무", "def_ko": "돌보는 것 (chăm sóc)", "def_vi": "일 (công việc)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (802, '4', '법적, 윤리적 태도를 위한 요양보호사의 태도로 옳은 것은?', '["장기요양등급을 받을 수 있도록 유인한다.", "서비스 제공은 정해진 원칙과 절차에 따른다.", "제공된 요양보호서비스는 중요한 내용만 기록한다.", "서비스 제공 시 대상자의 자기결정권을 제한한다.", "사고발생 시 대상자의 보호를 위해 발설하지 않는다."]'::jsonb, 2, NULL, NULL, '{"1": "장기요양등급을 받을 수 있도록 유인하는 것은 윤리적으로 바람직하지 않다.\n[정답]", "2": "서비스 제공은 정해진 원칙과 절차에 따라 이루어져야 한다.", "3": "제공된 요양보호서비스는 모든 중요한 내용을 기록해야 한다.", "4": "서비스 제공 시 대상자의 자기결정권은 존중되어야 하며 제한되어서는 안 된다.", "5": "사고 발생 시 대상자의 보호를 위해서도 정보를 공유해야 할 필요가 있다."}'::jsonb, '[{"term_ko": "법적", "term_vi": "윤리적", "def_ko": "법(luật)", "def_vi": "đạo đức(đạo đức)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (801, '4', '요양보호사가 갖추어야 할 직업윤리로 옳은 것은?', '["서비스 내용과 방법은 요양보호사가 결정한다.", "대상자 개인의 선호보다 기관의 지침을 중시한다.", "대상자의 신체, 정신적 변화가 있을 경우 즉시 보고한다.", "업무수행 상 발생한 문제는 요양보호사 스스로 판단하여 해결한다.", "노인학대가 확실한 경우에만 보고한다."]'::jsonb, 3, NULL, NULL, '{"1": "서비스 내용과 방법은 요양보호사가 결정하는 것이 아니라, 대상자와의 상의 후 결정해야 합니다.", "2": "기관의 지침도 중요하지만, 대상자의 개인적인 선호와 욕구가 더 우선해야 합니다.\n[정답]", "3": "대상자의 신체 및 정신적 변화는 즉시 보고해야 하며, 이는 필수적인 직업윤리입니다.", "4": "업무수행 중 발생한 문제는 팀원과 함께 해결해야 하며, 요양보호사 혼자 판단해서는 안 됩니다.", "5": "노인학대는 항상 보고해야 하며, 확실한 경우에만 제한해서 보고하는 것이 아닙니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리(한국어)", "def_vi": "Những nguyên tắc cần tuân thủ trong công việc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (800, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["대상자와 같은 종교를 믿으면 더욱 친절하게 대한다.", "업무에 협조하지 않을 경우 서비스를 종결한다.", "서비스 중 급한 용무는 대상자에게 양해를 구하고 다녀온다.", "제공 된 요양보호 서비스 내용을 정확히 기록한다.", "대상자에게 복지용구를 대여하거나 구입을 권유한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자와 같은 종교를 믿는 것이 윤리적 태도와는 무관하여 잘못된 행동입니다.\n[정답]", "4": "제공 된 요양보호 서비스 내용을 정확히 기록하는 것은 윤리적이며 필수적인 태도입니다.", "2": "업무에 협조하지 않을 경우 서비스를 종결하는 것은 비윤리적인 행위로 간주될 수 있습니다.", "3": "서비스 중 급한 용무는 대상자에게 양해를 구하고 다녀오는 것은 좋지만, 우선적으로 서비스의 연속성을 고려해야 합니다.", "5": "대상자에게 복지용구를 대여하거나 구입을 권유하는 것은 직무 범위를 벗어날 수 있습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적으로 올바른 것", "def_vi": "Điều đúng về mặt đạo đức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (799, '4', '대상자의 가족이 본인부담금 할인을 요구할 때 대처방법은?', '["기관장에게 알리고 본인부담금을 할인해 준다.", "비용 감면 대신 서비스 시간을 늘려 준다.", "본인부담금을 먼저 받고 나중에 일정액을 돌려 준다.", "다른 대상자를 소개해 주면 할인해 준다고 말한다.", "노인장기요양보험법 위반으로 불법이라고 명확하게 말한다."]'::jsonb, 5, NULL, NULL, '{"1": "기관장에게 알리고 본인부담금을 할인해 준다: 기관장은 본인부담금을 할인할 권한이 없으므로 잘못된 대처다.\n[정답]", "5": "노인장기요양보험법 위반으로 불법이라고 명확하게 말한다: 법적 근거에 따라 명확하게 설명해 주는 것이 올바른 대처법이다.", "2": "비용 감면 대신 서비스 시간을 늘려 준다: 서비스의 양과 질을 바꾸는 것은 적절한 해결이 아니다.", "3": "본인부담금을 먼저 받고 나중에 일정액을 돌려 준다: 이런 방식은 불법적이므로 적절하지 않다.", "4": "다른 대상자를 소개해 주면 할인해 준다고 말한다: 이는 비윤리적인 행위이며 허용되지 않는다."}'::jsonb, '[{"term_ko": "본인부담금", "term_vi": "Tiền đồng góp", "def_ko": "본인이 부담해야 하는 비용", "def_vi": "Số tiền mà người bệnh phải chi trả"}, {"term_ko": "할인", "term_vi": "Giảm giá", "def_ko": "금액을 줄이는 것", "def_vi": "Cắt giảm số tiền"}, {"term_ko": "법", "term_vi": "Luật", "def_ko": "규칙이나 규정을 정하는 것", "def_vi": "Quy tắc hoặc quy định"}, {"term_ko": "위반", "term_vi": "Vi phạm", "def_ko": "규칙을 어기는 것", "def_vi": "Vi phạm quy tắc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (798, '4', '대상자가 수고했다며 돈 봉투를 주려고 할 때 올바른 대처방법은?', '["\"돈은 받으면 안 돼요. 마음만 받을게요.\"", "\"저를 어떻게 보고 이런 행동을 하시는 거예요.\"", "\"제가 갖고 있다가 다음에 음료수 사다 드릴게요.\"", "\"마침 센터에 부족한 물건이 있었는데 이걸로 살게요.\"", "\"감사합니다.\"라고 받고 다음 날 대상자에게 돌려준다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자가 제안한 금전적인 선물을 받지 않고 마음만 받겠다고 표현함으로써 윤리적 기준을 지키는 올바른 대처입니다.\n[정답]", "2": "부정적인 반응을 보이는 것으로, 상대방의 감정을 상하게 할 수 있습니다.", "3": "돈을 일시적으로 보류하겠다는 제안은 윤리적으로 바람직하지 않습니다.", "4": "부적절한 상황에서 금전을 사용하겠다는 것은 전문가로서의 태도가 아닙니다.", "5": "금전을 받고 나중에 돌려주는 것은 올바른 대처가 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "버튼", "term_vi": "Cách đúng", "def_ko": "맞는 방법", "def_vi": "Phương pháp đúng"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적인", "def_vi": "Có liên quan đến đạo đức"}, {"term_ko": "금전", "term_vi": "Tiền tệ", "def_ko": "돈", "def_vi": "Tiền"}, {"term_ko": "선물", "term_vi": "Quà tặng", "def_ko": "주는 것", "def_vi": "Món tặng"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "대응하다", "def_vi": "Phản ứng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (797, '4', '요양보호사가 법적, 윤리적 책임을 다하기 위해 지켜야 할 사항으로 옳은 것은?', '["대상자의 복지용구를 저렴한 비용으로 구입해 준다.", "서비스 방법이 확실하지 않을 때는 동료와 의논한다.", "사고 발생 시에는 보호자에게 비밀로 한다.", "서비스 시간 변경을 요청할 때에는 관리책임자에게 보고한다.", "대상자의 질병 악화가 판단될 때에는 입원시킨다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 복지용구를 저렴한 비용으로 구입해 주는 것이 법적 책임을 다하는 방법이 아니다.\n[정답]", "2": "서비스 방법이 확실하지 않을 때는 동료와 의논하는 것은 법적, 윤리적 책임을 다하는 방법이다.", "3": "사고 발생 시 보호자에게 비밀로 하는 것은 윤리적으로 올바르지 않다.", "4": "서비스 시간 변경을 요청할 때 관리책임자에게 보고하는 것은 필수적인 절차이다.", "5": "대상자의 질병 악화가 판단될 때 입원시키는 것은 의료 전문가의 판단이 필요하다."}'::jsonb, '[{"term_ko": "법적", "term_vi": "Pháp lý", "def_ko": "법률에 관한", "def_vi": "Liên quan đến pháp luật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (796, '4', '다음 중 요양보호사의 올바른 윤리적 태도는?', '["방문 시 대상자가 없으면 기관에 연락하여 확인한다.", "방문 시 대상자가 없으면 바로 귀가한다.", "추가 서비스를 요구할 때는 요양보호사가 임의대로 들어준다.", "사정이 어려운 대상자의 본인부담금을 할인해 준다.", "다른 요양보호사에게 자신의 근무를 대신 요구한다."]'::jsonb, 1, NULL, NULL, '{"1": "올바른 윤리적 태도로, 대상자가 없을 때 기관에 확인하는 것은 책임감 있는 행동입니다.\n[정답]", "2": "대상을 확인하지 않고 귀가하는 것은 비윤리적입니다.", "3": "요양보호사는 임의로 추가 서비스를 제공할 수 없습니다. 이는 윤리에 어긋나는 행동입니다.", "4": "대상자의 본인부담금을 임의로 할인하는 것은 적절하지 않습니다.", "5": "자신의 근무를 다른 사람에게 부탁하는 것은 전문성을 저하할 수 있습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙에 따른", "def_vi": "Theo nguyên tắc đạo đức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (795, '4', '대상자와 상호신뢰를 형성할 수 있는 요양보호사의 윤리적 태도는?', '["상황에 맞게 적당한 신체접촉을 한다.", "친근하게 반말을 사용한다.", "대상자를 내려다보면서 시선을 맞춘다.", "추가서비스는 요양보호사가 별도로 계약을 한다.", "방문 시 대상자가 없으면 가사 일을 하면서 기다린다."]'::jsonb, 1, NULL, NULL, '{"1": "상황에 맞게 적당한 신체접촉을 한다. - 요양보호사와 대상자 간의 신뢰를 형성하는 데 중요한 요소입니다.\n[정답]", "2": "친근하게 반말을 사용한다. - 반말 사용은 상황에 따라 부적절할 수 있어 신뢰를 저해할 수 있습니다.", "3": "대상자를 내려다보면서 시선을 맞춘다. - 내려다보는 것은 대인 관계에서 부정적인 인상을 줄 수 있습니다.", "4": "추가서비스는 요양보호사가 별도로 계약을 한다. - 정식 계약 없이 제공되는 서비스는 신뢰를 떨어뜨릴 수 있습니다.", "5": "방문 시 대상자가 없으면 가사 일을 하면서 기다린다. - 대상자의 공간을 존중하는 태도가 필요합니다."}'::jsonb, '[{"term_ko": "상호신뢰", "term_vi": "Niềm tin lẫn nhau", "def_ko": "서로 믿고 의지하는 것", "def_vi": "Sự tin tưởng và dựa vào nhau"}, {"term_ko": "윤리적 태도", "term_vi": "Thái độ đạo đức", "def_ko": "도덕적으로 바람직한 행동", "def_vi": "Hành động đúng đắn về mặt đạo đức"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸을 직접 만지는 행동", "def_vi": "Hành động chạm vào cơ thể"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (794, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["서비스 제공 시 시설장의 의사결정을 우선한다.", "타 직종과의 협력보다 업무의 신속성을 중시한다.", "보수교육을 통해 전문적 지식과 기술을 연마한다.", "대상자의 등급에 따라 서비스할 대상자를 선택한다.", "대상자가 실수하면 질책하여 재발을 방지한다."]'::jsonb, 3, NULL, NULL, '{"1": "서비스 제공 시 시설장의 의사결정을 우선하는 것은 윤리적으로 바람직하지 않습니다.\n[정답]", "3": "보수교육을 통해 전문적 지식과 기술을 연마하는 것은 윤리적 태도의 중요한 부분입니다.", "2": "타 직종과의 협력보다 업무의 신속성을 중시하는 것은 비윤리적입니다.", "4": "대상자의 등급에 따라 서비스할 대상을 선택하는 것은 윤리적이지 않습니다.", "5": "대상자가 실수하면 질책하는 것은 비윤리적이며, 올바른 교육과 지원이 필요합니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕과 관련된", "def_vi": "Liên quan đến đạo đức"}, {"term_ko": "전문적", "term_vi": "Chuyên môn", "def_ko": "전문적인, 전문화된", "def_vi": "Chuyên nghiệp, chuyên sâu"}, {"term_ko": "보수교육", "term_vi": "Đào tạo lại", "def_ko": "재교육을 받는 과정", "def_vi": "Quá trình học lại"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받을 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "질책", "term_vi": "Khiển trách", "def_ko": "비난이나 타박을 하는 것", "def_vi": "Hành động chỉ trích hoặc chê trách"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (793, '4', '다음 설명에 해당하는 요양보호사의 윤리적 태도는?• 직무수행 시 필요한 전문적 지식과 기술을 습득한다. • 교육훈련 프로그램에 적극적으로 참여한다.', '["겸손한 태도", "상호 협조적인 태도", "자기를 계발하려는 태도", "친절하고 예의바른 태도", "인격체를 존중하는 태도"]'::jsonb, 3, NULL, NULL, '{"1": "겸손한 태도: 겸손함은 중요하지만, 전문적 지식 습득과 관련이 없습니다.\n[정답]", "3": "자기를 계발하려는 태도: 전문적 지식과 기술 습득, 교육 훈련 참여의 핵심을 나타냅니다.", "2": "상호 협조적인 태도: 협력은 중요하지만, 자아 개발과는 다소 차이 있습니다.", "4": "친절하고 예의바른 태도: 인간관계에서 중요한 요소지만, 직무수행에 초점을 맞춘 태도가 아닙니다.", "5": "인격체를 존중하는 태도: 존중은 중요하나, 여기서는 전문성 개발과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "태도", "def_ko": "도덕적, đạo đức", "def_vi": "태도, thái độ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (792, '4', '방문요양서비스를 제공하는 요양보호사의 윤리적 태도로 옳은 것은?', '["대상자의 권리를 지켜주고 존중한다.", "요양보호사의 편의를 위해 일회용 제품을 사용한다.", "대상자가 없어도 방에 들어가서 요양보호사의 할 일을 하고 나온다.", "서비스 우선순위를 요양보호사가 주관적으로 결정한다.", "대상자의 욕구보다 요양보호사의 편의를 중시한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 권리를 지켜주고 존중하는 것은 윤리적 태도로 반드시 필요한 자세입니다.\n[정답]", "2": "요양보호사의 편리를 위해 일회용 제품을 사용하는 것은 윤리적이지 않습니다.", "3": "대상자가 없어도 방에 들어가는 것은 개인의 사생활을 침해할 수 있으므로 부적절합니다.", "4": "서비스 우선순위를 주관적으로 결정하는 것은 윤리적 기준을 어기는 행동입니다.", "5": "대상자의 욕구보다 요양보호사의 편의를 중시하는 것은 부적절한 태도입니다."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "집에 가서 지원하는 요양 서비스", "def_vi": "Dịch vụ hỗ trợ tại nhà"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙과 기준에 따른", "def_vi": "Theo nguyên tắc và tiêu chuẩn đạo đức"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "편리", "term_vi": "Tiện lợi", "def_ko": "불편함이 없는 상태", "def_vi": "Trạng thái không có phiền phức"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요한 바람", "def_vi": "Mong muốn cần thiết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (791, '4', '시설에서 동료 요양보호사가 무의식 상태인 대상자를 때리는 것을 보았을 때 요양보호사의 올바른 행동은?', '["동료 요양보호사에게 주의를 준다.", "그냥 모른 척 넘어간다.", "보호자에게 알린다.", "시설정이나 간호사에게 즉시 보고한다.", "동료 요양보호사에게 대상자의 상태를 이해시킨다."]'::jsonb, 4, NULL, NULL, '{"1": "동료 요양보호사에게 주의를 줄 경우, 상황이 개선되지 않을 수 있으며, 대상자에게 더 큰 위험을 초래할 수 있습니다.\n[정답]", "4": "시설장이나 간호사에게 즉시 보고해야 합니다. 이는 대상자의 안전을 최우선으로 해야 하는 요양보호사의 의무입니다.", "3": "보호자에게 알린다고 해도 즉각적인 조치가 아니며, 보고가 늦어질 수 있습니다.", "2": "그냥 모른 척 넘어가는 것은 결코 용납될 수 없는 행동입니다.", "5": "동료에게 이해시킨다고 해서 문제의 행동이 멈출 것이라는 보장이 없습니다."}'::jsonb, '[{"term_ko": "무의식 상태", "term_vi": "Trạng thái không nhận thức", "def_ko": "의식이 없는 상태", "def_vi": "Tình trạng không có ý thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (789, '4', '다음의 사례에서 요양보호사의 대처 방법으로 옳은 것은?요양보호사 김씨는 장기요양 2등급을 받은 할머니에게 요양서비스를 제공하고 있었다. 그러던 중 배우자인 할아버지가 치매 진단을 받고 장기요양 3등급을 받게 되었다. 보호자가 오전에는 할머니를 돌봐주고 오후에는 할아버지를 돌봐달라고 요청했다.', '["다른 요양보호사를 소개시켜 준다.", "남자분은 불편하다고 정중히 거절한다.", "조용히 서비스를 중단한다.", "서비스료를 추가로 받는다.", "시설장에게 보고한다."]'::jsonb, 5, NULL, NULL, '{"1": "다른 요양보호사를 소개시켜 준다. - 이는 전문적이지 않은 대처로 적절하지 않습니다.\n[정답]", "5": "시설장에게 보고한다. - 상황 변화를 정확하게 전달하고 지침을 받는 것이 중요합니다.", "3": "조용히 서비스를 중단한다. - 이는 고객에게 불편을 주고 다른 문제를 초래할 수 있습니다.", "4": "서비스료를 추가로 받는다. - 서비스 제공자와 고객 간의 신뢰를 상실할 수 있는 행동입니다.", "2": "남자분은 불편하다고 정중히 거절한다. - 이는 상황을 해결하는 방법이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "Người cung cấp dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (788, '4', '다음 중 요양보호사의 직업윤리 원칙으로 올바른 것은?', '["대상자에게 복지용구 구매를 알선한다.", "대상자의 요구 시 별도의 서비스 계약을 한다.", "대상자의 요청이 있으면 타 기관에 의뢰한다.", "요양보호사와 대상자가 대등한 관계임을 인식한다.", "대상자의 권리보다는 시설의 운영 규칙을 우선시 한다."]'::jsonb, 4, NULL, NULL, '{"1": "복지용구 구매를 알선하는 것은 직업윤리에 어긋납니다.\n[정답]", "4": "요양보호사와 대상자는 대등한 관계임을 인식해야 합니다.", "2": "별도의 서비스 계약은 요양보호사의 윤리에 맞지 않습니다.", "3": "타 기관에 의뢰하는 것은 필요할 수 있지만, 윤리적 기준에 따라야 합니다.", "5": "대상자의 권리는 항상 우선시 되어야 하므로 잘못된 내용입니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 윤리적 원칙", "def_vi": "Nguyên tắc đạo đức cần tuân theo trong nghề"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "복지용구", "term_vi": "Dụng cụ hỗ trợ", "def_ko": "복지 서비스를 위한 도구", "def_vi": "Công cụ cho dịch vụ phúc lợi"}, {"term_ko": "서비스 계약", "term_vi": "Hợp đồng dịch vụ", "def_ko": "제공되는 서비스에 대한 계약", "def_vi": "Hợp đồng cho dịch vụ được cung cấp"}, {"term_ko": "대등한 관계", "term_vi": "Quan hệ bình đẳng", "def_ko": "평등한 관계", "def_vi": "Mối quan hệ bình đẳng"}, {"term_ko": "운영 규칙", "term_vi": "Quy tắc hoạt động", "def_ko": "시설의 규칙", "def_vi": "Quy tắc của cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (787, '4', '시설에서 요양보호사가 지켜야 할 직업윤리는?', '["대상자의 질병상태를 외부로 발설한다.", "지시 받지 않은 서비스는 경험에 따라 제공한다.", "서비스 제공 시 발생한 사고는 보고하지 않는다.", "업무와 관련하여 대상자의 가족, 의사, 간호사 등과 협력한다.", "법적인 소송에 휘말리지 않기 위해 신체접촉은 하지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 질병상태를 외부로 발설하는 것은 개인정보 보호와 직업윤리에 위배됩니다.\n[정답]", "4": "업무와 관련하여 대상자의 가족, 의사, 간호사 등과 협력하는 것은 매우 중요하며, 직업윤리를 잘 지키는 행동입니다.", "2": "지시 받지 않은 서비스를 임의로 제공하는 것은 위험할 수 있으며, 윤리에 어긋납니다.", "3": "서비스 제공 시 발생한 사고는 반드시 보고해야 하며, 보고하지 않는 것은 직업 윤리에 반합니다.", "5": "법적인 소송을 피하기 위해서만 신체 접촉을 하지 않는 것은 직업 윤리의 본질을 이해하지 못한 것입니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "윤리 trong nghề nghiệp", "def_vi": "Đạo đức trong công việc"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "서비스 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "협력", "term_vi": "Hợp tác", "def_ko": "함께 일하다", "def_vi": "Làm việc cùng nhau"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "정보를 전달하다", "def_vi": "Truyền đạt thông tin"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸을 접촉하다", "def_vi": "Chạm vào cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (786, '4', '요양보호사의 직업윤리로 옳은 것은?', '["기관장으 지시는 선택하여 따른다.", "대상자의 자기결정을 최대한 존중한다.", "대상자의 개인정보를 동료 요양보호사와 공유한다.", "장기요양 1등급 대상자는 서비스 대상에서 제외한다.", "서비스제공기록지에 대상자와 보호자에게 제공한 내용을 기록한다."]'::jsonb, 2, NULL, NULL, '{"1": "기관장의 지시는 반드시 따라야 되는 것은 아니므로 옳지 않은 답변입니다.\n[정답]", "2": "요양보호사는 대상자의 자기결정을 최대한 존중해야 하므로 옳은 사항입니다.", "3": "대상자의 개인정보는 비밀이므로 동료와 공유하는 것은 옳지 않습니다.", "4": "서비스 제공의 기준에 따라 장기요양 1등급 대상자도 서비스의 대상이 될 수 있습니다.", "5": "서비스제공기록지는 반드시 기록해야 하지만, 내용이 아닌 다른 요소를 강조해야 하므로 완전한 답변이 아닙니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 윤리적 기준", "def_vi": "tiêu chuẩn đạo đức cần tuân thủ trong nghề nghiệp"}, {"term_ko": "자기결정", "term_vi": "Quyết định bản thân", "def_ko": "스스로 결정을 내리는 것", "def_vi": "tự mình đưa ra quyết định"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인의 사적인 정보", "def_vi": "thông tin riêng tư của cá nhân"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "도움을 주는 행위", "def_vi": "hành động giúp đỡ"}, {"term_ko": "기록지", "term_vi": "Sổ ghi chép", "def_ko": "사건이나 내용이 정리된 문서", "def_vi": "tài liệu ghi lại sự kiện hoặc nội dung"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (785, '4', '시설에서 요양보호사가 지켜야 할 직업윤리 원칙은?', '["대상자와 수직적인 관계를 강조한다.", "자신의 종교를 권유하기 위해 더 잘해준다.", "대상자의 방은 경제수준에 따라 배정한다.", "대상자보다 가족의 의견을 우선으로 반영한다.", "업무수행을 위해 복장 및 외모관리, 건강관리를 철저히 한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자와 수직적인 관계를 강조하는 것은 직업윤리에 반하는 내용입니다.\n[정답]", "5": "업무수행을 위해 복장 및 외모관리, 건강관리를 철저히 하는 것은 직업윤리에 부합합니다.", "2": "자신의 종교를 권유하기 위해 더 잘해주는 것은 윤리적이지 않습니다.", "3": "대상자의 방을 경제수준에 따라 배정하는 것은 편견을 포함한 차별입니다.", "4": "대상자보다 가족의 의견을 우선으로 반영하는 것은 대상자의 권리를 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에 관련된 도덕적 원칙", "def_vi": "nguyên tắc đạo đức liên quan đến nghề nghiệp"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 필요한 사람", "def_vi": "người cần giúp đỡ"}, {"term_ko": "복장", "term_vi": "Trang phục", "def_ko": "입는 옷", "def_vi": "trang phục"}, {"term_ko": "외모", "term_vi": "Ngoại hình", "def_ko": "사람의 모습", "def_vi": "diện mạo của con người"}, {"term_ko": "건강관리", "term_vi": "Quản lý sức khỏe", "def_ko": "건강을 유지하기 위한 관리", "def_vi": "việc duy trì sức khỏe"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (784, '4', '요양보호사의 직업윤리원칙을 바르게 설명한 것은?', '["요양보호사의 자기결정을 최대한 존중한다.", "업무상 알게 된 대상자의 개인정보는 비밀을 유지한다.", "대상자의 성별, 연령, 종교에 따라 차별 서비스한다.", "대상자와 개인적으로 별도의 서비스 계약을 한다.", "모든 서비스는 가족의 요구대로 수행한다."]'::jsonb, 2, NULL, NULL, '{"1": "요양보호사는 자기결정을 존중해야 하지만, 보기에 제시된 내용은 그 자체로 맞다 볼 수 없습니다.\n[정답]", "2": "요양보호사는 업무상 알게 된 개인정보를 비밀로 유지해야 하는 윤리 원칙이 있습니다.", "3": "성별, 연령, 종교에 따라 차별적으로 서비스하는 것은 윤리적으로 옳지 않습니다.", "4": "요양보호사는 대상자와 개인적으로 서비스 계약을 맺지 않아야 합니다.", "5": "모든 서비스는 가족의 요구에 무조건적으로 따를 수 없으며, 대상자의 의사를 존중해야 합니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리", "def_vi": "Nghĩa vụ phải tuân thủ trong nghề nghiệp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (783, '4', '가정을 방문하여 목욕 서비스를 제공하던 중 대상자가 뒤에서 가슴을 만지는 경우 대처방법으로 옳은 것은?', '["\"이러시면 안됩니다.\"라고 단호하게 말한다.", "\"왜 이러세요.\"라고 화를 내며 나가 버린다.", "\"할머니가 생각나세요?\"라고 위로해 준다.", "\"제가 좋으세요?\"라고 말하며 웃어 넘긴다.", "\"비밀로 해 드릴게요\"하고 한번은 넘어간다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 행동에 대해 단호하게 거부의사를 표현하는 것은 필요한 조치입니다.\n[정답]", "2": "화를 내며 나가 버리는 것은 상황을 악화시킬 수 있습니다.", "3": "위로하는 것은 긍정적이지만 부적절한 행동을 받아들이는 것으로 해석될 수 있습니다.", "4": "웃어 넘기는 것은 행동을 용인하는 것으로 받아들여질 수 있습니다.", "5": "이성과 이 규범을 무시하는 행동이므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕하다(욕조나 물에서 씻다)", "def_vi": "Làm sạch bằng nước"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "치료나 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "부적절", "term_vi": "Không phù hợp", "def_ko": "적합하지 않은, 적절하지 않은", "def_vi": "Không thích hợp, không đúng mực"}, {"term_ko": "행동", "term_vi": "Hành vi", "def_ko": "어떤 방식으로 행동하거나 반응하는 것", "def_vi": "Cách mà ai đó hành động hoặc phản ứng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않거나 반대하는 것", "def_vi": "Không chấp nhận hoặc phản đối"}, {"term_ko": "위로", "term_vi": "An ủi", "def_ko": "슬퍼하거나 힘든 사람을 다독이는 것", "def_vi": "Động viên người đang buồn hoặc khó khăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (782, '4', '요양보호사가 대상자에게 성희롱을 당했을 때 장기요양기관장의 대처방법은?', '["대상자에게 서비스 중단 조치를 취한다.", "대상자에게 성희롱 예방교육을 2년에 1번 이상 실시한다.", "기관장의 판단에 따라 요양보호사를 다른 업무에 배치한다.", "요양보호사의 심리치료와 법적 대응에 대한 상담을 직접 실시한다.", "요양보호사가 성적 수치심을 느끼지 않도록 피해 사실을 묵인한다."]'::jsonb, 1, NULL, NULL, '{"1": "요양보호사가 성희롱을 당했을 경우, 즉각적으로 대처가 필요하며 서비스 중단 조치는 적절한 대안이다.\n[정답]", "2": "성희롱 예방교육은 중요하지만, 당장에 대처 방법으로는 적절하지 않다.", "3": "요양보호사가 다른 업무로 배치되는 것은 상황에 따라 다를 수 있지만, 최소한의 조치가 필요하다.", "4": "상담은 전문적으로 이루어져야 하므로, 기관장이 직접 실시하는 것은 바람직하지 않다.", "5": "피해 사실을 묵인하는 것은 절대로 수용할 수 없는 잘못된 대처다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 괴롭힘(한국어)", "def_vi": "Hành vi quấy rối về tình dục"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}, {"term_ko": "기관장", "term_vi": "Giám đốc", "def_ko": "장의(한국어)", "def_vi": "Người đứng đầu"}, {"term_ko": "심리치료", "term_vi": "Liệu pháp tâm lý", "def_ko": "심리 치료(한국어)", "def_vi": "Điều trị tâm lý"}, {"term_ko": "법적 대응", "term_vi": "Phản ứng pháp lý", "def_ko": "법적 조치(한국어)", "def_vi": "Phản ứng theo quy định pháp luật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (781, '4', '성희롱에 대한 요양보호사의 대처방법으로 옳은 것은?', '["대상자의 가족에게 비밀로 한다.", "단호히 거의의사를 표현한다.", "대상자으 행동을 넓은 마음으로 이해한다.", "가족에게 시정해 줄 것을 요구하며 감정적인 대응을 한다.", "시정 요구에도 상습적으로 계속할 경우에는 경찰서에 고소한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 가족에게 비밀로 하는 것은 적절하지 않습니다. 성희롱은 심각한 문제이므로 알리는 것이 필요합니다.\n[정답]", "2": "단호히 의사를 표현하는 것이 필요합니다. 감정적으로 대처하기보다 명확하게 의사를 전달해야 합니다.", "3": "대상자의 행동을 넓은 마음으로 이해하는 것은 잘못된 접근입니다. 성희롱은 결코 용납되어서는 안됩니다.", "4": "가족에게 시정해 줄 것을 요구하며 감정적인 대응을 하는 것은 비효율적이며 문제를 악화시킬 수 있습니다.", "5": "시정 요구에도 상습적으로 계속할 경우 경찰에 고소하는 것은 마지막 수단이며, 우선적으로 의사를 단호하게 표현해야 합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 행동이나 언어로 인한 괴롭힘", "def_vi": "Hành vi hoặc ngôn ngữ mang tính chất tình dục gây phiền phức"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제에 대한 대응 방법", "def_vi": "Phương pháp ứng phó với vấn đề"}, {"term_ko": "아름다운", "term_vi": "Đẹp", "def_ko": "좋거나 긍정적인 것", "def_vi": "Điều tốt hoặc tích cực"}, {"term_ko": "경찰서", "term_vi": "Đồn cảnh sát", "def_ko": "범죄를 신고하는 곳", "def_vi": "Nơi để báo cáo tội phạm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (780, '4', '다음 중 육체적 성희롱에 해당하는 행위는?', '["음란한 농담을 하며 외모를 평가함", "옆에 앉아 술을 따르라고 함", "음란한 편지, 사진을 전송함", "자신의 특정 신체부위를 만짐", "옆에 앉으며 허리를 잡아 당김"]'::jsonb, 5, NULL, NULL, '{"1": "음란한 농담을 하며 외모를 평가하는 것은 언어적 성희롱에 해당합니다.\n[정답]", "2": "옆에 앉아 술을 따르라고 하는 것은 상대방의 의사에 반하는 요구로 해석될 수 있지만, 육체적 성희롱으로 보기 어렵습니다.", "3": "음란한 편지, 사진을 전송하는 것도 언어적 성희롱에 해당합니다.", "4": "자신의 특정 신체부위를 만진 경우는 육체적 성희롱이 아닙니다.", "5": "옆에 앉으며 허리를 잡아 당기는 행위는 명백한 육체적 성희롱에 해당합니다."}'::jsonb, '[{"term_ko": "육체적", "term_vi": "Thể xác", "def_ko": "신체에 관련된", "def_vi": "Liên quan đến cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (779, '4', '대상자가 요양보호사에게 언어적 성희롱을 하는 행위는?', '["음란한 사진을 보여준다.", "가슴과 엉덩이를 만진다.", "성적 사실관계를 묻거나 성적인 정보를 유포한다.", "특정 신체부위를 고의적으로 노출한다.", "뒤에서 껴안으며 신체 접촉을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "음란한 사진을 보여주는 것은 성희롱의 일종이나, 언어적인 성희롱이 아님.", "2": "가슴과 엉덩이를 만지는 것은 신체적 성희롱으로 언어적 성희롱과는 다름.\n[정답]", "3": "성적 사실관계를 묻거나 성적인 정보를 유포하는 것은 언어적 성희롱의 명백한 예시임.", "4": "특정 신체부위를 고의적으로 노출하는 것은 신체적 성희롱으로 분류됨.", "5": "뒤에서 껴안으며 신체 접촉을 하는 것은 언어가 아닌 신체적 성희롱에 해당함."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적으로 불쾌감을 주는 언행", "def_vi": "Hành vi ngôn ngữ hoặc thể chất gây ra sự khó chịu về mặt tình dục"}, {"term_ko": "언어적", "term_vi": "Bằng lời", "def_ko": "말로 표현되는", "def_vi": "Biểu hiện bằng lời nói"}, {"term_ko": "신체적", "term_vi": "Cơ thể", "def_ko": "신체에 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "사실관계", "term_vi": "Thực tế", "def_ko": "사실의 관계나 상황", "def_vi": "Mối quan hệ hoặc tình huống của sự thật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (778, '4', '요양보호사에게 업무상 부상이나 질병이 발생했을 때, 산업재해보상보험봅의 보장 내용으로 옳은 것은?', '["보험급여는 양도, 압류할 수 있다.", "사업장이 부도, 폐업한 경우 지급받을 수 없다.", "시설장이 잘못이 없으면 급여가 지급되지 않는다.", "보험급여는 세금이 부과되지 않는다.", "산업재해로 퇴직할 경우 보험급여는 중단된다."]'::jsonb, 4, NULL, NULL, '{"1": "보험급여는 양도, 압류할 수 없다.\n[정답]", "2": "사업장이 부도, 폐업한 경우 지급받을 수 있다.", "3": "시설장이 잘못이 없으면 급여가 지급될 수 있다.", "4": "보험급여는 세금이 부과되지 않는다.", "5": "산업재해로 퇴직할 경우 보험급여는 중단되지 않는다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Y tá hỗ trợ", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}, {"term_ko": "업무상", "term_vi": "Liên quan đến công việc", "def_ko": "업무에 의해 발생함", "def_vi": "Phát sinh từ công việc"}, {"term_ko": "부상", "term_vi": "Thương tích", "def_ko": "다치다", "def_vi": "Bị thương"}, {"term_ko": "질병", "term_vi": "Bệnh", "def_ko": "병", "def_vi": "Bệnh tật"}, {"term_ko": "산업재해", "term_vi": "Tai nạn lao động", "def_ko": "직업상의 사고", "def_vi": "Tai nạn nghề nghiệp"}, {"term_ko": "보상보험", "term_vi": "Bảo hiểm bồi thường", "def_ko": "보상을 위한 보험", "def_vi": "Bảo hiểm bồi thường"}, {"term_ko": "급여", "term_vi": "Tiền lương", "def_ko": "보수", "def_vi": "Tiền lương"}, {"term_ko": "세금", "term_vi": "Thuế", "def_ko": "국가에 바치는 금액", "def_vi": "Số tiền nộp cho nhà nước"}, {"term_ko": "중단", "term_vi": "Ngừng", "def_ko": "멈추다", "def_vi": "Dừng lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (777, '4', '산업재해보상보험법의 설명으로 옳은 것은?', '["보험급여는 채권자가 압류할 수 있다.", "산업재해 인정을 받았다는 이유로 해고될 수 없다.", "사업주가 보험료를 꼭 납입해야 지급받을 수 있다.", "법으로 보장된 보험급여를 받을 권리는 1년이다.", "근무 중 본인의 실수로 인한 사고는 보상받을 수 없다."]'::jsonb, 2, NULL, NULL, '{"1": "보험급여는 채권자가 압류할 수 없다. (보험급여는 채권자의 압류에서 보호받는다.)\n[정답]", "2": "산업재해 인정을 받았다는 이유로 해고될 수 없다. (산업재해를 인정받은 경우 해고가 금지된다.)", "3": "사업주가 보험료를 꼭 납입해야 지급받을 수 없다. (노동자는 산업재해로 인한 보상을 받을 수 있다.)", "4": "법으로 보장된 보험급여를 받을 권리는 3년이다. (보험급여를 청구할 수 있는 기간은 3년으로, 1년이 아니다.)", "5": "근무 중 본인의 실수로 인한 사고는 보상받을 수 있다. (업무 중 발생한 사고는 보상받을 수 있는 경우가 많다.)"}'::jsonb, '[{"term_ko": "산업재해보상보험법", "term_vi": "Luật bảo hiểm bồi thường tai nạn lao động", "def_ko": "산업재해에 대한 보상을 규정한 법률", "def_vi": "Luật quy định bồi thường cho tai nạn lao động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (776, '4', '근로자의 업무상 재해를 신속하고 공정하게 보상하며, 재해근로자의 복지를 증진하기 위한 목적으로 제정된 법률은?', '["노인장기요양보험법", "국민연금법", "산업재해보상보험법", "고용보험법", "노인복지법"]'::jsonb, 3, NULL, NULL, '{"1": "노인장기요양보험법은 노인에 대한 장기 요양 서비스를 제공하기 위한 법률입니다.\n[정답]", "3": "산업재해보상보험법은 근로자의 업무상 재해에 대해 신속하고 공정한 보상을 제공하는 법률입니다.", "2": "국민연금법은 국민의 노후 보장을 위한 연금 제도를 규정한 법률입니다.", "4": "고용보험법은 실업급여 및 고용보험에 대한 내용을 포함한 법률입니다.", "5": "노인복지법은 노인의 복지 증진을 위한 법률입니다."}'::jsonb, '[{"term_ko": "업무상", "term_vi": "Tình huống lao động", "def_ko": "일과 관련된(한국어)", "def_vi": "liên quan đến công việc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (775, '4', '근로자의 기본적 생활을 보장, 향상하여 균형 있는 국민경제의 발전에 기여하는 것을 목적으로 제정된 법률은?', '["근로기준법", "산업안전보건법", "산업재해보상보험법", "건강보험법", "노인복지법"]'::jsonb, 1, NULL, NULL, '{"1": "근로자의 근로조건을 정하고 보호하기 위한 법률로, 기본적인 생활 보장과 균형 있는 국민경제 발전에 기여합니다.\n[정답]", "2": "산업현장에서의 안전과 건강을 보장하기 위한 법률입니다.", "3": "산업 재해로 인한 피해를 보상하기 위한 법률입니다.", "4": "국민의 건강을 보장하기 위한 보험 제도입니다.", "5": "노인의 복지를 증진하기 위한 법률입니다."}'::jsonb, '[{"term_ko": "근로자", "term_vi": "Người lao động", "def_ko": "노동자(한국어)", "def_vi": "Người làm việc"}, {"term_ko": "기본적", "term_vi": "Cơ bản", "def_ko": "기본적인(한국어)", "def_vi": "Cơ sở, nền tảng"}, {"term_ko": "생활", "term_vi": "Cuộc sống", "def_ko": "삶(한국어)", "def_vi": "Đời sống"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "보증하다(한국어)", "def_vi": "Bảo đảm"}, {"term_ko": "향상", "term_vi": "Nâng cao", "def_ko": "향상시키다(한국어)", "def_vi": "Tăng cường"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "균형(한국어)", "def_vi": "Cân bằng"}, {"term_ko": "국민경제", "term_vi": "Kinh tế quốc dân", "def_ko": "국가 경제(한국어)", "def_vi": "Kinh tế của quốc gia"}, {"term_ko": "사고", "term_vi": "Sự cố", "def_ko": "사고(한국어)", "def_vi": "Tai nạn"}, {"term_ko": "법률", "term_vi": "Luật", "def_ko": "법률(한국어)", "def_vi": "Bộ luật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (774, '4', '근로자의 기본적 생활을 보장, 향상하여 균형 있는 국민경제의 발전에 기여하는 것을 목적으로 제정된 법률은?', '["근로기준법", "산업안전보건법", "산업재해보상보험법", "건강보험법", "노인복지법"]'::jsonb, 1, NULL, NULL, '{"1": "근로자의 권리와 근로 조건을 보장하는 법입니다.\n[정답]", "2": "산업 현장에서의 안전과 건강을 보장하는 법입니다.", "3": "산업 재해로 인한 피해를 보상하는 법입니다.", "4": "국민의 건강을 보장하는 법입니다.", "5": "노인의 복지를 증진하기 위한 법입니다."}'::jsonb, '[{"term_ko": "근로자", "term_vi": "Người lao động", "def_ko": "노동자(한국어)", "def_vi": "Người làm việc"}, {"term_ko": "기본적", "term_vi": "Cơ bản", "def_ko": "기본적인(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "생활", "term_vi": "Cuộc sống", "def_ko": "생활(한국어)", "def_vi": "Cuộc sống"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "보장하다(한국어)", "def_vi": "Đảm bảo"}, {"term_ko": "향상", "term_vi": "Nâng cao", "def_ko": "향상시키다(한국어)", "def_vi": "Nâng cao"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "균형(한국어)", "def_vi": "Cân bằng"}, {"term_ko": "국민경제", "term_vi": "Kinh tế quốc dân", "def_ko": "국민 경제(한국어)", "def_vi": "Kinh tế quốc dân"}, {"term_ko": "발전", "term_vi": "Phát triển", "def_ko": "발전(한국어)", "def_vi": "Phát triển"}, {"term_ko": "법률", "term_vi": "Luật pháp", "def_ko": "법률(한국어)", "def_vi": "Luật pháp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (773, '4', '요양보호사가 업무상 부당한 대우를 받았을 때 대처방법은?', '["시설을 퇴사한다.", "동료 요양보호사와 의논한다.", "노인보호전문기관에 법적자문을 요청한다.", "장기요양요원지원센터에 상담을 신청한다.", "산업재해보상보험법에 따른 피해구제 방법을 알아본다."]'::jsonb, 4, NULL, NULL, '{"1": "시설을 퇴사한다: 부당한 대우를 해결하기보다 회피하는 방법으로 바람직하지 않습니다.", "2": "동료 요양보호사와 의논한다: 동료와의 의논이 도움이 될 수 있지만, 공식적인 도움을 받는 것이 중요합니다.\n[정답]", "3": "노인보호전문기관에 법적자문을 요청한다: 전문기관의 상담을 통해 법적 대처 방법을 모색할 수 있습니다.", "4": "장기요양요원지원센터에 상담을 신청한다: 이곳은 요양보호사에게 필요한 상담과 지원을 제공하는 곳입니다.", "5": "산업재해보상보험법에 따른 피해구제 방법을 알아본다: 법적 구제 방법을 알지만, 상담 요청이 더 직접적인 해결책입니다."}'::jsonb, '[{"term_ko": "부당한", "term_vi": "대우", "def_ko": "부당한 (không công bằng)", "def_vi": "대우 (đối xử)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (772, '4', '요양보호사의 건강검진, 취업상담 지원 및 대체인력을 지원해주는 곳은?', '["노인정보센터", "노인인권센터", "재가노인복지센터", "노인일자리지원센터", "장기요양요원지원센터"]'::jsonb, 5, NULL, NULL, '{"1": "노인정보센터: 노인들에게 필요한 정보 제공을 주로 하는 센터입니다.", "2": "노인인권센터: 노인의 권리를 보호하고 인권을 신장하기 위한 목적으로 운영됩니다.", "3": "재가노인복지센터: 가정에서 거주하는 노인을 대상으로 서비스를 제공합니다.\n[정답]", "4": "노인일자리지원센터: 고용 중심으로 노인들을 지원하는 기관입니다.", "5": "장기요양요원지원센터: 요양보호사를 포함한 장기요양 인력에 대한 지원과 관련된 기관입니다."}'::jsonb, '[{"term_ko": "건강검진", "term_vi": "Khám sức khỏe", "def_ko": "건강 상태를 확인하기 위한 검사", "def_vi": "Kiểm tra tình trạng sức khỏe"}, {"term_ko": "취업상담", "term_vi": "Tư vấn việc làm", "def_ko": "구직자를 대상으로 한 상담", "def_vi": "Tư vấn cho người tìm việc"}, {"term_ko": "대체인력", "term_vi": "Nhân lực thay thế", "def_ko": "대신 일을 수행하는 인력", "def_vi": "Nhân lực thay thế công việc"}, {"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "센터", "term_vi": "Trung tâm", "def_ko": "기관 또는 장소", "def_vi": "Cơ quan hoặc địa điểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (771, '4', '다음 상황에서 요양보호사가 침해받을 권리는?기관장: "지원서를 보니 어르신을 돌보기에는 나이가 많아 일하기 힘들 것 같네요." 요양보호사: "........"', '["자유에 관한 권리", "평등에 관한 권리", "신체의 안전에 대한 권리", "휴식 및 여가를 누릴 권리", "노후소득을 보장 받을 권리"]'::jsonb, 2, NULL, NULL, '{"1": "자유에 관한 권리: 요양보호사도 개인의 자유를 갖고 있지만 이 상황에서는 권리 침해와 직접적인 관련이 없습니다.\n[정답]", "2": "평등에 관한 권리: 요양보호사는 나이로 인해 차별받지 않을 권리가 있으며, 이 상황에서 침해받은 권리는 평등에 관한 권리입니다.", "3": "신체의 안전에 대한 권리: 신체의 안전은 중요하지만 주어진 상황에서는 해당되지 않습니다.", "4": "휴식 및 여가를 누릴 권리: 이 보기는 현재 상황과 관련이 없습니다.", "5": "노후소득을 보장 받을 권리: 노후소득 보장은 중요하지만 이 사례와는 무관합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc y tế", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (770, '4', '다음 상황에서 요양보호사가 침해받을 권리는?치매대상자를 돌보느라 휴식시간 없이 일을 하고, 퇴근 시간 이후에도 수당 없이 초과근무를 하였다.', '["평등권", "자유권", "교육권", "노동권", "참정권"]'::jsonb, 4, NULL, NULL, '{"1": "평등권은 개인이 평등하게 대우받아야 함을 의미하므로 해당 문제와 무관합니다.", "2": "자유권은 기본적인 자유를 보장받는 권리로, 이 상황과는 관련이 없습니다.", "3": "교육권은 교육을 받을 권리로, 문제의 상황과 연관이 없습니다.\n[정답]", "4": "노동권은 근로자가 합리적이고 공정하게 일할 권리이며, 이 경우 요양보호사가 자신의 근무 조건에 대해 침해받고 있는 상황입니다.", "5": "참정권은 정치적 권리로, 이 문제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자를 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc bệnh nhân"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리를 방해하다", "def_vi": "Ngăn cản quyền"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "개인의 이익을 보장하는 법적 권한", "def_vi": "Quyền lợi pháp lý đảm bảo lợi ích cá nhân"}, {"term_ko": "노동권", "term_vi": "Quyền lao động", "def_ko": "근로자의 권리", "def_vi": "Quyền của người lao động"}, {"term_ko": "휴식시간", "term_vi": "Thời gian nghỉ ngơi", "def_ko": "일을 쉬는 시간", "def_vi": "Thời gian không làm việc"}, {"term_ko": "초과근무", "term_vi": "Làm thêm giờ", "def_ko": "정해진 시간을 초과하여 일하는 것", "def_vi": "Làm việc vượt quá thời gian quy định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (769, '3', '노인학대 예방을 위한 유관기관(A)와 역할 (B)를 바르게 연결한 것은?', '["법률기관 현장조사 시 동행 협조", "사법경찰 학대 판정을 위한 의학적 진단, 소견", "의료기관 이용자 대상 노인학대 예방교육", "노인보호전문기관 학대 사례의 신고접수", "노인 및 사회복지시설 학대 피해노인의 후견인 지정"]'::jsonb, 4, NULL, NULL, '{"1": "법률기관은 법적인 문제 해결을 위한 지원을 제공하나, 현장조사 시 동행 협조는 주로 사회복지기관의 역할입니다.\n[정답]", "2": "사법경찰은 사건의 수사를 담당하지만, 의학적 진단과 소견은 의료기관의 역할입니다.", "3": "의료기관은 노인학대 예방교육을 실시하는 것이 아니라, 환자의 의료적 필요를 충족하는 곳입니다.", "4": "노인보호전문기관은 노인학대 사례에 대한 신고접수를 담당합니다.", "5": "노인 및 사회복지시설에서의 후견인 지정은 법원 등의 절차를 통해 이루어집니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에 대한 폭력 또는 학대", "def_vi": "Bạo lực hoặc lạm dụng đối với người cao tuổi"}, {"term_ko": "유관기관", "term_vi": "Cơ quan liên quan", "def_ko": "연관된 기관들", "def_vi": "Các tổ chức có liên quan"}, {"term_ko": "현장조사", "term_vi": "Khảo sát thực địa", "def_ko": "실제 사례 조사", "def_vi": "Điều tra thực tế"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 학대 행동", "def_vi": "Hành động bạo lực hoặc lạm dụng"}, {"term_ko": "신고접수", "term_vi": "Tiếp nhận báo cáo", "def_ko": "사건에 대한 보고를 받는 것", "def_vi": "Nhận báo cáo về sự việc"}, {"term_ko": "후견인", "term_vi": "Người giám hộ", "def_ko": "법적으로 대리인 역할을 하는 사람", "def_vi": "Người đại diện hợp pháp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (768, '3', '다음 중 직무상 노인학대 신고 의무자는?', '["이웃 주민", "요양 보호사", "집배원", "가족", "주민센터 일반 직원"]'::jsonb, 2, NULL, NULL, '{"1": "이웃 주민은 신고 의무자가 아닙니다.\n[정답]", "2": "요양 보호사는 직무상 노인학대에 대한 신고 의무가 있습니다.", "3": "집배원은 신고 의무자가 아닙니다.", "4": "가족은 신고를 할 수 있지만, 의무자는 아닙니다.", "5": "주민센터 일반 직원은 신고 의무자가 아닙니다."}'::jsonb, '[{"term_ko": "직무", "term_vi": "Nhiệm vụ", "def_ko": "의무/책임(한국어)", "def_vi": "nghĩa vụ/ trách nhiệm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (767, '3', '방문목욕서비스를 제공하던 중 대상자의 몸 여러 군데에 멍들고 상처난 자국이 발견되었다. 요양보호사의 대처방법은?', '["시설에 입소할 것을 권유한다.", "대상자의 이야기를 들어주고 위로해 준다.", "함께 사는 가족들에게 연락하여 대상자의 상태를 알려준다.", "노인보호전문기관이나 경찰서에 신고한다.", "개인적인 일이므로 모른 척 한다."]'::jsonb, 4, NULL, NULL, '{"1": "시설에 입소할 것을 권유하는 것은 문제의 원인을 중재하지 않는다.\n[정답]", "2": "대상자의 이야기를 들어주고 위로해 주는 것은 중요하지만, 더 큰 문제에 대한 대처가 아니다.", "3": "함께 사는 가족들에게 연락하여 대상자의 상태를 알려주는 것은 필요할 수 있지만, 즉각적인 대처가 요구된다.", "4": "노인보호전문기관이나 경찰서에 신고하는 것이 적절한 조치이다.", "5": "개인적인 일이므로 모른 척 하는 것은 책임 회피가 된다."}'::jsonb, '[{"term_ko": "방문목욕서비스", "term_vi": "Dịch vụ tắm tại nhà", "def_ko": "환자의 집을 방문해 목욕 서비스를 제공하는 것", "def_vi": "Dịch vụ tắm cho bệnh nhân tại nhà"}, {"term_ko": "멍", "term_vi": "Vết bầm", "def_ko": "피부에 생긴 푸른 반점", "def_vi": "Vết bầm trên da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부의 손상", "def_vi": "Tổn thương trên da"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 요양과 간호를 돕는 직업", "def_vi": "Nghề giúp đỡ chăm sóc bệnh nhân"}, {"term_ko": "노인보호전문기관", "term_vi": "Cơ quan bảo vệ người cao tuổi", "def_ko": "노인을 보호하기 위한 기관", "def_vi": "Tổ chức bảo vệ người già"}, {"term_ko": "경찰서", "term_vi": "Đồn cảnh sát", "def_ko": "범죄를 수사하는 기관", "def_vi": "Cơ quan điều tra tội phạm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (766, '3', '월별 입소비용 미납 등 노인에 대한 특별한 보호조치 없이 가족이 연락을 두절하는 학대유형은?', '["신체적 학대", "정서적 학대", "경제적 학대", "유기", "방임"]'::jsonb, 4, NULL, NULL, '{"1": "신체적 학대: 노인에게 신체적으로 강압을 가하는 경우로, 이 문제와는 관련이 없음.", "2": "정서적 학대: 노인의 감정이나 심리에 대한 학대로, 연락을 두절하는 행위와는 차이가 있음.\n[정답]", "3": "경제적 학대: 경제적인 자원을 제한하거나 착취하는 경우로, 이 문제와는 직접적인 관련이 없음.", "4": "유기: 가족이 노인을 돌보지 않고 연락을 끊는 경우로, 이 문제에 해당됨.", "5": "방임: 노인이 필요로 하는 기본적인 돌봄을 제공하지 않는 경우로, 유기와는 다름."}'::jsonb, '[{"term_ko": "입소비용", "term_vi": "학대", "def_ko": "비용 để vào viện", "def_vi": "lạm dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (765, '3', '다음에서 파악되는 노인학대의 유형으로 옳은 것은?• 집 안에 쓰레기가 쌓여 악취가 나는데도 대상자가 도움을 거부한다.• 대상자가 건강에 치명적인 약물이나 알코올 남용을 지속한다.', '["유기", "방임", "자기방임", "경제적 학대", "신체적 학대"]'::jsonb, 3, NULL, NULL, '{"1": "유기는 타인의 보호나 도움을 거부하는 상태를 의미한다. 이 경우는 해당되지 않는다.\n[정답]", "3": "자기방임은 스스로 자신의 안전이나 건강을 돌보지 않는 상태로, 해당 사례에 적합하다.", "2": "방임은 타인의 돌봄이 필요한 상황에서 그 돌봄이 이뤄지지 않는 상태를 의미한다.", "4": "경제적 학대는 피해자의 재정적 자원을 착취하는 행위를 뜻한다.", "5": "신체적 학대는 신체에 대한 폭력이나 상해를 가하는 것을 말한다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 하는 학대", "def_vi": "Hành vi ngược đãi đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (764, '3', '다음 사례에 해당하는 노인학대 유형은? 쪽방에서 생활하고 있는 대상자는 1개우러 전에 배우자와 사별한 후, 식사를 거부하고 약 복용을 중지한 채 홀로 지내고 있다. 그 결과 체중이 급격히 줄고 몸이 날로 쇠약해져 갔다.', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 3, NULL, NULL, '{"1": "방임: 필요한 기본적 요구를 충족하지 못한 경우로, 이 경우는 본인이 스스로 식사를 거부하고 약을 중지한 것으로 볼 수 있어 방임은 해당되지 않는다.\n[정답]", "3": "자기방임: 노인이 스스로 자신의 건강 관리를 소홀히 하는 경우로, 주어진 사례에서 대상자가 식사를 거부하고 약 복용을 중지한 것은 자기방임에 해당한다.", "2": "유기: 보호자나 가족이 노인을 방치한 경우로, 이 사례에서는 홀로 있더라도 방치가 아닌 자신의 행동으로 인한 것이므로 유기가 아니다.", "4": "착취: 경제적 혹은 신체적으로 착취당하는 상황으로, 이 사례와는 관련이 없다.", "5": "신체적 학대: 신체적으로 피해를 입는 경우로, 해당 사례와는 무관하다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에게 가해지는 폭력이나 방임", "def_vi": "Bạo lực hoặc bỏ mặc đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (763, '3', '노인학대의 유형과 학대행위가 바르게 연결된 것은?', '["신체적 학대 - 대화를 하지 않는다.", "방임- 안정된 주거공간을 제공하지 않고 떠돌게 한다.", "경제적 학대 - 의료적 처치와 생활비 제공을 중단한다.", "정서적 학대 - 노인이 자살을 시도한다.", "유기 - 거동이 불편한 노인의 간병을 소홀히 한다."]'::jsonb, 2, NULL, NULL, '{"1": "신체적 학대는 주로 물리적으로 상해를 입히는 행위로 대화를 하지 않는 것은 해당하지 않는다.\n[정답]", "2": "방임은 안정된 주거공간을 제공하지 않는 것으로, 노인을 안전하게 지내지 못하게 하는 경우를 설명한다.", "3": "경제적 학대는 재정적인 지원을 중단하는 것이 맞지만, 금전적 착취가 더 일반적인 설명이다.", "4": "정서적 학대는 노인의 자살 시도와 관련된 심리적 고통과 관계가 있지만, 학대행위로 직접 연결하기는 어렵다.", "5": "유기는 노인을 방치하거나 돌보지 않는 행위로 설명할 수 있으며, 거동이 불편한 노인의 간병 소홀은 유기의 정의에 맞는다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 학대", "def_vi": "Hành vi lạm dụng nhắm vào người cao tuổi"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체적으로 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "방임", "term_vi": "Bỏ bê", "def_ko": "필요한 보호를 하지 않는 행위", "def_vi": "Hành vi không bảo vệ cần thiết"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정적으로 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "유기", "term_vi": "Bỏ mặc", "def_ko": "책임을 다하지 않는 행위", "def_vi": "Hành vi không hoàn thành trách nhiệm"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정적으로 관련된", "def_vi": "Liên quan đến tài chính"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (762, '3', '다음 사례에 해당하는 노인학대 유형은?어머니가 화장실에서 넘어져 엉덩이의 통증을 호소하며 며칠 동안 누워있는데 아들은 병원에 모시고 갈 생각은 하지 않고, 방안에 방치하였다.', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 1, NULL, NULL, '{"1": "방임: 필요한 도움이나 치료를 제공하지 않는 경우로, 이 사례는 아들이 어머니를 방치했으므로 방임에 해당한다.\n[정답]", "2": "유기: 의도적으로 환자를 버리는 경우로, 이 사례는 아들이 어머니를 버린 것과는 다른 상황이다.", "3": "자기방임: 스스로 자신의 신체나 건강을 돌보지 않는 경우로, 어머니가 의식적으로 그렇게 한 것은 아니다.", "4": "착취: 다른 사람에게 경제적 이득을 취하기 위해 사용하는 경우로, 이 사례와는 관련이 없다.", "5": "신체적 학대: 신체적으로 상해를 가하는 경우로, 이 사례는 방치와 관련되어 있다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자의 권리를 침해하거나 건강을 해치는 행위", "def_vi": "Hành vi xâm phạm quyền lợi hoặc làm tổn hại sức khỏe của người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (761, '3', '다음 내용에 해당하는 노인학대 유형은?• 안경이 깨져있다.• 더럽고 찢어진 옷을 입고 있다.• 오물로 이불이 더럽고, 욕창이 있다.', '["방임", "유기", "신체적 학대", "경제적 학대", "정서적 학대"]'::jsonb, 1, NULL, NULL, '{"1": "방임: 노인이 기본적인 돌봄과 보호를 받지 못하는 상태를 의미합니다. 제시된 내용은 노인이 옷이나 안경이 불량하며, 욕창이 있는 상황이므로 방임에 해당합니다.\n[정답]", "2": "유기: 노인을 방치하거나 돌보지 않는 상황을 의미하지만, 이 문제에서는 물리적 방임이 강조되었으므로 정답이 아닙니다.", "3": "신체적 학대: 신체적 상해를 입히는 행위이나, 이 경우는 방임 문제입니다.", "4": "경제적 학대: 노인의 재산을 착취하거나 재정적 지원을 하지 않는 것을 의미하지만, 이 문제에서는 해당하지 않습니다.", "5": "정서적 학대: 정신적 고통을 주는 행위이지만, 여기서는 신체적 상황이 주제입니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người già", "def_ko": "늙은 사람에게 가해지는 배려 부족 또는 폭력", "def_vi": "Hành vi thiếu chăm sóc hoặc bạo lực đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (760, '3', '부양 의무자로서 책임이나 의무를 거부 또는 포기하여 노인에게 의식주 및 의료를 적절하게 제공하지 않는 행위의 학대 유형은?', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 1, NULL, NULL, '{"1": "방임: 부양 의무자가 책임이나 의무를 거부하여 노인에게 적절한 도움을 제공하지 않는 경우를 의미한다. \n[정답]", "2": "유기: 부양 의무자가 노인을 돌보지 않고 방치하는 경우를 뜻한다.", "3": "자기방임: 노인이 자신의 건강이나 안전을 스스로 무시하는 경우이다.", "4": "착취: 노인을 경제적이나 신체적으로 이용하여 이득을 취하는 경우를 말한다.", "5": "신체적 학대: 노인에게 신체적 상해를 가하는 행위를 의미한다."}'::jsonb, '[{"term_ko": "부양 의무자", "term_vi": "Người nuôi dưỡng", "def_ko": "가족이나 친척이 노인을 돕고 돌봐야 하는 책임이 있는 사람", "def_vi": "Người có trách nhiệm giúp đỡ và chăm sóc người cao tuổi trong gia đình"}, {"term_ko": "방임", "term_vi": "Bỏ bê", "def_ko": "필요를 무시하고 돌보지 않음", "def_vi": "Không quan tâm và bỏ mặc nhu cầu"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "돌보지 않고 방치함", "def_vi": "Bỏ mặc không chăm sóc"}, {"term_ko": "착취", "term_vi": "Khai thác", "def_ko": "부당하게 이용하는 것", "def_vi": "Sử dụng một cách không công bằng"}, {"term_ko": "신체적 학대", "term_vi": "Lạm dụng thể xác", "def_ko": "신체적으로 피해를 주는 것", "def_vi": "Gây hại về mặt thể chất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (759, '3', '아들이 사업의 실패로 대상자의 통장을 몰래 빼돌려 허락 없이 돈을 인출하여 세금과 공과금이 체납되었다. 어떤 유형의 학대인가?', '["경제적 학대", "정서적 학대", "성적 학대", "유기", "방임"]'::jsonb, 1, NULL, NULL, '{"1": "경제적 학대는 대상자의 재산이나 재정에 악영향을 주는 행위로, 이 경우 아들이 몰래 돈을 인출한 것이 해당된다.\n[정답]", "2": "정서적 학대는 감정적 상처를 주는 행위로, 문제의 경우와는 무관하다.", "3": "성적 학대는 성적 행위에 관련된 학대로, 이 경우와는 무관하다.", "4": "유기는 대상자를 아예 돌보지 않는 것을 의미하며, 이 상황과는 다르다.", "5": "방임은 필요한 돌봄을 제공하지 않는 것으로, 이번 경우에서는 아들이 직접 개입했기 때문에 해당하지 않는다."}'::jsonb, '[{"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정과 관련된", "def_vi": "Liên quan đến tài chính"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (758, '3', '노인의 의사에 반하여 성적 수치심 유발 행위 및 성희롱, 성추행을 강제적으로 행할 경우에 해당하는 학대 유형은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 3, NULL, NULL, '{"1": "신체적 학대: 신체적 손상을 주는 행위로, 이 문제와는 관련이 없습니다.", "2": "정서적 학대: 감정적 고통을 주는 행위로, 성적 행위와는 다른 차원의 문제입니다.\n[정답]", "3": "성적 학대: 노인의 의사에 반하여 성적 수치심을 유발하는 행위는 성적 학대에 해당합니다.", "4": "경제적 학대: 재정적으로 착취하는 행위로, 성적 관련 행위와는 무관합니다.", "5": "방임: 필요한 돌봄을 제공하지 않는 것을 의미하며, 이 문제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (757, '3', '다음 사례에 해당하는 노인학대 유형은?늦은 저녁식사를 하고 쇼파에 앉아 쉬고 있는 시어머니께 "에이, 꼴도 보기 싫은데 빨리 방에나 들어가지 왜 거기 앉아 있는 거야. 죽치고 앉아 있지 말고 빨리 들어가요." 라고 소리를 질렀다.', '["정서적 학대", "신체적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 1, NULL, NULL, '{"1": "상대방의 감정을 상하게 하고, 심리적 고통을 주는 언행을 직면했으므로 정서적 학대입니다.\n[정답]", "2": "신체적 접촉이나 폭력이 관여되지 않았기 때문에 신체적 학대가 아닙니다.", "3": "경제적 착취나 재산에 대한 위협이 없으므로 경제적 학대가 아닙니다.", "4": "충분한 돌봄이 부족하지 않기 때문에 방임이 아닙니다.", "5": "유기하고 방치하는 것이 아니므로 유기가 아닙니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인이 당하는 학대", "def_vi": "Hành vi lạm dụng đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (756, '3', '다음 내용에서 파아갈 수 있는 노인학대 유형은?• 대상자만 따로 식사하게 한다.• 대상자의 이성교제를 방해한다.• 대상자의 말과 행동에 반응하지 않는다.', '["유기", "방임", "신체적 학대", "정서적 학대", "경제적 학대"]'::jsonb, 4, NULL, NULL, '{"1": "유기는 누군가를 돌보지 않고 방치하는 것으로, 이 경우에 해당하지 않습니다.", "2": "방임은 필요한 돌봄을 제공하지 않는 것을 의미하지만, 이 시나리오에서 직접적으로 나타나지 않습니다.\n[정답]", "3": "신체적 학대는 물리적인 폭력을 포함하나 본 사례에는 해당하지 않습니다.", "4": "정서적 학대는 상대방의 감정을 해치거나 사회적 관계를 혼란스럽게 만드는 것으로, 본 사례의 내용은 여기에 적합합니다.", "5": "경제적 학대는 재정적 자원을 착취하는 것으로, 이 내용과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 하는 다양한 형태의 학대", "def_vi": "Các hình thức lạm dụng đa dạng đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (755, '3', '노인학대 행위(A)와 유형 (B)이 바르게 연결된 것은?', '["창피를 준다. 성적 학대", "외출을 못하게 한다. 신체적 학대", "가출을 해도 찾지 않는다. 자기방임", "치료를 못 받게 한다. 경제적 학대", "대상자의 말을 무시한다. 유기"]'::jsonb, 2, NULL, NULL, '{"1": "창피를 준다. 성적 학대", "2": "외출을 못하게 한다. 신체적 학대\n[정답]", "3": "가출을 해도 찾지 않는다. 자기방임", "4": "치료를 못 받게 한다. 경제적 학대", "5": "대상자의 말을 무시한다. 유기"}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 폭력이나 학대", "def_vi": "Bạo lực hoặc lạm dụng đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (754, '3', '가족이 일방적으로 수도와 전기를 단절하여 대상자의 생존을 위협하는 노인학대 유형은?', '["유기", "자기방임", "정서적 학대", "언어적 학대", "신체적 학대"]'::jsonb, 5, NULL, NULL, '{"1": "유기는 피할 수 있는 환경에서 의도적으로 방치하는 것으로, 생명에 위협적이지는 않지만 정서적으로 영향을 줄 수 있습니다.\n[정답]", "5": "신체적 학대는 생존을 위협할 수 있는 행위로, 수도와 전기를 차단하는 것은 명백한 신체적 학대의 사례입니다.", "2": "자기방임은 노인이 자기 자신을 돌보지 않는 경우로, 가족의 의도와는 무관합니다.", "3": "정서적 학대는 언어적 공격이나 심리적 압박을 포함하지만, 생명을 직접적으로 위협하지는 않습니다.", "4": "언어적 학대는 신체적 피해를 주지는 않지만, 정신적으로 상처를 남길 수 있습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 학대", "def_vi": "Hành vi lạm dụng nhắm vào người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (753, '3', '물리적인 힘이나 도구를 이용하여 노인에게 신체적 손상, 고통, 장애 등을 유발하는 노인학대의 유형은?', '["정서적 학대", "신체적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 2, NULL, NULL, '{"1": "정서적 학대: 노인에게 정서적 고통이나 심리적 스트레스를 주는 형태입니다.\n[정답]", "2": "신체적 학대: 물리적인 힘이나 도구를 사용하여 노인에게 신체적 손상이나 고통을 유발하는 학대입니다.", "3": "경제적 학대: 노인의 재산이나 재정을 착취하는 형태의 학대입니다.", "4": "방임: 필요한 돌봄이나 도움이 제공되지 않는 경우를 의미합니다.", "5": "유기: 노인이 돌보지 않아 혼자 남겨지는 상황입니다."}'::jsonb, '[{"term_ko": "신체적", "term_vi": "Thể xác", "def_ko": "신체(몸)와 관련된", "def_vi": "liên quan đến cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (752, '3', '노인학대를 발생시킬 수 있는 요인은?', '["노인부양 의식 강화", "노인의 의존성 증가", "가족관계 갈등 해소", "가족부양 부담 감소", "노인의 사회적 관계망 확대"]'::jsonb, 2, NULL, NULL, '{"1": "노인부양 의식 강화를 통해 노인에 대한 이해와 배려가 증진되어 학대를 줄일 수 있습니다.\n[정답]", "2": "노인의 의존성이 증가하면 가족의 부담감이 커져 노인학대를 촉발할 수 있습니다.", "3": "가족관계 갈등 해소는 노인학대와 관련이 없으며 오히려 긍정적인 결과를 가져올 수 있습니다.", "4": "가족부양 부담 감소는 노인학대와는 반대의 개념으로, 노인에 대한 도움이 줄어들게 할 수 있습니다.", "5": "노인의 사회적 관계망 확대는 노인이 더 많은 지원을 받을 수 있게 하여 학대를 방지하는 데 기여할 수 있습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에 대한 신체적, 정서적, 재정적 학대", "def_vi": "Lạm dụng về thể chất, tinh thần, tài chính đối với người cao tuổi"}, {"term_ko": "의존성", "term_vi": "Sự phụ thuộc", "def_ko": "다른 사람에게 의존하는 상태", "def_vi": "Trạng thái phụ thuộc vào người khác"}, {"term_ko": "가족부양", "term_vi": "Chăm sóc gia đình", "def_ko": "가족이 노인이나 아픈 가족을 돌보는 일", "def_vi": "Sự chăm sóc người cao tuổi hoặc thành viên gia đình bị bệnh"}, {"term_ko": "사회적 관계망", "term_vi": "Mạng lưới xã hội", "def_ko": "사람들 간의 관계와 연결망", "def_vi": "Mối quan hệ và kết nối giữa mọi người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (751, '3', '다음 중 퇴소 단계에서 노인에게 보장되어야할 권리로 옳은 것은?', '["노인의 퇴소 결정을 번복하고자 회유한다.", "퇴소가 불가피한 경우 그 사유를 통보하지 않는다.", "보호자의 방임, 종사자와의 불화 시 퇴소를 권유한다.", "노인의 의사에 반하는 전원 또는 퇴소 조치를 한다.", "퇴소 이후에도 지역사회 내 서비스를 연계하여 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "노인의 퇴소 결정을 번복하고자 회유하는 것은 노인의 권리를 침해하는 행동이다.", "2": "퇴소가 불가피한 경우 그 사유를 통보하지 않는 것은 투명한 소통을 하지 않는 것이므로 옳지 않다.", "3": "보호자의 방임, 종사자와의 불화 시 퇴소를 권유하는 것은 노인의 자율성을 인정하지 않는 내용이다.", "4": "노인의 의사에 반하는 전원 또는 퇴소 조치를 하는 것은 절대적으로 금지되어 있는 행위이다.\n[정답]", "5": "퇴소 이후에도 지역사회 내 서비스를 연계하여 제공하는 것은 노인의 권리를 보장하는 바람직한 행동이다."}'::jsonb, '[{"term_ko": "퇴소", "term_vi": "Xuất viện", "def_ko": "병원이나 요양시설에서 나가는 것", "def_vi": "Ra khỏi bệnh viện hoặc cơ sở chăm sóc"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "안전하게 지켜주는 것", "def_vi": "Đảm bảo an toàn"}, {"term_ko": "의사", "term_vi": "Ý chí", "def_ko": "원하는 것, 뜻", "def_vi": "Mong muốn, ý kiến"}, {"term_ko": "전원", "term_vi": "Chuyển viện", "def_ko": "다른 곳으로 옮기는 것", "def_vi": "Chuyển đến nơi khác"}, {"term_ko": "지역사회", "term_vi": "Cộng đồng", "def_ko": "살고 있는 지역의 주민", "def_vi": "Cư dân của khu vực sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (750, '3', '다음 사례에서 시설 생활노인의 권리 침해에 해당하는 것은?(박씨 할머니는 정기적으로 병원진료를 받아왔다.) 요양보호사: 어르신 오늘 진료를 늦게까지 했나 봐요? 식사 시간이 지났으니 그냥 찬밥을 드셔야 겠네요. 박씨 할머니: 밥도 차가운데, 국이라도 따뜻하게 데워주지...', '["존엄한 존재로 대우받을 권리", "안전한 생활환경을 제공받을 권리", "신체구속을 받지 않을 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 4, NULL, NULL, '{"1": "어르신의 존재를 존중받아야 한다는 권리로, 이 경우 침해되지 않음.", "2": "안전한 환경에서 생활해야 한다는 권리로, 이 경우 침해되지 않음.", "3": "신체적 구속이 없어야 한다는 권리로, 이 경우 침해되지 않음.\n[정답]", "4": "자신의 의견을 표현하고 이를 해결할 것을 요구할 수 있어야 하나, 이를 제대로 존중받지 못한 상황임.", "5": "차별 또는 학대를 받지 않아야 할 권리로, 이 경우 명확히 침해된 상황은 아님."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (749, '3', '다음에서 설명하는 시설 생활노인의 권리보호를 위한 윤리강령은?• 보안장치가 마련된 사물함을 개인에게 제공한다.• 개인의 금전 및 물품을 타인에게 양도, 처분해서는 안 된다.', '["신체구속을 받지 않을 권리", "충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "개인의 재산과 소유물을 스스로 관리할 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, NULL, NULL, '{"1": "신체적 자유침해를 막기 위한 권리로, 해당 문제와는 관련이 없습니다.", "2": "충분한 정보에 대한 권리는 중요한 사항이나 이에 대한 직접적인 내용은 포함되어 있지 않습니다.", "3": "사생활의 보호와 비밀 보장은 기본적인 윤리적 권리지만, 문제의 핵심은 개인의 재산 관리에 대한 것입니다.\n[정답]", "4": "개인의 재산과 소유물을 스스로 관리할 권리는 문제에서 언급된 내용과 일치합니다.", "5": "개인적 견해를 표현하는 권리는 중요하나, 문제의 맥락과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "cơ sở(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (748, '3', '다음 내용에 해당하는 시설 생활노인의 권리보호를 위한 윤리강령은?• 시설 내 자발적 모임이나 의사소통에 제재를 가하지 않는다.• 노인의 면회, 외출, 외박을 최대한 보장한다.• 노인의 정치적 이념과 종교적 신념을 인정한다.', '["존엄한 조냊로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "질 높은 생활서비스를 받을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "시설 내, 외부 활동 및 사회적 관계에 참여할 권리"]'::jsonb, 5, NULL, NULL, '{"1": "존엄한 대우를 받을 권리는 중요한 요소이나 이번 문제의 내용과는 직접적인 연관이 없습니다.", "2": "사생활과 비밀보장에 대한 권리도 중요하나, 주어진 내용에 명시된 사항과는 관련성이 부족합니다.", "3": "질 높은 생활서비스를 받을 권리는 시설 노인의 중요한 권리 중 하나지만, 직접적으로 문제의 내용과 연결되지 않습니다.", "4": "안락하고 안전한 생활환경을 제공받을 권리는 노인이 요구하는 기본적인 권리이나, 이번 문제의 구체적인 내용과 상관없습니다.\n[정답]", "5": "시설 내, 외부 활동 및 사회적 관계에 참여할 권리는 주어진 내용과 가장 밀접한 관련이 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền (Tiếng Việt)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (747, '3', '다음 사례에서 해당하는 시설 생활노인의 권리보호를 위한 윤리강령은?이씨 할머니는 머리를 만지면서 "아무리 나이를 먹었고 시설에서 남의 도움으로 생활하고 있다지만 저 사람한테 파마를 하면 머리카락이 많이 상해. 약이 안 좋은가봐. 못돼 먹은 봉사자야."라며 화를 내신다.', '["차별 및 노인학대를 받지 않을 권리", "질 높은 생활서비스를 받을 권리", "사생활과 비밀 보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 2, NULL, NULL, '{"1": "차별 및 노인학대를 받지 않을 권리: 맞지만, 이 사례의 핵심은 서비스 질에 대한 표현입니다.\n[정답]", "2": "질 높은 생활서비스를 받을 권리: 이씨 할머니의 불만은 제공받는 서비스의 질에 관한 것으로, 이는 권리 보호와 관련이 깊습니다.", "3": "사생활과 비밀 보장에 대한 권리: 관련이 없으며, 이 사례와는 거리가 있습니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리: 개인의 불만이 표현되었지만, 여기서는 서비스 질이 주제입니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리: 환경은 언급되었지만, 핵심은 생활서비스의 질입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (746, '3', '다음 설명에서 시설 생활노인에게 보장되는 권리로 옳은 것은?•대상자의 선호와 건강 상태에 따라 개별화된 식단을 제공한다.•잔존능력을 유지하고 기력 향상을 위한 재활 프로그램을 제공한다.•요양보호사의 능력 개발을 위한 직무훈련을 실시한다.', '["질 높은 생활서비스 및 보건의료서비스를 받을 권리", "존엄한 존재로 대우받을 권리", "사생활과 비밀 보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 1, NULL, NULL, '{"1": "질 높은 생활서비스 및 보건의료서비스를 받을 권리는 시설 생활노인에게 보장된 기본적인 권리입니다.\n[정답]", "2": "존엄한 존재로 대우받을 권리는 존엄성을 강조하는 권리이나, 이번 문제에서 요구하는 구체적인 설명과 맞지 않습니다.", "3": "사생활과 비밀 보장에 대한 권리는 중요한 권리지만, 개별화된 서비스에 대한 직접적인 내용과는 다릅니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리는 중요하나, 이번 질문의 범위와는 약간 차이가 있습니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리는 필요한 권리이나, 문제의 질문과는 다소 다른 맥락입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (745, '3', '다음 사례에서 요양원이 위반한 시설 생활노인의 권리보호를 위한 윤리강령은?', '["개별화된 서비스를 제공받고 선택할 수 있는 권리", "존엄한 존재로 대우받을 권리", "신체구속을 받지 않을 권리", "사생활 및 비밀보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 3, NULL, NULL, '{"1": "개별화된 서비스의 제공은 노인의 선택권을 존중하는 권리입니다.\n[정답]", "3": "신체구속을 받지 않을 권리는 노인의 기본적인 자유와 관련된 중요한 윤리적 사항입니다.", "2": "존엄한 존재로 대우받을 권리는 노인의 인격을 존중하는 것을 의미합니다.", "4": "사생활 및 비밀보장에 대한 권리는 프라이버시와 관련된 것입니다.", "5": "차별 및 노인학대를 받지 않을 권리는 노인의 인권 보호와 관련 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (744, '3', '다음 사례에서 시설대상자가 보장받아야 할 기본 권리는?"저 노인네는 자식들이 자주 와서 직원들한테 선물도 하고 그래서 그런지 말 한마디를 해도 고분고분하게 해. 똑같이 음식을 흘려도 나한테만 더 화를 내서 기분이 좋지 않아."', '["신체구속을 받지 않을 권리", "질 높은 생활서비스를 받을 권리", "충분한 정보를 제공받을 권리", "사생활과 비밀 보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 5, NULL, NULL, '{"1": "신체구속을 받을 권리는 시설이 아니라 개인의 자유를 보호하는 개념입니다.\n[정답]", "5": "차별 및 노인학대를 받지 않을 권리는 기본적인 인권으로, 사례의 상황에서 가장 중요한 권리입니다.", "2": "질 높은 생활서비스를 받을 권리는 기본 생활에 관한 권리의를 포함하지만, 본 사례와는 먼 내용입니다.", "3": "충분한 정보를 제공받을 권리는 정보에 대한 접근을 의미하나, 본 사례에서 주된 이슈는 차별입니다.", "4": "사생활과 비밀 보장에 대한 권리는 중요하지만, 사례의 본질적인 문제는 차별과 노인학대입니다."}'::jsonb, '[{"term_ko": "시설대상자", "term_vi": "Người cao tuổi trong cơ sở", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người sống trong cơ sở"}, {"term_ko": "차별", "term_vi": "Phân biệt", "def_ko": "특정 집단이나 개인이 불합리하게 대우받는 것", "def_vi": "Việc được đối xử không công bằng với một nhóm hoặc cá nhân"}, {"term_ko": "노인학대", "term_vi": "Lạm dụng tuổi già", "def_ko": "노인에 대한 신체적, 정신적 학대", "def_vi": "Bạo lực thể chất hoặc tâm lý đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (743, '3', '다음 설명에 해당하는 시설 생활노인 권리보호를 위한 윤리강령은?노인의 권리가 침해될 우려가 있거나, 침해받은 경우 이의 회복과 구제를 위한 적극적 조치를 강구해야 한다.', '["사생활과 비밀 보장에 대한 권리", "질 높은 생활서비스를 받을 권리", "존엄한 존재로 대우받을 권리", "신체구속을 받지 않을 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 3, NULL, NULL, '{"1": "사생활과 비밀 보장에 대한 권리는 노인의 개인 정보와 사생활이 보호되어야 함을 의미하지만, 질문의 주안점과는 거리가 있음.\n[정답]", "2": "존엄한 존재로 대우받을 권리는 노인이 인격적으로 존중받아야 함을 강조하며, 직접적으로 권리 보호의 필요성을 나타내는 표현이다.", "3": "질 높은 생활서비스를 받을 권리는 노인의 생활 수준을 보장받는 것과 관련이 있지만 직접적인 윤리강령을 설명하지는 않음.", "4": "신체구속을 받지 않을 권리는 노인의 신체적 자유를 강조하지만, 질문의 내용과는 연결되지 않음.", "5": "개인적 견해를 표현하고 해결을 요구할 권리는 중요한 권리이지만, 윤리강령의 주제와는 잘 어울리지 않는다."}'::jsonb, '[{"term_ko": "윤리강령", "term_vi": "Quy tắc đạo đức", "def_ko": "도덕적 원칙을 규정한 규칙", "def_vi": "quy tắc quy định nguyên tắc đạo đức"}, {"term_ko": "사생활", "term_vi": "Đời sống riêng tư", "def_ko": "개인의 비밀", "def_vi": "bí mật cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (742, '3', '노인이나 가족이 건강상태와 치료, 돌봄, 제반 서비스에 관한 정보와 기록을 요구할 때 허용해야 하며, 타인에게 정보를 제공해서는 안된다.''고 규정한 시설 생활노인의 윤리강령은?', '["존엄한 존재로 대우받을 권리", "사생활과 비밀 보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 2, NULL, NULL, '{"1": "존엄한 존재로 대우받을 권리는 노인의 가치와 존엄성을 강조합니다.\n[정답]", "2": "사생활과 비밀 보장에 대한 권리는 정보 보호의 중요성을 명확히 합니다.", "3": "개별화된 서비스를 제공받고 선택할 수 있는 권리는 개인 맞춤형 서비스를 의미합니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리는 의견 표출의 자유를 포함합니다.", "5": "차별 및 노인학대를 받지 않을 권리는 기본적인 인권 보장을 나타냅니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "늙은 사람", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (741, '3', '다음은 시설 생활노인의 어떤 권리를 위반한 내용인가?나씨 할머니는 외부에서 시설 방문을 왔다면서 자기들 맘대로 사진을 찍거나 방에 불쑥불쑥 들어와 구경하고 나가는 것을 보면 매우 불쾌하다고 하신다.', '["질 높은 생활서비스를 받을 권리", "안전한 생활을 제공받을 권리", "신체구속을 받지 않을 권리", "사생활과 비밀보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, NULL, NULL, '{"1": "질 높은 생활서비스를 받을 권리는 노인이 기본적으로 누려야 할 권리이지만, 이 문제에서는 해당되지 않습니다.", "2": "안전한 생활을 제공받을 권리는 중요하지만, 이 경우와 직접적인 연관이 없습니다.", "3": "신체구속을 받지 않을 권리는 타인의 간섭 여부와는 관련이 적습니다.\n[정답]", "4": "사생활과 비밀보장에 대한 권리는 해당 노인이 외부인의 불쾌감을 느끼는 이유와 직접적인 관련이 있습니다.", "5": "개인적 견해를 표현하고 해결을 요구할 권리는 노인이 의견을 표현하는 것을 다루지만, 사례의 핵심은 사생활입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (740, '3', '다음과 같은 사례에서 요양보호사의 대처방법으로 옳은 것은?송씨 할아버지는 평생을 온돌에서 생활하셨는데, 시설에서 무조건 침대를 쓰라고 한다면서, 떨어질까 겁도 나고 불편해서 잠이 안 온다고 투덜거리신다.', '["며칠 지나면 다른 분들처럼 곧 적응되실 거예요.", "참으셔야죠. 자꾸 그러시면 저희가 돌보기 힘들어요.", "저도 어쩔 수가 없네요. 다른 시설을 알아봐 드릴까요?", "불편하시죠? 온돌방이 있는지 알아볼게요.", "어르신, 여기서는 무조건 침대생활을 해야 돼요."]'::jsonb, 4, NULL, NULL, '{"1": "며칠 지나면 적응된다며 환자의 불안과 불편을 무시하는 접근입니다.\n[정답]", "4": "환자의 불편함을 인정하고 해결책을 모색하는 긍정적인 접근입니다.", "3": "다른 시설을 알아보겠다는 말은 현 상황을 부정적으로 인식하게 만듭니다.", "5": "무조건 침대생활을 해야 한다는 강압적 태도는 환자의 감정을 상해할 수 있습니다.", "2": "참으셔야 한다고 말하는 것은 환자의 기분을 고려하지 않은 접근입니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Cách giải quyết", "def_ko": "처리 방법(한국어)", "def_vi": "Phương pháp xử lý"}, {"term_ko": "불편", "term_vi": "Khó chịu", "def_ko": "불편함(한국어)", "def_vi": "Sự khó chịu"}, {"term_ko": "온돌", "term_vi": "Sàn sưởi", "def_ko": "온돌 시스템(한국어)", "def_vi": "Hệ thống sưởi sàn"}, {"term_ko": "적응", "term_vi": "Thích nghi", "def_ko": "적응하다(한국어)", "def_vi": "Thích nghi"}, {"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "어르신", "term_vi": "Người lớn tuổi", "def_ko": "노인(한국어)", "def_vi": "Người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (739, '3', '다음 내용에서 어르신이 요구할 수 있는 권리는?(거울을 보며 머리를 만지면서) "아무리 늙고 병들었다고 해도 머리를 이렇게 남자같이 짧게 깎아 놨어!"라고 말하며 요양보호사에게 화를 내신다.', '["신체구속을 받지 않을 권리", "충분한 정보를 제공받을 권리", "사생활과 비밀 보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 4, NULL, NULL, '{"1": "신체구속을 받지 않을 권리: 어르신이 원하지 않는 신체적인 제약을 받지 않을 권리입니다.", "2": "충분한 정보를 제공받을 권리: 필요한 정보를받아 자신의 상황에 대해 이해할 수 있는 권리입니다.", "3": "사생활과 비밀 보장에 대한 권리: 개인의 사생활과 비밀이 보장되어야 함을 나타냅니다.\n[정답]", "4": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 어르신이 원하는 대로 자신의 머리 스타일을 선택할 수 있는 권리입니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리: 안전하고 편안한 환경에서 생활할 권리를 의미합니다."}'::jsonb, '[{"term_ko": "어르신", "term_vi": "Người cao tuổi", "def_ko": "노인", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (738, '2', '다음 중 요양보호사의 역할이 바르게 연결된 것은?', '["옹호자 - 숙련된 기술로 대상자의 불편함을 경감하기 위해 돕는다.", "관찰자 - 대상자가 능력을 최대한 발휘하여 스스로 할 수 있도록 격려한다.", "동기 유발자 - 호흡곤란, 피부 발진이 생기는지 살펴본다.", "정보 전달자 - 대상자의 신체, 심리적 상태변화를 의료진에게 전달한다.", "말벗과 상담자 - 소외되고 차별받는 대상자의 입장에서 편들어 주고 지켜준다."]'::jsonb, 4, NULL, NULL, '{"1": "옹호자는 대상자의 불편함을 경감하기 위해 도와주는 역할이 아닙니다. 이는 ''말벗과 상담자''의 역할에 가깝습니다.\n[정답]", "4": "정보 전달자는 대상자의 신체 및 심리적 상태 변화를 의료진에게 전달하는 중요한 역할을 수행합니다.", "3": "동기 유발자는 건강 상태를 관찰하는 역할이 아니며, 주로 대상자의 의욕을 높이는 역할입니다.", "2": "관찰자는 주로 대상자가 능력을 최대한 발휘하도록 격려하는 역할이 아닙니다. 이는 ''동기 유발자''의 역할에 해당합니다.", "5": "말벗과 상담자는 소외된 대상을 편들어 주기보다 의사소통과 정서적 지지를 제공합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "맡은 기능이나 일", "def_vi": "Chức năng đảm nhận"}, {"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "권리를 지키고 보호하는 사람", "def_vi": "Người bảo vệ và bảo vệ quyền lợi"}, {"term_ko": "정보 전달자", "term_vi": "Người truyền thông", "def_ko": "정보를 전달하는 사람", "def_vi": "Người chuyển tải thông tin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (737, '2', '소외되고 차별 받는 대상자를 위해 편들어 주고 지켜주는 요양보호사의 역할은?', '["옹호자", "관찰자", "숙련된 수발자", "동기 유발자", "정보 전달자"]'::jsonb, 1, NULL, NULL, '{"1": "옹호자: 소외된 대상자를 위해 그들의 권리를 지키고 지지하는 역할을 하므로 정답입니다.\n[정답]", "2": "관찰자: 단순히 관찰하는 사람으로서의 역할을 나타내며 옹호와는 거리가 멉니다.", "3": "숙련된 수발자: 기술적 지원이 주요 역할이지 대상자를 지키는 것은 아닙니다.", "4": "동기 유발자: 격려하거나 동기를 부여하는 역할에 해당하지만 보호의 개념은 포함되지 않습니다.", "5": "정보 전달자: 정보를 제공하는 역할이지 직접적인 보호와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "권리를 지키고 지원하는 사람", "def_vi": "Người bảo vệ quyền lợi và hỗ trợ"}, {"term_ko": "관찰자", "term_vi": "Người quan sát", "def_ko": "단순히 지켜보는 사람", "def_vi": "Người chỉ theo dõi"}, {"term_ko": "숙련된 수발자", "term_vi": "Người chăm sóc có tay nghề", "def_ko": "기술적으로 지원하는 사람", "def_vi": "Người cung cấp sự hỗ trợ kỹ thuật"}, {"term_ko": "동기 유발자", "term_vi": "Người khuyến khích động lực", "def_ko": "격려하고 동기를 주는 사람", "def_vi": "Người tạo động lực"}, {"term_ko": "정보 전달자", "term_vi": "Người cung cấp thông tin", "def_ko": "정보를 제공하는 사람", "def_vi": "Người cung cấp thông tin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (736, '2', '다음 사례에서 요양보호사의 수행역할로 옳은 것은?편마비 환자가 잔존기능을 최대한 발휘할 수 있도록 요양보호사가 지지를 하였더니, 환자 스스로 식사와 옷 입기를 할 수 있게 되었다.', '["관찰자", "옹호자", "중재자", "동기 유발자", "정보 전달자"]'::jsonb, 4, NULL, NULL, '{"1": "관찰자: 요양보호사로서 환자의 상태를 관찰하는 역할을 하며, 직접적인 지원은 포함되지 않습니다.\n[정답]", "2": "옹호자: 환자의 권리와 요구를 지지하고 보호하는 역할이지만, 사례에서는 동기 부여가 주된 내용입니다.", "3": "중재자: 문제 해결을 위한 조정자 역할이나 이번 사례와는 직접적인 관련이 없습니다.", "4": "동기 유발자: 환자가 스스로 능동적으로 활동하도록 동기를 부여하는 역할로, 사례와 잘 맞습니다.", "5": "정보 전달자: 필요한 정보를 제공하는 역할로, 이번 사례에서는 주로 동기 부여에 중점을 두고 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "직접적인 돌봄을 제공하는 사람", "def_vi": "Người trực tiếp cung cấp sự chăm sóc"}, {"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 몸의 기능이 저하된 상태", "def_vi": "Tình trạng giảm chức năng của một bên cơ thể"}, {"term_ko": "잔존기능", "term_vi": "Chức năng còn lại", "def_ko": "남아있는 기능", "def_vi": "Chức năng còn tồn tại"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "지원, 도움", "def_vi": "Sự hỗ trợ"}, {"term_ko": "동기 유발자", "term_vi": "Người khơi dậy động lực", "def_ko": "스스로 행동하도록 하는 사람", "def_vi": "Người khuyến khích tự hành động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (735, '2', '다음 중 요양보호사의 역할로 옳은 것은?신체활동지원서비스나 일상생활지우너서비스 등을 제공하는 것에 그치지 않고 대상자가 능력을 최대한 발휘하도록 지지한다.', '["정보 전달자", "관찰자", "동기 유발자", "옹호자", "말벗과 상담자"]'::jsonb, 3, NULL, NULL, '{"1": "정보 전달자는 정보와 지식을 제공하는 역할을 합니다.\n[정답]", "3": "동기 유발자는 대상자가 스스로의 능력을 최대한 발휘하도록 격려하고 지지하는 역할을 합니다.", "2": "관찰자는 대상자의 상태를 주의 깊게 살피고 기록하는 역할입니다.", "4": "옹호자는 대상자의 권리와 이익을 보호하기 위해 노력하는 역할입니다.", "5": "말벗과 상담자는 정서적 지지를 제공하는 역할을 합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 포함한 환자를 보살피는 전문 직업", "def_vi": "Nghề chăm sóc bệnh nhân, bao gồm cả người già"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "어떤 일을 수행하는 직무나 기능", "def_vi": "Nhiệm vụ hoặc chức năng thực hiện một công việc"}, {"term_ko": "동기", "term_vi": "Động lực", "def_ko": "어떤 일을 하도록 이끄는 내적 요인", "def_vi": "Yếu tố bên trong thúc đẩy một hoạt động"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "도움을 주는 것, 또는 지지하는 행동", "def_vi": "Hành động giúp đỡ ai đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (734, '2', '대상자와 관게를 형성하고 서비스를 제공하여 대상자의 신체적, 정신적, 심리적 안위를 도모하는 요양보호사의 역할은?', '["정보 전달자", "관찰자", "숙련된 수발자", "말벗과 상담자", "동기 유발자"]'::jsonb, 4, NULL, NULL, '{"1": "정보 전달자는 주로 정보를 제공하는 역할을 합니다.\n[정답]", "4": "말벗과 상담자는 대상자와 관계를 형성하며 그들의 심리적 안위를 도모하는 데 중점을 둡니다.", "2": "관찰자는 대상자의 상태를 관찰하고 기록하는 역할을 합니다.", "3": "숙련된 수발자는 신체적 도움이 필요한 경우 직접적인 돌봄을 제공하는 역할을 합니다.", "5": "동기 유발자는 대상자의 동기를 높이려는 역할을 수행합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người nhận dịch vụ"}, {"term_ko": "관계", "term_vi": "Mối quan hệ", "def_ko": "상호작용, 소통", "def_vi": "Tương tác, giao tiếp"}, {"term_ko": "안위", "term_vi": "An nguy", "def_ko": "안전과 행복", "def_vi": "An toàn và hạnh phúc"}, {"term_ko": "상담자", "term_vi": "Người tư vấn", "def_ko": "조언을 주는 사람", "def_vi": "Người cho lời khuyên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (733, '2', '맥박, 호흡, 체온, 혈압 등의 건강상태와 심리적인 변화까지 관찰하여 증상을 완화하고, 합병증을 예방하는 요양보호사의 역할은?', '["정보 전달자 역할", "관찰자 역할", "숙련된 수발자 역할", "동기 유발자 역할", "옹호자 역할"]'::jsonb, 2, NULL, NULL, '{"1": "정보 전달자 역할: 정보를 전달하는 역할이지만, 관찰의 중요성을 포함하지 않습니다.\n[정답]", "2": "관찰자 역할: 건강상태와 심리적인 변화를 관찰하여 증상을 완화하고 합병증을 예방하는 역할입니다.", "3": "숙련된 수발자 역할: 수발의 숙련도를 강조하지만 관찰 역할은 포함되어 있지 않습니다.", "4": "동기 유발자 역할: 환자의 동기를 유발하려는 역할은 관찰과는 관련이 없습니다.", "5": "옹호자 역할: 환자의 권리를 옹호하는 역할이나 관찰 기능은 아닙니다."}'::jsonb, '[{"term_ko": "맥박", "term_vi": "Mạch", "def_ko": "맥박(한국어)", "def_vi": "Mạch đập(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (732, '2', '다음 내용에 해당하는 요양보호사의 역할로 옳은 것은?대상자의 신체, 심리에 관한 정보를 가족, 시설장, 의료진에게 전달하며 필요 시 지시사항을 대상자와 가족에게 전달한다.', '["정보 전달자 역할", "관찰자 역할", "숙련된 수발자 역할", "말벗과 상담자 역할", "동기 유발자 역할"]'::jsonb, 1, NULL, NULL, '{"1": "정보 전달자 역할: 대상자의 신체, 심리에 관한 정보를 전달하는 역할을 정확히 설명합니다.\n[정답]", "2": "관찰자 역할: 대상자의 상태를 관찰하는 역할이지만, 정보 전달과는 직접 관련이 없습니다.", "3": "숙련된 수발자 역할: 신체적 돌봄을 강조하는 역할로 정보 전달과는 관련이 없습니다.", "4": "말벗과 상담자 역할: 정서적 지지를 제공하지만 정보 전달과는 다릅니다.", "5": "동기 유발자 역할: 대상자를 격려하고 동기를 부여하지만 정보 전달에는 해당하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (731, '2', '다음 중 요양보호사의 역할로 옳은 것은?숙련된 요양보호서비스에 대한 지식과 기술로 필요한서비스를 지원하여 대상자를 도와준다.', '["정보 전달자", "관찰자", "숙련된 수발자", "상담자", "동기 유발자"]'::jsonb, 3, NULL, NULL, '{"1": "정보 전달자는 정보를 제공하는 역할이나, 요양보호사의 주 역할이 아니다.\n[정답]", "3": "숙련된 수발자는 요양보호사의 핵심 역할로, 숙련된 기술로 환자를 지원하는 것이 중요하다.", "2": "관찰자는 환자의 상태를 관찰하는 역할이지만, 수발자의 역할이 더 강조된다.", "4": "상담자는 주로 심리적 지원을 제공하는 역할이지만, 이는 요양보호사의 보조적인 역할이다.", "5": "동기 유발자는 환자의 동기를 부여하는 역할이나, 요양보호사의 주요 책임은 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (730, '2', '요양보호사 자격 취소 사유에 해당되지 않는 것은?', '["자격증을 대여, 양도 또는 위조, 변조한 경우", "노인에 대한 금지행위를 위반하여 처벌받은 경우", "영리를 목적으로 요양서비스를 알선, 유인한 경우", "거짓이나 부정한 방법으로 자격증을 취득한 경우", "대상자의 욕구에 맞는 장기요양서비스를 제공한 경우"]'::jsonb, 5, NULL, NULL, '{"1": "자격증을 대여, 양도 또는 위조, 변조한 경우는 자격 취소 사유입니다.\n[정답]", "5": "대상자의 욕구에 맞는 장기요양서비스를 제공한 경우는 자격 취소 사유에 해당하지 않습니다.", "2": "노인에 대한 금지행위를 위반하여 처벌받은 경우는 자격 취소 사유입니다.", "3": "영리를 목적으로 요양서비스를 알선, 유인한 경우는 자격 취소 사유입니다.", "4": "거짓이나 부정한 방법으로 자격증을 취득한 경우는 자격 취소 사유입니다."}'::jsonb, '[{"term_ko": "자격증", "term_vi": "Chứng chỉ", "def_ko": "증명서(한국어)", "def_vi": "Giấy chứng nhận"}, {"term_ko": "대여", "term_vi": "Cho thuê", "def_ko": "빌려주는 것(한국어)", "def_vi": "Cho mượn"}, {"term_ko": "양도", "term_vi": "Chuyển nhượng", "def_ko": "양도하는 것(한국어)", "def_vi": "Chuyển nhượng"}, {"term_ko": "위조", "term_vi": "Làm giả", "def_ko": "가짜로 만드는 것(한국어)", "def_vi": "Làm giả"}, {"term_ko": "변조", "term_vi": "Sửa đổi", "def_ko": "수정하는 것(한국어)", "def_vi": "Sửa đổi"}, {"term_ko": "금지행위", "term_vi": "Hành vi cấm", "def_ko": "금지된 행동(한국어)", "def_vi": "Hành vi bị cấm"}, {"term_ko": "처벌", "term_vi": "Xử phạt", "def_ko": "벌을 받는 것(한국어)", "def_vi": "Bị xử phạt"}, {"term_ko": "영리", "term_vi": "Lợi nhuận", "def_ko": "이익을 추구하는 것(한국어)", "def_vi": "Tìm kiếm lợi nhuận"}, {"term_ko": "알선", "term_vi": "Môi giới", "def_ko": "중개하는 것(한국어)", "def_vi": "Đảm bảo"}, {"term_ko": "유인", "term_vi": "Dụ dỗ", "def_ko": "끌어모으는 것(한국어)", "def_vi": "Thu hút"}, {"term_ko": "거짓", "term_vi": "Giả", "def_ko": "사실이 아닌 것(한국어)", "def_vi": "Giả"}, {"term_ko": "부정한", "term_vi": "Bất hợp pháp", "def_ko": "불법적인(한국어)", "def_vi": "Bất hợp pháp"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요한 것(한국어)", "def_vi": "Nhu cầu"}, {"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "긴 기간의 관리 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (729, '2', '노인장기요양보험법 상 요양보호사가 1년 동안 장기요양급여를 제공 할 수 없는 경우는?', '["업무 수행능력이 저하되었다.", "업무상의 어려움을 시설장에게 전달하였다.", "동료와 경험을 공유하며 서로 지지해 주었다.", "대상자의 요구로 시간을 초과하여 서비스를 제공하였다.", "부정한 방법으로 장기요양급여비용을 청구하는 행위에 가담하였다."]'::jsonb, 5, NULL, NULL, '{"1": "업무 수행능력이 저하되었다. - 요양보호사의 능력 저하가 서비스 제공 여부에 영향을 미칠 수 있지만 장기요양급여 중단 사유는 아님.\n[정답]", "5": "부정한 방법으로 장기요양급여비용을 청구하는 행위에 가담하였다. - 이는 법적인 문제로, 장기요양급여 제공을 받을 수 없게 되는 명백한 사유임.", "2": "업무상의 어려움을 시설장에게 전달하였다. - 어려움이 있을 때는 공유하는 것이 바람직하며, 문제를 해결할 수 있는 방향으로 나아가는 행동임.", "3": "동료와 경험을 공유하며 서로 지지해 주었다. - 동료 간의 지지와 협력은 서비스 품질을 높이는 긍정적인 행동임.", "4": "대상자의 요구로 시간을 초과하여 서비스를 제공하였다. - 대상자의 요구에 따른 추가 서비스 제공은 긍정적인 행동이며, 서비스 제공에 문제가 되지 않음."}'::jsonb, '[{"term_ko": "장기요양보험법", "term_vi": "Luật bảo hiểm chăm sóc dài hạn", "def_ko": "장기요양보험에 관한 법률", "def_vi": "Luật liên quan đến bảo hiểm chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (728, '2', '다음 중 요양보호사의 금지행위에 해당하는 것으로 옳은 것은?가. 노인학대 신고 나. 수급자 유인 알선행위 다. 부당수급 관련 행위 라. 개인정보 비밀유지 마. 급여제공자료 거짓 작성 바. 본인부담금 면제 및 감경', '["가,나,다,라", "가,나,다,마", "나,다,마,바", "나,다,라,마", "나,다,라,바"]'::jsonb, 3, NULL, NULL, '{"1": "노인학대 신고는 법적 의무로, 금지행위가 아니다.\n[정답]", "2": "수급자 유인 알선행위는 금지행위에 해당한다.", "3": "부당수급 관련 행위는 금지행위에 해당한다.", "4": "개인정보 비밀유지는 요양보호사로서 지켜야 할 의무이다.", "5": "급여제공자료 거짓 작성은 금지행위에 해당한다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인과 장애인을 돌봐주는 전문직", "def_vi": "Nghề chuyên chăm sóc người cao tuổi và người khuyết tật"}, {"term_ko": "금지행위", "term_vi": "Hành vi bị cấm", "def_ko": "법적으로 금지된 행동", "def_vi": "Hành động bị cấm theo luật pháp"}, {"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자에 대한 폭력이나 학대", "def_vi": "Bạo lực hoặc ngược đãi đối với người cao tuổi"}, {"term_ko": "부당수급", "term_vi": "Nhận phúc lợi không chính đáng", "def_ko": "불법적인 방법으로 이익을 취하는 것", "def_vi": "Có lợi ích theo cách bất hợp pháp"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인의 사생활에 관한 정보", "def_vi": "Thông tin liên quan đến đời sống riêng tư của cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (727, '2', '시설에서 응급상황 발생하였을 때 대처방법으로 옳은 것은?', '["대상자를 가급적 빨리 옮긴다.", "나이가 많은 대상자부터 처치한다.", "긴급을 요하는 대상자 순으로 처치한다.", "대상자를 발견한 순서대로 처치한다.", "대상자에게 손상을 입힌 화학약품은 즉시 버린다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자를 가급적 빨리 옮기는 것은 위험할 수 있습니다. 응급처치는 상황에 따라 다르게 진행되어야 합니다.\n[정답]", "3": "긴급을 요하는 대상자 순으로 처치하는 것이 최선의 방법입니다.", "2": "나이가 많은 대상자부터 처치하는 것은 옳지 않은 판단입니다.", "4": "대상자를 발견한 순서대로 처치하는 것은 비효율적입니다.", "5": "손상을 입힌 화학약품은 안전한 방법으로 처리해야 하며 즉시 버리는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "긴급한 상황(한국어)", "def_vi": "Tình huống gấp gáp(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (726, '2', '요양보호사의 요양업무 수행 내용으로 옳은 것은?', '["작업치료", "외상 처치", "관절운동범위 평가", "복지용구 이용도움", "유치도뇨관 삽입"]'::jsonb, 4, NULL, NULL, '{"1": "작업치료는 주로 치료사에 의해 수행됩니다.\n[정답]", "4": "복지용구 이용도움은 요양보호사의 중요한 업무입니다.", "2": "외상 처치는 기본적으로 전문의료진의 역할입니다.", "3": "관절운동범위 평가는 재활 전문직에 의한 평가입니다.", "5": "유치도뇨관 삽입은 전문적인 의료행위에 해당합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "요양업무", "term_vi": "Nhiệm vụ chăm sóc", "def_ko": "환자를 돌보는 업무", "def_vi": "Nhiệm vụ chăm sóc bệnh nhân"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "필요한 복지 장비", "def_vi": "Thiết bị cần thiết cho phúc lợi"}, {"term_ko": "작업치료", "term_vi": "Liệu pháp nghề nghiệp", "def_ko": "특정 작업을 통해 치료하는 방법", "def_vi": "Phương pháp điều trị thông qua công việc"}, {"term_ko": "외상 처치", "term_vi": "Xử lý tổn thương", "def_ko": "부상의 치료", "def_vi": "Việc điều trị cho các vết thương"}, {"term_ko": "관절운동범위", "term_vi": "Phạm vi chuyển động khớp", "def_ko": "관절의 운동 범위", "def_vi": "Phạm vi hoạt động của khớp"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하기 위한 관", "def_vi": "Ống dùng để thải nước tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (725, '2', '요양보호사가 제공할 수 있는 서비스로 옳은 것은?', '["드레싱", "도뇨처치", "투약 및 주사", "비위관 삽입", "관절구축 예방"]'::jsonb, 5, NULL, NULL, '{"1": "드레싱: 요양보호사가 수행할 수 없는 전문적인 간호행위입니다.\n[정답]", "5": "관절구축 예방: 요양보호사가 제공할 수 있는 서비스 중 하나로, 환자의 운동과 관절 유지를 도와줍니다.", "2": "도뇨처치: 의료인이 수행해야 하는 전문적인 처치입니다.", "3": "투약 및 주사: 요양보호사의 업무 범위를 넘어서는 행위입니다.", "4": "비위관 삽입: 전문적인 의료 기술이 필요한 행위로 요양보호사가 수행할 수 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "dịch vụ chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "dịch vụ chăm sóc mà người chăm sóc có thể cung cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (724, '2', '요양보호사는 모든 의료행위를 하지 않아야한다. 다음 중 의료행위에 속하는 것들을 고르시오.가.도뇨 나.흡인 다.관장 라.욕창관리 마.경구약 및 외용약투약', '["가.나.다.마", "가.다.마", "나.라.마", "나.다.라.마", "가.나.다.라"]'::jsonb, 5, NULL, NULL, '{"1": "도뇨와 흡인, 관장은 의료행위에 해당하지만, 욕창관리와 경구약 및 외용약투약은 비의료행위입니다.\n[정답]", "5": "도뇨, 흡인, 관장, 욕창관리 전부가 의료행위에 속합니다.", "2": "의료행위에 해당하는 도뇨, 관장을 포함하나, 욕창관리는 비의료행위입니다.", "3": "흡인을 포함하고 있으나, 도뇨와 관장은 의료행위입니다.", "4": "흡인, 관장, 욕창관리가 포함돼 의료행위에 해당합니다."}'::jsonb, '[{"term_ko": "의료행위", "term_vi": "Hành động y tế", "def_ko": "환자에 대한 진료와 치료를 수행하는 행위", "def_vi": "Hành động điều trị và chăm sóc bệnh nhân."}, {"term_ko": "도뇨", "term_vi": "Thông tiểu", "def_ko": "방광 내 소변을 비워내기 위한 의료행위", "def_vi": "Hành động y tế để làm rỗng bàng quang."}, {"term_ko": "흡인", "term_vi": "Hút", "def_ko": "기도에서 분비물을 제거하는 의료행위", "def_vi": "Hành động y tế để loại bỏ dịch trong đường hô hấp."}, {"term_ko": "관장", "term_vi": "Thụt", "def_ko": "배변을 유도하기 위한 의료행위", "def_vi": "Hành động y tế để kích thích đại tiện."}, {"term_ko": "욕창관리", "term_vi": "Chăm sóc loét", "def_ko": "욕창으로 인한 상처를 예방하고 관리하는 비의료행위", "def_vi": "Hành động không phải y tế để phòng ngừa và kiểm soát vết thương do loét."}, {"term_ko": "경구약", "term_vi": "Thuốc uống", "def_ko": "입으로 복용하는 약물", "def_vi": "Thuốc dùng qua đường miệng."}, {"term_ko": "외용약", "term_vi": "Thuốc bôi", "def_ko": "피부에 바르는 약물", "def_vi": "Thuốc dùng cho da."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (723, '2', '요양보호서비스 제공 시 요양보호사가 지켜야 할 원칙으로 옳은 것은?', '["서비스 제공 전 대상자의 성격, 습관 등 상태를 파악한다.", "대상자의 보호자에게도 서비스를 제공한다.", "대상자를 수동적인 존재로 간주한다.", "대상자의 미미한 상태변화는 기록을 생략한다.", "대상자의 상태가 달라지면 요양보호사가 서비스를 조정한다."]'::jsonb, 1, NULL, NULL, '{"1": "서비스 제공 전 대상자의 성격, 습관 등 상태를 파악한다. 이 원칙은 요양보호사가 대상자의 개인적 특성을 이해하여 적절한 서비스를 제공하기 위해 반드시 지켜야 하는 사항이다.\n[정답]", "2": "대상자의 보호자에게도 서비스를 제공한다. 보호자에게 서비스 제공은 원칙이 아니다. 대상자가 중심이 되어야 한다.", "3": "대상자를 수동적인 존재로 간주한다. 이는 옳지 않으며, 대상자는 적극적인 참여가 필요하다.", "4": "대상자의 미미한 상태변화는 기록을 생략한다. 모든 상태변화는 기록되어야 한다.", "5": "대상자의 상태가 달라지면 요양보호사가 서비스를 조정한다. 서비스 조정은 필요한 사항이지만 이 보기 자체가 서비스 제공 원칙이 아니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스", "def_vi": "Dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (722, '2', '요양보호사가 서비스 제공 시 지켜야 할 기본원칙으로 옳은 것은?', '["대상자의 잔존능력을 최대한 활용한다.", "치매 대상자는 보호자 동의 없이 서비스를 제공한다.", "서비스를 제공하기 전에 보호자의 특성을 확인한다.", "서비스 제공 중 응급상황이 발생하면 알아서 처치한다.", "대상자의 사생활에 대해 자유롭게 이야기한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 잔존능력을 최대한 활용하는 것은 요양보호사가 반드시 지켜야 할 기본 원칙이므로 올바른 진술입니다.\n[정답]", "2": "치매 대상자는 보호자 동의 없이 서비스를 제공하면 안 되므로 잘못된 진술입니다.", "3": "서비스 제공 전에 보호자의 특성을 확인하는 것은 중요하지만, 기본 원칙으로 명시되지 않았습니다.", "4": "서비스 제공 중 응급상황이 발생하면 보호자와 상의하여 적절히 대처해야 하므로 잘못된 진술입니다.", "5": "대상자의 사생활에 대해 자유롭게 이야기하는 것은 프라이버시를 존중하지 않는 행위로 잘못된 진술입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 보호하고 돌보는 직업", "def_vi": "Nghề bảo vệ và chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (721, '2', '요양보호서비스 제공의 기본원칙으로 옳은 것은?', '["요양보호사 중심으로 서비스를 제공한다.", "대상자의 상태를 관찰하면서 서비스를 제공한다.", "중요한 서비스는 설명 없이 제공한다.", "서비스를 변경할 때에는 요양보호사가 혼자서 결정한다.", "응급 상황 시 우선순위에 따라 의료 행위를 한다."]'::jsonb, 2, NULL, NULL, '{"1": "요양보호사는 대상자의 상태를 고려하여 서비스를 제공해야 하므로 요양보호사 중심으로 서비스를 제공하는 것은 옳지 않습니다.\n[정답]", "2": "대상자의 상태를 관찰하면서 서비스를 제공하는 것은 요양보호서비스의 기본 원칙 중 하나입니다.", "3": "중요한 서비스는 반드시 대상자에게 설명한 후 제공해야 합니다.", "4": "서비스 변경은 팀원 간의 협의 후 결정해야 하며, 요양보호사가 혼자서 결정하는 것은 올바르지 않습니다.", "5": "응급 상황에서도 절차에 따라 진행해야 하며, 의료 행위는 전문 인력에게 맡겨야 합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "서비스의 주체", "def_vi": "Người chủ trì dịch vụ"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 돌봄", "def_vi": "Chăm sóc được cung cấp"}, {"term_ko": "응급 상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "즉각적인 조치가 필요한 기급한 상황", "def_vi": "Tình huống cần hành động ngay lập tức"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "건강이나 처치 상황", "def_vi": "Tình hình sức khỏe hoặc chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (720, '2', '요양보호서비스 원칙에 대한 설명으로 옳은 것은?', '["대상자로부터 많지 않은 물질적 보상은 받아도 된다.", "치매 대상자에게 발생하는 돌발 상황은 가족들과 의논하여 처리한다.", "변비인 대상자가 관장을 요구하면 지체 없이 도움을 주어야한다.", "대상자의 가족과 의견이 상충될 때는 마찰을 피하고 요구를 들어 준다.", "대상자 외 가족의 세탁, 청소, 식사준비 등은 업무범위가 아니므로 해서는 안 된다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자로부터 전혀 물질적 보상을 받지 않는 것이 원칙입니다.\n[정답]", "5": "대상자 외 가족의 업무는 요양보호사의 범위가 아닙니다.", "2": "가족과 상의하여 처리하는 것이 아니라 요양보호사가 직접 책임지고 처리해야 합니다.", "3": "변비인 대상자에게는 관장을 하는 것이 적절하지 않을 수 있습니다.", "4": "가족과의 의견이 상충할 경우, 대상자의 복지를 우선적으로 고려해야 합니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄을 제공하는 서비스", "def_vi": "Dịch vụ cung cấp sự chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (719, '2', '권리와 책임에 따른 급여제공 시 ㅇ양보호사의 준수 사항으로 옳은 것은?', '["제공인력이 변경되면 급여제공을 보류한다.", "매년 건강검진을 받고 건강관리를 철저히 한다.", "사고예방을 위해 개인적인 판단을 우선시한다.", "급여제공내용과 상태변화를 월별로 기록한다.", "학대나 기관의 부당행위에는 개입하지 않는다."]'::jsonb, 2, NULL, NULL, '{"1": "제공인력이 변경되면 급여제공을 보류한다: 잘못된 내용입니다.\n[정답]", "2": "매년 건강검진을 받고 건강관리를 철저히 한다: 요양보호사는 정기적인 건강검진을 통해 자신의 건강을 관리해야 합니다.", "3": "사고예방을 위해 개인적인 판단을 우선시한다: 개인적인 판단이 아니라 전문가의 지침을 따라야 합니다.", "4": "급여제공내용과 상태변화를 월별로 기록한다: 기록은 중요하지만 월별 기록이 아닌 상황에 따라 필요할 때 기록해야 합니다.", "5": "학대나 기관의 부당행위에는 개입하지 않는다: 요양보호사는 그러한 상황에 개입하고 보고해야 합니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권한(한국어)", "def_vi": "quyền hạn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (718, '2', '급여제공 계획과 기준에 근거한 급여제공 시 요양보호사의 준수사항으로 옳은 것은?', '["상황에 따라 보호자에게 필요한 급여를 제공한다.", "응급 상황이 발생하면, 임의로 판단하여 처리한다.", "수급자의 부당한 요구는 대가를 받고 들어준다.", "급여제공내용과 방법은 동료 요양보호사의 경험을 따른다.", "기관의 운영규정, 근로계약 내용, 급여제공기준을 숙지한다."]'::jsonb, 5, NULL, NULL, '{"1": "상황에 따라 보호자에게 필요한 급여를 제공한다. (잘못된 내용입니다. 요양보호사는 정해진 기준에 따라 급여를 제공해야 합니다.)\n[정답]", "5": "기관의 운영규정, 근로계약 내용, 급여제공기준을 숙지한다. (정확한 내용으로, 요양보호사는 이러한 사항을 반드시 숙지해야 합니다.)", "3": "수급자의 부당한 요구는 대가를 받고 들어준다. (부당한 요구는 들어줄 수 없습니다.)", "4": "급여제공내용과 방법은 동료 요양보호사의 경험을 따른다. (개인의 경험에 의존하기보다는 기준에 따라야 합니다.)", "2": "응급 상황이 발생하면, 임의로 판단하여 처리한다. (임의로 판단하기보다는 정해진 절차에 따라야 합니다.)"}'::jsonb, '[{"term_ko": "급여제공", "term_vi": "Cung cấp dịch vụ", "def_ko": "제공하는 서비스", "def_vi": "Dịch vụ được cung cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (717, '2', '요양보호사가 준수해야 할 수급자 중심의 급여제공으로 옳은 것은?', '["수급자의 경제적 능력을 파악하여 급여낸용을 변경한다.", "제공할 급여내용을 수급자의 요구대로 임의로 계약한다.", "수급자의 상태에 따라 급여시간을 자유롭게 조절한다.", "수급자의 개별적인 욕구를 반영하여 급여를 제공한다.", "급여제공기록지를 사전에 작성하여 수급자에게 확인을 받는다."]'::jsonb, 4, NULL, NULL, '{"1": "수급자의 경제적 능력을 반영하여 급여내용은 변경될 수 있지만, 이는 수급자의 동의를 필요로 합니다.\n[정답]", "4": "수급자의 개별적인 욕구를 반영하여 급여를 제공하는 것이 핵심 원칙입니다.", "2": "제공할 급여내용은 수급자의 요구에 따라 임의로 계약할 수 없습니다.", "3": "수급자의 상태에 따라 급여시간은 조절하지만, 무작위로 조절할 수 없습니다.", "5": "급여제공기록지는 수급자의 확인을 받기 전에 작성하는 것이 일반적입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "서비스 수혜자(한국어)", "def_vi": "Người nhận dịch vụ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (716, '2', '다음 상황에서 요양보호사의 대처 방법으로 옳은 것은?대상자:며느리가 들어온 후 아들과도 사이가 멀어졌어. 친척들한테 말해도 며느리편만 들어서 속상해. 요양보호사: ( )', '["신경쓰지 말라고 말한다.", "옳고 그름에 대해 판단하여 말해준다.", "자신의 경험에 비추어 이해를 시킨다.", "이야기를 들어주되 가족관계에 관여하지 않는다.", "아들에게 대상자의 마음 상태를 알려준다."]'::jsonb, 4, NULL, NULL, '{"1": "신경쓰지 말라고 말하는 것은 대상자의 감정을 무시하는 것으로 부적절합니다.\n[정답]", "2": "옳고 그름에 대해 판단하여 말해주는 것은 주관적인 판단을 포함하므로 바람직하지 않습니다.", "3": "자신의 경험에 비추어 이해를 시키는 것은 이야기의 상황에 따라 적절할 수 있으나, 보편적으로 대상자의 입장을 들어주는 것이 우선입니다.", "4": "이야기를 들어주되 가족관계에 관여하지 않는 것은 대상자의 감정 지지를 제공하면서도 중립성을 유지할 수 있어서 가장 적절한 대처입니다.", "5": "아들에게 대상자의 마음 상태를 알려주는 것은 가족 간의 갈등을 유발할 수 있으므로 신중해야 합니다."}'::jsonb, '[{"term_ko": "대처", "term_vi": "Cách đối phó", "def_ko": "대처하는 것(한국어)", "def_vi": "cách xử lý tình huống"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람(한국어)", "def_vi": "người nhận dịch vụ"}, {"term_ko": "며느리", "term_vi": "Dâu", "def_ko": "아들의 아내(한국어)", "def_vi": "vợ của con trai"}, {"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 사이의 관계(한국어)", "def_vi": "mối quan hệ giữa các thành viên trong gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (715, '2', '대상자가 서비스 시간에 자주 전화하여 일너저런 푸념을 할 때 요양보호사의 대처방법은?', '["업무시간 외에는 전화를 받지 않는다.", "대상자를 이해하며 전화를 받아 끝까지 들어준다.", "상황을 파악한 후 개인적으로 해결해 준다.", "이야기를 들어주고 추가 서비스료를 받는다.", "서비스 시간 외에는 통화가 어려움을 이해시킨다."]'::jsonb, 5, NULL, NULL, '{"1": "서비스 시간 외에 전화를 받지 않는 것은 고객과의 신뢰를 구축하는 데 부정적 영향을 미칠 수 있습니다.", "2": "대상자를 이해하며 전화 통화를 끝까지 듣는 것은 바람직하지만, 모든 전화에 응대하는 것은 적절하지 않습니다.", "3": "상황 파악 후 개인적으로 해결하는 것은 요양보호사의 역할을 넘어서는 행동입니다.", "4": "이야기를 들어주고 추가 서비스료를 받는 것은 윤리적이지 않으며 바람직하지 않습니다.\n[정답]", "5": "서비스 시간 외에는 통화가 어려움을 이해시킨다. 이는 요양보호사로서의 적절한 대처법입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "환자, 돌보아야 할 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "서비스 시간", "term_vi": "Thời gian dịch vụ", "def_ko": "제공되는 서비스의 시간", "def_vi": "Thời gian mà dịch vụ được cung cấp"}, {"term_ko": "전화", "term_vi": "Điện thoại", "def_ko": "전화 통화", "def_vi": "Cuộc gọi điện thoại"}, {"term_ko": "푸념", "term_vi": "Phàn nàn", "def_ko": "불만 사항 등을 이야기하다", "def_vi": "Nói về các vấn đề, sự không hài lòng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (714, '2', '대상자가 요양보호사에게 약 사러 가는 길에 아들 운동화도 사다달라고 부탁을 할 때 대처 방법은?', '["다음에 올 때 운동화를 사다 주겠다고 말한다.", "대상자가 직접 관리책임자에게 요청하게 한다.", "관리책임자에게 보고 한 후 운동화를 사다준다.", "가족에게 대상자의 약과 아들 운동화를 사오게 한다.", "가족의 물품은 사다줄 수 없다고 설명한다."]'::jsonb, 5, NULL, NULL, '{"1": "다음에 올 때 운동화를 사다 주겠다고 말한다. 이는 약속을 어길 수 있는 가능성을 내포하므로 바람직하지 않다.\n[정답]", "5": "가족의 물품은 사다줄 수 없다고 설명한다. 이는 요양보호사의 역할과 책임을 명확히 하고 윤리적 기준을 준수하는 방법이다.", "3": "관리책임자에게 보고 한 후 운동화를 사다준다. 이는 불필요한 절차로 시간이 지체될 수 있다.", "4": "가족에게 대상자의 약과 아들 운동화를 사오게 한다. 이는 가족에게 추가적인 부담을 줄 수 있다.", "2": "대상자가 직접 관리책임자에게 요청하게 한다. 이는 대상자의 자율성을 존중하지만 명확한 대처가 되지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자나 요양을 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận chăm sóc"}, {"term_ko": "운동화", "term_vi": "Giày thể thao", "def_ko": "신발의 한 종류", "def_vi": "Một loại giày"}, {"term_ko": "관리책임자", "term_vi": "Người quản lý", "def_ko": "요양시설을 관리하는 사람", "def_vi": "Người quản lý cơ sở chăm sóc"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "짐이나 걱정", "def_vi": "Gánh nặng hoặc lo lắng"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적으로 올바른", "def_vi": "Đúng về mặt đạo đức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (713, '2', '거동이 불편한 대상자가 은행에 가서 고액의 돈을 인출해 달라고 부탁했을 때 요양보호사의 올바른 대처 방법은?', '["동료 요양보호사와 함께 간다.", "요양보호사 혼자 가서 인출해 온다.", "대상자의 가족과 함께 가서 인출한다.", "고액의 은행 업무는 본인과 함께 가야 한다고 설득한다.", "고액의 돈은 인출할 수 없다고 정중하게 거절한다."]'::jsonb, 3, NULL, NULL, '{"1": "동료 요양보호사와 함께 가는 것은 좋지만, 고액 인출은 대상자 본인의 동행이 필요합니다.\n[정답]", "3": "대상자의 가족과 함께 가서 인출하는 것이 안전하고 법적으로 올바른 방법입니다.", "2": "요양보호사 혼자 가서 인출하는 것은 대상자의 안전을 보장할 수 없습니다.", "4": "고액의 은행 업무는 본인과 함께 가야 한다고 설득하는 것은 어려운 상황에서는 적절하지 않습니다.", "5": "고액의 돈은 인출할 수 없다고 정중하게 거절하는 것은 대상자의 요청을 무시하는 행동입니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (712, '2', '냉장고에 음식이 상한 것을 발견했을 때 요양보호사의 대처방법으로 옳은 것은?', '["버리고 나서 대상자에게 설명한다.", "먹을 수 있도록 가열해 둔다.", "상한 부분만 버리고 냉장고에 넣는다.", "냉동실에 넣고 얼린다.", "대상자에게 알리고 즉시 폐기한다."]'::jsonb, 5, NULL, NULL, '{"1": "잘못된 대응입니다. 상한 음식을 버린 후 설명할 필요 없으며, 바로 조치를 취해야 합니다.\n[정답]", "5": "상한 음식을 발견했을 경우, 즉시 폐기하고 대상자에게 알려야 안전합니다.", "3": "상한 부분만 버리고 냉장고에 넣는 것은 안전하지 않습니다.", "2": "가열하여 먹을 수 있도록 하는 것은 더 위험한 방법입니다.", "4": "냉동실에 넣고 얼리는 것도 적절하지 않습니다."}'::jsonb, '[{"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "음식(한국어)", "def_vi": "Thức ăn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (711, '2', '치매 대상자가 입맛이 없다면서 식사를 거부할 때 대처방법은?', '["식욕촉진제를 준다.", "음식을 강제로 떠 먹인다.", "평소 좋아하는 음식을 제공한다.", "식사할 때까지 옆에서 기다린다.", "음식을 먹을 때까지 치우지 않는다."]'::jsonb, 3, NULL, NULL, '{"1": "식욕촉진제를 주는 것은 단기적인 해결책일 뿐입니다. 따라서, 효과적이지 않을 수 있습니다.\n[정답]", "3": "평소 좋아하는 음식을 제공하는 것은 대상자의 식욕을 자극할 수 있는 좋은 방법입니다.", "2": "음식을 강제로 떠 먹이는 것은 대상자에게 스트레스를 주고 식사에 대한 거부감을 더욱 키울 수 있습니다.", "4": "식사할 때까지 옆에서 기다리는 것은 비효율적이며 식사하지 않을 수 있습니다.", "5": "음식을 먹을 때까지 치우지 않는 것은 오히려 위생적이지 않고, 불필요한 스트레스를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력의 저하 등을 특징으로 하는 질환", "def_vi": "Bệnh đặc trưng bởi giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "식욕", "term_vi": "Sự thèm ăn", "def_ko": "음식을 먹고 싶어 하는 욕구", "def_vi": "Mong muốn ăn uống"}, {"term_ko": "강제", "term_vi": "Ép buộc", "def_ko": "어떤 일을 하도록 강요하는 것", "def_vi": "Bắt buộc làm một việc gì đó"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움이나 서비스를 받을 사람", "def_vi": "Người nhận sự giúp đỡ hoặc dịch vụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (710, '2', '혼자 사는 재가대상자가 명절음식을 만들어 달라고 요구할 때 요양보호사의 대처방법으로 옳은 것은?', '["별도의 비용을 지불하면 가능하다고 한다.", "대상자의 병이 다 나으면 만들어 준다고 한다.", "관리 책임자에게 허락받고 만들어주겠다고 한다.", "원칙상 안 되지만 특별히 만들어 준다고 한다.", "명절음식 차리기 등은 요양서비스 업무 범위가 아니라고 설명한다."]'::jsonb, 5, NULL, NULL, '{"1": "별도의 비용을 지불하면 가능하다고 한다: 요양서비스는 일반적으로 정해진 범위 내에서 제공되므로 추가 비용을 요구하는 것은 부적절합니다.\n[정답]", "5": "명절음식 차리기 등은 요양서비스 업무 범위가 아니라고 설명한다: 요양보호사는 정해진 서비스 범위 내에서만 업무를 수행해야 하므로 가장 적절한 대처입니다.", "2": "대상자의 병이 다 나으면 만들어 준다고 한다: 이 또한 기본적인 서비스 범위를 벗어난 답변입니다.", "3": "관리 책임자에게 허락받고 만들어주겠다고 한다: 이를 따르더라도 요양서비스의 범위를 넘어섭니다.", "4": "원칙상 안 되지만 특별히 만들어 준다고 한다: 원칙을 무시하고 행동하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận sự chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (709, '2', '변비인 대상자가 관장을 해달라고 요구할 때 대처방법으로 옳은 것은?', '["즉시 관장을 해준다.", "변비약을 구입하여 제공한다.", "못 들은 척 하고 다른 일을 한다.", "의료행위에 해당되므로 스스로 해결하게 한다.", "의부를 배꼽 주위에서 시계방향으로 마사지한다."]'::jsonb, 5, NULL, NULL, '{"1": "즉시 관장을 해주는 것은 전문가가 아닌 요양보호사가 할 수 없는 의료행위이다.\n[정답]", "5": "의부를 배꼽 주위에서 시계방향으로 마사지하는 것은 변비 완화에 도움을 줄 수 있는 비의료적 접근이다.", "3": "못 들은 척 하고 다른 일을 하는 것은 대상자의 요구를 무시하는 행동으로 올바르지 않다.", "4": "의료행위에 해당되므로 스스로 해결하게 하는 것은 적절한 대처가 아니다.", "2": "변비약을 구입하여 제공하는 것은 요양보호사의 역할에 해당하지 않는다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi đại tiện"}, {"term_ko": "관장", "term_vi": "Thụt tháo", "def_ko": "항문으로 약물이나 수액을 집어넣는 행위", "def_vi": "Hành động đưa thuốc hoặc dung dịch vào hậu môn"}, {"term_ko": "의료행위", "term_vi": "Hành động y tế", "def_ko": "의료목적으로 하는 모든 행위", "def_vi": "Tất cả các hành động nhằm mục đích y tế"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "주물러서 자극을 주는 행위", "def_vi": "Hành động xoa bóp để kích thích"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (708, '2', '대상자가 기저귀를 차고 있는 상황에서 기저귀 안으로 손을 자주 넣을 때 올바른 대처방법은?', '["기저귀를 꽉 조여준다.", "음부의 피부 상태를 확인한다.", "화장실로 데려가 변기에 앉힌다.", "상하의가 붙은 옷을 입힌다.", "무의식적으로 하는 행동이므로 그냥 둔다."]'::jsonb, 2, NULL, NULL, '{"1": "기저귀를 너무 꽉 조이면 오히려 불편함을 줄 수 있습니다.\n[정답]", "2": "기저귀 안에 손을 넣는 이유 중 하나는 피부 상태에 문제가 있을 수 있어서 확인하는 것이 중요합니다.", "3": "기저귀 착용자의 상태에 따라 화장실에 데려가는 방법이 필요할 수 있지만, 현재 문제의 본질은 피부 확인입니다.", "4": "상하의가 붙은 옷은 오히려 불편하게 하여 행동을 유발할 수 있습니다.", "5": "무의식적인 행동이라고 하더라도 필요한 경우에는 대처가 필요합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (707, '2', '밤에 추워서 화장실에 가기 싫다며 기저귀를 사용하려는 대상자를 돕는 방법은?', '["이동변기를 사용한다.", "원하는 대로 기저귀를 사용한다.", "휠체어를 타고 가도록 한다.", "식사와 수분섭취를 줄인다.", "배설 욕구를 참았다가 화장실에 가게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "이동변기를 사용한다. 적절한 방법으로 대상자가 편리하게 화장실을 이용하게 도와준다.\n[정답]", "2": "원하는 대로 기저귀를 사용한다. 기저귀 사용이 아닌 보다 적절한 배설 방법을 제시해야 한다.", "3": "휠체어를 타고 가도록 한다. 이동이 어렵다면 휠체어를 이용하는 방법이지만, 효과적이지 않을 수 있다.", "4": "식사와 수분섭취를 줄인다. 이 방법은 건강에 해로운 영향을 미칠 수 있다.", "5": "배설 욕구를 참았다가 화장실에 가게 한다. 욕구를 참게 하는 것은 불필요한 스트레스를 줄 수 있다."}'::jsonb, '[{"term_ko": "밤", "term_vi": "Đêm", "def_ko": "밤(한국어)", "def_vi": "đêm"}, {"term_ko": "추워서", "term_vi": "Lạnh", "def_ko": "추위로 인해(한국어)", "def_vi": "do lạnh"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "화장실(한국어)", "def_vi": "nhà vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã"}, {"term_ko": "이동변기", "term_vi": "Bô di động", "def_ko": "이동변기(한국어)", "def_vi": "bô di động"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "xe lăn"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배설(한국어)", "def_vi": "bài tiết"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "욕구(한국어)", "def_vi": "nhu cầu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (706, '2', '치매 대상자가 목욕 도중 큰 소리로 욕을 하며 목욕을 그만하겠다고 할 때 대처방법으로 옳은 것은?', '["정해진 시간에 목욕을 마쳐야 한다고 말한다.", "욕하지 못하게 큰 소리로 꾸짖는다.", "무시하고 신속하게 목욕을 마친다.", "잠시 자리를 피해 혼자 있게 한다.", "안전을 위해 무리하게 목욕을 시키지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "정해진 시간에 목욕을 마쳐야 한다고 말하는 것은 치매 환자의 불안감을 증가시킬 수 있습니다.", "2": "욕하지 못하게 큰 소리로 꾸짖는 것은 환자의 기분을 더욱 나쁘게 만들 수 있습니다.", "3": "무시하고 신속하게 목욕을 마치는 것은 환자의 권리를 침해할 수 있습니다.", "4": "잠시 자리를 피해 혼자 있게 하는 것은 고립감을 유발할 수 있습니다.\n[정답]", "5": "안전을 위해 무리하게 목욕을 시키지 않는 것이 가장 바람직한 대처 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và khả năng suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (705, '2', '방문요양 시 대상자가 매번 목욕을 시켜 달라고 옷을 벗고 알몸으로 기다릴 때 요양보호사의 대처방법은?', '["서비스 제공을 중단한다.", "이웃에게 알려 도움을 청한다.", "같이 TV를 보자고 한다.", "임의로 목욕서비스를 실시한다.", "목욕 서비스가 없음을 설명하고 옷을 입도록 단호하게 말한다."]'::jsonb, 5, NULL, NULL, '{"1": "서비스 제공을 중단하는 것은 원인을 해결하지 못하는 방법입니다.", "2": "이웃에게 도움을 청하는 것은 적절한 대처가 아닙니다.", "3": "같이 TV를 보자고 하는 것은 목표에 부합하지 않는 대응입니다.", "4": "임의로 목욕서비스를 실시하는 것은 대상자의 의사와 상반되는 행동입니다.\n[정답]", "5": "목욕 서비스가 없음을 설명하고 옷을 입도록 단호하게 말하는 것이 적절한 대응 방법입니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "대상자의 집을 방문하여 요양 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà cho đối tượng"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스나 치료를 받는 사람", "def_vi": "Người nhận dịch vụ hoặc điều trị"}, {"term_ko": "대처방법", "term_vi": "Cách xử lý", "def_ko": "문제에 대한 대응 방안", "def_vi": "Giải pháp đối phó với vấn đề"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "단호하게", "term_vi": "Kiên quyết", "def_ko": "확고하고 강한 태도로", "def_vi": "Với thái độ vững vàng và mạnh mẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (704, '2', '대상자가 혈압이 높은데도 목욕을 하겠다고 하는 경우 대처방법은?', '["혈압약을 복용한 후 목욕을 한다.", "대상자의 가족에게 허락받고 목욕을 시킨다.", "샤워보다는 통 목욕으로 한다.", "목욕시간은 1시간 이내로 한다.", "혈압이 높을 때 목욕을 하면 위험함을 설명한다."]'::jsonb, 5, NULL, NULL, '{"1": "혈압약을 복용한 후 목욕을 하게 되면 혈압이 더 낮아질 수 있어 위험할 수 있습니다.\n[정답]", "5": "혈압이 높을 때 목욕을 하면 위험할 수 있음을 설명하여 개인의 안전을 확보하는 것이 중요합니다.", "3": "통 목욕보다 샤워가 혈압에 덜 영향을 미칠 수 있으나, 대처 방법으로 적절하지 않습니다.", "4": "목욕 시간은 일반적으로 20-30분 이내로 제한하는 것이 바람직합니다.", "2": "가족에게 허락받고 목욕하게 되면 문제를 해결할 수 없으니 적절하지 않습니다."}'::jsonb, '[{"term_ko": "혈압", "term_vi": "Huyết áp", "def_ko": "혈액이 혈관벽에 미치는 압력(압 lực)", "def_vi": "Áp lực của máu tác động lên thành mạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (703, '2', '치매 대상자가 속옷을 갈아입으려고 하지 않을 때 올바른 대처 방법은?', '["갈아입지 않으려는 이유를 알아본다.", "목욕을 한다며 강제로 갈아 입힌다.", "갈아입지 않으면 밥을 주지 않는다고 말한다.", "속옷을 사다 주고 혼자 갈아입으라고 한다.", "자년에게 갈아 입히라고 말한다."]'::jsonb, 1, NULL, NULL, '{"1": "갈아입지 않으려는 이유를 알아본다. [정답] 치매 대상자의 심리적, 정서적 이유를 이해하고, 그에 맞는 대처를 할 수 있어야 한다.", "2": "목욕을 한다며 강제로 갈아 입힌다. 강제적인 방법은 치매 환자의 불안감을 초래할 수 있다.", "3": "갈아입지 않으면 밥을 주지 않는다고 말한다. 이러한 방식은 환자에게 스트레스를 줄 수 있으며 부적절하다.", "4": "속옷을 사다 주고 혼자 갈아입으라고 한다. 환자의 자존감을 해칠 수 있으며 올바른 대처가 아니다.", "5": "자녀에게 갈아 입히라고 말한다. 이러한 방법은 기본적인 돌봄 책임을 다하지 않는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억상실증(한국어)", "def_vi": "Bệnh không nhớ điều gì"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (702, '2', '회음부 세척 시 대상자가 부끄러워하며 도움을 거부할 때 대처방법은?', '["청결을 위해 무시하고 씻긴다.", "보호자에게 연락하여 도움을 요청한다.", "대상자가 도움을 요청할 때까지 기다린다.", "대상자의 거부의사를 존중하여 다음으로 미룬다.", "편안한 환경을 조성하고 세척의 필요성을 이해시킨다."]'::jsonb, 5, NULL, NULL, '{"1": "청결을 위해 무시하고 씻기는 것은 대상자의 의사를 존중하지 않는 행동입니다.\n[정답]", "5": "편안한 환경을 조성하고 세척의 필요성을 이해시키는 것이 올바른 접근법입니다.", "3": "대상자가 도움을 요청할 때까지 기다리는 것은 시간이 소요될 수 있습니다.", "4": "대상자의 거부의사를 존중하되, 다음으로 미루는 것은 문제 상황을 해결하지 못합니다.", "2": "보호자에게 연락하여 도움을 요청하는 것은 상황을 개선하기 위한 방법이지만, 먼저 대상자의 의사를 존중해야 합니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Cơ quan sinh dục", "def_ko": "생식기와 항문 사이의 부분", "def_vi": "Phần giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗하게 하다", "def_vi": "Làm sạch"}, {"term_ko": "부끄러워하다", "term_vi": "Xấu hổ", "def_ko": "쑥스러워하다", "def_vi": "Ngại ngùng"}, {"term_ko": "거부하다", "term_vi": "Từ chối", "def_ko": "거절하다", "def_vi": "Từ chối"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "해결 방법", "def_vi": "Cách giải quyết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (701, '2', '치매 대상자가 식사 후에 양치질을 거부할 때 돕는 방법은?', '["심하게 거부하면 그냥 둔다.", "입안을 물로 헹궈준다.", "간식을 주지 않는다고 말한다.", "치약과 칫솔을 손에 쥐어주고 기다린다.", "동료에게 도움을 요청하여 강제로 시도한다."]'::jsonb, 2, NULL, NULL, '{"1": "심하게 거부할 경우, 강제로 시도하기보다 대상자의 의사를 존중하는 것이 중요합니다.\n[정답]", "2": "입안을 물로 헹구어주면 간접적으로 구강 위생을 도울 수 있습니다.", "3": "간식을 주지 않는다고 말하는 것은 부적절한 대응입니다.", "4": "치약과 칫솔을 손에 쥐어주고 기다리는 것은 비효율적입니다.", "5": "동료에게 도움을 요청하여 강제로 시도하는 것은 환자에게 스트레스를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이 상실되고 사고 능력이 저하되는 증상", "def_vi": "Tình trạng mất khả năng nhớ và suy giảm khả năng suy nghĩ"}, {"term_ko": "양치질", "term_vi": "Đánh răng", "def_ko": "이빨을 닦는 행위", "def_vi": "Hành động chải răng"}, {"term_ko": "구강", "term_vi": "Miệng", "def_ko": "입안의 구역", "def_vi": "Khu vực trong miệng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "어떤 것을 원하지 않거나 받지 않다", "def_vi": "Không muốn hoặc không chấp nhận điều gì"}, {"term_ko": "간접적으로", "term_vi": "Gián tiếp", "def_ko": "직접 효과가 아닌 방법을 통해", "def_vi": "Thông qua phương pháp không hiệu quả trực tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (700, '2', '요양보호사가 제공하는 정서지원, 의사소통에 해당하는 것은?', '["양치 지켜보기", "산책 시 부축", "손발톱 깎기", "화장하기", "편지대필"]'::jsonb, 5, NULL, NULL, '{"1": "양치 지켜보기는 신체적 도움을 주는 행위입니다.", "2": "산책 시 부축은 이동에 대한 지원으로, 정서적 지원과는 직접적 연관이 없습니다.", "3": "손발톱 깎기는 신체적 관리에 해당합니다.", "4": "화장하기는 개인 위생과 미용 관련 행위입니다.\n[정답]", "5": "편지대필은 정서적 소통을 통해 환자의 감정을 지원하는 행동입니다."}'::jsonb, '[{"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정을 지원하는 것", "def_vi": "Hỗ trợ cảm xúc cho người bệnh"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 것", "def_vi": "Sự giao tiếp"}, {"term_ko": "편지대필", "term_vi": "Viết thư thay mặt", "def_ko": "편지를 대신 써주는 것", "def_vi": "Viết thư cho người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (699, '2', '대상자에게 제공하는 가사 및 일상생활지원에 해당되는 것은?', '["좋아하는 시를 읽어준다.", "대상자와 함께 보건소 방문을 한다.", "기념일을 달력에 표기하도록 도와준다.", "전화로 생활상의 문제를 상담한다.", "대상자가 앉았다 일어서는 행동을 도와준다."]'::jsonb, 2, NULL, NULL, '{"1": "좋아하는 시를 읽어주는 것은 정서적 지원의 일환으로, 가사 및 일상생활 지원에 해당하지 않음.\n[정답]", "2": "대상자와 함께 보건소 방문을 하는 것은 일상생활 지원의 일환으로, 필요한 의료적 지원을 받을 수 있도록 돕는 활동임.", "3": "기념일을 달력에 표기하도록 도와주는 것은 관리적 지원에 해당하지만, 일상생활 지원에는 포함되지 않음.", "4": "전화로 생활상의 문제를 상담하는 것은 정서적 지원에 해당하며, 직접적인 일상생활 지원이 아님.", "5": "대상자가 앉았다 일어서는 행동을 도와주는 것은 신체적 지원으로, 일상생활 지원에 해당하지 않음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người cần chăm sóc", "def_ko": "환자 또는 요양을 받는 사람", "def_vi": "Bệnh nhân hoặc người được chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (698, '2', '개인활동이 곤라한 재가 대상자에게 제공할 수 있는 서비스는?', '["정원 잡초 뽑기", "시장 다녀오기", "가족식사 준비하기", "애완견 산책 다녀오기", "명절음식 만들기"]'::jsonb, 2, NULL, NULL, '{"1": "정원 잡초 뽑기는 개인의 정원 관리에 해당하는 활동으로, 재가 대상자에게 제공하기에는 적절하지 않습니다.\n[정답]", "2": "시장 다녀오기는 재가 대상자가 필요로 하는 기본적인 외출 활동으로, 적합한 서비스입니다.", "3": "가족식사 준비하기는 가족이 함께할 때 고려할 수 있는 사항이며, 재가 대상자에게는 직접적인 서비스가 아닙니다.", "4": "애완견 산책 다녀오기는 재가 대상자가 아니라 애완견의 필요에 해당하므로 적합하지 않습니다.", "5": "명절음식 만들기는 특별한 경우를 제외하고는 재가 대상자에게 필요한 서비스가 아닙니다."}'::jsonb, '[{"term_ko": "개인활동", "term_vi": "Hoạt động cá nhân", "def_ko": "개인의 일상적인 활동", "def_vi": "Các hoạt động hàng ngày của cá nhân"}, {"term_ko": "재가 대상자", "term_vi": "Đối tượng chăm sóc tại nhà", "def_ko": "재가에서 돌보아야 하는 사람", "def_vi": "Người cần được chăm sóc ở nhà"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움", "def_vi": "Sự giúp đỡ được cung cấp"}, {"term_ko": "시장", "term_vi": "Chợ", "def_ko": "물건을 사는 곳", "def_vi": "Nơi mua sắm"}, {"term_ko": "가족식사", "term_vi": "Bữa ăn gia đình", "def_ko": "가족이 함께하는 식사", "def_vi": "Bữa ăn cùng gia đình"}, {"term_ko": "명절음식", "term_vi": "Món ăn ngày lễ", "def_ko": "특별한 날에 만드는 음식", "def_vi": "Món ăn được chế biến vào dịp lễ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (697, '2', '대상자에게 제공되는 일상생활지원 내용으로 옳은 것은?', '["대상자 배우자의 바지를 다려 주었다.", "대상자 가족의 행정업무를 도와 주었다.", "대상자 손주의 유치원 등원을 도와 주었다.", "대상자가 먹고 싶어 하는 전복죽을 끓여 주었다.", "병문안을 온 친척의 점심을 차려 주었다."]'::jsonb, 4, NULL, NULL, '{"1": "잘못됨: 대상자 배우자의 바지를 다리는 것은 일상생활지원에 해당되지 않습니다.", "2": "잘못됨: 가족의 행정업무 지원은 요양보호사가 제공하는 일상생활지원 범주에 포함되지 않습니다.", "3": "잘못됨: 손주의 유치원 등원 도와 주는 것은 대상자가 아닌 다른 사람을 지원하는 것입니다.\n[정답]", "4": "맞음: 대상자가 먹고 싶어 하는 음식을 제공하는 것은 일상생활지원의 일환입니다.", "5": "잘못됨: 병문안을 온 친척의 점심을 차려 주는 것은 대상자가 아닌 다른 사람을 지원하는 것입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "지원을 받는 사람", "def_vi": "Người nhận hỗ trợ"}, {"term_ko": "일상생활지원", "term_vi": "Hỗ trợ sinh hoạt hàng ngày", "def_ko": "일상적인 생활을 지원하는 것", "def_vi": "Hỗ trợ cho cuộc sống hàng ngày"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹을 것을 의미", "def_vi": "Thức ăn có nghĩa là món ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (696, '2', '다음 내용에 해당하는 표준서비스는?음식물 조리, 청소 및 주변정돈, 의복세탁 및 관리', '["신체활동지원", "가사 및 일상생활지원", "방문목욕", "정서지원, 의사소통", "건강 및 간호관리"]'::jsonb, 2, NULL, NULL, '{"1": "신체적인 도움을 제공하는 서비스입니다.\n[정답]", "2": "음식물 조리, 청소 및 주변정돈, 의복세탁 및 관리와 관련된 서비스입니다.", "3": "개인의 위생을 위한 목욕 서비스입니다.", "4": "정서적 안정과 의사소통을 위한 지원 서비스입니다.", "5": "건강 상태 체크와 간호 관련 서비스입니다."}'::jsonb, '[{"term_ko": "표준서비스", "term_vi": "Dịch vụ tiêu chuẩn", "def_ko": "표준적인 서비스나 지원의 형태", "def_vi": "Hình thức dịch vụ hoặc hỗ trợ tiêu chuẩn"}, {"term_ko": "음식물 조리", "term_vi": "Chuẩn bị thức ăn", "def_ko": "음식을 준비하고 만드는 것", "def_vi": "Việc chuẩn bị và nấu ăn"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "환경을 정리하고 깨끗하게 하는 것", "def_vi": "Làm sạch và sắp xếp môi trường"}, {"term_ko": "주변정돈", "term_vi": "Quản lý môi trường xung quanh", "def_ko": "주변을 정리하는 것", "def_vi": "Việc sắp xếp và duy trì môi trường xung quanh"}, {"term_ko": "의복세탁", "term_vi": "Giặt quần áo", "def_ko": "옷을 세탁하는 것", "def_vi": "Hành động giặt giũ quần áo"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "무엇인가를 잘 유지하고 감독하는 것", "def_vi": "Hành động duy trì và giám sát cái gì đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (695, '2', '재가 요양보호서비스 중 신체활동지원에 해당하는 것은?', '["식재료 구매", "몸 단장", "세탁물 빨기", "생활상담", "외출 시 동행"]'::jsonb, 2, NULL, NULL, '{"1": "식재료 구매는 신체활동이 아닌 생활 지원에 해당한다.\n[정답]", "2": "몸 단장은 개인의 신체적 활동에 해당하여 신체활동지원에 포함된다.", "3": "세탁물 빨기는 신체적 활동보다는 생활지원에 가까운 서비스이다.", "4": "생활상담은 상담 서비스로 신체활동지원에 포함되지 않는다.", "5": "외출 시 동행은 활동 지원이지만 신체활동지원이라는 범주에 포함되지 않는다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 서비스를 제공받는 요양", "def_vi": "Dịch vụ nhận được tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (694, '2', '요양보호사의 업무 중 올바르게 짝지어진 것은?', '["신체활동지원 - 말벗, 격려, 위로, 생활상담", "정서지원, 의사소통 - 화장실 이동 보조, 몸 단장 하기", "기능회복훈련 - 몸 씻기 도움, 목욕 기계 조작", "가사 및 일상생활지원 - 약 타기, 병원 동행, 관공서 업무대행", "방문목욕 - 취사, 청소, 세탁"]'::jsonb, 4, NULL, NULL, '{"1": "신체활동지원 - 말벗, 격려, 위로, 생활상담 (잘못된 조합)\n[정답]", "2": "정서지원, 의사소통 - 화장실 이동 보조, 몸단장 하기 (잘못된 조합)", "3": "기능회복훈련 - 몸 씻기 도움, 목욕 기계 조작 (잘못된 조합)", "4": "가사 및 일상생활지원 - 약 타기, 병원 동행, 관공서 업무대행 (올바른 조합)", "5": "방문목욕 - 취사, 청소, 세탁 (잘못된 조합)"}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돕는 전문가", "def_vi": "Chuyên gia giúp đỡ người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (693, '2', '노인장기요양보험 표준서비스 내용 중 ''인지행동 변화 관리''에 해당하는 것으로 옳은 것은?', '["신체활동지원", "정서지원, 의사소통", "가사 및 일상생활지원", "방문목욕", "인지지원"]'::jsonb, 5, NULL, NULL, '{"1": "신체활동지원은 신체적 기능을 지원하는 서비스이다.\n[정답]", "5": "인지지원은 인지기능 향상을 위한 서비스로, 인지행동 변화 관리에 포함된다.", "2": "정서지원, 의사소통은 정서적 안정을 위한 지원이지만 인지행동 변화 관리와는 다르다.", "3": "가사 및 일상생활지원은 일상 활동을 돕는 서비스로, 인지 관련 서비스가 아니다.", "4": "방문목욕은 신체 위생 관리를 지원하는 서비스이다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스 제공 정책", "def_vi": "Chính sách cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (692, '2', '노인장기요양보험 표준서비스 내용 중 기능회복훈련의 내용으로 옳은 것은?', '["이동 도움", "식사 도움", "화장실 이용 돕기", "작업치료", "체위변경"]'::jsonb, 4, NULL, NULL, '{"1": "이동 도움: 기능회복훈련의 일부일 수 있지만 직접적인 내용은 아닙니다.", "2": "식사 도움: 활동 지원의 일환으로 기능회복 접근이 아닌, 기본적인 돌봄입니다.", "3": "화장실 이용 돕기: 기본적인 일상 생활 지원이라 기능회복훈련의 핵심이라고 할 수 없습니다.\n[정답]", "4": "작업치료: 기능회복훈련의 중요한 부분으로, 재활을 돕기 위한 치료입니다.", "5": "체위변경: 기본적 돌봄 활동으로 기능회복훈련의 중심은 아닙니다."}'::jsonb, '[{"term_ko": "기능회복훈련", "term_vi": "Đào tạo phục hồi chức năng", "def_ko": "재활 훈련(한국어)", "def_vi": "Huấn luyện phục hồi chức năng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (691, '2', '노인장기요양보험 표준서비스 중 건강 및 간호관리에 해당하는 것은?', '["몸단장", "의사소통 도움", "관찰 및 측정", "목욕 기계 조작", "일상생활 동작훈련"]'::jsonb, 3, NULL, NULL, '{"1": "몸단장: 개인 위생과 관련이 있지만, 건강 및 간호관리와 직접적인 연관은 없습니다.\n[정답]", "3": "관찰 및 측정: 건강 상태를 관찰하고 측정하는 것이 간호관리의 핵심입니다.", "2": "의사소통 도움: 의사소통은 중요하지만 간호관리의 구체적인 요소는 아닙니다.", "4": "목욕 기계 조작: 목욕 서비스를 제공하는 것이지만 건강 관리와는 연결되지 않습니다.", "5": "일상생활 동작훈련: 기본적인 일상 생활 지원일 뿐 건강 및 간호관리와는 다른 범주입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자 장기 요양 시설에서 제공되는 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc lâu dài cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (690, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원에 속하는 것은?', '["머리 감기기", "복약 도움", "함께 은행가기", "배뇨, 배변 도움", "신체기능의 유지, 증진"]'::jsonb, 3, NULL, NULL, '{"1": "머리 감기기는 개인 위생 관리로, 가사 및 일상생활지원에 해당되지만 주된 서비스는 아닙니다.\n[정답]", "3": "함께 은행 가기는 외부 활동을 지원하는 것으로 가사 및 일상생활지원에 포함됩니다.", "2": "복약 도움은 의료 지원의 일환으로 가사 서비스에는 포함되지 않습니다.", "4": "배뇨, 배변 도움은 신체적 지원이며 가사 서비스가 아닙니다.", "5": "신체기능의 유지, 증진은 재활 또는 의료적 지원과 관련된 내용입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스 제공을 위한 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (689, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원에 해당하는 것은?', '["머리 감기기", "복약 도움", "함께 은행가기", "배뇨, 배변 도움", "신체기능의 유지, 증진"]'::jsonb, 5, NULL, NULL, '{"1": "머리 감기기: 개인 위생에 해당하지만, 가사 및 일상 생활 지원의 직접적 범위는 아닙니다.", "2": "복약 도움: 약물 관리에 해당하며, 가사 지원과는 거리가 있습니다.", "3": "함께 은행가기: 사회적 활동 지원으로 분류되지만, 가사 및 일상생활 지원에는 포함되지 않습니다.\n[정답]", "4": "배뇨, 배변 도움: 이것은 개인의 일상생활을 지원하는 안전한 서비스 범위에 적합한 항목입니다.", "5": "신체기능의 유지, 증진: 이것은 노인의 신체적 활동과 관련된 지원으로 가사 및 일상생활 지원의 일부로 볼 수 있습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 보호 보험", "def_vi": "Bảo hiểm cho những người cao tuổi gặp khó khăn trong hoạt động hàng ngày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (688, '2', '노인장기요양보험 표준서비스 중 신체활동지원에 해당하는 것은?', '["구강청결 도움", "생활상담 지원", "의사소통 도움", "인지자극 활동", "기본동작 훈련"]'::jsonb, 1, NULL, NULL, '{"1": "구강청결 도움은 신체활동지원에 해당하여 중요합니다.\n[정답]", "2": "생활상담 지원은 신체활동지원과는 관련이 없습니다.", "3": "의사소통 도움은 신체활동지원이 아닙니다.", "4": "인지자극 활동은 신체활동지원과는 관련이 없습니다.", "5": "기본동작 훈련은 신체활동지원의 일환으로 간주되지 않습니다."}'::jsonb, '[{"term_ko": "신체활동지원", "term_vi": "Hỗ trợ hoạt động thể chất", "def_ko": "신체 활동을 지원하는 서비스", "def_vi": "Dịch vụ hỗ trợ hoạt động thể chất"}, {"term_ko": "구강청결", "term_vi": "Làm sạch miệng", "def_ko": "입 안을 깨끗하게 하는 것", "def_vi": "Làm sạch bên trong miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (687, '2', '인간의 욕구 5단계 중 가장 높은 단계로서 삶의 보람, 자기만족을 느끼는 단계는?', '["생리적 욕구", "안전의 욕구", "사랑, 소속의 욕구", "존경의 욕구", "자아실현의 욕구"]'::jsonb, 5, NULL, NULL, '{"1": "생리적 욕구는 생존을 위한 기본적인 필요입니다.", "2": "안전의 욕구는 신체적, 정서적 안전을 추구하는 것입니다.", "3": "사랑, 소속의 욕구는 인간관계의 형성에 대한 욕구입니다.\n[정답]", "4": "존경의 욕구는 타인으로부터 존중받고 인정받고 싶어하는 욕구입니다.", "5": "자아실현의 욕구는 개인의 잠재력을 최대한 발휘하고 삶의 의미를 찾는 단계입니다."}'::jsonb, '[{"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요(한국어)", "def_vi": "Nhu cầu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (686, '2', '매슬로의 욕구단계 중, 요양보호서비스 제공 시 우선적으로 해결해주어야 하는 욕구는?', '["음식을 섭취할 욕구", "자아실현을 할 욕구", "가족에게 사랑받을 욕구", "타인으로부터 존중받을 욕구", "위험으로부터 안전하게 보호받을 욕구"]'::jsonb, 1, NULL, NULL, '{"1": "매슬로의 이론에 따르면 생리적 욕구는 가장 기본적이고 우선적으로 충족되어야 하는 욕구이다.\n[정답]", "2": "자아실현 욕구는 보다 높은 차원의 욕구로 후순위에 해당된다.", "3": "사랑받고자 하는 욕구는 생리적 욕구 다음으로 중요하지만 식사의 필요 보다는 뒤에 위치한다.", "4": "존중받고자 하는 욕구는 개인의 자아와 관련이 있으나 생존을 위한 기본 욕구보다 우선할 수 없다.", "5": "위험으로부터의 안전은 중요하지만 매슬로의 이론에서는 생리적 욕구보다 후순위로 여겨진다."}'::jsonb, '[{"term_ko": "매슬로", "term_vi": "Maslow", "def_ko": "심리학자, 욕구 이론의 창시자", "def_vi": "Nhà tâm lý học, người sáng lập lý thuyết nhu cầu"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "원하는 상태", "def_vi": "Trạng thái mong muốn"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "인체의 기본적인 생존 관련", "def_vi": "Liên quan đến sự tồn tại cơ bản của cơ thể"}, {"term_ko": "자아실현", "term_vi": "Tự thể hiện", "def_ko": "개인의 잠재력 발휘", "def_vi": "Khả năng tối đa hóa tiềm năng của cá nhân"}, {"term_ko": "사랑받다", "term_vi": "Được yêu thương", "def_ko": "애정을 받다", "def_vi": "Nhận được tình yêu"}, {"term_ko": "존중", "term_vi": "Tôn trọng", "def_ko": "타인을 존중하는 것", "def_vi": "Việc tôn trọng người khác"}, {"term_ko": "위험", "term_vi": "Nguy cơ", "def_ko": "위험한 상황", "def_vi": "Tình huống nguy hiểm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "보호받는 상태", "def_vi": "Trạng thái được bảo vệ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (685, '2', '매슬로의 인간 욕구 5단계 중 식사, 배설, 수면은 어느 단계에 해당하는가?', '["안전의 욕구", "사랑과 소속의 욕구", "자아실현의 욕구", "생리적 욕구", "존경의 욕구"]'::jsonb, 4, NULL, NULL, '{"1": "안전의 욕구: 인간이 생존에 위협을 느끼지 않도록 보호받고자 하는 욕구입니다.\n[정답]", "4": "생리적 욕구: 기본적인 생존을 위한 욕구로, 식사, 배설, 수면 등이 포함됩니다.", "3": "자아실현의 욕구: 자신의 잠재력을 최대한 발휘하고자 하는 욕구입니다.", "2": "사랑과 소속의 욕구: 인간관계 속에서 사랑받고 소속감을 느끼고자 하는 욕구입니다.", "5": "존경의 욕구: 타인의 존경을 받고, 자존감을 높이고자 하는 욕구입니다."}'::jsonb, '[{"term_ko": "매슬로", "term_vi": "Maslow", "def_ko": "미국의 심리학자로, 욕구 이론으로 유명함", "def_vi": "Nhà tâm lý học Mỹ, nổi tiếng với lý thuyết nhu cầu"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "사람의 필요나 원하는 것", "def_vi": "Những điều cần thiết hoặc mong muốn của con người"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "생명 유지에 필요한 것과 관련된", "def_vi": "Liên quan đến những điều cần thiết cho sự sống"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험으로부터 보호받고자 하는 상태", "def_vi": "Trạng thái muốn được bảo vệ khỏi nguy hiểm"}, {"term_ko": "사랑", "term_vi": "Yêu", "def_ko": "긍정적인 감정의 표현", "def_vi": "Sự thể hiện cảm xúc tích cực"}, {"term_ko": "소속", "term_vi": "Tham gia", "def_ko": "어떤 그룹에 포함되거나 관계가 있는 상태", "def_vi": "Trạng thái được bao gồm trong một nhóm hoặc có mối quan hệ"}, {"term_ko": "자아실현", "term_vi": "Tự hiện thực hóa", "def_ko": "개인의 잠재력을 충분히 발휘하는 것", "def_vi": "Việc phát huy tối đa tiềm năng của một cá nhân"}, {"term_ko": "존경", "term_vi": "Tôn trọng", "def_ko": "타인으로부터 인정받는 것", "def_vi": "Được công nhận bởi người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (684, '2', '노인장기요양보험제도에서 대상자에게 제공하는 요양보호서비스의 목적으로 옳은 것은?', '["신체기능 증진 및 삶의 질 향상", "안전의 욕구 충족", "자아실현의 욕구 충족", "생리적 욕구 충족", "자아존중의 욕구 충족"]'::jsonb, 1, NULL, NULL, '{"1": "신체기능 증진 및 삶의 질 향상은 요양보호서비스의 주요 목적 중 하나입니다.\n[정답]", "2": "안전의 욕구 충족은 요양보호서비스의 하나의 측면이지만 주된 목적은 아닙니다.", "3": "자아실현의 욕구 충족은 요양보호 서비스의 직접적인 목적이라기보다는 장기적인 목표일 수 있습니다.", "4": "생리적 욕구 충족은 기본적인 요구를 포함하지만, 요양보호서비스의 모든 목적을 포괄하지 않습니다.", "5": "자아존중의 욕구 충족도 중요하지만, 제공 서비스의 주요 목적이라 보기 어려운 하나입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người già", "def_ko": "노인을 위한 장기 요양 서비스 제공 시스템", "def_vi": "Hệ thống cung cấp dịch vụ chăm sóc dài hạn cho người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (683, '2', '장기요양서비스 제공 계획을 수립하기 전에 대상자의 신체적 상황, 정신심리 상태, 사회 환경까지 파악하는 평가 방법은?', '["업무평가", "상태평가", "욕구평가", "종합평가", "자가평가"]'::jsonb, 3, NULL, NULL, '{"1": "업무평가는 특정 업무의 수행 능력이나 진행 상황을 평가하는 방법이다.", "2": "상태평가는 대체로 건강 상태를 중점적으로 평가하는 방법이다.\n[정답]", "3": "욕구평가는 대상자의 신체적, 정신적, 사회적 요구를 파악하기 위한 평가 방법이다.", "4": "종합평가는 여러 가지 요소를 아우르는 전체적인 평가를 의미한다.", "5": "자가평가는 본인이 스스로 자신의 상태를 평가하는 방법이다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 동안 지속되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài trong thời gian dài"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된, 신체적 특성", "def_vi": "Liên quan đến cơ thể, đặc điểm thể chất"}, {"term_ko": "정신심리", "term_vi": "Tâm lý", "def_ko": "정신적이고 심리적인 것과 관련된", "def_vi": "Liên quan đến tâm trí và tâm lý"}, {"term_ko": "사회 환경", "term_vi": "Môi trường xã hội", "def_ko": "사회적 맥락", "def_vi": "Bối cảnh xã hội"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요, 요구", "def_vi": "Cần thiết, yêu cầu"}, {"term_ko": "평가", "term_vi": "Đánh giá", "def_ko": "측정하거나 판단하는 과정", "def_vi": "Quá trình đo lường hoặc đánh giá"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (682, '2', '장기요양서비스 이용절차 단계 중 대상자 및 가족에게 만족스러운 서비스가 제공되고 있는지를 점검하는 것은?', '["서비스 신청접수 및 방문상담", "서비스 제공 계획 수립", "서비스 이용 계획 체결", "서비스 제공", "모니터링 실시"]'::jsonb, 5, NULL, NULL, '{"1": "서비스 신청접수 및 방문상담: 서비스 제공을 위한 초기 단계입니다.", "2": "서비스 제공 계획 수립: 서비스 제공을 위한 계획을 만드는 과정입니다.", "3": "서비스 이용 계획 체결: 이용 계획을 공식적으로 체결하는 단계입니다.", "4": "서비스 제공: 실제 서비스를 제공하는 단계입니다.\n[정답]", "5": "모니터링 실시: 서비스 제공 후 대상자와 가족의 만족도를 점검하는 단계입니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적인 간호와 요양이 필요한 사람을 위한 서비스", "def_vi": "Dịch vụ dành cho những người cần chăm sóc và điều dưỡng lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (681, '2', '개인별장기요양이용계획서에 기록되지 않는 것은?', '["인정유효기간", "월 한도액", "수급자 희망급여", "급여의 종류와 횟수", "수급자의 월 수입액"]'::jsonb, 5, NULL, NULL, '{"1": "인정유효기간은 장기 요양 서비스 제공에 필요한 기간을 나타내기 때문에 기록되어야 합니다.\n[정답]", "5": "수급자의 월 수입액은 개인별 장기 요양 이용 계획서에 기록되지 않습니다.", "2": "월 한도액은 서비스 이용 시 상한선을 나타내므로 기록되어야 합니다.", "3": "수급자 희망급여는 수급자가 원하는 서비스를 나타내므로 기록되어야 합니다.", "4": "급여의 종류와 횟수는 어떤 서비스를 얼마나 받을지를 나타내므로 기록되어야 합니다."}'::jsonb, '[{"term_ko": "개인별", "term_vi": null, "def_ko": "개인에 대한", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (680, '2', '대상자의 등급에 따른 한도액과 본인부담률, 급여의 종류와 횟수 등 대상자와 가족들이 적절히 장기요양서비스를 이용할 수 있도록 돕기 위한 안내서는?', '["장기요양인정서", "개인별장기요양이용계획서", "장기요양평가서", "국민건강보험증", "모니터링기록지"]'::jsonb, 2, NULL, NULL, '{"1": "장기요양인정서는 장기요양급여를 받을 수 있는 자격을 인증하는 문서입니다.\n[정답]", "2": "개인별장기요양이용계획서는 장기요양 서비스 이용을 위한 세부 계획을 제시하며, 대상자와 가족이 필요한 정보를 얻을 수 있습니다.", "3": "장기요양평가서는 대상자의 건강 상태나 필요를 평가하는 문서입니다.", "4": "국민건강보험증은 건강보험의 자격을 증명하는 카드로, 장기요양서비스와는 직접적인 연관이 없습니다.", "5": "모니터링기록지는 서비스 제공 후의 상태를 기록하는 문서입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người hưởng lợi", "def_ko": "환자 또는 수혜자", "def_vi": "bệnh nhân hoặc người nhận hỗ trợ"}, {"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기 요양지원 서비스", "def_vi": "dịch vụ hỗ trợ chăm sóc dài hạn"}, {"term_ko": "본인부담률", "term_vi": "Tỷ lệ tự chi trả", "def_ko": "본인이 부담해야 하는 비용 비율", "def_vi": "tỷ lệ chi phí mà người hưởng lợi phải chi trả"}, {"term_ko": "한도액", "term_vi": "Giới hạn số tiền", "def_ko": "최대 금액", "def_vi": "số tiền tối đa"}, {"term_ko": "안내서", "term_vi": "Tài liệu hướng dẫn", "def_ko": "사용 설명서", "def_vi": "tài liệu chỉ dẫn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (679, '2', '장기요양인정 등급판정결과에 이의가 있는 경우 통보를 받은 날로부터 며칠 내에 공단에 증명서류를 제출하는가?', '["15일", "30일", "45일", "60일", "90일"]'::jsonb, 5, NULL, NULL, '{"1": "15일은 이의 제기 기간이 아닙니다.\n[정답]", "5": "90일 내에 공단에 증명서류를 제출해야 합니다.", "2": "30일은 이의 제기 기간이 아닙니다.", "3": "45일은 틀린 정보입니다.", "4": "60일 또한 이의 제기에 대한 규정이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 사람에 대한 공식적인 인정", "def_vi": "Sự công nhận chính thức cho những người cần chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (678, '2', '다음 ( ) 안에 들어갈 내용은?장기요양보험료를 ( ) 이상 납부하지 아니하면 장기요양급요를 받을 수 없다.', '["1회", "2회", "3회", "4회", "5회"]'::jsonb, 4, NULL, NULL, '{"1": "1회 이상 납부는 장기요양급여를 받을 수 있는 조건이 아니다.\n[정답]", "4": "4회 이상 납부해야 장기요양급여를 받을 수 있다.", "2": "2회 이상 납부는 기준에 미달한다.", "3": "3회 이상 납부 역시 기준에 미달한다.", "5": "5회 이상 납부하면 조건을 초과한 것이므로 부적절하다."}'::jsonb, '[{"term_ko": "장기요양보험료", "term_vi": "Bảo hiểm chăm sóc dài hạn", "def_ko": "장기요양 서비스를 위한 보험료", "def_vi": "Phí bảo hiểm cho dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (677, '2', '장기요양인정의 갱신신청을 하고자 할 경우 올바른 신청 기간은?', '["유효기간이 만료되기 60일 전부터 30일 전까지", "유효기간이 만료된 후 30일 전부터 60일 까지", "유효기간이 만료된 후 30일 전부터 90일 까지", "유효기간이 만료되기 90일 전부터 60일 전까지", "유효기간이 만료되기 90일 전부터 30일 전까지"]'::jsonb, 5, NULL, NULL, '{"1": "유효기간이 만료되기 60일 전부터 30일 전까지는 틀린 정보입니다. 갱신 신청은 만료 전 90일 이내에 해야 합니다.\n[정답]", "5": "유효기간이 만료되기 90일 전부터 30일 전까지가 맞습니다. 이 기간 내에 신청해야 갱신이 가능합니다.", "2": "유효기간이 만료된 후 30일 전부터 60일 까지는 잘못된 정보입니다. 만료 후에는 갱신이 불가능합니다.", "3": "유효기간이 만료된 후 30일 전부터 90일 까지도 틀린 정보입니다.", "4": "유효기간이 만료되기 90일 전부터 60일 전까지는 잘못된 내용입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc lâu dài", "def_ko": "장기요양 서비스 제공을 위해 필요한 인증", "def_vi": "Chứng nhận cần thiết để cung cấp dịch vụ chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (676, '2', '장기요양인정서에 기재하는 내용으로 옳은 것은?', '["이용가능 한도액", "장기요양급여의 종류 및 내용", "수급자 희망급여", "수급자의 주요 기능상태", "본인부담금"]'::jsonb, 2, NULL, NULL, '{"1": "이용가능 한도액은 장기요양급여의 재정적 측면에 해당하지만, 장기요양인정서에는 기재되지 않습니다.\n[정답]", "2": "장기요양급여의 종류 및 내용은 장기요양인정서에 필수적으로 기재되어야 하는 내용입니다.", "3": "수급자 희망급여는 신청서와 관련이 있지만, 인정을 받는 서류에는 포함되지 않습니다.", "4": "수급자의 주요 기능상태는 보통 평가에 포함되지만, 인정을 받는 구조에는 기재되지 않습니다.", "5": "본인부담금은 장기요양 급여와 관련된 내용이지만, 장기요양인정서에는 포함되지 않습니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적 지원이 필요한 노인이나 장애인을 위한 요양 서비스", "def_vi": "Dịch vụ chăm sóc cho người già hoặc người khuyết tật cần hỗ trợ lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (675, '2', '등급 판정 후 수급자가 서비스르 제공받을 때 제시해야 하는 것은?', '["모니터링기록지", "국민건강보험증", "장기요양인정서", "장기요양평가서", "장기요양이용계획서"]'::jsonb, 3, NULL, NULL, '{"1": "모니터링기록지는 서비스 제공 후 상태를 체크하는 용도이므로, 서비스 제공 전에 제시할 필요는 없음.\n[정답] (③) 장기요양인정서는 서비스 제공을 받기 위해 필수적으로 제시해야 하는 서류임.", "2": "국민건강보험증은 일반적인 의료 서비스에 필요하지만, 장기요양 서비스에는 직접적으로 무관함.", "4": "장기요양평가서는 평가 과정에서 작성되나, 서비스 제공 시 제시해야 하는 서류는 아님.", "5": "장기요양이용계획서는 서비스 제공 계획을 설명하는 문서이나, 공식적으로 제시해야 하는 서류는 아닌 경우가 많음."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (674, '2', '장기요양등급, 유효기간 등 수급자가 장기요양서비스를 제공받을 때 필요한 안내사항이 기재되어 있는 것은?', '["모니터링기록표", "장기요양인정서", "방문간호지시서", "요양보호기록지", "개인별장기요양이용계획서"]'::jsonb, 2, NULL, NULL, '{"1": "모니터링기록표: 수급자의 상태를 지속적으로 기록하는 표로, 안내사항과는 다소 관련이 없다.\n[정답]", "2": "장기요양인정서: 수급자가 어떤 장기요양서비스를 받을 수 있는지를 명시한 공식 문서로, 안내사항을 포함하고 있다.", "3": "방문간호지시서: 방문간호사가 수급자에게 필요한 치료내용에 대한 지시사항으로, 안내사항과는 다소 관련이 없다.", "4": "요양보호기록지: 요양보호사가 수급자의 일일 상태를 기록하는 지표로, 안내사항이 기재되지는 않는다.", "5": "개인별장기요양이용계획서: 수급자의 이용계획을 담은 문서이나, 직접적인 안내사항이 포함되지는 않는다."}'::jsonb, '[{"term_ko": "장기요양등급", "term_vi": "장기요양서비스", "def_ko": "등급 phân loại dịch vụ chăm sóc dài hạn", "def_vi": "dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (673, '2', '등급판정을 받은 장기요양인정자의 서비스이용 신청 절차로 옳은 것은?가. 서비스신청 접수 및 받문 상담 나. 서비스제공 다. 서비스제공 계획 수립 라. 서비스이용 계약 체결 마. 모니터링 실시', '["가 - 나 - 다 - 라 - 마 - 바", "나 - 가 - 다 - 마 - 라 - 바", "다 - 가 - 나 - 라 - 마 - 바", "가 - 다 - 라 - 나 - 마 - 바", "라 - 가 - 나 - 다 - 마 - 바"]'::jsonb, 4, NULL, NULL, '{"1": "서비스 신청이 접수되어야 제반 상담이 이루어질 수 있지만, 순서가 잘못되어 있습니다.", "2": "서비스 제공은 그 후에 진행될 주체적 활동이므로 올바른 순서가 아닙니다.", "3": "모든 단계가 후속 조치에 대한 착각이 있습니다.  \n[정답]", "4": "서비스 신청 접수 후 상담이 실시되고, 이후 서비스 제공 계획이 수립되며, 계약 체결 후 모니터링이 이루어지는 순서가 맞습니다.", "5": "계약 체결이 신청 접수보다 먼저 이루어질 수는 없습니다."}'::jsonb, '[{"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준(한국어)", "def_vi": "Mức độ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (672, '2', '다음 설명 중 ( ) 안에 들어갈 내용으로 옳은 것은?', '["15% 20%", "15% 10%", "20% 15%", "10% 7.5%", "7.5% 10%"]'::jsonb, 3, NULL, NULL, '{"1": "15%와 20%의 비율은 질문과 관련이 없음.\n[정답]", "3": "20%와 15%의 비율은 질문에 적합한 설명입니다.", "2": "15%와 10%의 비율은 부적합합니다.", "4": "10%와 7.5%의 비율은 질문과 맞지 않습니다.", "5": "7.5%와 10%의 비율 역시 부적합합니다."}'::jsonb, '[{"term_ko": "비율", "term_vi": "Tỷ lệ", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (671, '2', '장기요양보험의 재원조달에 대한 설명으로 옳은 것은?', '["공단은 장기요양보험료와 건강보험료를 별도로 징수한다.", "국가는 보험료 예상 수입액의 80%를 부담한다.", "재원은 장기요양보험료, 국가지원, 본인부담금으로 구성된다.", "저소득층, 의료급여 수급권자 등은 본인부담금의 20%를 경감해 준다.", "비급여 항목은 전액 국가가 부담한다."]'::jsonb, 3, NULL, NULL, '{"1": "공단은 장기요양보험료와 건강보험료를 별도로 징수한다. (장기요양보험료와 건강보험료는 통합 징수됩니다.)\n[정답]", "3": "재원은 장기요양보험료, 국가지원, 본인부담금으로 구성된다. (정확한 설명입니다.)", "2": "국가는 보험료 예상 수입액의 80%를 부담한다. (국가의 부담 비율은 다릅니다.)", "4": "저소득층, 의료급여 수급권자 등은 본인부담금의 20%를 경감해 준다. (정확한 경감 비율이 아닙니다.)", "5": "비급여 항목은 전액 국가가 부담한다. (비급여 항목은 개인이 부담합니다.)"}'::jsonb, '[{"term_ko": "장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn", "def_ko": "장기적인 요양 필요를 위한 보험", "def_vi": "Bảo hiểm cho nhu cầu chăm sóc lâu dài"}, {"term_ko": "재원", "term_vi": "Nguồn tài chính", "def_ko": "자금을 조달하는 방법", "def_vi": "Phương pháp thu tài chính"}, {"term_ko": "국가지원", "term_vi": "Hỗ trợ của nhà nước", "def_ko": "국가에서 지원하는 금액", "def_vi": "Số tiền hỗ trợ từ nhà nước"}, {"term_ko": "본인부담금", "term_vi": "Tiền tự chi trả", "def_ko": "개인이 부담해야 하는 금액", "def_vi": "Số tiền cá nhân phải chi trả"}, {"term_ko": "비급여", "term_vi": "Không được hưởng bảo hiểm", "def_ko": "보험 적용이 안 되는 항목", "def_vi": "Các hạng mục không nằm trong bảo hiểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (670, '2', '다음 중 노인장기요양보험제도에 대한 설명으로 옳은 것은?', '["장기요양기고나은 장기요양급여를 제공한 후 국민건강보험공단에 비용을 청구한다.", "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다.", "시설급여는 15%, 재가급여는 20%를 본인이 부담한다.", "유효기간 갱신 시 직전등급과 같은 2등급일 경우 유효기간 4년이다.", "국민기초생활수급권자는 본인이 50%를 부담한다."]'::jsonb, 1, NULL, NULL, '{"1": "장기요양기관에서 장기요양급여를 제공한 후 국민건강보험공단에 비용을 청구하게 되며, 이는 맞는 설명입니다.\n[정답]", "2": "국민건강보험공단은 급여비용을 연 1회가 아닌 매월 장기요양기관에 지급합니다.", "3": "시설급여와 재가급여에 대한 본인 부담률은 다르지만, 시설급여 15%, 재가급여 20%는 틀린 정보입니다.", "4": "유효기간 갱신 시 직전등급이 2등급일 경우 4년이 아닌 3년입니다.", "5": "국민기초생활수급권자는 본인 부담이 발생하지 않으며, 0%로 부담하는 것이 맞습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자를 위한 장기요양 지원 프로그램", "def_vi": "Chương trình hỗ trợ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (669, '2', '다음 중 방문목욕을 제공하는 장기요양요원으로 옳은 것은?', '["간호사", "사회복지사", "간호조무사", "요양보호사", "물리치료사"]'::jsonb, 4, NULL, NULL, '{"1": "간호사는 전문적인 의료 서비스를 제공하지만 방문목욕은 포함되지 않습니다.\n[정답]", "4": "요양보호사는 방문목욕을 포함하여 여러 가지 요양서비스를 제공할 수 있는 자격을 가지고 있습니다.", "2": "사회복지사는 주로 상담 및 지원 서비스를 제공하며, 신체적인 목욕 서비스는 담당하지 않습니다.", "3": "간호조무사는 간호사 보조 업무를 수행하지만 방문목욕은 주된 업무가 아닙니다.", "5": "물리치료사는 재활 치료를 수행하지만 직접적인 목욕 서비스를 제공하지 않습니다."}'::jsonb, '[{"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "가정에서 이루어지는 목욕 서비스", "def_vi": "Dịch vụ tắm thực hiện tại nhà"}, {"term_ko": "장기요양요원", "term_vi": "Nhân viên chăm sóc dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc lâu dài"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양과 돌봄을 전문으로 하는 직원", "def_vi": "Nhân viên chuyên về chăm sóc và hỗ trợ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (668, '2', '수급자가 장기요양기관이 아닌 노인요양시설 등의 기관 도는 시설에서 장기요양급여를 받은 경우 수급자에게 지급되는 현금급여는?', '["가족요양비", "특례요양비", "요양병원 간병비", "방문요양비", "장해급여비"]'::jsonb, 2, NULL, NULL, '{"1": "가족요양비: 가족이 수급자를 돌보는 경우 지급되는 비용이다.\n[정답]", "2": "특례요양비: 장기요양기관이 아닌 시설에서 제공되는 요양급여에 대한 지급으로, 노인요양시설 등에서 받는 경우 적용된다.", "3": "요양병원 간병비: 요양병원에서 간병 서비스를 제공받을 때 소요되는 비용이다.", "4": "방문요양비: 방문 요양 서비스를 제공받을 때 지급되는 비용이다.", "5": "장해급여비: 장애인에 대한 특별한 지원금을 의미한다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "요양급여를 받는 사람", "def_vi": "Người nhận trợ cấp chăm sóc"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기관", "def_vi": "Nơi cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "현금급여", "term_vi": "Trợ cấp tiền mặt", "def_ko": "현금 형태로 지급되는 지원금", "def_vi": "Khoản hỗ trợ tiền mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (667, '2', '장기요양기관이 없는 외딴 섬에 살고 있는 대상자가 며느리로부터 방문요양에 상당하는 장기요양급여를 받았다. 이때 지급되는 특별현금급여는?', '["재가급여", "시설급여", "가족요양비", "특례요양비", "요양병원 간병비"]'::jsonb, 3, NULL, NULL, '{"1": "재가급여는 장기요양기관이 아닌 개인에게 지급되는 요양 서비스입니다.\n[정답]", "3": "가족요양비는 가족이 직접 요양을 제공하는 경우 지급되는 특별현금급여입니다.", "2": "시설급여는 기관에 입소해 요양을 받는 경우에 해당합니다.", "4": "특례요양비는 특정 조건에 따라 지급되는 요양비입니다.", "5": "요양병원 간병비는 병원에서 발생하는 간병비와 관련이 있습니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}, {"term_ko": "특별현금급여", "term_vi": "Trợ cấp tiền mặt đặc biệt", "def_ko": "특별한 조건에서 지급되는 현금 지원", "def_vi": "Hỗ trợ tiền mặt được trả trong các trường hợp đặc biệt"}, {"term_ko": "가족요양비", "term_vi": "Chi phí chăm sóc gia đình", "def_ko": "가족이 제공하는 요양에 대한 지급", "def_vi": "Khoản thanh toán cho việc chăm sóc của gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (666, '2', '수급자의 일상생활, 신체활동 지원에 필요한 복지용구를 제공하는 장기요양급여는?', '["가족요양급여", "단기보호 급여", "방문요양 급여", "주, 야간보호 급여", "기타 재가급여"]'::jsonb, 5, NULL, NULL, '{"1": "가족요양급여: 가족이 수급자를 돌보는 경우에 제공되는 급여로, 복지용구에 대한 직접적인 지원이 아님.\n[정답]", "5": "기타 재가급여: 수급자의 일상생활과 신체활동을 지원하기 위해 필요한 복지용구를 제공하는 장기요양급여를 포함하는 개념.", "3": "방문요양 급여: 직접적인 방문을 통해 서비스를 제공하지만 복지용구와는 관련이 적음.", "4": "주, 야간보호 급여: 주간 또는 야간에 보호 서비스를 제공하는 것으로 복지용구의 제공과는 직접적으로 연결되지 않음.", "2": "단기보호 급여: 제한된 기간 동안 보호하는 프로그램으로, 장기요양급여의 일환일 수 있으나 복지용구 지원과는 거리가 있음."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "요양이나 재활 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc hoặc phục hồi chức năng"}, {"term_ko": "복지용구", "term_vi": "Dụng cụ phúc lợi", "def_ko": "신체활동을 돕기 위한 도구", "def_vi": "Công cụ hỗ trợ hoạt động thể chất"}, {"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 요양 관련 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "매일의 기본 활동", "def_vi": "Các hoạt động cơ bản hàng ngày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (665, '2', '요양보호사가 할 수 없는 업무는 무엇인가?', '["방문목욕", "신체활동지원", "방문간호", "정서지원, 의사소통", "가사 및 일상생활지원"]'::jsonb, 3, NULL, NULL, '{"1": "방문목욕은 요양보호사가 수행할 수 있는 업무이다.", "2": "신체활동지원은 요양보호사의 주요 업무 중 하나이다.\n[정답]", "3": "방문간호는 의료 행위로, 요양보호사가 수행할 수 없는 업무이다.", "4": "정서지원 및 의사소통은 요양보호사가 수행할 수 있는 업무이다.", "5": "가사 및 일상생활지원도 요양보호사의 업무에 포함된다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문 직업인", "def_vi": "Người chuyên chăm sóc bệnh nhân"}, {"term_ko": "업무", "term_vi": "Công việc", "def_ko": "직무, 사무", "def_vi": "Nhiệm vụ"}, {"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "집에서 목욕을 도와주는 서비스", "def_vi": "Dịch vụ giúp tắm tại nhà"}, {"term_ko": "신체활동지원", "term_vi": "Hỗ trợ hoạt động cơ thể", "def_ko": "신체 활동을 돕는 것", "def_vi": "Giúp đỡ các hoạt động thể chất"}, {"term_ko": "방문간호", "term_vi": "Chăm sóc tại nhà", "def_ko": "환자의 집에서 전문 간호를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc sức khỏe tại nhà"}, {"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정적인 지지를 제공하는 것", "def_vi": "Cung cấp sự hỗ trợ về cảm xúc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "의사전달과 관련된 활동", "def_vi": "Hoạt động liên quan đến giao tiếp"}, {"term_ko": "가사", "term_vi": "Công việc nhà", "def_ko": "집안일과 관련된 활동", "def_vi": "Các hoạt động liên quan đến công việc gia đình"}, {"term_ko": "일상생활지원", "term_vi": "Hỗ trợ sinh hoạt hàng ngày", "def_ko": "일상 생활에서 필요한 지원", "def_vi": "Sự hỗ trợ cần thiết trong cuộc sống hàng ngày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (664, '2', '대상자의 가정을 방문하여 신체활동과 가사활동 등의 서비스를 제공하는 재가급여를 무엇이라 하는가?', '["방문요양", "방문목욕", "방문간호", "단기보호", "주-야간보호"]'::jsonb, 1, NULL, NULL, '{"1": "방문요양: 가정에서 신체활동과 가사활동 등의 서비스를 제공하는 재가급여의 대표적인 형태이다.\n[정답]", "2": "방문목욕: 목욕 서비스를 전문적으로 제공하는 형태로, 신체활동의 일부일 수 있으나 재가급여 전체를 포괄하지 않는다.", "3": "방문간호: 간호 서비스를 제공하는 형태로, 물리적인 신체활동과 가사활동을 포함하지 않는다.", "4": "단기보호: 일정 기간 동안 보호를 필요로 하는 대상자를 위한 서비스로, 재가급여의 범위를 벗어난다.", "5": "주-야간보호: 정해진 시간 동안의 보호 서비스를 제공하나, 주로 시설 내에서 제공된다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 혹은 보호를 받는 사람", "def_vi": "Bệnh nhân hoặc người được bảo trợ"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thân thể", "def_ko": "신체의 움직임과 관련된 활동", "def_vi": "Các hoạt động liên quan đến sự di chuyển của cơ thể"}, {"term_ko": "가사활동", "term_vi": "Hoạt động gia đình", "def_ko": "집안일을 포함하는 활동", "def_vi": "Các hoạt động bao gồm công việc trong gia đình"}, {"term_ko": "재가급여", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "가정에서 제공되는 사회복지 서비스", "def_vi": "Dịch vụ phúc lợi xã hội cung cấp tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (663, '2', '대상자를 하루 중 일정 시간 동안 장기요양기관에 보호하여 신체활동 지원 등을 제공하는 장기요양급여는?', '["주-야간보호", "단기보호", "특례요양급여", "가족요양급여", "요양병원 간병급여"]'::jsonb, 1, NULL, NULL, '{"1": "주-야간보호는 대상자가 하루 중 일정 시간에 보호를 받을 수 있는 장기요양급여입니다.\n[정답]", "2": "단기보호는 일정 기간 동안 일시적으로 제공되는 서비스입니다.", "3": "특례요양급여는 특별한 경우에 제공되는 요양급여입니다.", "4": "가족요양급여는 가족이 보호자의 역할을 수행하는 경우의 급여입니다.", "5": "요양병원 간병급여는 병원에서 간병을 제공받는 것과 관련된 급여입니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기간 요양 서비스를 제공하는 기관", "def_vi": "Tổ chức cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "신체의 움직임과 활동", "def_vi": "Sự chuyển động và hoạt động của cơ thể"}, {"term_ko": "주-야간보호", "term_vi": "Chăm sóc ngày và đêm", "def_ko": "낮과 밤에 제공되는 보호 서비스", "def_vi": "Dịch vụ bảo vệ cả ban ngày và ban đêm"}, {"term_ko": "단기보호", "term_vi": "Chăm sóc ngắn hạn", "def_ko": "짧은 기간 동안 제공되는 보호 서비스", "def_vi": "Dịch vụ bảo vệ được cung cấp trong thời gian ngắn"}, {"term_ko": "가족요양급여", "term_vi": "Trợ cấp chăm sóc gia đình", "def_ko": "가족이 제공하는 요양 서비스", "def_vi": "Dịch vụ chăm sóc do gia đình cung cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (662, '2', '다음 재가급여의 내용 중 옳은 것은?', '["방문요양: 재가 대상자의 기능 유지를 위한 복지용구를 제공한다.", "방문간호; 수급자를 방문하여 신체활동 및 가사활동을 지원한다.", "방문목욕: 수급자의 가정 등을 방문하여 목욕을 제공한다.", "단기보호: 장기요양기관에 장기간 입소하여 보호한다.", "주-야간보호: 일정기간 동안 장기요양기관에 보호하여 신체활동을 지원한다."]'::jsonb, 3, NULL, NULL, '{"1": "방문요양: 복지용구 제공은 포함되지 않으며, 주로 신체활동 지원을 목적으로 함.\n[정답]", "3": "방문목욕: 수급자의 가정에 방문하여 목욕을 제공하는 것이 옳음.", "2": "방문간호: 신체활동 지원이 아닌 의료적 간호 서비스를 제공함.", "4": "단기보호: 장기간이 아닌 단기간의 보호 서비스임.", "5": "주-야간보호: 주-야간 보호는 일정 기간 동안 보호하는 것이 아닌, 주간/야간에 제공되는 보호 서비스임."}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Dịch vụ hỗ trợ tại nhà", "def_ko": "가정에서 제공되는 복지 서비스", "def_vi": "Dịch vụ phúc lợi được cung cấp tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (661, '2', '장기요양급여 중 시설급여의 장점으로 옳은 것은?', '["개인중심의 생활을 할 수 있다.", "사생활이 보호된다.", "친숙한 환경에서 지낼 수 있다.", "종합적인 서비스를 받을 수 있다.", "재가급여보다 본인부담금이 저렴하다."]'::jsonb, 4, NULL, NULL, '{"1": "개인중심의 생활을 할 수 있다. - 시설급여는 주로 관리와 돌봄이 필요할 때 제공되므로 개인중심의 생활이 제한될 수 있다.\n[정답]", "4": "종합적인 서비스를 받을 수 있다. - 시설급여는 다양한 서비스를 통합적으로 제공하여, 복합적인 필요에 대응하는 것이 장점이다.", "3": "친숙한 환경에서 지낼 수 있다. - 시설급여는 종종 낯선 환경을 제공하므로 친숙하지 않을 수 있다.", "5": "재가급여보다 본인부담금이 저렴하다. - 본인부담금은 경우에 따라 다르므로 반드시 저렴하다고 할 수 없다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Bồi dưỡng dài hạn", "def_ko": "장기적으로 요양이 필요한 사람에게 제공되는 복지 급여", "def_vi": "Trợ cấp phúc lợi cung cấp cho những người cần chăm sóc dài hạn"}, {"term_ko": "시설급여", "term_vi": "Chăm sóc tại cơ sở", "def_ko": "시설에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại cơ sở"}, {"term_ko": "종합적인", "term_vi": "Tổng hợp", "def_ko": "여러 가지를 포괄하는", "def_vi": "Bao gồm nhiều điều"}, {"term_ko": "본인부담금", "term_vi": "Chi phí tự trả", "def_ko": "의료 서비스를 이용할 때 개인이 직접 부담해야 하는 비용", "def_vi": "Số tiền mà cá nhân phải tự chi trả khi sử dụng dịch vụ y tế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (660, '2', '장기요양급여 중 재가급여의 장점으로 옳은 것은?', '["의료, 간호, 요양서비스가 단편적으로 진행되기 쉽다.", "긴급한 상황에 대한 신속한 대응이 어렵다.", "평소 생활했던 친숙한 환경에서 지낼 수 있다.", "개인중심의 생활이 어렵다.", "의료, 간호, 요양서비스를 종합적으로 제공 받을 수 있다."]'::jsonb, 3, NULL, NULL, '{"1": "재가급여는 의료, 간호, 요양서비스가 통합적으로 제공되므로 단편적으로 진행되지 않습니다.", "2": "재가급여는 가정에서 이루어지기 때문에 긴급한 상황에 신속히 대응하기 어렵습니다.\n[정답]", "3": "재가급여는 환자가 평소 생활하던 환경에서 서비스를 받을 수 있어 정신적 안정을 제공합니다.", "4": "재가급여는 개인중심의 생활을 가능하게 합니다.", "5": "재가급여는 의료, 간호, 요양서비스를 통합적으로 제공하지 않는 경우도 있습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 환자에게 제공되는 서비스", "def_vi": "Dịch vụ dành cho bệnh nhân cần chăm sóc lâu dài"}, {"term_ko": "재가급여", "term_vi": "Chăm sóc tại nhà", "def_ko": "집에서 이루어지는 요양 서비스", "def_vi": "Dịch vụ chăm sóc diễn ra tại nhà"}, {"term_ko": "의료", "term_vi": "Y tế", "def_ko": "치료와 관련된 서비스", "def_vi": "Dịch vụ liên quan đến chăm sóc sức khỏe"}, {"term_ko": "간호", "term_vi": "Điều dưỡng", "def_ko": "환자의 상태를 살피고 간호하는 서비스", "def_vi": "Dịch vụ chăm sóc và theo dõi tình trạng bệnh nhân"}, {"term_ko": "요양서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "진료 이외의 서비스", "def_vi": "Dịch vụ không thuộc điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (659, '2', '다음의 서비스를 포함하는 장기요양급여 종류는?•방문간호 •단기보호 •주-야간보호', '["재가급여", "시설급여", "간병급여", "퇴직급여", "요양급여"]'::jsonb, 1, NULL, NULL, '{"1": "재가급여는 방문간호, 단기보호, 주-야간보호 등과 같은 서비스를 포함합니다.\n[정답]", "2": "시설급여는 시설에서 제공하는 요양 서비스를 포함하지만, 문제의 서비스와는 관련이 없습니다.", "3": "간병급여는 주로 간병인을 통한 개별적인 간호 서비스를 의미하며, 방문간호 등은 포함되지 않습니다.", "4": "퇴직급여는 근로자가 퇴직 후 받는 급여로, 요양급여와는 차별적입니다.", "5": "요양급여는 일반적으로 요양을 제공받기 위한 총체적인 개념으로, 특정 서비스의 종류가 아닙니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기초 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (658, '2', '노인장기요양보험제도의 설명으로 옳은 것은?', '["고용노동부 장관이 관장한다.", "보험급여에는 재가급여, 시설급여, 특별현금급여가 있다.", "독거노인은 장기요양인정등급이 없어도 수급자가 된다,", "신청일로부터 20일 이내에 등급판정을 완료한다.", "장기요양인정 여부 및 등급은 방문조사자가 최종 판정한다."]'::jsonb, 2, NULL, NULL, '{"1": "고용노동부가 아닌 보건복지부가 관장합니다.\n[정답]", "2": "재가급여, 시설급여, 특별현금급여가 포함됩니다.", "3": "독거노인은 장기요양인정등급을 받아야 수급자가 됩니다.", "4": "신청일로부터 20일 이내에 등급판정이 완료되는 것은 아닙니다.", "5": "방문조사자의 판단만으로는 최종 판정이 이루어지지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Hệ thống bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인의 장기요양에 대한 보험 제도", "def_vi": "Hệ thống bảo hiểm cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (657, '2', '2022년 9월에 1등급 판정을 받고, 2024년 9월에 다시 1등급을 받은 대상자의 장기요양인정 유효기간은 몇 년인가?', '["1년", "2년", "3년", "4년", "5년"]'::jsonb, 4, NULL, NULL, '{"1": "1년: 1등급 판정을 받은 시점에서 1년의 유효기간은 불가능합니다.\n[정답]", "4": "4년: 2022년 9월에 1등급을 받고, 2024년 9월에 다시 1등급을 받으면 유효기간은 4년입니다.", "3": "3년: 3년은 해당 사항이 아닙니다.", "2": "2년: 2년도 기간이 아닙니다.", "5": "5년: 5년은 과도한 기간으로 잘못된 답변입니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간 동안 요양이 필요한 상태", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (656, '2', '장기요양인정 신청을 하여 최초로 등급판정을 받았을 때, 장기요양 인정 최소 유효기간은?', '["6개월 이상", "1년 이상", "2년 이상", "3년 이상", "5년 이상"]'::jsonb, 3, NULL, NULL, '{"1": "6개월은 장기요양인정의 최소 유효기간이 아닙니다.", "2": "1년도 최소 유효기간에 해당하지 않습니다.\n[정답]", "3": "최초로 등급판정을 받을 경우, 최소 유효기간은 2년 이상입니다.", "4": "3년은 장기요양 인정의 최소 유효기간이 아닙니다.", "5": "5년은 과도한 기간으로, 장기요양 인정의 최소 기간이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기요양을 필요로 하는 사람에게 주어지는 공식적인 인정", "def_vi": "Sự công nhận chính thức dành cho những người cần chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (655, '2', '장기요양인정 점수가 45점 미만인 경증치매 어르신이 받을 수 있는 장기요양 등급은?', '["1등급", "2등급", "3등급", "4등급", "인지지원등급"]'::jsonb, 5, NULL, NULL, '{"1": "1등급은 높은 지원이 필요한 경우 부여됩니다.", "2": "2등급은 중간 정도의 지원이 필요할 때 할당됩니다.", "3": "3등급은 경증의 지원이 필요할 경우 주어집니다.", "4": "4등급은 매우 낮은 점수의 경우에는 부여되지 않습니다.\n[정답]", "5": "인지지원등급은 경증치매 어르신이 받을 수 있는 등급입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Xác nhận chăm sóc dài hạn", "def_ko": "장기적 요양서비스를 받을 수 있는 자격", "def_vi": "Đủ điều kiện nhận dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (654, '2', '인지지능 장애로 치매 진단을 확인받고 장기요양인정점수가 45점 이상 51점 미만인 경우 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 5, NULL, NULL, '{"1": "1등급은 95점 이상인 경우에 해당하므로 틀립니다.", "2": "2등급은 61점 이상 70점 미만인 경우에 해당하므로 틀립니다.", "3": "3등급은 46점 이상 60점 미만인 경우에 해당하므로 틀립니다.\n[정답]", "4": "4등급은 41점 이상 45점 미만인 경우에 해당하므로 틀립니다.", "5": "5등급은 45점 이상 51점 미만인 경우에 해당하므로 정답입니다."}'::jsonb, '[{"term_ko": "인지지능", "term_vi": "Năng lực nhận thức", "def_ko": "인지능력이나 사고 능력(한국어)", "def_vi": "Khả năng tư duy và nhận thức"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 요양과 치료를 뜻함(한국어)", "def_vi": "Điều trị và chăm sóc lâu dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "단계나 수준(한국어)", "def_vi": "Cấp bậc hay mức độ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (653, '2', '장기요양 4등급에 대한 설명으로 옳은 것은?', '["일상생활에서 전적으로 다른 사람의 도움이 필요하다.", "자립이나 생활관리 능력 저하로 일정부분 도움이 필요하다.", "휠체어를 이용하여 일상생활을 유지한다.", "스스로 움직일 수 없는 와상 상태이다.", "낮에도 주로 침대에서 생활하는 경우가 많다."]'::jsonb, 2, NULL, NULL, '{"1": "일상생활에서 전적으로 다른 사람의 도움이 필요한 경우는 5등급에 해당합니다.\n[정답]", "2": "자립이나 생활관리 능력 저하로 일정부분 도움이 필요하다. 이는 4등급의 적절한 설명입니다.", "3": "휠체어를 이용해도 자립적인 움직임이 가능한 경우는 3등급에 해당할 수 있습니다.", "4": "스스로 움직일 수 없는 와상 상태는 5등급의 설명입니다.", "5": "낮에 침대에서 주로 생활하는 경우는 5등급에 해당하며, 4등급은 일정 부분 도움을 필요로 합니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 상태(한국어)", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "평가 기준에 의한 단계(한국어)", "def_vi": "Bậc theo tiêu chí đánh giá"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 기본적인 활동(한국어)", "def_vi": "Các hoạt động cơ bản thực hiện hàng ngày"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "스스로 생활할 수 있는 능력(한국어)", "def_vi": "Khả năng sống tự mình"}, {"term_ko": "생활관리", "term_vi": "Quản lý cuộc sống", "def_ko": "일상적인 생활을 관리하는 것(한국어)", "def_vi": "Quản lý cuộc sống hàng ngày"}, {"term_ko": "와상", "term_vi": "Nằm bất động", "def_ko": "누워서만 생활하는 상태(한국어)", "def_vi": "Trạng thái chỉ nằm không thể di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (652, '2', '대상자가 장기요양등급 판정 결과로 55점을 받았을 경우 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 4, NULL, NULL, '{"1": "1등급은 90점 이상으로 주어지며 해당되지 않습니다.", "2": "2등급은 75점 이상으로 주어지므로 해당되지 않습니다.", "3": "3등급은 60점 이상으로 해당되지 않습니다.\n[정답]", "4": "4등급은 55점으로 해당 등급입니다.", "5": "5등급은 50점 이하로 주어지므로 해당되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (651, '2', '장기요양 점수가 61점이며 일상생활에서 부분적으로 다른 사람의 도움이 필요한 대상자의 등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 3, NULL, NULL, '{"1": "1등급은 점수가 90점 이상인 대상자에게 해당합니다.\n[정답]", "3": "3등급은 점수가 60점에서 79점 사이인 대상자에게 해당하며, 일상생활에서 부분적인 도움이 필요합니다.", "2": "2등급은 점수가 80점에서 89점 사이인 경우에 해당합니다.", "4": "4등급은 점수가 40점에서 59점 사이인 경우입니다.", "5": "5등급은 점수가 39점 이하인 경우입니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간의 요양이 필요한 상태", "def_vi": "Trạng thái cần chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (650, '2', '장기요양등급 판정 시 다음 설명에 해당하는 대상자의 등급은?• 일상생활에서 부분적으로 다른 사람의 도움을 받아야 외출이 가능하다. • 휠체어를 통해 이동한다. • 장기요양인정점수가 65점이다.', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 3, NULL, NULL, '{"1": "1등급은 일상생활 전반에 걸쳐 전적인 도움이 필요한 경우에 해당합니다.", "2": "2등급은 하루에 5시간 미만으로 도움을 받는 경우에 해당합니다.\n[정답]", "3": "3등급은 부분적으로 다른 사람의 도움이 필요한 경우, 외출이 가능하지만 휠체어를 통해 이동하는 경우에 해당합니다.", "4": "4등급은 대체로 독립적인 생활이 가능한 상태에서 필요시 약간의 도움이 필요할 경우입니다.", "5": "5등급은 완전한 자립이 가능한 상황에 해당합니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc lâu dài", "def_ko": "장기간동안 요양이 필요한 상태", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (649, '2', '일상생활에서 상당 부분 다른 사람의 도움이 필요하며, 장기요양인정 점수가 75점인 대상자에게 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 2, NULL, NULL, '{"1": "1등급은 95점 이상일 때 해당됩니다.\n[정답]", "2": "2등급은 75점에서 94점 사이일 때 해당됩니다.", "3": "3등급은 60점에서 74점 사이일 때 해당됩니다.", "4": "4등급은 50점에서 59점 사이일 때 해당됩니다.", "5": "5등급은 49점 이하일 때 해당됩니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 필요한 요양 및 간호 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc và y tế cần thiết trong thời gian dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준이나 품질을 나타내는 기준", "def_vi": "Tiêu chí để thể hiện mức độ hoặc chất lượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (648, '2', '장기요양인정 점수가 95점 이상이며, 스스로 움직일 수 없는 와병 상태로 모든 활동에서 전적으로 다른 사람의 도움이 필요한 대상자의 등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 1, NULL, NULL, '{"1": "1등급은 장기요양인정 점수가 95점 이상이며, 모든 활동에서 전적으로 다른 사람의 도움이 필요한 상태입니다.\n[정답]", "2": "2등급은 75점 이상 95점 미만이며, 부분적인 도움을 필요로 하는 상태입니다.", "3": "3등급은 60점 이상 75점 미만으로, 독립적인 활동이 가능한 경우도 포함됩니다.", "4": "4등급은 48점 이상 60점 미만인 경우입니다.", "5": "5등급은 48점 미만인 경우로, 가장 낮은 등급입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc lâu dài", "def_ko": "장기적인 요양이 필요하다고 인정받은 상태", "def_vi": "Tình trạng được công nhận cần chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (647, '2', '다음 노인장기요양보험제도에 대한 설명 중 올바른 것은?', '["장기요양인정점수가 75점이면 장기요양 3등급을 받는다.", "장기요양인정점수가 52점이면 장기요양 4등급을 받는다.", "장기요양기관이 현저히 부족한 지역은 특례요양비를 지급한다.", "장기요양인정 유효기간은 최소 6개월이다.", "65세 이상의 노인만을 대상자로 한다."]'::jsonb, 2, NULL, NULL, '{"1": "장기요양인정점수는 75점일 경우 2등급에 해당합니다.\n[정답]", "2": "장기요양인정점수가 52점이면 장기요양 4등급을 받습니다.", "3": "장기요양기관이 부족한 지역에서 특례요양비가 지급되는 것은 맞지 않습니다.", "4": "장기요양인정 유효기간은 최소 12개월입니다.", "5": "65세 이상의 노인뿐만 아니라 65세 미만의 장애인도 대상자가 될 수 있습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người già", "def_ko": "노인을 위한 장기요양 보험 제도", "def_vi": "Chế độ bảo hiểm phục vụ người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (646, '2', '노인장기요양보험 인정 절차에 관한 설명으로 옳은 것은?', '["의사소견서를 첨부하여 장기요양기관에 장기요양인정을 신청한다.", "국민건강보험공단은 조사결과서를 등급판정위원회에 제출한다.", "보건복지부는 1차 판정 결과를 심의하여 장기요양 등급을 최종 판정한다.", "지자체는 장기요양인정서를 국민건강보험공단에 제출한다.", "장기요양인정 점수에 따라 10등급으로 나뉜다."]'::jsonb, 2, NULL, NULL, '{"1": "장기요양인정 신청은 의사소견서를 첨부해야 하나, 신청 주체는 장기요양기관이 아닌 개인이나 가족이다.\n[정답]", "2": "국민건강보험공단은 조사결과서를 등급판정위원회에 제출하는 절차가 맞다.", "3": "보건복지부는 등급판정 결과를 심의하지만 최종 등급 판정은 국민건강보험공단이 한다.", "4": "장기요양인정서는 국민건강보험공단에 제출하는 것이 아니라 해당 개인에게 발급된다.", "5": "장기요양인정 점수에 따라 등급은 1~5등급으로 나뉘고, 10등급은 존재하지 않는다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "장기요양보험", "def_ko": "노인이란 나이가 든 사람, 특히 65세 이상의 사람을 말한다.(người già)", "def_vi": "장기적인 요양과 돌봄을 위한 보험 제도.(bảo hiểm chăm sóc dài hạn)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (645, '2', '다음 중 노인장기요양인정 신청 및 판정절차로 옳은 것은?', '["65세 미만 노인성 질병 대상자는 의사소견서를 첨부하여 공단에 신청한다.", "방문조사는 교육을 이수한 장기요양기관 직원이 한다.", "개인별장기요양이용계획서는 공단이 장기요양기관에 제공한다.", "장기요양인정 신청은 본인만 가능하다.", "장기요양인정 점수가 60점이면 장기요양 4등급을 받는다."]'::jsonb, 1, NULL, NULL, '{"1": "65세 미만 노인성 질병 대상자는 의사소견서를 첨부하여 공단에 신청한다. [정답] 이는 정확한 절차로, 65세 미만 한국 노인성 질병에 대한 신청이 올바르게 반영됩니다.", "2": "방문조사는 교육을 이수한 장기요양기관 직원이 한다. 이는 사실이지만, 방문조사는 공단에서 검증하는 과정관리가 필요한 절차입니다.", "3": "개인별장기요양이용계획서는 공단이 장기요양기관에 제공한다. 개인별 계획서는 장기요양기관이 제출해야 합니다.", "4": "장기요양인정 신청은 본인만 가능하다. 이는 잘못된 정보로, 대리 신청도 가능합니다.", "5": "장기요양인정 점수가 60점이면 장기요양 4등급을 받는다. 이는 사실이 아닌 정보로, 60점은 3등급 해당입니다."}'::jsonb, '[{"term_ko": "노인장기요양", "term_vi": "Đánh giá dài hạn người cao tuổi", "def_ko": "노인장기요양", "def_vi": "Chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (644, '2', '등급 판정기준에 따라 심의에 필요한 자료를 검토하여 장기요양등급을 최종 판정하는 곳은?', '["장기요양위원회", "국민연금위원회", "등급판정위원회", "장애판정위원회", "건강보험심사평가원"]'::jsonb, 3, NULL, NULL, '{"1": "장기요양위원회는 정책 결정 기관으로 심의에 참여하나 최종 판정은 하지 않습니다.\n[정답]", "3": "등급판정위원회는 심의에 필요한 자료를 바탕으로 장기요양등급을 최종 판정합니다.", "2": "국민연금위원회는 국민연금 관련 업무를 담당합니다.", "4": "장애판정위원회는 장애인 판정을 담당하는 기관입니다.", "5": "건강보험심사평가원은 건강보험 관련 업무를 하지만 장기요양등급 판정과는 무관합니다."}'::jsonb, '[{"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "등급(한국어)", "def_vi": "Cấp độ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (643, '2', '장기요양인정 신청 시 가정에 방문하여 신청인의 심신상태를 조사하는 기관은?', '["보건소", "주민 센터", "근로복지공단", "고용보험공단", "국민건강보험공단"]'::jsonb, 5, NULL, NULL, '{"1": "보건소는 기본적인 보건 서비스를 제공하지만, 장기요양인정 신청과 직접적으로 관련이 없습니다.", "2": "주민 센터는 지역 주민의 복지 서비스를 지원하지만, 심신상태 조사는 하지 않습니다.", "3": "근로복지공단은 근로자와 관련된 복지 업무를 담당합니다.", "4": "고용보험공단은 고용보험 관련 업무를 담당하며 장기요양인정과는 관련이 없습니다.\n[정답]", "5": "국민건강보험공단은 장기요양인정 신청 시 가정에 방문하여 신청인의 심신상태를 조사하는 기관입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Đăng ký chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 받기 위한 공식 인가", "def_vi": "Giấy phép chính thức để nhận dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (642, '2', '다음은 장기요양인정 신청 및 판정 절차이다. ( ) 속에 들어갈 내용으로 옳은 것은?신청 → ( A ) → 장기요양인정 점수산정 → ( B ) → 등급판정위원회 개최 → 등급판정', '["방문상담 계약체결", "계약체결 의사소견서 제출", "의사소견서 제출 방문조사", "방문조사 의사소견서 제출", "의사소견서 제출 계약체결"]'::jsonb, 4, NULL, NULL, '{"1": "방문상담 계약체결: 이 과정은 신청 후의 절차가 아닙니다.\n[정답]", "2": "계약체결 의사소견서 제출: 의사소견서 제출은 방문조사가 완료된 후 이루어져야 합니다.", "3": "의사소견서 제출 방문조사: 순서가 잘못되었습니다.", "4": "방문조사 의사소견서 제출: 올바른 순서입니다. 신청 후 방문조사를 시행하고 이후 의사소견서를 제출하게 됩니다.", "5": "의사소견서 제출 계약체결: 이 과정 역시 절차를 잘못 이해한 것입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Nhận dạng chăm sóc dài hạn", "def_ko": "장기적인 요양이 필요한지를 판별하는 공식적인 인정", "def_vi": "Sự công nhận chính thức việc có cần chăm sóc dài hạn hay không"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (641, '2', '65세 미만자가 앓고 있는 질병 중 장기요양급여 대상자로 인정받을 수 있는 질환은?', '["파킨슨병", "심부전증", "고혈압", "퇴행성 관절염", "당뇨병"]'::jsonb, 1, NULL, NULL, '{"1": "파킨슨병은 신경계 질환으로, 장기요양급여 대상입니다.\n[정답]", "2": "심부전증은 장기요양급여 대상에는 포함되지 않습니다.", "3": "고혈압은 일반적으로 장기요양급여 대상이 아닙니다.", "4": "퇴행성 관절염은 장기요양급여 대상이 아닙니다.", "5": "당뇨병은 장기요양급여 대상이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 위해 제공되는 지원금", "def_vi": "Tiền hỗ trợ được cấp cho dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (640, '2', '등급판정위원회의 심의 결과 노인장기요양보험 급열를 받을 수 있는 대상자는?', '["팔이 골절된 60세 남자", "당뇨약을 복용하는 60세 남자", "혈압약을 복용하는 50세 여자", "혈관성 치매를 진단받은 50세 남자", "결핵으로 신체활동이 제한적인 60세 여자"]'::jsonb, 4, NULL, NULL, '{"1": "팔이 골절된 60세 남자는 요양보험의 대상자가 아닙니다.", "2": "당뇨약을 복용하는 60세 남자도 단순한 질병으로 요양보험 대상이 아닙니다.", "3": "혈압약을 복용하는 50세 여자 역시 요양보험 대상자가 아닙니다.\n[정답]", "4": "혈관성 치매를 진단받은 50세 남자는 요양보험의 대상자가 됩니다.", "5": "결핵으로 신체활동이 제한적인 60세 여자도 요양보험의 대상자가 아닙니다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "지급받는 돈(한국어)", "def_vi": "tiền trợ cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (639, '2', '다음 중 장기요양급여 대상자로 인정 가능한 경우로 옳은 것은?', '["관절염을 앓고 있는 64세 남성", "혼자서 걸을 수 없는 50세 말기 암 여자", "파킨슨병으로 일상생활이 어려운 55세 남자", "난청이 있고 일상 생활이 가능한 80세 독거노인", "뇌출혈로 쓰러져 병원에서 치료중인 70세 남자"]'::jsonb, 3, NULL, NULL, '{"1": "관절염만으로는 장기요양급여 대상자가 되지 않음.\n[정답]", "2": "혼자서 걷지 못하는 경우는 장기요양급여 인정.", "3": "파킨슨병으로 일상생활이 어려운 경우는 장기요양급여 인정.", "4": "난청은 장기요양급여 기준에 해당하지 않음.", "5": "병원에서 치료 중인 경우는 장기요양급여 대상이 아님."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 필요한 요양 및 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc và điều dưỡng cần thiết lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (638, '2', '노인장기요양보험 기본 구조 및 절차에서 국민건강보험공단이 하는 일은?', '["요양서비스 재공", "등급판정", "서비스비용 청구", "서비스 신청 및 계약", "장기요양기관의 시설설립인가"]'::jsonb, 2, NULL, NULL, '{"1": "요양서비스를 제공하는 기관의 역할에 해당하는 내용입니다.\n[정답]", "2": "국민건강보험공단이 장기요양 등급을 판별하는 역할을 수행합니다.", "3": "서비스 비용 청구는 요양기관이 담당하는 부분입니다.", "4": "서비스 신청 및 계약 또한 요양기관의 역할에 해당합니다.", "5": "장기요양기관의 시설설립 인가는 지방자치단체가 담당합니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스를 제공하는 보험 제도", "def_vi": "Hệ thống bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (637, '2', '노인장기요양보험의 가입자로부터 보험료를 받아 계약조건에 따라 보험급여를 지급하는 기관은?', '["근로복지공단", "국민건강보험공단", "국민연금공단", "공무원연금공단", "고용보험공단"]'::jsonb, 2, NULL, NULL, '{"1": "근로복지공단은 근로자에 대한 재해 보상 및 복지 서비스를 제공합니다.\n[정답]", "2": "국민건강보험공단은 노인장기요양보험의 가입자로부터 보험료를 받아 보험급여를 지급하는 주 기관입니다.", "3": "국민연금공단은 연금 보험 관련 업무를 담당합니다.", "4": "공무원연금공단은 공무원에 대한 연금 서비스만을 담당합니다.", "5": "고용보험공단은 실업급여 및 고용 관련 사업을 지원합니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "가입자", "def_ko": "노老 dài hạn tuyệt đối", "def_vi": "người tham gia"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (636, '2', '노인장기요양보험제도의 목적으로 옳은 것은?', '["안정적 노후를 위한 소득보장", "최저생활 보장으로 자활의욕 고취", "업무상 재해 보상을 통한 사회복귀를 촉진", "일상생활이 어려운 노인의 가사 및 신체활동 지원", "입원 중인 중증 노인의 의료비를 보장하여 가족의 부담 경감"]'::jsonb, 4, NULL, NULL, '{"1": "안정적 노후를 위한 소득보장은 노인장기요양보험의 주된 목적이 아니다.\n[정답]", "2": "일상생활이 어려운 노인의 가사 및 신체활동 지원은 노인장기요양보험의 주요 목적 중 하나이다.", "3": "업무상 재해 보상을 통한 사회복귀는 다른 법적 제도에 해당한다.", "4": "입원 중인 중증 노인의 의료비를 보장하여 가족의 부담 경감은 건강보험에서 다루는 내용이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (635, '2', '일상생활을 혼자하기 어려운 노인에게 신체활동 또는 가사활동 등을 지원하여 노후의 건강증진 및 생활안정을 도모하고 가족의 부담을 덜어주기 위한 사회보험제도는?', '["고용보험", "노인장기요양보험", "국민연금", "산업재해보상보험", "국민건강보험"]'::jsonb, 2, NULL, NULL, '{"1": "고용보험: 근로자의 고용 안정을 위한 보험으로, 노인과 직접적인 관련이 없습니다.\n[정답]", "2": "노인장기요양보험: 노인의 신체활동 및 가사활동을 지원하고 건강 증진을 도모하기 위한 제도입니다.", "3": "국민연금: 노후 소득을 지원하는 제도로, 일상생활 지원과는 관련이 없습니다.", "4": "산업재해보상보험: 업무와 관련된 재해를 보상하는 보험으로, 노인 복지와는 연결되지 않습니다.", "5": "국민건강보험: 국민의 건강을 지키기 위한 보험이지만, 노인 지원에 특화된 제도는 아닙니다."}'::jsonb, '[{"term_ko": "신체활동", "term_vi": "가사활동", "def_ko": "신체를 움직이며 하는 활동(활동 thể chất)", "def_vi": "집안일이나 가정에서 하는 일(hoạt động gia đình)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (634, '2', '심신이 허약한 노인과 장애노인을 단기간 입소시켜 노인복지를 증진하는 서비스는?', '["방문목욕서비스", "방문요양서비스", "주-야간보호서비스", "단기보호서비스", "방문간호서비스"]'::jsonb, 4, NULL, NULL, '{"1": "방문목욕서비스: 집에서 목욕을 도와주는 서비스로, 단기간 입소와는 관련이 없음.", "2": "방문요양서비스: 요양보호사가 집으로 방문하여 간호, 요양을 하는 서비스이지만, 단기간 입소는 포함되지 않음.\n[정답]", "3": "주-야간보호서비스: 낮 동안 또는 밤 동안 노인을 보호하는 서비스이나, 단기간 입소가 핵심이 아님.", "4": "단기보호서비스: 심신이 허약한 노인과 장애노인을 위해 단기간 입소하여 복지를 증진하는 적합한 서비스.", "5": "방문간호서비스: 의료적 필요를 가진 환자에게 간호사를 파견하는 서비스지만, 단기 입소와는 관련이 없음."}'::jsonb, '[{"term_ko": "심신", "term_vi": null, "def_ko": "마음과 몸", "def_vi": null}, {"term_ko": "허약", "term_vi": null, "def_ko": "약함", "def_vi": null}, {"term_ko": "노인", "term_vi": null, "def_ko": "나이 많은 사람", "def_vi": null}, {"term_ko": "장애", "term_vi": null, "def_ko": "신체적, 정신적 기능에 장애가 있는 상태", "def_vi": null}, {"term_ko": "단기간", "term_vi": null, "def_ko": "짧은 시간", "def_vi": null}, {"term_ko": "입소", "term_vi": null, "def_ko": "시설에 들어가다", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (633, '2', '방문요양, 방문목욕, 주-야간 보호서비스는 노인복지시설 유형 중 어느 것에 해당 하는가?', '["노인의료복지시설", "재가노인복지시설", "노인주거복지시설", "노인여가복지시설", "노인일자리지원기관"]'::jsonb, 2, NULL, NULL, '{"1": "노인의료복지시설은 주로 의료 서비스를 제공하는 시설입니다.\n[정답]", "2": "재가노인복지시설은 가정에서 서비스를 제공하는 시설로, 방문요양, 방문목욕 등이 포함됩니다.", "3": "노인주거복지시설은 노인이 거주하며 생활 지원을 받는 시설입니다.", "4": "노인여가복지시설은 노인의 여가 활동을 지원하는 시설입니다.", "5": "노인일자리지원기관은 노인의 일자리 제공 및 지원을 하는 기관입니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서의 요양 서비스 제공", "def_vi": "Dịch vụ chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (632, '2', '노인의 교양 취미생활 및 사회 참여활동 등에 대한 각종 정보와 노인의 복지 증진에 필요한 서비스를 제공하는 노인여가복지시설은?', '["양로시설", "노인복지관", "경로당", "노인교실", "노인복지주택"]'::jsonb, 2, NULL, NULL, '{"1": "양로시설: 노인의 주거를 제공하는 시설이나 주로 요양 서비스에 중점을 둠.\n[정답]", "2": "노인복지관: 노인의 교양, 취미생활 및 복지 증진을 위한 정보와 서비스를 제공하는 전천후의 시설임.", "3": "경로당: 노인들의 지역 사회 내 모임을 위한 공간이지만, 활동성과 서비스가 노인복지관에 비해 제한적임.", "4": "노인교실: 노인 교육을 주제로 한 특화 시설이나 복지 증진과는 거리가 있음.", "5": "노인복지주택: 고령자의 주거 안정성을 지원하지만, 사회 참여 활동보다는 주거지위 중심의 시설임."}'::jsonb, '[{"term_ko": "교양", "term_vi": "Giáo dục", "def_ko": "문화 및 지식의 향상(한국어)", "def_vi": "Sự nâng cao văn hóa và tri thức (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (631, '2', '치매, 중픙 등으로 심신에 상당한 장애가 있는 노인에게 가정과 같은 주거여건과 급식, 요양, 일상생활 서비스 등을 제공하는 입소자 9인 이내의 노인의료복지시설은?', '["양로시설", "노인복지관", "노인복지주택", "노인요양시설", "노인요양공동생활가정"]'::jsonb, 5, NULL, NULL, '{"1": "양로시설: 노인이 생활하는 시설이나 급식, 요양 서비스를 제공하지 않습니다.\n[정답]", "5": "노인요양공동생활가정: 노인의 심신에 장애가 있는 경우 가정과 같은 환경에서 서비스를 제공하는 시설입니다.", "2": "노인복지관: 다양한 노인 복지 프로그램이 제공되지만 입소 시설은 아닙니다.", "3": "노인복지주택: 독립적인 주거 형태로, 요양 서비스를 포함하지 않습니다.", "4": "노인요양시설: 입소자 수가 더 많고, 설치 기준이 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고의 기능이 저하되는 질병", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (630, '2', '노인의료복지시설 유형에 해당하는 것은?', '["노인요양공동생활가정", "양로시설", "노인복지관", "경로당", "노인복지주택"]'::jsonb, 1, NULL, NULL, '{"1": "노인요양공동생활가정은 의료 및 돌봄 서비스를 제공하는 노인의료복지시설의 한 형태입니다.\n[정답]", "2": "양로시설은 노인들이 거주하는 시설이지만, 의료적인 서비스를 주로 제공하는 곳은 아닙니다.", "3": "노인복지관은 노인 복지 서비스를 제공하는 곳으로, 주로 여가 및 사회 활동을 지원합니다.", "4": "경로당은 지역 사회에서 노인들이 모여 활동하는 공간으로, 의료복지시설은 아닙니다.", "5": "노인복지주택은 자립적인 생활을 지원하는 주거 형태로, 의료 서비스는 중심이 아닙니다."}'::jsonb, '[{"term_ko": "노인요양공동생활가정", "term_vi": "Nhà chung sống cho người cao tuổi", "def_ko": "노인의료복지시설의 한 형태", "def_vi": "Một hình thức cơ sở y tế và phúc lợi dành cho người cao tuổi"}, {"term_ko": "양로시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "노인들이 거주하는 시설", "def_vi": "Nơi cư trú cho người cao tuổi"}, {"term_ko": "노인복지관", "term_vi": "Trung tâm phúc lợi cho người cao tuổi", "def_ko": "노인 복지 서비스를 제공하는 곳", "def_vi": "Nơi cung cấp dịch vụ phúc lợi cho người cao tuổi"}, {"term_ko": "경로당", "term_vi": "Nhà cộng đồng cho người cao tuổi", "def_ko": "노인들이 모여 활동하는 공간", "def_vi": "Không gian nơi người cao tuổi tụ tập"}, {"term_ko": "노인복지주택", "term_vi": "Nhà ở phúc lợi cho người cao tuổi", "def_ko": "자립적인 생활을 지원하는 주거 형태", "def_vi": "Hình thức cư trú hỗ trợ cho cuộc sống tự lập"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (629, '2', '치매 중픙 등 노인성 질환 등으로 심신에 상당한 장애가 발생하여 도움이 필요한 노인을 입소시켜 급식, 요양 등을 제공하는 노인복지 시설은?', '["양로시설", "노인공동생활가정", "노인복지관", "노인전문병원", "노인요양시설"]'::jsonb, 5, NULL, NULL, '{"1": "양로시설: 주로 노인의 생활을 위한 시설로, 간호 등의 전문적인 요양 서비스는 제공하지 않습니다.\n[정답]", "5": "노인요양시설: 치매 및 노인성 질환이 있는 노인을 위해 급식, 요양 등을 제공하는 전문 시설입니다.", "3": "노인복지관: 노인의 사회적 활동과 복지를 지원하는 기관으로, 요양 서비스를 제공하지 않습니다.", "4": "노인전문병원: 노인의 질병 치료를 전문으로 하는 병원으로, 장기 요양 시설이 아닙니다.", "2": "노인공동생활가정: 여러 노인이 함께 생활하지만 노인성 질환이 심한 환자를 위한 시설은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 저하 및 인지능력 감소로 이어지는 질병(한국어)", "def_vi": "Bệnh lý dẫn đến suy giảm trí nhớ và khả năng nhận thức (베트남어)"}, {"term_ko": "노인성", "term_vi": "Bị lão hóa", "def_ko": "노화로 인해 발생하는 질병이나 상태(한국어)", "def_vi": "Bệnh hoặc trạng thái phát sinh do lão hóa (베트남어)"}, {"term_ko": "입소", "term_vi": "Nhập viện", "def_ko": "시설에 들어가 거주하는 것(한국어)", "def_vi": "Vào sinh sống tại cơ sở (베트남어)"}, {"term_ko": "급식", "term_vi": "Cung cấp bữa ăn", "def_ko": "식사를 제공하는 것(한국어)", "def_vi": "Việc cung cấp thức ăn (베트남어)"}, {"term_ko": "요양", "term_vi": "Chăm sóc sức khỏe", "def_ko": "건강을 돌보는 일(한국어)", "def_vi": "Việc chăm sóc sức khỏe (베트남어)"}, {"term_ko": "노인복지 시설", "term_vi": "Cơ sở phúc lợi người cao tuổi", "def_ko": "노인을 위한 복지 서비스 제공 시설(한국어)", "def_vi": "Cơ sở cung cấp dịch vụ phúc lợi cho người cao tuổi (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (628, '2', '다음 설명에 해당하는 노인복지시설은?• 양로시설 • 노인복지주택 • 노인공동생활가정', '["노인의료복지시설", "노인주거복지시설", "노인여가복지시설", "재가노인복지시설", "노인보호전문기관"]'::jsonb, 2, NULL, NULL, '{"1": "노인의료복지시설은 의료 서비스를 제공하는 시설입니다.\n[정답]", "2": "노인주거복지시설은 노인들이 거주할 수 있도록 마련된 주거 공간입니다.", "3": "노인여가복지시설은 노인의 여가 활동을 지원하는 시설입니다.", "4": "재가노인복지시설은 홈케어 서비스를 제공하는 시설입니다.", "5": "노인보호전문기관은 노인 학대 예방 및 상담을 처리하는 기관입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}, {"term_ko": "복지시설", "term_vi": "Cơ sở phúc lợi", "def_ko": "복지시설(한국어)", "def_vi": "Cơ sở phúc lợi"}, {"term_ko": "양로시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "양로시설(한국어)", "def_vi": "Cơ sở dưỡng lão"}, {"term_ko": "노인복지주택", "term_vi": "Nhà ở phúc lợi cho người cao tuổi", "def_ko": "노인복지주택(한국어)", "def_vi": "Nhà ở phúc lợi cho người già"}, {"term_ko": "노인공동생활가정", "term_vi": "Nhà sống chung cho người cao tuổi", "def_ko": "노인공동생활가정(한국어)", "def_vi": "Nhà sống chung cho người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (626, '2', '노인복지사업의 유형 중 노인 사회활동 및 여가활동 지원사업에 해당하는 것은?', '["노인 건강진단", "경로당 지원사업", "노인실명 예방 사업", "결식 우려 노인 무료급식 지원", "노인 무릎인공관절 수술 지원"]'::jsonb, 2, NULL, NULL, '{"1": "노인 건강진단은 건강관리에 해당하므로 제외됩니다.\n[정답]", "2": "경로당 지원사업은 노인의 사회활동과 여가활동을 지원하는 사업입니다.", "3": "노인실명 예방 사업은 건강 관련 지원으로 관련이 없습니다.", "4": "결식 우려 노인 무료급식 지원은 식사가 필요한 노인을 지원하는 사업입니다.", "5": "노인 무릎인공관절 수술 지원은 의료 지원으로 사회활동 및 여가활동과는 관계가 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "복지사업", "term_vi": "Dự án phúc lợi", "def_ko": "사업의 지원과 서비스", "def_vi": "Dự án hỗ trợ và dịch vụ"}, {"term_ko": "사회활동", "term_vi": "Hoạt động xã hội", "def_ko": "사회에서의 활동", "def_vi": "Hoạt động trong xã hội"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 이용한 활동", "def_vi": "Hoạt động trong thời gian rảnh"}, {"term_ko": "경로당", "term_vi": "Nhà văn hóa", "def_ko": "노인을 위한 쉼터", "def_vi": "Nơi nghỉ ngơi cho người cao tuổi"}, {"term_ko": "무료급식", "term_vi": "Bữa ăn miễn phí", "def_ko": "무료로 음식을 제공하는 것", "def_vi": "Cung cấp bữa ăn miễn phí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (625, '2', '다음과 같은 내용의 사업을 실시하는 기관은?• 치매 조기검진, 치매환자 등록 및 관리 • 1:1로 매칭하여 필요한 서비스 연계', '["치매안심센터", "노인요양시설", "노인종합복지관", "노인보호전문기관", "노인의료나눔재단"]'::jsonb, 1, NULL, NULL, '{"1": "치매 환자에 맞춤형 서비스와 관리를 제공하는 기관입니다. [정답]", "2": "노인들의 주거 및 생활 지원이 주된 기능을 하는 시설입니다.", "3": "노인 복지 관련 다양한 프로그램을 제공하지만, 치매 관련 서비스는 제한적입니다.", "4": "노인 학대 및 보호를 위한 전문 기관으로, 주로 보호적인 역할을 합니다.", "5": "노인의료나눔재단은 의료 서비스 관련 재단으로, 직접적인 치매 관리 기관은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "치매(한국어)", "def_vi": "Chứng mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (624, 'unknown', '학대 받은 노인을 일정기간 보호하며 숙식과 기본적인 의료비를 지원하는 기관은?', '["정신요양시설", "주간보호센터", "노인학대신고센터", "정신건강복지센터", "학대피해노인 전용쉼터"]'::jsonb, 5, NULL, NULL, '{"1": "정신요양시설: 정신장애인의 치료와 재활을 위한 시설이므로 정답이 아닙니다.\n[정답]", "5": "학대피해노인 전용쉼터: 학대받은 노인을 일정기간 보호하며 숙식과 기본적인 의료비를 지원하는 기관입니다.", "2": "주간보호센터: 낮 시간 동안 노인을 돌보는 시설이므로 정답이 아닙니다.", "3": "노인학대신고센터: 신고와 상담을 위한 기관이지 직접적인 보호를 제공하지 않으므로 정답이 아닙니다.", "4": "정신건강복지센터: 정신 건강 문제를 지원하는 기관이므로 정답이 아닙니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 학대의 행동(한국어)", "def_vi": "Hành vi bạo lực hoặc lạm dụng"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "돕거나 지원하는 것(한국어)", "def_vi": "Sự giúp đỡ"}, {"term_ko": "숙식", "term_vi": "Chỗ ở và ăn uống", "def_ko": "잠자고 먹는 것(한국어)", "def_vi": "Nơi ngủ nghỉ và ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (623, '2', '다음 설명에 해당하는 업무를 담당하는 기관은?• 노인학대 사례의 신고접수 • 신고 된 시설학대 사례에 대한 개입 • 학대사례에 대한 사례관리 절차 지원', '["사법경찰", "노인보호전문기관", "법률기관", "의료기관", "보건복지부"]'::jsonb, 2, NULL, NULL, '{"1": "사법경찰은 범죄 사건 수사 및 법 집행 관련 업무를 수행하므로 해당되지 않음.\n[정답]", "2": "노인보호전문기관은 노인학대 관련 신고 접수 및 개입, 사례관리를 주 업무로 담당함.", "3": "법률기관은 법률적 상담 및 지원을 담당하지만 노인학대의 직접적 개입과는 관련이 없음.", "4": "의료기관은 의료적 치료를 제공하지만 학대 사례 관리와는 무관함.", "5": "보건복지부는 정책 수립과 감독 역할을 하지만 직접적으로 사례를 관리하지는 않음."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자에게 가해지는 신체적, 정신적 학대", "def_vi": "Sự lạm dụng về thể chất và tinh thần đối với người cao tuổi"}, {"term_ko": "신고접수", "term_vi": "Tiếp nhận báo cáo", "def_ko": "사건에 대한 신고를 접수하는 것", "def_vi": "Nhận thông báo về vụ việc"}, {"term_ko": "사례관리", "term_vi": "Quản lý hồ sơ", "def_ko": "사건을 관리하는 절차", "def_vi": "Quy trình quản lý các vụ việc"}, {"term_ko": "개입", "term_vi": "Can thiệp", "def_ko": "사건에 직접 개입하는 것", "def_vi": "Can thiệp trực tiếp vào vụ việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (622, '2', '등급판정위원회의 심의 결과 등급판정을 받지 못한 대상자가 이용할 수 있는 서비스는?', '["노인요양시설", "노인복지관", "단기보호", "방문목욕", "방문간호"]'::jsonb, 2, NULL, NULL, NULL, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (621, '2', '일상생활을 영위하기 어려운 노인에게 적절한 돌봄서비스를 제공하여 안정적인 노후생활을 보장하고 노인의 기능, 건강의 악화 예방을 목적으로 하는 노인 복지사업은?', '["노인맞춤돌봄서비스", "노인일자리 지원서비스", "독거노인 공동생활홈 서비스", "독거노인 응급안전안심서비스", "결식 우려 노인 무료급식 지원서비스"]'::jsonb, 1, NULL, NULL, '{"1": "노인맞춤돌봄서비스는 노인의 기능, 건강 악화 예방에 중점을 두고 있어 정답이다.\n[정답]", "2": "노인일자리 지원서비스는 일자리에 관련된 서비스로 노인 돌봄 서비스가 아니다.", "3": "독거노인 공동생활홈 서비스는 공동생활을 지원하는 서비스일 뿐 돌봄 서비스 직접 제공과는 거리가 있다.", "4": "독거노인 응급안전안심서비스는 응급 상황 처리를 위한 서비스로, 목적이 다르다.", "5": "결식 우려 노인 무료급식 지원서비스는 식사 지원에 관련된 서비스로 노인 돌봄 서비스와는 차별화된다."}'::jsonb, '[{"term_ko": "일상생활", "term_vi": "돌봄서비스", "def_ko": "일상 cuộc sống", "def_vi": "dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (620, '2', '노인의 경륜을 사회에 재투자할 수 있도록 노인의 적극적 사회참여 및 노인의 인적자원 활용을 극대화하기 위한 사업은?', '["노인자원봉사", "노인보호전문기관", "노인 건강진단사업", "치매공공후견사업", "노인일자리 및 사회활동 지원사업"]'::jsonb, 1, NULL, NULL, '{"1": "노인이 자원봉사 활동을 통해 사회에 기여하는 방안이다.\n[정답]", "2": "노인을 보호하고 지원하는 기관으로 자원봉사와는 직접적으로는 관련이 없다.", "3": "노인의 건강 상태를 진단하는 것이며 사회참여와는 거리가 있다.", "4": "치매환자를 위한 공공후견사업으로 사회참여와는 다소 무관하다.", "5": "노인의 일자리와 사회활동을 지원하여 사회참여를 촉진하는 사업이다."}'::jsonb, '[{"term_ko": "경륜", "term_vi": "사회참여", "def_ko": "경험(경험)", "def_vi": "참여 xã hội(사회를 포함한 활동에 참여하다)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (619, '2', '다음 설명에 해당하는 노인복지 원칙은?• 노인의 잠재력을 개발할 수 있는 기회가 있어야 한다.• 사회의 교육적, 문화적, 정신적 자원과 여가서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 5, NULL, NULL, '{"1": "독립의 원칙: 노인이 자율적으로 생활할 수 있도록 지원하는 원칙이다.\n[정답]", "5": "자아실현의 원칙: 노인이 자신의 잠재력을 최대한 발휘하고 자아를 실현할 수 있도록 기회를 제공하는 원칙이다.", "2": "참여의 원칙: 노인이 사회 활동에 참여할 수 있는 기회를 강조하는 원칙이다.", "3": "보호의 원칙: 노인을 안전하게 보호하는 것이 주된 목표인 원칙이다.", "4": "존엄의 원칙: 노인의 존엄성을 존중하고 보호하는 원칙이다."}'::jsonb, '[{"term_ko": "잠재력", "term_vi": "Tiềm năng", "def_ko": "가능성(한국어)", "def_vi": "Khả năng"}, {"term_ko": "기회", "term_vi": "Cơ hội", "def_ko": "기회(한국어)", "def_vi": "Cơ hội"}, {"term_ko": "자원", "term_vi": "Tài nguyên", "def_ko": "자원(한국어)", "def_vi": "Tài nguyên"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "Nguyên tắc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (618, '2', '의사결정능력 부족으로 어려움을 겪는 치매노인에게 지원하는 공공후견사업에 대한 내용으로 옳은 것은?', '["사업주체는 노인의료나눔제단이다.", "노인의 건강 유지, 증진을 위한 사업이다.", "사업대상은 일반 노인, 치매노인 및 가족이다.", "후견심판 청구 절차 및 비용을 지원한다.", "공공후견인 활동비는 지원하지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "사업주체는 노인의료나눔제단이 아니라 공공기관입니다.\n[정답]", "4": "후견심판 청구 절차 및 비용을 지원하는 것이 공공후견사업의 중요한 내용입니다.", "2": "사업은 건강 유지, 증진을 목표로 하지만, 주로 후견 지원을 중점적으로 다룹니다.", "3": "치매노인 및 그 가족을 포함하나, 일반 노인 포함 여부는 다소 다를 수 있습니다.", "5": "공공후견인 활동비는 지원하지 않습니다."}'::jsonb, '[{"term_ko": "의사결정능력", "term_vi": "Năng lực quyết định", "def_ko": "결정을 내리는 능력", "def_vi": "Khả năng đưa ra quyết định"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 인지 능력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "공공후견사업", "term_vi": "Dự án bảo trợ công cộng", "def_ko": "공공기관이 주관하는 후견지원 사업", "def_vi": "Dự án hỗ trợ bảo trợ do cơ quan công cộng tổ chức"}, {"term_ko": "후견심판", "term_vi": "Quyết định của tòa án giám hộ", "def_ko": "법원의 판단에 따라 후견인을 지정하는 절차", "def_vi": "Quy trình xác định người giám hộ theo phán quyết của tòa án"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지출하는 금액", "def_vi": "Số tiền chi tiêu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (617, '2', '국제연합(유엔)이 채택한 노인을 위한 원칙에 관한 설명으로 옳은 것은?', '["가능한 시설 거주를 권장한다.", "경제적 능력에 따라 대우한다.", "젊은 세대와 분리된 노인문화를 형성한다.", "교육과 문화 서비스 제공은 최소화한다.", "시설에서도 기본적인 자유를 누려야 한다."]'::jsonb, 5, NULL, NULL, '{"1": "가능한 시설 거주를 권장한다: 유엔의 원칙에서는 가능한 한 노인이 자택에서 생활할 수 있도록 권장한다.\n[정답]", "5": "시설에서도 기본적인 자유를 누려야 한다: 노인은 시설 내에서도 자신의 삶에 대한 기본적인 선택과 자유를 누릴 권리가 있다.", "3": "젊은 세대와 분리된 노인문화를 형성한다: 유엔의 원칙은 노인이 젊은 세대와의 통합을 강조한다.", "4": "교육과 문화 서비스 제공은 최소화한다: 원칙에서는 교육과 문화 서비스의 중요성을 강조한다.", "2": "경제적 능력에 따라 대우한다: 유엔의 원칙은 모든 노인이 동등하게 대우받아야 한다고 강조한다."}'::jsonb, '[{"term_ko": "국제연합", "term_vi": "Tổ chức Liên hợp quốc", "def_ko": "유엔(United Nations)", "def_vi": "Liên Hợp Quốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (616, '2', '다음에서 설명하는 노인을 위한 유엔의 원칙은?• 노인은 착취와 육체적, 정신적 학대로부터 자유로워야 한다.• 노인은 장애나 여타 지위에 상관없이 공정하게 대우받아야 한다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "평등의 원칙"]'::jsonb, 4, NULL, NULL, '{"1": "독립의 원칙: 노인이 자율적으로 생활할 수 있도록 지원하는 원칙이다.", "2": "참여의 원칙: 노인이 사회 활동에 적극적으로 참여할 수 있도록 하는 원칙이다.\n[정답]", "3": "보호의 원칙: 노인이 착취와 학대에 대한 보호를 받아야 한다는 내용을 포함한다.", "4": "존엄의 원칙: 노인의 존엄성을 지키는 것과 관련된 원칙이다.", "5": "평등의 원칙: 모든 노인이 공정하게 대우받아야 한다는 의미를 담고 있으나, 질문의 맥락은 아니다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원리, 규칙(한국어)", "def_vi": "Nguyên lý, quy tắc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (615, '2', '교사로 은퇴한 노인이 지역아동센터에서 교육봉사 단체를 조직하여 활동하는 노인복지 원칙은?', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "평등의 원칙"]'::jsonb, 2, NULL, NULL, '{"1": "독립의 원칙: 노인이 스스로 생활할 수 있도록 지원하는 원칙\n[정답]", "2": "참여의 원칙: 노인이 사회활동에 적극적으로 참여할 수 있도록 장려하는 원칙", "3": "보호의 원칙: 노인을 보호하고 안전하게 지킬 수 있도록 하는 원칙", "4": "존엄의 원칙: 노인의 존엄성이 유지되도록 존중하는 원칙", "5": "평등의 원칙: 모든 노인이 동등한 권리를 가지고 대우받아야 한다는 원칙"}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (614, '2', '노인은 ''일할 수 있는 기회를 갖거나 다른 소득을 얻을 수 있어야 한다.''는 노인을 위한 유엔원칙은?', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 1, NULL, NULL, '{"1": "독립의 원칙: 노인이 자주적이고 독립적으로 생활할 수 있도록 하는 원칙입니다.\n[정답]", "2": "참여의 원칙: 노인이 사회에 참여할 수 있도록 하는 원칙이라는 점에서 가장 알맞습니다.", "3": "보호의 원칙: 노인을 보호하는 내용에 관련된 원칙입니다.", "4": "존엄의 원칙: 노인의 존엄성을 유지하는 것에 관련된 원칙입니다.", "5": "자아실현의 원칙: 개인의 잠재력을 실현하도록 하는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령의 사람", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (613, '2', '다음 설명에 해당되는 사회복지제도는?• 목적: 노인의 노후소득 보장 및 생활안정 지원• 대상: 만 65세 이상 소득인정액 기준 70% 수준 이하의 노인• 재원: 국가와 지방자치단체에 의해 조성', '["주택연금", "국민연금", "기초연금", "퇴직연금", "고용보험"]'::jsonb, 3, NULL, NULL, '{"1": "주택연금은 주택을 담보로 현금을 지급받는 제도입니다.", "2": "국민연금은 모든 국민이 일정 금액을 납부하고 노후에 지급받는 연금입니다.\n[정답]", "3": "기초연금은 65세 이상의 저소득 노인에게 지급되며, 노후소득 보장 및 생활안정을 지원합니다.", "4": "퇴직연금은 근로자가 퇴직할 때 지급받는 연금입니다.", "5": "고용보험은 실직 시 소득을 지원하는 제도입니다."}'::jsonb, '[{"term_ko": "사회복지제도", "term_vi": "Chế độ phúc lợi xã hội", "def_ko": "복지 사회 체계", "def_vi": "Hệ thống phúc lợi xã hội"}, {"term_ko": "노후소득", "term_vi": "Thu nhập hưu trí", "def_ko": "노인의 퇴직 후 소득", "def_vi": "Thu nhập sau khi nghỉ hưu"}, {"term_ko": "소득인정액", "term_vi": "Mức thu nhập công nhận", "def_ko": "소득 기준", "def_vi": "Tiêu chí thu nhập"}, {"term_ko": "생활안정", "term_vi": "Ổn định cuộc sống", "def_ko": "경제적 안정", "def_vi": "Ổn định kinh tế"}, {"term_ko": "국가", "term_vi": "Nhà nước", "def_ko": "국가", "def_vi": "Nhà nước"}, {"term_ko": "지방자치단체", "term_vi": "Chính quyền địa phương", "def_ko": "지역 자치 단체", "def_vi": "Chính quyền địa phương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (612, '2', '다음 중 사회보험의 종류와 내용이 올바르게 짝지어진 것은?', '["고용보험 - 근로자의 업무상 재해를 보상, 재활 및 사회복귀를 촉진", "국민연금보험 - 생활이 어려운 사람에게 필요한 급여를 제공하여 최저 생활을 보장", "국민건강보험 - 노령, 장애 ,사망에 대하여 연금을 지급하여 생활안정과 복지를 증진", "산업재해보상보험 - 근로자가 실업한 경우 생활안정, 구직활동을 위해 급여를 지급", "노인장기요양보험 - 고령, 노인성 질병으로 일상생활이 어려운 노인에게 급여를 제공"]'::jsonb, 5, NULL, NULL, '{"1": "고용보험은 실업급여와 구직활동 지원을 목적으로 합니다. 이 설명은 맞지 않습니다.\n[정답]", "5": "노인장기요양보험은 고령, 노인성 질병으로 일상생활이 어려운 노인에게 급여를 제공하는 보험입니다.", "2": "국민연금보험은 노령연금, 장애연금, 유족연금을 지급하여 최저 생활을 보장합니다. 이 설명은 맞지 않습니다.", "3": "국민건강보험은 건강보험으로 여러 의료비를 지원합니다. 노령, 장애, 사망에 대한 연금을 지급하지 않습니다. 이 설명은 맞지 않습니다.", "4": "산업재해보상보험은 근로자의 업무상 재해에 대해 보상하며, 실업 시의 급여 지급과는 관련이 없습니다. 이 설명은 맞지 않습니다."}'::jsonb, '[{"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "사회적 위험에 대비하기 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm để đối phó với các rủi ro xã hội"}, {"term_ko": "고용보험", "term_vi": "Bảo hiểm thất nghiệp", "def_ko": "실업 등으로 인해 소득이 중단된 근로자에게 제공되는 보험", "def_vi": "Bảo hiểm cung cấp cho người lao động khi thu nhập bị gián đoạn do thất nghiệp"}, {"term_ko": "국민연금", "term_vi": "Quỹ hưu trí quốc dân", "def_ko": "국민의 노후 생활을 보장하기 위한 연금 제도", "def_vi": "Hệ thống lương hưu nhằm đảm bảo cuộc sống cho công dân trong thời gian nghỉ hưu"}, {"term_ko": "국민건강보험", "term_vi": "Bảo hiểm sức khỏe quốc dân", "def_ko": "국민의 건강 관리를 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm nhằm quản lý sức khỏe của người dân"}, {"term_ko": "산업재해보상보험", "term_vi": "Bảo hiểm bồi thường tai nạn lao động", "def_ko": "근로자가 업무 중 재해를 당했을 때 보상해주는 보험", "def_vi": "Bảo hiểm bồi thường cho người lao động khi gặp tai nạn trong công việc"}, {"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "장기 요양이 필요한 노인에게 서비스를 제공하는 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ cho người cao tuổi cần chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (611, '2', '요양보호사가 실직했을 때 생활에 필요한 급여를 제공하는 사회보험은?', '["고용보험", "국민건강보험", "국민연금보험", "산업재해보상보험", "노인장기요양보험"]'::jsonb, 1, NULL, NULL, '{"1": "고용보험은 실직 시 생활에 필요한 급여를 제공하는 보험입니다.\n[정답]", "2": "국민건강보험은 의료 서비스를 제공받기 위한 보험입니다.", "3": "국민연금보험은 노후 소득을 보장하는 보험입니다.", "4": "산업재해보상보험은 산업재해로 인한 보상을 위한 보험입니다.", "5": "노인장기요양보험은 노인에 대한 장기요양 서비스를 제공하는 보험입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자 또는 노인 등을 돌보는 직업", "def_vi": "Người chăm sóc bệnh nhân hoặc người cao tuổi"}, {"term_ko": "실직", "term_vi": "Mất việc", "def_ko": "일자리를 잃는 것", "def_vi": "Bị mất công việc"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "삶에 필요한 돈", "def_vi": "Tiền cần thiết cho cuộc sống"}, {"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "사회적 위험을 대비한 보험", "def_vi": "Bảo hiểm cho các rủi ro xã hội"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (610, '1', '대상자가 최소한의 움직임도 하지 않고 오랜 시간 침상에 누워만 있을 때 발생할 수 있는 상황은?', '["순환기가 안정되어 심장 기능이 좋아진다.", "근력이 저하되어 보행 능력이 상실된다.", "호흡이 안정되어 폐활량에 도움이 된다.", "골격근이 강화되고 근력이 상승한다.", "관절이 보호되어 낙상 위험이 줄어든다."]'::jsonb, 2, NULL, NULL, '{"1": "순환기가 안정되어 심장 기능이 좋아질 수 없다. 이는 장기적인 부동 상태에서 심장 기능이 감소할 위험이 있다.\n[정답]", "2": "근력이 저하되어 보행 능력이 상실될 수 있다. 이는 오랜 시간 부동으로 인해 발생하는 일반적인 상식이다.", "3": "호흡이 안정되어 폐활량에 도움이 되지 않는다. 오히려 침대에 오래 눕게 되면 폐활량이 감소할 수 있다.", "4": "골격근이 강화되고 근력이 상승하지 않는다. 지속적인 부동은 근육의 위축을 초래한다.", "5": "관절이 보호되어 낙상 위험이 줄어드는 것이 아니다. 오히려 장기간의 부동은 관절 경직을 초래할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (609, '1', '요양보호 실천의 4가지 원칙 중 말하기 방법으로 옳은 것은?', '["긍정형과 부정형 문장을 섞어서 또박또박 말한다.", "대상자가 반응이 없으면 말을 걸지 않는다.", "잠에서 덜 깨었을 때 말을 걸기 시작한다.", "말을 이해하지 못하면 서비스만 제공한다.", "이야기를 한 후 최소 3초 이상 기다린다."]'::jsonb, 5, NULL, NULL, '{"1": "긍정형과 부정형 문장을 섞어서 또박또박 말하는 것은 적절하지 않습니다.\n[정답]", "5": "이야기를 한 후 최소 3초 이상 기다리는 것이 올바른 의사소통 방법입니다.", "2": "대상자가 반응이 없으면 말을 걸지 않는 것은 비효율적인 방법입니다.", "3": "잠에서 덜 깨었을 때 말을 걸기 시작하는 것은 상대방의 상태에 따라 다를 수 있습니다.", "4": "말을 이해하지 못하면 서비스만 제공하는 것은 영양보호의 질을 떨어뜨릴 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "원칙", "def_ko": "돌봄 (chăm sóc)", "def_vi": "원리 (nguyên tắc)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (608, '1', '요양보호 실천의 4가지 원칙과 내용이 옳은 것은?', '["대면하기 : 위에서 내려다보며 옆에서 힐끗 본다.", "말하기 : 대상자가 졸고 있을 때 말을 건다.", "접촉하기 : 손가락에 힘을 주어 꽉 잡는다.", "말하기 : 봐야 할 것을 눈높이에서 보여주며 말을 한다.", "일어서게 하기 : 도움을 주어 혼자 움직이지 않게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "대면하기는 적절하지 않으며, 위에서 내려다보며 옆에서 힐끗 보는 것은 바람직하지 않습니다.", "2": "졸고 있는 대상자에게 말을 건다면 상대방의 상태를 고려하지 않은 행동입니다.", "3": "손가락에 힘을 주어 꽉 잡는 것은 오히려 불편함을 줄 수 있으므로 적절하지 않습니다.\n[정답]", "4": "눈높이에서 봐야 할 것을 보여주며 말을 걸면 대상자와의 소통이 원활해집니다.", "5": "도움을 줄 때는 혼자 행동하지 못하게 하는 것이 아니라 혼자서도 할 수 있도록 돕는 것이 중요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄과 지원을 필요로 하는 사람을 도와주는 직업", "def_vi": "Nghề giúp đỡ những người cần sự chăm sóc và hỗ trợ"}, {"term_ko": "대면하기", "term_vi": "Gặp gỡ", "def_ko": "시선이나 신체를 직접 맞대는 것", "def_vi": "Sự tiếp xúc trực tiếp bằng ánh mắt hoặc cơ thể"}, {"term_ko": "접촉하기", "term_vi": "Tiếp xúc", "def_ko": "서로의 신체를 만지는 것", "def_vi": "Sờ vào cơ thể của nhau"}, {"term_ko": "혼자", "term_vi": "Một mình", "def_ko": "외롭고 따로 있는 상태", "def_vi": "Trạng thái đơn độc và tách biệt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (607, '1', '억제대 사용 시 대상자에게 발생할 수 있는 상황으로 옳은 것은?', '["혈액순환에 도움이 된다.", "폐활량이 좋아진다.", "골격근의 근력 유지에 도움이 된다.", "자세변환이 힘들어 욕창이 잘 생긴다.", "뼈와 관절을 보호하고 골다공증에 도움이 된다."]'::jsonb, 4, NULL, NULL, '{"1": "억제대는 혈액순환에 긍정적인 영향을 주지 않습니다.", "2": "폐활량이 개선되지 않습니다.", "3": "골격근의 근력 유지와 관련이 없습니다. \n[정답]", "4": "억제대 사용 시 자세변환이 어려워져 욕창 발생 위험이 증가합니다.", "5": "뼈와 관절 보호에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "억제대", "term_vi": "Dây kiềm chế", "def_ko": "제한, 제어하기 위해 사용되는 장치", "def_vi": "Thiết bị được sử dụng để hạn chế và kiểm soát"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "혈액이 신체를 순환하는 과정", "def_vi": "Quá trình máu lưu thông trong cơ thể"}, {"term_ko": "폐활량", "term_vi": "Khả năng hô hấp", "def_ko": "폐에서 호흡할 수 있는 공기의 양", "def_vi": "Lượng không khí có thể hít vào và thở ra từ phổi"}, {"term_ko": "골격근", "term_vi": "Cơ xương", "def_ko": "신체를 움직이는 데 필요하는 주요 근육", "def_vi": "Các cơ chính cần thiết để di chuyển cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét do nằm lâu", "def_ko": "누워 있는 환자에게 생길 수 있는 피부손상", "def_vi": "Tổn thương da có thể xảy ra ở bệnh nhân nằm lâu"}, {"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지기 쉽고 부서지기 쉬운 상태", "def_vi": "Tình trạng xương trở nên yếu và dễ vỡ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (606, '1', '노인부양 문제를 개선하기 위한 방안으로 옳은 것은?', '["노인돌봄정책을 축소한다.", "장기요양등급판정 항목을 늘린다.", "사회보험제도를 통해 세대통합을 증진한다.", "소득재분배를 위해 기초연금을 축소시킨다.", "국가 주도의 획일적인 노인복지서비스를 제공한다."]'::jsonb, 3, NULL, NULL, '{"1": "노인돌봄정책을 축소하는 것은 부정적인 영향을 초래할 수 있다.\n[정답]", "3": "사회보험제도를 통해 세대통합을 증진하는 것은 노인의 삶의 질을 개선할 수 있는 긍정적인 방안이다.", "2": "장기요양등급판정 항목을 늘리는 것은 복잡성을 증가시킬 수 있다.", "4": "기초연금을 축소하는 것은 노인의 경제적 어려움을 가중시킬 수 있다.", "5": "국가 주도의 획일적인 노인복지서비스는 개인의 필요를 충족하지 못할 수 있다."}'::jsonb, '[{"term_ko": "노인부양", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "늙은이들을 돌보는 것", "def_vi": "Việc chăm sóc cho người già"}, {"term_ko": "장기요양등급판정", "term_vi": "Đánh giá mức độ chăm sóc dài hạn", "def_ko": "장기요양 서비스의 필요성을 평가하는 것", "def_vi": "Đánh giá nhu cầu dịch vụ chăm sóc dài hạn"}, {"term_ko": "세대통합", "term_vi": "Hội nhập thế hệ", "def_ko": "서로 다른 세대 간의 관계를 증진하는 것", "def_vi": "Tăng cường mối quan hệ giữa các thế hệ"}, {"term_ko": "소득재분배", "term_vi": "Tái phân phối thu nhập", "def_ko": "소득의 불균형 해소를 위한 정책", "def_vi": "Chính sách nhằm giải quyết sự bất bình đẳng thu nhập"}, {"term_ko": "기초연금", "term_vi": "Trợ cấp hưu trí cơ bản", "def_ko": "노인이 받을 수 있는 기본적인 연금", "def_vi": "Khoản trợ cấp hưu trí cơ bản mà người cao tuổi có thể nhận được"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (605, '1', '노인부양 문제의 해결을 위해 노인의 개인적 대처방법으로 옳은 것은?', '["노인요양보험 확대", "사회 교육프로그램 참여", "양질의 노인일자리 개발", "노인복지정책 강화", "노인요양시설 확대"]'::jsonb, 2, NULL, NULL, '{"1": "노인요양보험 확대는 정부의 정책 변화에 해당하며 개인적 대처와는 관련이 없다.\n[정답]", "2": "사회 교육프로그램 참여는 노인이 자신의 사회적 역할을 강화하는 방법으로 개인적 대처에 적합하다.", "3": "양질의 노인일자리 개발은 주로 정부와 관련된 문제로 개인 대처와 거리가 있다.", "4": "노인복지정책 강화는 정부 차원의 문제이며 개인적 대처와는 관련이 적다.", "5": "노인요양시설 확대는 사회적 지원 문제에 해당하며 개인적 대처가 아니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인을 뜻하는 말", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (604, '1', '요양보호사가 대상자를 대하는 원칙 중 옳은 것은?', '["무엇이든 강제로 한다.", "사고방지를 위해 억제대를 하게 한다.", "움직임이 불편한 대상자는 겨드랑이를 잡아 올린다.", "화장실을 걸어서 이동하려고 하면 걸을 수 있게 해준다.", "대답이 없는 대상자에게는 말을 건네지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "강제로 하는 것은 대상자의 인권을 침해하는 행동입니다.\n[정답]", "4": "대상자가 스스로 이동할 수 있도록 도와주는 것이 바람직합니다.", "2": "억제대 사용은 최소화해야 하며, 필요할 경우에도 대상자의 동의를 우선시해야 합니다.", "3": "겨드랑이는 민감한 부위로, 잘못된 방법으로 올리면 부상을 초래할 수 있습니다.", "5": "대답이 없는 경우에도 지속적으로 말을 건네는 것이 중요합니다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "nguyên tắc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (603, '1', '인간다움 케어에서 대상자가 기분 좋게 느끼도록 돌봄을 시행하는 단계로 옳은 것은?', '["케어의 준비 단계", "만남의 준비 단계", "감정의 고정 단계", "지각의 연결 단계", "재회의 약속 단계"]'::jsonb, 4, NULL, NULL, '{"1": "케어의 준비 단계: 돌봄을 위한 사전 준비 단계로, 이는 감정이나 기분을 조성하는 단계가 아니다.\n[정답]", "2": "만남의 준비 단계: 대상자와의 만남에서 서로의 감정을 이해하고 연결하는 단계로, 인간다움을 느끼도록 하는 데 중요한 역할을 한다.", "3": "감정의 고정 단계: 감정이 고정되거나 고착되는 것이 아니라, 지속적으로 변화하는 것이 바람직하다.", "4": "지각의 연결 단계: 대상자의 기분을 좋게 만드는 데 중요한 단계이다. 감정과 기억이 연결되어 긍정적인 경험으로 이어진다.", "5": "재회의 약속 단계: 이후의 만남을 약속하는 단계로, 현재의 돌봄과는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "인간다움", "term_vi": "Nhân tính", "def_ko": "인간성(한국어)", "def_vi": "Nhân văn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (602, '1', '대상자를 대하는 실천 원칙으로 5가지 단계의 순서로 옳은 것은?가. 케어의 준비 나. 만남의 준비 다. 감정의 고정 라. 지각의 연결 마.재회의 약속', '["가 → 나 → 다 → 라 → 마", "나 → 가 → 라 → 다 → 마", "나 → 다 → 마 → 라 → 가", "다 → 가 → 라 → 나 → 마", "라 → 가 → 디 → 마 → 나"]'::jsonb, 2, NULL, NULL, '{"1": "케어의 준비가 먼저 이루어져야 하지만, 그 다음 단계는 만남의 준비가 앞서야 합니다. 따라서, 이 순서는 옳지 않습니다.\n[정답]", "2": "만남의 준비 후에 케어의 준비가 이어지고, 그 다음 감정의 고정, 지각의 연결, 재회의 약속 순으로 진행됩니다. 이 순서가 올바릅니다.", "3": "만남의 준비를 먼저 하고, 감정의 고정이 이루어지되, 이 순서는 바올바로 진행되지 못합니다.", "4": "감정의 고정을 가장 먼저 진행하는 것은 정해진 원칙에 맞지 않으므로 올바르지 않습니다.", "5": "지각의 연결이 먼저 오는 것도 옳지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (601, '1', '노인부양 문제의 해결 방안으로 옳은 것은?', '["재가노인은 요양보호사가 24시간 서비스를 담당한다.", "비공식적 돌봄인력인 간호사, 사회복지사가 참여한다.", "공식적 돌봄인력인 가족의 역할이 필수적이다.", "가족의 역할을 요양보호사로 대체한다.", "가족의 돌봄을 요양보호사가 함께 지원한다."]'::jsonb, 5, NULL, NULL, '{"1": "재가노인이 24시간 요양보호사 서비스를 받는 것은 일반적이지 않으며, 재가노인은 가족 등의 지원이 필요합니다.\n[정답]", "5": "가족의 돌봄을 요양보호사가 함께 지원하는 것은 협력적인 돌봄 모델로 적절합니다.", "3": "가족의 역할이 중요하지만, 공식적 돌봄인력만으로는 부족한 상황이 많습니다.", "4": "가족 역할을 대체는 비효율적이며, 가족의 참여가 중요합니다.", "2": "비공식적 돌봄인력의 참여도 필요하지만, 요양보호사와의 협력이 더 중요합니다."}'::jsonb, '[{"term_ko": "재가노인", "term_vi": "Người cao tuổi tại gia", "def_ko": "집에서 돌봄을 받는 노인", "def_vi": "Người cao tuổi nhận sự chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (600, '1', '노인부양 문제의 해결방안으로 옳은 것은?', '["장남이 부양하는 것이 최선책이다.", "자녀에게 일방적인 부양을 강조한다.", "정서적 부양보다 경제적 부양을 중요시한다.", "몸이 불편해지면 바로 노인요양시설에 입소시킨다.", "사회와 가족이 협력하는 공적·사적 부양이 모두 필요하다."]'::jsonb, 5, NULL, NULL, '{"1": "장남이 부양하는 것이 최선책이라는 고정관념은 현대 사회에서 다양성을 무시합니다.", "2": "자녀에게 일방적인 부양을 강조하는 것은 비효율적이며, 가족 간의 갈등을 유발할 수 있습니다.", "3": "정서적 부양보다 경제적 부양을 중요시하는 것은 노인의 정서적 안정에 부정적인 영향을 미칠 수 있습니다.", "4": "몸이 불편해지면 바로 노인요양시설에 입소시키는 것은 가족과의 관계를 단절할 수 있습니다.\n[정답]", "5": "사회와 가족이 협력하는 공적·사적 부양이 모두 필요하다는 것이 현대적 해결 방안입니다."}'::jsonb, '[{"term_ko": "노인부양", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 것", "def_vi": "Chăm sóc cho người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (599, '1', '현대사회의 가족관계 변화로 옳은 것은?', '["세대 간 갈등이 완화되고 있다.", "독거노인의 비율이 낮아지고 있다.", "노인부양 의식이 점차 높아지고 있다.", "자녀의 독립으로 빈둥지증후군을 경험한다.", "조부모는 손자녀와 관계를 형성하는데 어려움을 겪는다."]'::jsonb, 4, NULL, NULL, '{"1": "세대 간 갈등이 완화되고 있다. - 현대 사회에서는 세대 간 갈등이 여전히 존재하고 있다.\n[정답]", "2": "자녀의 독립으로 빈둥지증후군을 경험한다. - 자녀가 독립해 나가면 부모가 느끼는 외로움이나 공허함을 빈둥지증후군이라고 한다.", "3": "노인부양 의식이 점차 높아지고 있다. - 실제로는 부양의식이 약해지고 있는 경향이 많다.", "4": "독거노인의 비율이 낮아지고 있다. - 독거노인의 비율은 오히려 높아지고 있는 추세이다.", "5": "조부모는 손자녀와 관계를 형성하는데 어려움을 겪는다. - 조부모와 손자녀 간의 관계는 일반적으로 긍정적인 측면이 많다."}'::jsonb, '[{"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 간의 유대 및 관계", "def_vi": "Sự gắn bó và mối quan hệ giữa các thành viên trong gia đình"}, {"term_ko": "세대", "term_vi": "Thế hệ", "def_ko": "세대, 시대", "def_vi": "Thế hệ, kỷ nguyên"}, {"term_ko": "갈등", "term_vi": "Xung đột", "def_ko": "갈등, 충돌", "def_vi": "Mâu thuẫn, xung đột"}, {"term_ko": "독거노인", "term_vi": "Người già sống một mình", "def_ko": "혼자 사는 노인", "def_vi": "Người cao tuổi sống độc lập"}, {"term_ko": "빈둥지증후군", "term_vi": "Hội chứng tổ trống", "def_ko": "자녀가 독립한 후 부모가 느끼는 심리적 증상", "def_vi": "Triệu chứng tâm lý mà cha mẹ cảm thấy khi con cái độc lập"}, {"term_ko": "조부모", "term_vi": "Ông bà", "def_ko": "손자녀를 가진 할아버지와 할머니", "def_vi": "Ông bà, ông với cháu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (598, '1', '노인이 되면 나타나는 대표적인 4가지 고통 중 옳은 것은?', '["무병장수", "직업", "무위", "여유", "저임금"]'::jsonb, 3, NULL, NULL, '{"1": "무병장수: 노인이 되면 건강 문제가 발생할 가능성이 높아지므로, 이는 옳지 않습니다.\n[정답]", "3": "무위: 노인이 되어 다양한 활동을 하지 못하고 무위 상태가 되는 경우가 많습니다.", "2": "직업: 노인이 되어도 일할 수 있는 경우가 있지만, 일반적으로는 은퇴 후 직업을 잃는 경우가 많지요.", "4": "여유: 노인이 되면 여유를 느끼는 경우도 있지만, 많은 고통을 함께 경험하는 경우가 많습니다.", "5": "저임금: 이는 경제적 문제와 관련된 것으로 노인의 고통을 직접적으로 나타내지는 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (597, '1', '노인 부모가 자녀와 근거리에 살면서 부양을 받는 가족 형태는?', '["핵가족", "수정확대가족", "대가족", "다문화가족", "한부모가족"]'::jsonb, 2, NULL, NULL, '{"1": "핵가족: 부모와 자녀로 구성된 작은 가족 단위입니다.\n[정답]", "2": "수정확대가족: 부모와 자녀가 함께 살고, 노인 부모도 근처에 살며 가족의 부양을 받는 형태입니다.", "3": "대가족: 여러 세대가 함께 살거나 여러 가족이 모여 구성된 가족입니다.", "4": "다문화가족: 다양한 문화적 배경을 가진 사람들이 이루는 가족입니다.", "5": "한부모가족: 한쪽 부모만 있는 가족을 의미합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "고령자(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "부모", "term_vi": "Bố mẹ", "def_ko": "부모님(한국어)", "def_vi": "Cha mẹ"}, {"term_ko": "부양", "term_vi": "Nuôi dưỡng", "def_ko": "지원(한국어)", "def_vi": "Chăm sóc"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "가족(한국어)", "def_vi": "Gia đình"}, {"term_ko": "근거리", "term_vi": "Khoảng cách gần", "def_ko": "가까운 거리(한국어)", "def_vi": "Khoảng cách gần"}, {"term_ko": "형태", "term_vi": "Hình thức", "def_ko": "형식(한국어)", "def_vi": "Hình thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (596, '1', '노인이 적응하기 어렵고, 심한 고독감을 느끼게 되는 상황은?', '["전원생활", "자녀의 취업", "손자 손녀의 출생", "친한 친구의 죽음", "노인일자리사업 참여"]'::jsonb, 4, NULL, NULL, '{"1": "전원생활은 노인이 자연 속에서 생활하는 것으로, 고독감과 관련이 적을 수 있습니다.\n[정답]", "4": "친한 친구의 죽음은 노인이 느끼는 심각한 고독감의 원인이 될 수 있습니다.", "2": "자녀의 취업은 긍정적인 요소로 작용할 수 있습니다.", "3": "손자 손녀의 출생은 노인에게 기쁨을 줄 수 있습니다.", "5": "노인일자리사업 참여는 활동적일 수 있어 고독감과는 거리가 있을 수 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "노인 또는 늙은 사람", "def_vi": "Người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (595, '1', '노인이 죽음이라는 현실을 보다 잘 인식할 수 있는 계기가 되는 상황은?', '["배우자 사별", "경제적 빈곤감", "유대감 상실", "자녀의 결혼", "은퇴"]'::jsonb, 4, NULL, NULL, '{"1": "배우자 사별은 큰 슬픔을 느끼게 하여 죽음을 인식하게 만들 수 있지만, 주로 개인의 슬픔에 국한됩니다.\n[정답]", "4": "자녀의 결혼은 삶의 새로운 단계로 접어들면서 노인의 생애에 대한 성찰을 하게 만들고, 죽음이라는 현실을 더 잘 인식하게 만들 수 있습니다.", "2": "경제적 빈곤감은 삶의 질을 저하시킬 수 있지만, 직접적으로 죽음을 인식하게 만드는 요인은 아닙니다.", "3": "유대감 상실은 외로움을 느끼게 할 수 있지만, 죽음 인식과는 다소 관련성이 적습니다.", "5": "은퇴는 새로운 생활의 시작으로 느껴질 수 있어 죽음을 인식하는 요인과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (594, '1', '배우자 사별에 대한 적응단계 중 노인이 처음으로 경험하는 정서적 반응은?', '["소외감", "불안감", "상실감", "정체감", "자아존중감"]'::jsonb, 3, NULL, NULL, '{"1": "소외감: 친구나 가족과의 관계에서 느끼는 고립감을 의미합니다.", "2": "불안감: 사별 후 미래에 대한 불안이나 두려움을 느끼는 것입니다.\n[정답]", "3": "상실감: 배우자의 사별로 인한 가장 처음 느껴지는 정서적 반응이며, 잃어버린 것에 대한 아픔입니다.", "4": "정체감: 노후에 자신의 존재 의미를 찾는 것입니다.", "5": "자아존중감: 자신의 가치와 존엄성을 인식하는 것입니다."}'::jsonb, '[{"term_ko": "배우자", "term_vi": "Người phối ngẫu", "def_ko": "결혼한 사람", "def_vi": "Người đã kết hôn"}, {"term_ko": "사별", "term_vi": "Mất người yêu", "def_ko": "사랑하는 사람을 잃다", "def_vi": "Mất người mà mình yêu quý"}, {"term_ko": "상실감", "term_vi": "Cảm giác mất mát", "def_ko": "잃은 것에 대한 슬픔", "def_vi": "Nỗi buồn về những gì đã mất"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정에 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "어떤 행동이나 태도를 보이는 것", "def_vi": "Hành động hoặc thái độ thể hiện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (593, '1', '현대 사회에서 나타나는 노년기의 가족관계 변화 중 옳은 것은?', '["부부간의 관계가 동반자로 전환된다.", "성 역할의 구분이 명확해지고 있다.", "노년기 부부간 관계의 중요성이 감소되고 있다.", "부모에 비해 손자녀에 대한 책임감이 강해진다.", "노년기에 이르면서 형제자매와의 경쟁심이나 갈등이 심해진다."]'::jsonb, 1, NULL, NULL, '{"1": "부부는 보다 동반자로서의 관계를 중시하게 됩니다.\n[정답]", "2": "성 역할의 구분은 노년기에 상대적으로 명확해질 수 없으며 부부간의 역할이 변화합니다.", "3": "노년기 부부간의 관계는 오히려 중요성이 증가하는 경향이 있습니다.", "4": "손자녀에 대한 책임감은 부부의 관계와 다르게 나타날 수 있습니다.", "5": "형제자매간의 갈등은 노년기에 일반적이지 않고, 오히려 서로의 지원이 중요하게 여겨집니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Giai đoạn tuổi già", "def_ko": "일생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc đời"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (592, '1', '현대사회의 노인과 가족관계에 대한 설명으로 옳은 것은?', '["조부모들이 손자손녀와의 동거 관계를 불편해한다.", "기혼 자녀와의 동거가 줄면서 혼자 사는 노인이 늘고 있다.", "고부갈등이 늘어나고 장서갈등은 줄어든다.", "자녀가 직접 노인 부모를 봉양하는 일이 증가하고 있다.", "배우자와 사별 후 남성노인이 여성노인보다 더 오래 산다."]'::jsonb, 2, NULL, NULL, '{"1": "조부모와 손자손녀의 동거 관계에 대한 일반적인 불편함은 없다. \n[정답]", "2": "기혼 자녀와의 동거가 줄어들고 혼자 사는 노인의 수가 증가하고 있다는 사실은 현재 사회의 중요한 변화 중 하나이다.", "3": "고부갈등이 늘어나고 장서갈등이 줄어들 것이라는 주장은 통계적으로 뒷받침되지 않는다.", "4": "자녀가 직접 노인 부모를 봉양하는 일은 최근 감소하고 있다는 연구 결과가 많다.", "5": "배우자와 사별 후 남성 노인이 여성 노인보다 더 오래 산다는 통계는 존재하지 않는다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "elderly (한국어)", "def_vi": "elderly (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (591, '1', '생애주기 중 노인의 특성에 대한 이해로 옳은 것은?', '["노인의 특성은 선입견을 갖고 일반화시킨다.", "노인과의 만남은 일회적 접촉으로 충분하다.", "반복적 만남을 통해 노인의 특성을 파악한다.", "통합은 지나온 삶을 부정적으로 인식하는 것이다.", "절망은 과거와 현재 상황을 받아들이고 통합하는 상태이다."]'::jsonb, 3, NULL, NULL, '{"1": "노인의 특성을 일반화하는 것은 선입견을 낳을 수 있습니다.", "2": "노인과의 만남은 일회적이지 않고 반복적이어야 합니다.\n[정답]", "3": "반복적 만남을 통해 노인의 특성을 파악하는 것이 중요합니다.", "4": "통합은 지나온 삶을 부정적으로 인식하지 않습니다.", "5": "절망은 과거와 현재의 상황을 통합하는 것이 아닙니다."}'::jsonb, '[{"term_ko": "생애주기", "term_vi": "Vòng đời", "def_ko": "인생의 각 단계", "def_vi": "Các giai đoạn trong cuộc đời"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징, 성질", "def_vi": "Tính chất, đặc tính"}, {"term_ko": "선입견", "term_vi": "Định kiến", "def_ko": "선입관, 편견", "def_vi": "Định kiến, ý kiến đã hình thành trước"}, {"term_ko": "통합", "term_vi": "Tích hợp", "def_ko": "하나로 합쳐짐", "def_vi": "Sự kết hợp, hợp nhất"}, {"term_ko": "절망", "term_vi": "Tuyệt vọng", "def_ko": "희망이 없음", "def_vi": "Không còn hy vọng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (590, '1', '에릭 에릭슨의 인간발달 단계 중 노년기에 경험하는 위기와 변화는?', '["근면성과 열등감", "친밀감과 고립감", "신뢰감과 불신감", "자아통합성과 절망감", "정체감과 역활혼돈"]'::jsonb, 4, NULL, NULL, '{"1": "근면성과 열등감은 아동기에 해당하는 주제입니다.", "2": "친밀감과 고립감은 청년기에 관련된 개념입니다.", "3": "신뢰감과 불신감은 유아기에 해당합니다.\n[정답]", "4": "자아통합성과 절망감은 노년기의 주요 주제로, 자신이 인생을 어떻게 평가하느냐에 대한 문제입니다.", "5": "정체감과 역할혼돈은 청소년기에 해당하는 개념입니다."}'::jsonb, '[{"term_ko": "인간발달", "term_vi": "Phát triển con người", "def_ko": "사람의 성장 과정(한국어)", "def_vi": "Quá trình lớn lên của con người(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (589, '1', '노인의 사회적 역할 변화로 인한 사회적 특성으로 옳은 것은?', '["퇴직으로 여유로운 생활을 한다.", "사회적 관계가 늘어나면서 유대감이 강화된다.", "사회적 역할이 상실되고 가정에서의 역할이 많아진다.", "역할 변화를 받아들이며 정서적 안정을 느끼게 된다.", "복합적이고 만성적인 질환으로 사회적 관계가 위축된다."]'::jsonb, 5, NULL, NULL, '{"1": "퇴직 후 여유로운 생활을 하는 것은 일반적이지만, 모든 노인이 그렇게 느끼는 것은 아니다.\n[정답]", "5": "만성적인 질환으로 인해 사회적 관계가 위축되는 것이 노인의 일반적인 특성 중 하나이다.", "2": "사회적 관계가 늘어나기보다 약화되는 경향이 있다.", "3": "사회적 역할의 상실은 많아지지만, 가정에서의 역할 변화는 개인마다 다르다.", "4": "정서적 안정을 느끼는 것이 아니라 어려움을 겪는 경우가 많다."}'::jsonb, '[{"term_ko": "사회적 역할", "term_vi": "Vai trò xã hội", "def_ko": "사람의 사회 내에서의 기능과 위치", "def_vi": "Chức năng và vị trí của một người trong xã hội"}, {"term_ko": "사회적 관계", "term_vi": "Mối quan hệ xã hội", "def_ko": "사람들 간의 연결과 상호작용", "def_vi": "Sự kết nối và tương tác giữa mọi người"}, {"term_ko": "정서적 안정", "term_vi": "Sự ổn định cảm xúc", "def_ko": "감정의 안정된 상태", "def_vi": "Trạng thái cảm xúc ổn định"}, {"term_ko": "만성적 질환", "term_vi": "Bệnh mãn tính", "def_ko": "장기간 지속되는 질병", "def_vi": "Bệnh kéo dài trong thời gian dài"}, {"term_ko": "유대감", "term_vi": "Cảm giác gắn bó", "def_ko": "사람들 간의 끈끈한 관계", "def_vi": "Mối quan hệ chặt chẽ giữa mọi người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (588, '1', '노화로 인한 노인의 심리적 변화로 옳은 것은?', '["유연성 증가", "외향성 증가", "조심성 증가", "독립성 증가", "의존성 증가"]'::jsonb, 5, NULL, NULL, '{"1": "유연성 증가: 노화가 진행됨에 따라 유연성이 줄어드는 경향이 있습니다.", "2": "외향성 증가: 대개 내향적인 성향이 강화될 수 있습니다.", "3": "조심성 증가: 조심성이 증가하는 경우도 있으나, 이는 개인 차이에 따라 다를 수 있습니다.\n[정답]", "4": "독립성 증가: 나이가 들수록 독립적인 생활을 하려는 경향이 약해질 수 있습니다.", "5": "의존성 증가: 노화로 인해 신체적, 정서적인 의존성이 증가하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어감(한국어)", "def_vi": "sự già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (587, '1', '다음 설명에 해당하는 노인의 심리적 특성은?• 자신이 이 세상에 다녀갔다는 흔적을 후세에 남기고자 한다.• 자신이 가치 있는 삶을 살았다는 것을 인정받고자 한다.', '["의존성의 증가", "유산을 남기려는 경향", "내향성의 증가", "친근한 사물에 대한 애착심", "생에 대한 회고의 경향"]'::jsonb, 2, NULL, NULL, '{"1": "노인의 의존성이 증가하는 것은 심리적 특성 중 하나지만, 여기서는 후세에 대한 유산 남기기와 관련이 없습니다.\n[정답]", "2": "노인이 자신의 존재 가치를 인정받고자 하는 것은 유산을 남기려는 경향입니다.", "3": "내향성의 증가는 일반적인 심리적 경향일 수 있지만, 문제의 맥락에서는 부적합합니다.", "4": "친근한 사물에 대한 애착은 심리적 특성이지만, 직접적으로 유산 남기기와 연결되지 않습니다.", "5": "생에 대한 회고의 경향은 노인의 특성 중 하나이나, 유산을 남기려는 경향과는 다릅니다."}'::jsonb, '[{"term_ko": "심리적 특성", "term_vi": "Đặc điểm tâm lý", "def_ko": "인간의 정신과 감정의 특징", "def_vi": "Những đặc trưng về tâm trí và cảm xúc của con người"}, {"term_ko": "유산", "term_vi": "Di sản", "def_ko": "후세에 남기는 재산이나 가치", "def_vi": "Tài sản hoặc giá trị để lại cho thế hệ sau"}, {"term_ko": "가치", "term_vi": "Giá trị", "def_ko": "소중한 것", "def_vi": "Những điều quý giá"}, {"term_ko": "존재", "term_vi": "Sự tồn tại", "def_ko": "살아 있음", "def_vi": "Sự sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (586, '1', '다음 내용은 노인의 심리적 특성 중 어떤 것을 고려한 것인가?요양시설에서 대상자의 가족에게 집에서 쓰던 물건이나 가족사진을 가져오게 하여 정서적 안정감을 유지하도록 돕는다.', '["의존성", "애착심", "경직성", "조심성", "내향성"]'::jsonb, 2, NULL, NULL, '{"1": "의존성: 노인이 다른 사람에게 의존하는 경향을 의미한다.\n[정답]", "2": "애착심: 대상자가 사랑하는 사람이나 익숙한 사물에 대해 가지는 정서적 유대를 뜻한다.", "3": "경직성: 변경이나 새로운 것에 대한 저항을 나타낸다.", "4": "조심성: 신중함이나 위험을 피하려는 성향을 나타낸다.", "5": "내향성: 낯선 환경에서 스스로를 방어하며 외부와의 접촉을 피하는 성향을 의미한다."}'::jsonb, '[{"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "심리적인 것과 관련된", "def_vi": "Liên quan đến tâm lý"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc trưng"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác ổn định", "def_ko": "안전하고 편안한 느낌", "def_vi": "Cảm giác an toàn và thoải mái"}, {"term_ko": "애착심", "term_vi": "Tình cảm gắn bó", "def_ko": "사랑하는 사람에 대한 감정적인 유대", "def_vi": "Sự gắn bó tình cảm với người yêu thích"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (585, '1', '다음 설명에 해당하는 노인의 심리적 특성은?• 자신의 지나온 일생의 여러 요인들을 떠올려 본다.• 실패와 좌절에 담담해 진다.•다가오는 죽음을 평온한 마음으로 받아들인다.', '["우울증 경향의 증가", "내향성의 증가", "유산을 남기려는 경향", "생에 대한 회고의 경향", "친근한 사물에 대한 애착심"]'::jsonb, 4, NULL, NULL, '{"1": "우울증 경향의 증가는 노인의 행동 특성을 나타내지만, 질문에 주어진 설명과는 관련이 없다.", "2": "내향성의 증가는 특정한 행동 특성을 의미하지만, 설명된 내용과 직접적으로 연결되지 않는다.\n[정답]", "3": "생에 대한 회고의 경향은 과거의 경험을 되새기는 노인의 행동을 잘 나타내며 최종 선택지로 적합하다.", "4": "친근한 사물에 대한 애착심은 노인들의 일반적인 심리 감정이지만, 설명된 특성과는 관련이 적다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (584, '1', '자신에게 익숙한 습관적인 태도나 방법을 고수하고 매사에 융통성이 없어지며 새로운 변화를 싫어한다. 노인의 심리적 특성은?', '["애착심 증가", "경직성 증가", "의존성 증가", "내향성 증가", "조심성 증가"]'::jsonb, 2, NULL, NULL, '{"1": "애착심 증가: 노인이 친밀한 관계를 필요로 한다는 의미인데, 변화에 대한 저항과는 관련이 적습니다.\n[정답]", "2": "경직성 증가: 새로운 상황에 적응하지 않고 고집스러운 태도를 유지하는 것과 관련됩니다.", "3": "의존성 증가: 노인이 외부의 도움에 의존하게 되는 것을 의미하지만, 융통성과는 관련이 없습니다.", "4": "내향성 증가: 대인관계의 변화와 상관이 있으며, 경직성과는 다른 개념입니다.", "5": "조심성 증가: 변화에 대한 두려움을 포함하지만, 경직성과는 다르게 행동할 수 있는 여지가 있습니다."}'::jsonb, '[{"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "습관(듣기)", "def_vi": "Thói quen"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "태도(듣기)", "def_vi": "Thái độ"}, {"term_ko": "융통성", "term_vi": "Tính linh hoạt", "def_ko": "융통성(듣기)", "def_vi": "Tính linh hoạt"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "변화(듣기)", "def_vi": "Thay đổi"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "경직성(듣기)", "def_vi": "Tính cứng nhắc"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "심리적(듣기)", "def_vi": "Tâm lý"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특성(듣기)", "def_vi": "Đặc điểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (583, '1', '일의 결과를 중시하고, 질문이나 문제에 대해 대답을 할지 망설이거나 하지 못하며, 매사에 신중해지는 노인의 심리적 특성은?', '["조심성의 증가", "내향성의 증가", "경직성의 증가", "우울증 경향의 증가", "친근한 사물에 대한 애착심 증가"]'::jsonb, 1, NULL, NULL, '{"1": "조심성이 증가하면 질문이나 문제에 대한 망설임이 발생할 수 있습니다.\n[정답]", "2": "내향성 증가와는 관련이 적습니다.", "3": "경직성의 증가는 특정 상황에 국한되지 않습니다.", "4": "우울증 경향은 별개의 심리적 특성입니다.", "5": "친근한 사물에 대한 애착심 증가와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "일의 결과", "term_vi": "신중", "def_ko": "결과 của công việc", "def_vi": "cẩn trọng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (582, '1', '사회적 활동이 감소하고 타인과 만나는 것을 점차 기피하는 경향이 나타나는 노인의 심리적 특성은?', '["조심성의 증가", "우울증 경향의 증가", "내향성의 증가", "경직성의 증가", "의존성의 증가"]'::jsonb, 3, NULL, NULL, '{"1": "조심성이 증가하면 외부 환경에 대한 경계가 커지지만, 노인들이 만남을 기피하는 것과는 다소 동떨어진 개념입니다.\n[정답]", "2": "우울증 경향이 증가하는 것은 심리적 에너지의 감소와 관련이 있지만, 내향성의 증가와 직접 연결되지는 않습니다.", "3": "내향성의 증가는 사회적 활동을 감소시키고 타인과의 만남을 기피하게 만듭니다.", "4": "경직성의 증가는 정신적 유연성을 잃는 것을 의미하지만, 사회적 기피와는 거리가 있습니다.", "5": "의존성의 증가는 외부에 대한 의존성을 높이지만, 내향성과는 다른 방향입니다."}'::jsonb, '[{"term_ko": "사회적 활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들 간의 상호작용과 교류", "def_vi": "Tương tác và giao lưu giữa mọi người"}, {"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "기분이 지속적으로 저하되는 정신 질환", "def_vi": "Bệnh tâm thần có tâm trạng liên tục bị giảm"}, {"term_ko": "내향성", "term_vi": "Hướng nội", "def_ko": "자신의 감정을 내면적으로 표현하는 성향", "def_vi": "Xu hướng biểu hiện cảm xúc bên trong"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "유연함을 상실한 상태", "def_vi": "Trạng thái mất đi sự linh hoạt"}, {"term_ko": "의존성", "term_vi": "Tính phụ thuộc", "def_ko": "다른 사람에게 의지하는 성향", "def_vi": "Xu hướng dựa vào người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (581, '1', '우울증 경향이 있는 노인에게 나타나는 특성은?', '["자신감이 증가한다.", "숙면을 취한다.", "식욕이 증가한다.", "기억력이 저하된다.", "대인관계가 활발해진다."]'::jsonb, 4, NULL, NULL, '{"1": "자신감이 증가하는 것은 우울증의 특징이 아니다.", "2": "숙면을 취하는 것은 우울증 환자에게서 흔하지 않다.", "3": "식욕이 증가하는 것은 우울증과 관련이 적다.\n[정답]", "4": "기억력이 저하되는 것은 우울증 환자에게 자주 나타나는 현상이다.", "5": "대인관계가 활발해지는 것은 우울증과 반대되는 경향이다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질병으로 기분이 우울하고 기능이 저하됨", "def_vi": "Bệnh tâm lý khiến tâm trạng u ám và chức năng giảm sút"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (580, '1', '다음에서 설명하는 노인의 심리적인 특성은?•불면증, 식욕부진 •기억력 저하, 체중감소 •흥미와 의욕상실', '["조심성의 증가", "우울증 경향의 증가", "경직성의 증가", "내향성의 증가", "의존성의 증가"]'::jsonb, 2, NULL, NULL, '{"1": "조심성의 증가: 노인에서 나타나는 심리적 특성이지만 질문의 증상과는 맞지 않음.\n[정답]", "2": "우울증 경향의 증가: 불면증, 식욕부진, 기억력 저하 등의 증상은 우울증의 특징들로 볼 수 있어 정답.", "3": "경직성의 증가: 성격의 구조적 변화와 관련있지만 질문의 증상과는 무관함.", "4": "내향성의 증가: 심리적 특성이지만 직접적인 관련성은 낮음.", "5": "의존성의 증가: 노인의 특성 중 하나이나 질문의 조건에선 적합하지 않음."}'::jsonb, '[{"term_ko": "불면증", "term_vi": "Mất ngủ", "def_ko": "잠을 충분히 자지 못하는 상태(한국어)", "def_vi": "Trạng thái không thể ngủ đủ"}, {"term_ko": "식욕부진", "term_vi": "Suy giảm cảm giác thèm ăn", "def_ko": "음식에 대한 욕구가 감소한 상태(한국어)", "def_vi": "Trạng thái giảm nhu cầu về thực phẩm"}, {"term_ko": "기억력 저하", "term_vi": "Giảm trí nhớ", "def_ko": "기억하는 능력이 떨어지는 상태(한국어)", "def_vi": "Trạng thái giảm khả năng ghi nhớ"}, {"term_ko": "체중감소", "term_vi": "Giảm cân", "def_ko": "몸무게가 줄어드는 현상(한국어)", "def_vi": "Hiện tượng trọng lượng cơ thể giảm"}, {"term_ko": "흥미", "term_vi": "Sự quan tâm", "def_ko": "어떤 것에 대해 관심을 가지는 것(한국어)", "def_vi": "Có sự quan tâm đến điều gì đó"}, {"term_ko": "의욕", "term_vi": "Ý chí", "def_ko": "어떤 일을 하려는 의향이나 열망(한국어)", "def_vi": "Sự mong muốn hoặc khát vọng làm một việc gì đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (579, '1', '노인의 공통적인 신체적 특성으로 옳은 것은?', '["신체 조직의 적응력이 빠르다.", "질병이 발생할 경우 급격하게 상황이 악화된다.", "인간의 노력으로 노화의 진행을 막을 수 있다.", "잔존능력의 증가로 일상생활에 어려움은 없다.", "회복이 가능한 만성질환이 대부분이다."]'::jsonb, 2, NULL, NULL, '{"1": "신체 조직의 적응력이 빠르지 않으므로 틀립니다.\n[정답]", "2": "질병이 발생할 경우 급격하게 상황이 악화되므로 옳은 설명입니다.", "3": "노화의 진행은 완전히 막을 수 없습니다.", "4": "잔존 능력이 증가하지 않으므로 일상생활에 어려움이 있을 수 있습니다.", "5": "대부분의 만성질환은 회복이 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "cơ thể(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (578, '1', '노인의 신체적 특성으로 옳은 것은?', '["면역능력이 향상된다.", "회복능력이 향상된다.", "노화가 비가역적으로 진행된다.", "신체기관의 잔존능력이 향상된다.", "일상생활 수행능력이 향상된다."]'::jsonb, 3, NULL, NULL, '{"1": "면역능력은 노화와 함께 감소한다.", "2": "회복능력 역시 노화로 인해 저하된다. \n[정답]", "3": "노화는 비가역적인 과정으로 진행된다.", "4": "신체기관의 잔존능력은 노화에 따라 감소할 수 있다.", "5": "일상생활 수행능력은 보통 노화와 함께 저하된다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "몸과 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc điểm"}, {"term_ko": "면역능력", "term_vi": "Khả năng miễn dịch", "def_ko": "면역 기능", "def_vi": "Chức năng miễn dịch"}, {"term_ko": "회복능력", "term_vi": "Khả năng hồi phục", "def_ko": "회복 능력", "def_vi": "Khả năng hồi phục"}, {"term_ko": "비가역적", "term_vi": "Không thể đảo ngược", "def_ko": "되돌릴 수 없는", "def_vi": "Không thể đảo ngược"}, {"term_ko": "신체기관", "term_vi": "Cơ quan trong cơ thể", "def_ko": "몸의 기관", "def_vi": "Các cơ quan trong cơ thể"}, {"term_ko": "잔존능력", "term_vi": "Khả năng còn lại", "def_ko": "남아 있는 능력", "def_vi": "Khả năng tồn tại"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "일상적인 활동", "def_vi": "Các hoạt động hàng ngày"}, {"term_ko": "수행능력", "term_vi": "Khả năng thực hiện", "def_ko": "수행 능력", "def_vi": "Khả năng thực hiện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (577, '1', '건강한 노화를 위한 방법으로 옳은 것은?', '["체면을 위해 애정 표현은 삼간다.", "뇌에 자극을 주는 활동을 한다.", "사생활을 위해 대인관계를 자제한다.", "만성질환을 민간요법으로 지속적으로 관리한다.", "신체적 노화를 늦추기 위해 매시간 고강도 운동을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "체면을 위해 애정 표현은 삼간다는 노화와 관련이 없는 부정적인 태도를 나타냅니다.\n[정답]", "2": "뇌에 자극을 주는 활동은 노화 방지와 인지 기능 향상에 도움이 됩니다.", "3": "사생활을 위해 대인관계를 자제하는 것은 건강한 사회적 관계를 맺는 데 방해가 됩니다.", "4": "만성질환을 민간요법으로 관리하는 것은 전문적인 치료에 비해 신뢰성이 떨어질 수 있습니다.", "5": "신체적 노화를 늦추기 위해 매시간 고강도 운동을 하는 것은 오히려 신체에 무리를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "건강한", "term_vi": "Khỏe mạnh", "def_ko": "건강한(한국어)", "def_vi": "khỏe mạnh(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (576, '1', '노년기를 건강하게 보내기 위한 방법으로 옳은 것은?', '["야외 활동을 점차 줄인다.", "기억력 유지를 위해 단조로운 생활을 한다.", "만성질환의 유무를 정기적으로 확인한다.", "건강을 위해 자신에게 맞지 않는 음식도 먹도록 한다.", "여가활동, 지역사회 참여 등 생산적 활동을 자제한다."]'::jsonb, 3, NULL, NULL, '{"1": "야외 활동을 점차 줄이는 것은 건강에 좋지 않다.", "2": "기억력 유지를 위해 단조로운 생활을 하는 것은 좋지 않다.\n[정답]", "3": "만성질환의 유무를 정기적으로 확인하는 것은 건강 유지에 필수적이다.", "4": "건강을 위해 자신에게 맞지 않는 음식을 먹는 것은 해롭다.", "5": "여가활동과 지역사회 참여는 노년기의 생산적 활동으로 권장된다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Thời kỳ cao niên", "def_ko": "노인의 생애 단계", "def_vi": "Giai đoạn sống của người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (575, '1', '국가가 ''노인의 날''을 지정하여 해마다 기념하는, 노인을 위한 보상 유형은?', '["정치적 보상", "신체적 보상", "경제적 보상", "문화유산의 전수", "지적, 정신적 보상"]'::jsonb, 1, NULL, NULL, '{"1": "정치적 보상: 노인을 위한 정치적 권리 및 참여 기회를 포함한다.\n[정답]", "2": "신체적 보상: 노인의 건강 및 신체적 지원을 제공하는 것을 의미하지만, 이 문제의 정답은 아니다.", "3": "경제적 보상: 노인의 경제적 지원을 의미하나, ''노인의 날''의 취지와는 관련이 적다.", "4": "문화유산의 전수: 노인에게 문화유산을 계승하는 것을 의미하며 보상 유형이 아니다.", "5": "지적, 정신적 보상: 지적 및 정신적 지원을 포함하지만, 국가의 공식적인 보상 형태로서는 부적합하다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (574, 'mock', '중이염을 앓고 있는 대상자에게 귀약을 투여할 때 귓바퀴를 잡아당기는 방향은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 2, NULL, NULL, '{"1": "잘못된 방향이다. 올바른 투여 방법이 아니다.\n[정답]", "2": "중이염 환자에게 귀약을 투여할 때는 귓바퀴를 위로 잡아당기는 것이 올바른 방법이다.", "3": "잘못된 방향이다. 올바른 투여 방법이 아니다.", "4": "잘못된 방향이다. 올바른 투여 방법이 아니다.", "5": "잘못된 방향이다. 올바른 투여 방법이 아니다."}'::jsonb, '[{"term_ko": "중이염", "term_vi": "Viêm tai giữa", "def_ko": "귀의 염증", "def_vi": "Viêm ở tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (573, 'mock', '다음 그림에서 대상자에게 안연고를 투여하는 위치와 방향이 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 4, NULL, NULL, '{"1": "(해당 방향이 잘못된 경우)", "2": "(해당 위치가 부적절한 경우)", "3": "(안연고 투여의 원리에 맞지 않는 경우)\n[정답] (라) (대상자에게 안연고를 적절한 위치와 방향으로 투여하는 방법)", "5": "(해당 방법이 잘못된 경우)"}'::jsonb, '[{"term_ko": "안연고", "term_vi": "Thuốc mỡ mắt", "def_ko": "눈에 사용하는 약물 형태", "def_vi": "Hình thức thuốc dùng cho mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (572, 'mock', '다음 그림 중 안약을 투여할 때 올바른 위치는?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 5, NULL, NULL, '{"1": "(가) 안약을 투여할 위치가 아닙니다.\n[정답]", "5": "(마) 안약을 투여할 올바른 위치입니다.", "2": "(나) 안약을 투여할 위치가 아닙니다.", "3": "(다) 안약을 투여할 위치가 아닙니다.", "4": "(라) 안약을 투여할 위치가 아닙니다."}'::jsonb, '[{"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "눈에 넣는 약", "def_vi": "Thuốc dùng cho mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (571, 'mock', '다음 중 물약을 사용하기 위해 병뚜껑을 열어 내려놓는 방법으로 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 1, NULL, NULL, '{"1": "병뚜껑을 열어 놓는 방법이 올바른 방식입니다.\n[정답]", "2": "잘못된 방법입니다.", "3": "잘못된 방법입니다.", "4": "잘못된 방법입니다.", "5": "잘못된 방법입니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "병뚜껑", "term_vi": "Nắp chai", "def_ko": "병에 덮는 뚜껑(한국어)", "def_vi": "Nắp đậy của chai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (570, 'mock', '가파른 내리막길에서 휠체어를 타고 있는 대상자의 이동을 돕는 방법은?', '["휠체어를 뒤로 돌려 지그재그로 내려간다.", "휠체어를 뒤로 돌려 앞바퀴를 들고 내려간다.", "휠체어를 앞으로 하여 똑바로 내려간다.", "휠체어를 앞으로 하여 지그재그로 내려간다.", "휠체어를 앞으로 하여 앞바퀴를 들고 내려간다."]'::jsonb, 1, NULL, NULL, '{"1": "휠체어를 뒤로 돌려 지그재그로 내려가면 이동이 안전합니다.\n[정답]", "2": "휠체어를 뒤로 돌려 앞바퀴를 들고 내려가는 방법은 안전하지 않습니다.", "3": "휠체어를 앞으로 하여 똑바로 내려가는 방법은 위험할 수 있습니다.", "4": "휠체어를 앞으로 하여 지그재그로 내려가는 방법은 안전하지 않습니다.", "5": "휠체어를 앞으로 하여 앞바퀴를 들고 내려가는 방법은 매우 위험합니다."}'::jsonb, '[{"term_ko": "가파른", "term_vi": "Dốc", "def_ko": "경사가 심한", "def_vi": "độ dốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (569, 'mock', '다음과 같이 반좌위 상태인 대상자를 침대 위쪽으로 이동시키는 방법은?', '["침대 시트를 잡아 당긴다.", "양 팔을 잡아 당긴다.", "겨드랑이 밑을 잡아 당긴다.", "발 아래에서 위로 밀어 올린다.", "침대 양 쪽에 서서 어깨와 등, 둔부와 대퇴를 받쳐 올려준다."]'::jsonb, 5, NULL, NULL, '{"1": "침대 시트를 잡아 당기는 것은 대상자를 이동시키는 데 안전하지 않은 방법입니다.\n[정답]", "2": "침대 양쪽에 서서 대상자의 어깨와 등, 둔부와 대퇴를 받쳐 올려주는 방법이 가장 안전하고 효과적입니다.", "3": "겨드랑이 밑을 잡아 당기는 것은 안전하지 않으며, 대상자에게 불편함을 줄 수 있습니다.", "4": "발 아래에서 위로 밀어 올리는 것은 부상의 위험이 있습니다.", "5": "양 팔을 잡아 당기는 것은 힘이 과도하게 들어 가므로 좋지 않습니다."}'::jsonb, '[{"term_ko": "반좌위", "term_vi": "Nửa nằm nửa ngồi", "def_ko": "반 앉은 자세", "def_vi": "Tư thế nửa nằm nửa ngồi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (568, 'mock', '그림과 같이 엎드린 대상자를 베개와 타월로 지지하는 이유는?', '["허리와 넙다리의 긴장 완화", "폐기능의 촉진", "척추 측만증 완화", "무릎관절 구축 예방", "혈액 순환 증진"]'::jsonb, 1, NULL, NULL, '{"1": "허리와 넙다리의 긴장 완화: 엎드린 자세는 허리와 넙다리의 긴장을 완화시켜 주며, 따라서 지지하는 것이 필요하다.\n[정답]", "2": "폐기능의 촉진: 엎드린 자세가 폐 기능에 긍정적인 영향을 줄 수 있지만, 본 질문의 주요 목적과는 다르다.", "3": "척추 측만증 완화: 엎드린 자세는 척추 측만증을 완화할 수 있지만 직접적인 지지 방법은 아니다.", "4": "무릎관절 구축 예방: 엎드린 자세가 직접적인 영향을 미치지 않음.", "5": "혈액 순환 증진: 혈액 순환은 일반적으로 모든 자세에서 증가할 수 있으나, 이 질문의 특정 초점에는 해당하지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 도움이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần trợ giúp"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 기구", "def_vi": "Vật dụng kê đầu"}, {"term_ko": "타월", "term_vi": "Khăn tắm", "def_ko": "개인 위생을 위한 천", "def_vi": "Vải dùng cho vệ sinh cá nhân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "신체의 중간 부분", "def_vi": "Phần giữa cơ thể"}, {"term_ko": "넙다리", "term_vi": "Đùi", "def_ko": "허벅지", "def_vi": "Phần đùi"}, {"term_ko": "척추", "term_vi": "Cột sống", "def_ko": "등뼈", "def_vi": "Xương sống"}, {"term_ko": "측만증", "term_vi": "Cột sống lệch", "def_ko": "척추의 비정상 곡선", "def_vi": "Đường cong bất thường của cột sống"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "체내의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "순환", "term_vi": "Tuần hoàn", "def_ko": "회전 또는 흐름", "def_vi": "Quá trình lưu thông"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (566, 'mock', '장기간의 와상 상태에서 기저귀를 사용하는 대상자에게 욕창이 가장 잘 생기는 부위는?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 4, NULL, NULL, '{"1": "(가) 이 부위는 욕창 발생에 크게 영향을 미치지 않는다.\n[정답]", "4": "(라) 이 부위는 피부 압력으로 인해 욕창이 발생할 가능성이 높다.", "3": "(다) 이 부위의 욕창 위험은 낮다.", "5": "(마) 이 부위의 욕창 위험은 중간 정도이다."}'::jsonb, '[{"term_ko": "와상", "term_vi": "Nằm lâu", "def_ko": "침대에 눕거나 움직이지 못하는 상태", "def_vi": "Trạng thái nằm lâu không thể di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (565, 'mock', '오른쪽 다리가 약한 대상자가 보행기를 사용하여 이동하는 순서는?', '["왼쪽 다리와 보행기 → 오른쪽 다리", "왼쪽 다리 → 오른쪽 다리 → 보행기", "오른쪽 다리와 보행기 → 왼쪽 다리", "오른쪽 다리 → 보행기 → 왼쪽 다리", "보행기 → 왼쪽 다리 → 오른쪽 다리"]'::jsonb, 3, NULL, NULL, '{"1": "왼쪽 다리와 보행기를 사용하는 것은 보행기 사용법에 맞지 않음.\n[정답]", "3": "오른쪽 다리와 보행기를 먼저 사용한 후 왼쪽 다리를 이동하는 것은 약한 다리에 대한 올바른 지지 방법임.", "2": "이 방법은 보행기 사용 시 균형을 잃을 위험이 있음.", "4": "오른쪽 다리와 보행기를 먼저 이동하고 나면 균형 유지가 어려워질 수 있음.", "5": "처음에 보행기를 사용하는 것은 잘못된 순서임."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "Chân"}, {"term_ko": "보행기", "term_vi": "Khung đi bộ", "def_ko": "보행기(한국어)", "def_vi": "Khung đi bộ"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "대상자(한국어)", "def_vi": "Người dùng"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동(한국어)", "def_vi": "Di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (562, 'mock', '다음 그림과 같이 정맥주사를 맞고 있는 왼쪽 편마비 대상자에게 단추있는 옷을 입히는 순서로 옳은 것은?', '["수액주머니 → 오른쪽 팔 → 왼쪽 팔", "오른쪽 팔 → 수액주머니 → 왼쪽 팔", "오른쪽 팔 → 왼쪽 팔 → 수액주머니", "왼쪽 팔 → 수액주머니 → 오른쪽 팔", "왼쪽 팔 → 오른쪽 팔 → 수액주머니"]'::jsonb, 4, NULL, NULL, '{"1": "수액주머니를 먼저 입히면 연결이 끊길 수 있습니다.\n[정답]", "4": "왼쪽 팔을 먼저 입히면 편마비로 인한 불편함을 최소화할 수 있습니다.", "2": "오른쪽 팔부터 시작하는 것은 편마비 대상자에게 적절하지 않습니다.", "3": "수액주머니를 나중에 입히면 연결 상태에 문제가 생길 수 있습니다.", "5": "왼쪽 팔을 먼저 하면서 수액주머니를 나중에 입히는 것은 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "정맥주사", "term_vi": "Truyền nước biển", "def_ko": "정맥에 주입하는 약물 또는 수액", "def_vi": "Dịch truyền vào tĩnh mạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (561, 'mock', '왼쪽 편마비 대상자가 지팡이를 이용하여 버스를 탈 때 순서로 옳은 것은?', '["지팡이 - 오른발 - 왼발", "지팡이 - 왼발 - 오른발", "왼발 - 지팡이 - 오른발", "오른발 -지팡이 - 왼발", "왼발 - 오른발 - 지팡이"]'::jsonb, 1, NULL, NULL, '{"1": "오른발로 지팡이를 지지하고 앞으로 나아가면서 왼발로 버스에 승차하는 방법이 가장 올바릅니다.\n[정답]", "2": "왼발로 먼저 나아가면 균형을 잃을 수 있습니다.", "3": "왼발 먼저 나아가는 것도 부적절한 방법입니다.", "4": "오른발로 먼저 나아가면 지팡이의 역할을 제대로 할 수 없습니다.", "5": "지팡이의 위치가 부적절하여 안정성이 떨어집니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Trạng thái tê liệt một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (557, 'mock', '다음 그림과 같이 휠체어를 자동차의 트렁크로 옮기는 방법으로 옳은 것은?', '["몸에서 멀리하여 들어 올린다.", "허리의 회전을 이용하여 옮긴다.", "허리를 굽혔다 펴면서 들어 올린다.", "무릎을 굽혀 자세를 낮춰서 들어 올린다.", "다리를 모아 지지면을 좁혀 들어 올린다."]'::jsonb, 4, NULL, NULL, '{"1": "몸에서 멀리하여 들어 올리는 것은 허리의 부상을 유발할 수 있습니다.\n[정답]", "4": "무릎을 굽혀 자세를 낮춰서 들어 올리는 방법이 가장 안전하고 올바른 방법입니다.", "3": "허리를 굽혔다 펴면서 들어 올리는 방법은 허리에 부담을 줄 수 있습니다.", "2": "허리의 회전을 이용하여 옮기는 것은 잘못된 방법입니다.", "5": "다리를 모아 지지면을 좁혀 들어 올리는 것은 안정성을 저해할 수 있습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": null, "def_ko": "휠체어", "def_vi": null}, {"term_ko": "트렁크", "term_vi": "Cốp xe", "def_ko": "자동차 후면의 짐을 실는 공간", "def_vi": "không gian để chứa đồ ở phía sau ô tô"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "우리의 관절 중 하나", "def_vi": "một trong những khớp của chúng ta"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "무엇인가를 하고 있는 상태", "def_vi": "trạng thái khi làm một việc gì đó"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "다치거나 아프게 되는 것", "def_vi": "việc bị chấn thương hoặc đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (554, 'mock', '왼쪽 편마비 대상자를 바닥에서 휠체어로 이동시킬 때 휠체어 놓는 위치로 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 1, NULL, NULL, '{"1": "올바른 위치로, 편마비 측과 가까운 방향에 놓여 있어야 하므로 적합하다.\n[정답]", "2": "휠체어가 대상자에게 너무 멀리 놓여 있어 이동에 어려움이 있을 수 있다.", "3": "휠체어가 너무 높은 위치에 놓여 있어 이동 시 불편할 수 있다.", "4": "휠체어가 담넘는 위치에 놓여 있어 안전하지 않다.", "5": "휠체어가 불안정한 위치에 놓여 있어 대상자를 이동하기 위험하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비(한국어)", "def_vi": "Liệt một bên cơ thể(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (553, 'mock', '대상자가 침대 아래쪽으로 미끄러져 내려가 있을 때 위쪽으로 이동시키는 순서는?', '["가 - 나 - 다 - 라", "나 - 라 - 가 - 다", "나 - 다 - 가 - 라", "나 - 가 - 다 - 라", "다 - 나 - 가 - 라"]'::jsonb, 3, NULL, NULL, '{"1": "가: 올바른 세팅이 아님.", "2": "나: 환자를 먼저 안정적으로 잡지 못함.\n[정답]", "3": "나: 먼저 환자의 머리를 안정시킨 후, 다리 쪽을 들어올리고, 가: 환자의 몸을 중앙으로 이동하며, 라: 마지막으로 몸을 고정하는 단계로 이동.", "4": "가: 올바른 순서가 아님.", "5": "다: 이동 순서에서 불필요한 단계가 포함됨."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (552, 'mock', '휠체어를 잡는 순으로 옳은 것은?', '["나 - 가 - 다 - 라", "나 - 라 - 가 - 다", "나 - 다 - 가 - 라", "나 - 다 - 라 - 가", "나 - 가 - 라 - 다"]'::jsonb, 3, NULL, NULL, '{"1": "나 - 가 - 다 - 라: 순서가 잘못되었습니다.\n[정답]", "3": "나 - 다 - 가 - 라: 올바른 순서입니다.", "2": "나 - 라 - 가 - 다: 순서가 잘못되었습니다.", "4": "나 - 다 - 라 - 가: 순서가 잘못되었습니다.", "5": "나 - 가 - 라 - 다: 순서가 잘못되었습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 수단인 휠체어", "def_vi": "Xe trợ giúp di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (551, 'mock', '그림과 같이 오른쪽 편마비 대상자가 지팡이를 이용하여 경사로를 내려갈 때 이동 순서는?', '["지팡이 → 오른쪽 다리 → 왼쪽 다리", "지팡이 → 왼쪽 다리 → 오른쪽 다리", "왼쪽 다리 → 지팡이 → 오른쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "왼쪽 다리 → 오른쪽 다리 → 지팡이"]'::jsonb, 1, NULL, NULL, '{"1": "지팡이로 몸을 지탱한 후 오른쪽 다리를 내리고, 마지막으로 왼쪽 다리를 내리는 순서입니다. 이는 안전하게 내려가는 방법입니다.\n[정답]", "2": "왼쪽 다리를 먼저 내리는 경우, 편마비 대상자가 더욱 불안해질 수 있습니다.", "3": "왼쪽 다리 다음에 지팡이를 내리는 것은 잘못된 순서입니다.", "4": "오른쪽 다리부터 내리는 것은 비슷한 위험을 초래할 수 있습니다.", "5": "이 순서는 편마비 대상을 제대로 고려하지 않으므로 부적절합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리가 마비된 상태", "def_vi": "Tình trạng tê liệt một bên tay và chân"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại"}, {"term_ko": "경사로", "term_vi": "Dốc", "def_ko": "기울어진 도로", "def_vi": "Đường nghiêng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (547, 'mock', '그림과 같이 반좌위를 하고 있는 대상자가 미끄러져 내려가지 않고 편안하도록 돕는 방법은?', '["발바닥에 베개를 대어 준다.", "머리 쪽 침대를 조금 더 올려 준다.", "목과 어깨 밑에 베개를 받쳐 준다.", "다리 쪽의 침대르 살짝 올려 준다.", "등 뒤에 베개를 A자 형태로 받쳐 준다."]'::jsonb, 4, NULL, NULL, '{"1": "발바닥에 베개를 대어 준다: 발바닥에 베개를 두는 것은 반좌위를 유지하는 데 도움이 되지 않습니다.\n[정답]", "2": "머리 쪽 침대를 조금 더 올려 준다: 머리 쪽을 올리면 몸이 안정되지만 미끄러짐 방지에는 효과적이지 않습니다.", "3": "목과 어깨 밑에 베개를 받쳐 준다: 이 방법은 반좌위를 유지하는 데 적합하지 않으며 불편할 수 있습니다.", "4": "다리 쪽의 침대를 살짝 올려 준다: 다리 쪽을 올리면 중심이 안정되어 미끄러지지 않도록 도와줍니다.", "5": "등 뒤에 베개를 A자 형태로 받쳐 준다: 이 방법은 지원을 제공하지만 반좌위를 유지하는 데 한계가 있습니다."}'::jsonb, '[{"term_ko": "반좌위", "term_vi": "Tư thế nửa nằm", "def_ko": "반 누운 자세", "def_vi": "Tư thế nằm nghiêng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (544, 'mock', '다음 그림과 같이 휠체어에 앉아있는 대상자를 자동차에 태울 때 순서로 옳은 것은?', '["나 - 가 - 다 - 라", "나 - 가 - 라 - 다", "나 - 다 - 가 - 라", "나 - 다 - 라 - 가", "나 - 라 - 다 - 가"]'::jsonb, 5, NULL, NULL, '{"1": "나 - 가 - 다 - 라: 순서가 비효율적이며 안전하지 않습니다.\n[정답]", "5": "나 - 라 - 다 - 가: 휠체어 사용자가 안전하게 차량에 탑승하는 정답 순서입니다.", "2": "나 - 가 - 라 - 다: 올바른 순서가 아닙니다.", "3": "나 - 다 - 가 - 라: 비효율적인 순서입니다.", "4": "나 - 다 - 라 - 가: 안전하지 않은 순서입니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "자동차", "def_ko": "휠체어(휠체어)", "def_vi": "자동차(ô tô)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (543, 'mock', '그림과 같은 방법으로 휠체어를 이동해야 하는 상황은?', '["오르막길을 올라갈 때", "내리막길을 내려갈 때", "울퉁불퉁한 길을 갈 때", "엘리베이터를 타고 내릴 때", "평지를 이동할 때"]'::jsonb, 3, NULL, NULL, '{"1": "오르막길을 올라갈 때는 휠체어를 뒤에서 밀어주어야 하므로 주의가 필요합니다.\n[정답]", "2": "내리막길에는 속도를 충분히 조절해야 하므로 주의가 필요합니다.", "3": "울퉁불퉁한 길을 갈 때는 휠체어에 진동이 가해지므로 더욱 주의가 요구됩니다.", "4": "엘리베이터를 타고 내릴 때는 안전한 이동이 필요합니다.", "5": "평지를 이동할 때는 비교적 안전하나 기본적인 주의가 필요합니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (541, 'mock', '다음 그림에 해당하는 세탁방법은?', '["30℃ 물에 중성세제 사용, 약하게 손세탁 가능", "30℃ 물에 중성세제 사용, 세탁기 사용 불가", "30℃ 물에 세제 종류 제한 없음", "중성세제 사용, 삶을 수 있음", "물세탁 안 됨"]'::jsonb, 1, NULL, NULL, '{"1": "30℃ 물에 중성세제를 사용하여 약하게 손세탁이 가능한 방법입니다. [정답]", "2": "30℃ 물에 중성세제를 사용하나 세탁기 사용이 불가능하다는 의미로, 그림에 적합하지 않습니다.", "3": "30℃ 물에는 세제 종류의 제한이 없지만, 그림의 세탁 방법을 고려할 때 이 방법은 적합하지 않습니다.", "4": "중성세제를 사용하고 삶을 수 있는 방법은 일반적으로 부드러운 세탁 조건을 요구하는 그림의 내용과 맞지 않습니다.", "5": "물세탁이 불가능한 경우는 그림과 일치하지 않습니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (540, 'mock', '다음 그림과 같이 방바닥에 누워있는 대상자를 일으켜 앉힌 후, 휠체어로 옮기는 순서로 옳은 것은?', '["가 - 나 - 라 - 다", "가 - 라 - 나 - 다", "나 - 가 - 다 - 라", "다 - 라 - 나 - 가", "라 - 다 - 가 - 나"]'::jsonb, 5, NULL, NULL, '{"1": "가 - 나 - 라 - 다: 이 순서는 대상자를 안전하게 세울 수 없습니다.\n[정답]", "5": "라 - 다 - 가 - 나: 올바른 순서로 대상자를 세우고 휠체어로 옮기는 방법입니다.", "3": "나 - 가 - 다 - 라: 위험한 방법으로, 대상자를 안전하게 옮길 수 없습니다.", "4": "다 - 라 - 나 - 가: 비효율적인 방법으로 안전하지 않습니다.", "2": "가 - 라 - 나 - 다: 짜임새가 없는 순서입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "방바닥", "term_vi": "Sàn nhà", "def_ko": "바닥이 있는 곳(한국어)", "def_vi": "Nơi có sàn"}, {"term_ko": "퀼체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "다치지 않음(한국어)", "def_vi": "Không bị thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (539, 'mock', '그림과 같이 대상자가 누워서 엉덩이를 들어 올리는 운동을 하는 이유는?', '["침대 위에서 이동이나 보행 시 신체안정에 도움이 된다.", "장시간 와상상태 시 욕창을 예방한다.", "어지러움, 오심, 구토 등의 증상을 완화시킨다.", "폐기능을 강화하여 호흡에 도움을 준다.", "관절의 굳어짐을 예방한다."]'::jsonb, 1, NULL, NULL, '{"1": "침대 위에서 이동이나 보행 시 신체안정에 도움이 된다.\n[정답]", "2": "장시간 와상상태 시 욕창을 예방한다.", "3": "어지러움, 오심, 구토 등의 증상을 완화시킨다.", "4": "폐기능을 강화하여 호흡에 도움을 준다.", "5": "관절의 굳어짐을 예방한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "사람(한국어)", "def_vi": "Người được chăm sóc"}, {"term_ko": "운동", "term_vi": "Bài tập", "def_ko": "신체활동(한국어)", "def_vi": "Hoạt động thể chất"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이 부위(한국어)", "def_vi": "Vùng mông"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부손상(한국어)", "def_vi": "Tổn thương da"}, {"term_ko": "폐기능", "term_vi": "Chức năng phổi", "def_ko": "호흡 기능(한국어)", "def_vi": "Chức năng hô hấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (537, 'mock', '그림과 같이 대상자가 오른쪽으로 쏠려있을 때 침대 중앙으로 이동시키는 방법으로 옳은 것은?', '["어깨와 둔부를 밀어서 이동시킨다.", "팔과 다리를 잡고 당겨 이동시킨다.", "상반신과 하반신을 나누어서 이동시킨다.", "몸통 밑을 받쳐 한 번에 이동시킨다.", "머리와 허리를 잡고 당겨 이동시킨다."]'::jsonb, 3, NULL, NULL, '{"1": "어깨와 둔부를 밀어서 이동시키는 것은 안전하지 않고, 근골격계에 부담을 줄 수 있다.\n[정답]", "3": "상반신과 하반신을 나누어서 이동시키는 방법은 안전하고 효과적으로 이동할 수 있다.", "2": "팔과 다리를 잡고 당겨 이동시키면 약한 부위에 무리가 갈 수 있다.", "4": "몸통 밑을 받쳐 한 번에 이동시키는 것은 불안정할 수 있고, 잘못하면 부상 위험이 있다.", "5": "머리와 허리를 잡고 당겨 이동시키는 것은 잘못된 움직임으로 인해 부상 위험이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자", "def_vi": "Người được chăm sóc"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동하다", "def_vi": "Chuyển động"}, {"term_ko": "어깨", "term_vi": "Vai", "def_ko": "어깨", "def_vi": "Vai"}, {"term_ko": "둔부", "term_vi": "Hông", "def_ko": "엉덩이", "def_vi": "Hông"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "상체", "def_vi": "Phần thân trên"}, {"term_ko": "하반신", "term_vi": "Thân dưới", "def_ko": "하체", "def_vi": "Phần thân dưới"}, {"term_ko": "몸통", "term_vi": "Thân", "def_ko": "몸", "def_vi": "Thân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리", "def_vi": "Lưng"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "부상", "def_vi": "Chấn thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (530, 'mock', '보행보조차(실버카)의 안전한 사용을 위해 반드시 점검해야 하는 부분은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 3, NULL, NULL, '{"1": "(가)", "2": "(나)\n[정답]", "3": "보행보조차의 바퀴가 정상적으로 작동하는지 확인해야 합니다.", "4": "(라)", "5": "(마)"}'::jsonb, '[{"term_ko": "보행보조차", "term_vi": "Xe đi bộ hỗ trợ", "def_ko": "보행을 도와주는 기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (529, 'mock', '그림과 같은 표시 방법에 따라 건조해야 하는 세탁물은?', '["꽃무늬 블라우스", "하얀색 면 티셔츠", "이불 커버", "노란색 울 스웨터", "빨간색 니트"]'::jsonb, 1, NULL, NULL, '{"1": "꽃무늬 블라우스는 일반적으로 통풍이 잘 되는 그늘에서 건조해야 합니다.\n[정답]", "2": "하얀색 면 티셔츠는 직사광선을 피하고 건조할 수 있습니다.", "3": "이불 커버는 널고 건조하는 것이 적합합니다.", "4": "노란색 울 스웨터는 세탁 후 평평하게 눕혀서 건조해야 합니다.", "5": "빨간색 니트는 서늘한 그늘에서 짠 후 조심스럽게 건조해야 합니다."}'::jsonb, '[{"term_ko": "세탁물", "term_vi": "Đồ giặt", "def_ko": "세탁하기 위한 물품", "def_vi": "Các vật phẩm cần giặt"}, {"term_ko": "건조", "term_vi": "Sấy khô", "def_ko": "물이나 습기를 제거하여 마르는 것", "def_vi": "Việc loại bỏ nước hoặc độ ẩm để vật phẩm khô"}, {"term_ko": "블라우스", "term_vi": "Blouse", "def_ko": "여성용 상의", "def_vi": "Áo nữ"}, {"term_ko": "티셔츠", "term_vi": "Áo phông", "def_ko": "일반적인 상의 형태", "def_vi": "Kiểu áo thông dụng"}, {"term_ko": "이불", "term_vi": "Chăn", "def_ko": "수면용 커버", "def_vi": "Vỏ chăn dùng để ngủ"}, {"term_ko": "울", "term_vi": "Len", "def_ko": "양모로 만들어진 섬유", "def_vi": "Sợi làm bằng lông cừu"}, {"term_ko": "스웨터", "term_vi": "Áo len", "def_ko": "따뜻하게 입는 니트 의류", "def_vi": "Trang phục dệt kim để giữ ấm"}, {"term_ko": "니트", "term_vi": "Vải dệt kim", "def_ko": "뜨개질로 만들어진 의류", "def_vi": "Vải được làm bằng cách đan"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (526, 'mock', '그림과 같이 대상자가 침대 아래쪽에 누워있을 때 침대 위쪽으로 이동시키는 방법으로 옳은 것은?', '["다리 쪽의 침대를 올려준다.", "침대 시트를 잡아서 끌어 올린다.", "양쪽 팔을 잡고 당겨 올린다.", "대상자가 협조를 할 수 있는 경우 침대 머리쪽 난간을 잡게 한다.", "대상자가 협조를 할 수 없는 경우 두 사람이 나란히 서서 올린다."]'::jsonb, 4, NULL, NULL, '{"1": "다리 쪽의 침대를 올려주는 것은 그리 안전한 방법이 아닙니다.\n[정답]", "4": "대상자가 협조를 할 수 있는 경우 침대 머리쪽 난간을 잡게 하는 것이 안전하고 효과적입니다.", "2": "침대 시트를 잡아서 끌어 올리는 것은 대상자에게 불편함을 줄 수 있습니다.", "3": "양쪽 팔을 잡고 당겨 올리는 것은 대상자의 안전에 위협이 될 수 있습니다.", "5": "대상자가 협조를 할 수 없는 경우 두 사람이 나란히 서서 올려주는 것은 더욱 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자, 병자", "def_vi": "Người bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (521, '15', '주어진 사례를 읽고 치매에 걸린 아내를 돌보는 주보호자인 남편에 대한 요양보호사의 반응으로 옳은 것은?"아내는 갈수록 상태가 더 나빠지는 것 같아요. 내가 잘 돌보지 못해서 나날이 나빠지는 것만 같아 힘이 들어요. 나도 잘하고 싶은데 이게 잘하는 건지 못하는 건지 몰라 매번 답답해요. 이러다 아내가 어디로 없어지거나 더 상태가 나빠질까 봐 걱정이네요."', '["\"다른 가족분은 안 계시나요? 혼자서 돌보시기 힘드시겠어요.\"", "\"제가 바빠서요, 말씀은 나중에 다시 듣겠습니다.\"", "\"다른 집들도 다 똑같은 것 같아요. 너무 힘들어하지 마세요.\"", "\"더 잘 돌봐드리고 싶은데, 아내분이 더 나빠질까 봐 걱정이 되시나 봐요.\"", "\"더 도와드릴 부분이 있는지 시설장님께 말씀드려볼게요.\""]'::jsonb, 4, NULL, NULL, '{"1": "다른 가족이 없다는 것을 언급하며 공감을 나타내는 것이 맞지만, 남편의 감정을 깊게 이해하지 못함.\n[정답]", "4": "남편의 걱정을 공감하고 그에 따른 감정의 상태를 잘 보여주는 적절한 반응입니다.", "2": "상대방의 말을 듣지 않겠다고 말하는 것은 매우 부적절합니다.", "3": "다른 집과 비교하는 것은 남편의 감정을 무시하는 것이나 마찬가지입니다.", "5": "도움을 주겠다는 의도는 좋지만, 남편의 감정을 먼저 이해해야 합니다."}'::jsonb, '[{"term_ko": "주보호자", "term_vi": "Người chăm sóc chính", "def_ko": "환자를 곁에서 가장 많이 도와주는 사람", "def_vi": "Người giúp đỡ bệnh nhân nhiều nhất ở bên cạnh"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억 상실증", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "대응", "def_vi": "Đối phó"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인", "def_vi": "Tâm lý"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "짐", "def_vi": "Gánh nặng"}, {"term_ko": "걱정", "term_vi": "Lo lắng", "def_ko": "염려", "def_vi": "Lo lắng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (520, '15', '주어진 사례를 읽고 치매 시아버지를 돌보는 며느리에 대한 요양보호사의 반응으로 옳은 것은?"시아버지를 돌보지 않겠다는 것은 아니지만 고맙다는 말 한마디도 안 하고 집에 올 때마다 방으로 들어가 버리는 남편이나 자기는 하나도 챙기지 않는다며 투정하는 딸 때문에 스트레스가 이만저만이 아니에요. 난 모든 것을 열심히 하려고 하는데, 주위에서는 내가 집에서 노는 줄 알아요."', '["\"남편들이 다 그렇지요, 많이 속상하시겠어요.\"", "\"아...그러시군요. 네네...\"하며 하던 일을 계속한다.", "\"제가 남편분께 한번 말씀드려볼까요.\"", "\"남편분이 따뜻한 말 한마디 해주시면 좋겠는데 그렇지 않아서 서운하시군요.\"", "\"따님이 아직 어려서 엄마가 힘든 걸 모르네요. 속상하시겠어요.\""]'::jsonb, 4, NULL, NULL, '{"1": "남편에 대한 일반적인 편견을 표현한 것으로, 적절한 반응이 아니다.\n[정답]", "4": "남편의 행동에 대한 이해를 보이며, 감정을 공감하는 적절한 반응이다.", "2": "환자가 이야기하는 중에도 대화에 관심을 두지 않은 반응이다.", "3": "상황 해결을 위한 조력을 제안하지만, 우선적으로 감정을 이해해주지 않아서 부적절하다.", "5": "딸의 문제를 언급하며, 주어진 상황의 본질을 간과한 반응이다."}'::jsonb, '[{"term_ko": "주어진", "term_vi": "Được đưa ra", "def_ko": "주어진 상태에 있는, 주어짐", "def_vi": "Ở trạng thái đã đưa ra, được cung cấp"}, {"term_ko": "시아버지", "term_vi": "Bố chồng", "def_ko": "남편의 아버지", "def_vi": "Bố của chồng"}, {"term_ko": "투정", "term_vi": "Lếu láo", "def_ko": "불만을 말하고 소란을 피우는 것", "def_vi": "Nói những điều không đúng và gây rối"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "심리적 압박 상태", "def_vi": "Trạng thái áp lực tâm lý"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "어떤 상황에 대한 응답", "def_vi": "Phản ứng với một tình huống nào đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (519, '15', '주어진 내용을 읽고 치매 대상자에 대한 요양보호사의 돕기 방법으로 옳은 것은?• 치매 어르신에게 인사를 해도 멍하니 반응이 없다. • 이야기를 해도 대꾸가 없다. • 그냥 가만히 의자에 앉아만 있다. • 텔레비전 시청도, 산책도 아무런 소용이 없다.', '["갑자기 뒤에서 안으며 이름을 부른다.", "대답을 하지 않으면 큰소리로 물어본다.", "과거에 좋아했던 활동을 하도록 유도한다.", "반응이 없으면 화를 내어 관심을 갖도록 한다.", "방으로 들어가 편히 쉬게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "갑자기 뒤에서 안으며 이름을 부른다. 치매 환자는 갑작스러운 접근에 놀라거나 불안해할 수 있으므로 적절하지 않습니다.\n[정답]", "3": "과거에 좋아했던 활동을 하도록 유도한다. 이는 치매 환자의 기억과 정서에 긍정적인 영향을 줄 수 있는 방법입니다.", "2": "대답을 하지 않으면 큰소리로 물어본다. 이는 불안감을 유발하고 환자의 스트레스를 증가시킬 수 있습니다.", "4": "반응이 없으면 화를 내어 관심을 갖도록 한다. 이는 환자에게 상처를 줄 수 있고, 도움이 되지 않습니다.", "5": "방으로 들어가 편히 쉬게 한다. 이는 환자가 원할 때 선택적으로 제공될 수 있으나, 적극적인 상호작용이 필요할 때에는 적절하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 인지 기능이 감소하는 질환", "def_vi": "Một bệnh làm giảm trí nhớ và khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (518, '15', '주어진 사례를 읽고 요양보호사의 돕기 방법으로 옳은 것은?보호자는 치매 대상자를 욕실로 데려가 옷을 갈아입히거나 샤워기로 물을 뿌릴 때마다 설명 없이 끌고 가거나 옷을 벗기려 한다. 이럴 때마다 노인은 화를 내며 손을 뿌리치고 보호자를 밀치며 목욕을 거부하고 있다.', '["인지기능이 저하된 치매 대상자는 충분한 설명을 이해하기 어렵다.", "협조가 어려울 때는 강압적인 행동으로 목욕을 마무리한다.", "목욕을 하는 이유와 과정을 설명하고 목욕 후 좋아하는 일을 하자며 유도한다.", "목욕물의 온도, 옷 갈아입을 준비하기는 스스로 하도록 격려한다.", "목욕을 자주 할 수 없으므로 가능한 오랜 시간 동안 목욕한다."]'::jsonb, 3, NULL, NULL, '{"1": "인지기능이 저하된 치매 대상자는 충분한 설명을 이해하기 어렵다. 이는 사실일 수 있지만, 이것만으로 목욕을 강요할 수는 없다.\n[정답]", "3": "목욕을 하는 이유와 과정을 설명하고 목욕 후 좋아하는 일을 하자며 유도한다. 이런 접근이 노인의 협조를 이끌어내는 데 효과적이다.", "2": "협조가 어려울 때는 강압적인 행동으로 목욕을 마무리한다. 이는 노인을 더 불안하게 만들고 상황을 악화시킬 수 있다.", "4": "목욕물의 온도, 옷 갈아입을 준비하기는 스스로 하도록 격려한다. 이는 긍정적인 방법이지만, 노인이 이미 불안해하고 있는 상황에서는 적절치 않다.", "5": "목욕을 자주 할 수 없으므로 가능한 오랜 시간 동안 목욕한다. 이는 오히려 노인의 스트레스를 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "주요 관점", "term_vi": "Chính yếu tố", "def_ko": "요양보호사가 장애인을 돕기 위한 접근 방법", "def_vi": "Cách tiếp cận mà nhân viên chăm sóc cần thiết để hỗ trợ người khuyết tật"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "노인이 정보를 처리하고 이해하는 능력", "def_vi": "Khả năng tiếp nhận và hiểu thông tin của người già"}, {"term_ko": "협조", "term_vi": "Hợp tác", "def_ko": "노인이 목욕을 기꺼이 함께 하도록 하는 것", "def_vi": "Khi người cao tuổi sẵn sàng tham gia vào việc tắm"}, {"term_ko": "강압적", "term_vi": "Ép buộc", "def_ko": "강제로 푸는 태도", "def_vi": "Thái độ cưỡng chế"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "노인이 느끼는 스트레스", "def_vi": "Căng thẳng mà người cao tuổi cảm thấy"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "노인의 심리적 부담", "def_vi": "Gánh nặng tâm lý của người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (517, '15', '주어진 사례를 읽고 요양보호사가 치매 대상자의 일상생활 돕기 방법으로 옳은 것은?• 치매 대상자인 80세 여성은 식사를 할 때 한 가지 반찬만 주로 먹으며 수저를 사용하지 않고 손으로 음식을 집어 먹으려 한다. 요양보호사가 수저로 먹으라고 하면 알았다고 한 후 몇 번 서툴게 수저로 먹지만 금방 다시 손으로 음식을 집는다. • 식사 후 물을 컵에 따라주면 손으로 잡아 입에 대긴 하지만 제대로 마시지 못하고 대부분 흘린다. 요양보호사의 도움을 받아 물을 다 마시고 나면 컵을 테이블에 놓지 못하고 바닥에 떨어뜨린다.', '["숟가락을 사용하여 음식을 떠서 입안에 넣어준다.", "수저를 손에 쥐어 \"수저로 드셔야지요\" 하며 부드럽게 말한다.", "젓가락으로 음식을 집어 입안에 넣어준다.", "스스로 컵을 사용한 후 탁자 위에 놓을 수 있도록 격려한다.", "물을 많이 흘리므로 컵 사용을 제한한다."]'::jsonb, 2, NULL, NULL, '{"1": "숟가락을 사용하게 하는 것은 전문가의 지원 없이 갑자기 수저만 사용하도록 강요하는 것으로, 치매 대상자에게 적합하지 않습니다.\n[정답]", "2": "수저를 손에 쥐어 주며 부드럽게 말하는 것은 대상자의 자존감을 지키면서 식사 습관을 개선할 수 있도록 돕는 좋은 방법입니다.", "3": "젓가락은 사용이 어려울 수 있어 치매 대상자에게 적합하지 않습니다.", "4": "스스로 컵을 사용하도록 격려하는 것은 좋으나, 현재로서는 그 대상자가 컵을 놓지 못하는 상황이므로 아직은 적합하지 않습니다.", "5": "물을 많이 흘리는 것은 사실이지만 컵 사용을 제한하면 자립성을 더욱 감소시킬 수 있습니다."}'::jsonb, '[{"term_ko": "주요", "term_vi": "대상자", "def_ko": "주요한 (quan trọng)", "def_vi": "환자 (bệnh nhân)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (516, '14', '심폐소생술을 할 때 자동심장 충격기를 사용하는 순서로 옳은 것은?', '["패드부착 → 심장충격 시행 → 전원 켜기 → 심장리듬분석 → 가슴압박", "패드부착 → 심장리듬분석 → 심장충격 시행 → 전원 켜기 → 가슴압박", "전원켜기 → 패드부착 → 심장리듬분석 → 심장충격 시행 → 가슴압박", "전원켜기 → 패드부착 → 심장충격 시행 → 심장리듬분석 → 가슴압박", "심장충격 시행 → 전원 켜기 → 패드부착 → 심장리듬분석 → 가슴압박"]'::jsonb, 3, NULL, NULL, '{"1": "올바른 순서가 아니다. 전원이 꺼져 있는 자동심장 충격기를 먼저 켜야 한다.\n[정답]", "3": "전원켜기 → 패드부착 → 심장리듬분석 → 심장충격 시행 → 가슴압박이 올바른 순서이다.", "2": "전원을 켜기 전에 심장리듬을 분석하는 것은 잘못된 순서이다.", "4": "심장리듬 분석 전에 충격을 시행해서는 안 된다.", "5": "먼저 심장충격을 시행하는 것은 잘못된 순서이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 위급한 환자에게 제공하는 응급처치", "def_vi": "Chăm sóc khẩn cấp cung cấp cho bệnh nhân nguy cấp"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 리듬 이상 시 전기 충격을 주는 장비", "def_vi": "Thiết bị cung cấp sốc điện khi có bất thường nhịp tim"}, {"term_ko": "패드부착", "term_vi": "Gắn miếng dán", "def_ko": "전극 패드를 환자 몸에 붙이는 행동", "def_vi": "Hành động gắn miếng dán điện cực lên cơ thể bệnh nhân"}, {"term_ko": "가슴압박", "term_vi": "Áp lực lồng ngực", "def_ko": "심장 기능을 외부에서 압박하여 수행하는 행동", "def_vi": "Hành động nén tim từ bên ngoài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (514, '14', '자동심장 충격기 사용법으로 옳은 것은?', '["의료인만 사용한다.", "패드 1은 왼쪽 젖꼭지 아래 중간 겨드랑이선, 패드 2는 오른쪽 빗장뼈아래 부착한다.", "심장리듬 분석중이라는 음성이 나오면 가슴 압박을 시행한다.", "심장충격 버튼을 누르기 전 모두 물러나게 하고 버튼을 누른다.", "자동심장 충격기는 2초 간격으로 심장리듬을 분석한다."]'::jsonb, 4, NULL, NULL, '{"1": "자동심장 충격기는 의료인 외에도 일반인도 사용할 수 있습니다. \n[정답]", "2": "패드는 지정된 위치에 부착해야 하지만 설명이 다소 잘못되어 있습니다.", "3": "심장리듬 분석 중에는 가슴 압박을 하지 않아야 합니다.", "4": "모든 사람들이 물러난 후 버튼을 눌러야 하며, 정답입니다.", "5": "자동심장 충격기는 2분마다 심장리듬을 분석하는 것으로 일반적입니다."}'::jsonb, '[{"term_ko": "자동심장 충격기", "term_vi": "Máy sốc tim tự động", "def_ko": "자동 외부 제세동기 (AED)", "def_vi": "Máy tán nội bộ tự động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (511, '14', '의식을 잃고 쓰러져 있는 대상자에게 심폐소생술을 시행하는 방법으로 옳은 것은?', '["분당 60회 속도로 가슴압박을 한다.", "쓰러진 대상자의 호흡을 1분 이내로 관찰한다.", "양팔을 쭉 편 상태로 체중을 실어 가슴을 압박한다.", "대상자의 가슴이 약 2cm 눌릴 수 있게 살짝 압박한다.", "반응확인 → 가슴압박 → 도움요청 → 호흡확인 순으로 실시한다."]'::jsonb, 3, NULL, NULL, '{"1": "분당 60회 속도로 가슴압박을 한다는 것은 너무 느린 속도로, 올바른 가슴 압박 속도는 분당 100-120회입니다.\n[정답]", "3": "양팔을 쭉 편 상태로 체중을 실어 가슴을 압박하는 것이 올바른 방법입니다.", "2": "쓰러진 대상자의 호흡을 1분 이내로 관찰하는 것은 부적절하며, 심폐소생술을 즉시 시작해야 합니다.", "4": "대상자의 가슴이 약 2cm 눌릴 수 있게 살짝 압박하는 것은 충분한 압박이 아닙니다.", "5": "반응확인 → 가슴압박 → 도움요청 → 호흡확인 순서 또한 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장 및 호흡이 멈춘 사람에게 응급처치를 하는 방법", "def_vi": "Phương pháp cấp cứu đối với người ngừng tim và ngừng thở"}, {"term_ko": "가슴압박", "term_vi": "Bơm ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 동작", "def_vi": "Hành động ấn để làm tuần hoàn máu"}, {"term_ko": "체중", "term_vi": "Trọng lượng cơ thể", "def_ko": "자신의 몸의 무게", "def_vi": "Cân nặng của cơ thể"}, {"term_ko": "호흡", "term_vi": "Hơi thở", "def_ko": "공기를 들이마시고 내쉬는 과정", "def_vi": "Quá trình hít vào và thở ra"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người đang được điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (510, '14', '심폐소생술 시 가슴압박 시행 방법으로 옳은 것은?', '["분당 100~120회 속도로 압박한다.", "가슴이 3cm 눌릴 수 있게 한다.", "매번 압박의 위치를 바꾼다.", "양팔을 굽은 상태로 한다.", "흉골 아래 명치부분을 압박한다."]'::jsonb, 1, NULL, NULL, '{"1": "분당 100~120회 속도로 압박하는 것이 심폐소생술의 기본 원칙이다.\n[정답]", "2": "가슴이 3cm 눌릴 수 있게 하는 것은 좋지 않다. 왜냐하면, 충분한 압박 깊이가 요구된다.", "3": "매번 압박의 위치를 바꾸는 것은 오히려 효율성을 떨어뜨린다.", "4": "양팔이 굽은 상태일 경우 압박의 힘이 감소하므로 바른 방법이 아니다.", "5": "흉골 아래 명치부분을 압박하는 것은 잘못된 방법이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sinh tim phổi", "def_ko": "심장을 다시 시작하게 하는 응급 절차", "def_vi": "Quy trình cấp cứu để khởi động lại tim."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (509, '14', '심정지 대상자에게 심폐소생술을 시행하는 순서로 옳은 것은?', '["반응확인 → 가슴압박 → 도움요청 → 호흡확인 → 회복자세", "반응확인 → 도움요청 → 호흡확인 → 가슴압박 → 회복자세", "반응확인 → 도움요청 → 회복자세 → 호흡확인 → 가슴압박", "반응확인 → 회복자세 → 도움요청 → 가슴압박 → 호흡확인", "반응확인 → 회복자세 → 호흡확인 → 도움요청 → 가슴압박"]'::jsonb, 2, NULL, NULL, '{"1": "반응확인 후 가슴압박은 잘못된 순서입니다.\n[정답]", "2": "반응확인 후 도움 요청, 호흡 확인 후 가슴압박이 올바른 순서입니다.", "3": "회복자세는 심정지 환자에게 시행하지 않고 가슴압박이 먼저입니다.", "4": "회복자세는 심정지 시 필요하지 않으며, 올바른 순서가 아닙니다.", "5": "호흡확인이 제대로 이루어진 후 가슴압박을 시행해야 합니다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 뛰지 않는 상태", "def_vi": "Trạng thái tim không đập"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sinh tim phổi", "def_ko": "심장과 호흡을 재개하기 위한 응급처치", "def_vi": "Biện pháp khẩn cấp để phục hồi tim và hô hấp"}, {"term_ko": "가슴압박", "term_vi": "Bơm ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 행위", "def_vi": "Hành động ấn vào ngực để lưu thông máu"}, {"term_ko": "회복자세", "term_vi": "Tư thế hồi phục", "def_ko": "환자를 안정적으로 지탱하도록 돕는 자세", "def_vi": "Tư thế hỗ trợ ổn định cho bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (508, '14', '심정지 대상자에게 심폐소생술을 하는 일차적인 목적으로 옳은 것은?', '["쇼크 예방", "뇌 손상 최소화", "면역 기능 향상", "신장 기능 향상", "근골격 손상 회복"]'::jsonb, 2, NULL, NULL, '{"1": "쇼크 예방: 심정지 상황에서는 쇼크 예방이 중요하지만, 심폐소생술의 주된 목적은 아님.\n[정답]", "2": "뇌 손상 최소화: 심폐소생술의 일차적인 목적은 뇌 손상을 최소화하는 것이다. 심정지 상태에서 뇌는 산소 공급이 중단되어 심각한 손상을 받을 수 있으므로, 이 목적이 가장 중요하다.", "3": "면역 기능 향상: 심폐소생술과는 관련이 없으며, 심정지와 면역 기능 향상은 직접적인 관련이 없다.", "4": "신장 기능 향상: 신장 기능 향상과 관련이 없으며, 심정지 상황에서는 생명을 구하는 것이 우선이다.", "5": "근골격 손상 회복: 근골격 손상 회복은 심정지와는 관련이 없으며, 심폐소생술의 목표와는 거리가 있다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "생명이 멈추는 상태", "def_vi": "Tình trạng ngừng sự sống"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈춘 환자를 살리기 위한 응급처치", "def_vi": "Thủ tục cứu sống bệnh nhân khi tim ngừng đập"}, {"term_ko": "뇌", "term_vi": "Não", "def_ko": "인체의 중요한 기관", "def_vi": "Cơ quan quan trọng của cơ thể"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "상처나 피해", "def_vi": "Vết thương hoặc thiệt hại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (507, '14', '대상자가 넘어져 발목에 통증이 있고 골절이 의심될 때 응급처치 방법으로 옳은 것은?', '["발목을 압박한다.", "다리에 온찜질을 한다.", "압박붕대를 꽉 조이게 감아준다.", "발목을 절대로 움직이지 않게 한다.", "부축하여 병원에 진료를 보러 간다."]'::jsonb, 4, NULL, NULL, '{"1": "발목을 압박한다: 이러한 방법은 부상의 악화를 초래할 수 있으므로 부적절합니다.\n[정답]", "4": "발목을 절대로 움직이지 않게 한다: 골절이 의심될 때는 움직임을 최소화하여 추가적인 손상을 방지해야 합니다.", "2": "다리에 온찜질을 한다: 온찜질은 부록에 영향을 줄 수 있어 부적절한 응급처치입니다.", "3": "압박붕대를 꽉 조이게 감아준다: 너무 세게 감으면 혈액 순환 문제를 일으킬 수 있습니다.", "5": "부축하여 병원에 진료를 보러 간다: 증상이 악화될 수 있으므로 부상 부위를 보호한 채로 이동하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bị thương", "def_ko": "피해자", "def_vi": "Người bị thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (506, '14', '대상자가 산책 중 넘어져 움직이기 어려울 정도로 심한 손목 통증을 호소할 때 응급처치 방법으로 옳은 것은?', '["손목을 움직여보게 한다.", "온찜질을 한다.", "붕대를 압박하여 감아준다.", "손목부위를 마사지한다.", "팔찌를 미리 벗겨낸다."]'::jsonb, 5, NULL, NULL, '{"1": "손목을 움직이면 통증이 더 심해질 수 있으므로 올바른 응급처치가 아닙니다.\n[정답]", "5": "팔찌와 같은 액세서리는 swelling (부종) 시 혈류를 압박할 수 있으므로 미리 벗겨주는 것이 중요합니다.", "3": "붕대를 압박하여 감는 것은 잘못된 방법이며, 손목이 부풀어 오를 수 있습니다.", "2": "온찜질은 부상 직후에 적용해선 안 되는 방법입니다.", "4": "손목부위를 마사지하는 것은 부상을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 시에 하는 치료", "def_vi": "Điều trị khi có tình huống khẩn cấp"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Nỗi đau"}, {"term_ko": "부종", "term_vi": "Sưng", "def_ko": "몸의 일부분이 부풀어 오름", "def_vi": "Phần nào đó trên cơ thể bị sưng lên"}, {"term_ko": "마사지", "term_vi": "Massage", "def_ko": "근육을 풀기 위한 동작", "def_vi": "Hành động để thư giãn cơ bắp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (505, '14', '정수기를 사용하던 대상자가 뜨거운 물에 손을 데었을 때 대처방법으로 옳은 것은?', '["손가락의 반지를 빼준다.", "얼음물에 15분 이상 담근다.", "화상부위에 치약을 발라준다.", "화상이 어느 정도인지 모를 때는 멸균드레싱을 한다.", "경미한 화상의 후기고령자는 집에서 치료한다."]'::jsonb, 1, NULL, NULL, '{"1": "손가락의 반지를 빼주는 것은 부종을 방지하기 위함이다.\n[정답]", "2": "얼음물에 15분 이상 담그는 것은 과도한 냉각으로 인한 손상 위험이 있다.", "3": "치약을 바르는 것은 화상에 도움이 되지 않으며 오히려 감염을 유발할 수 있다.", "4": "화상의 정도를 파악하기 전 멸균드레싱을 하는 것은 전문적인 판단이 필요하다.", "5": "후기고령자의 경우, 반드시 병원 치료가 필요하다."}'::jsonb, '[{"term_ko": "정수기", "term_vi": "손", "def_ko": "정수기(한국어) / máy lọc nước: nghĩa tiếng Việt", "def_vi": "손(한국어) / tay: nghĩa tiếng Việt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (504, '14', '대상자가 식사 도중 뜨거운 국을 소등에 쏟았을 때 응급처치 방법으로 옳은 것은?', '["흐르는 수돗물에 환부를 직접 씻는다.", "15분 이상 찬물에 담근다.", "팔찌, 귀고리는 그대로 둔다.", "핸드크림을 발라 열기를 내보낸다.", "2도 화상에는 얼음으로 문지른다."]'::jsonb, 2, NULL, NULL, '{"1": "흐르는 수돗물에 환부를 직접 씻는 것은 위험할 수 있으므로 옳지 않습니다.\n[정답]", "2": "15분 이상 찬물에 담그는 것이 2도 화상에 대한 적절한 응급처치입니다.", "3": "팔찌, 귀고리는 빼는 것이 좋습니다.", "4": "핸드크림을 발라서는 안 됩니다.", "5": "2도 화상에는 얼음을 직접 문지르면 위험합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급 상황에서 즉시 취하는 조치를 의미합니다.", "def_vi": "Các biện pháp khẩn cấp được thực hiện ngay lập tức trong tình huống khẩn cấp."}, {"term_ko": "화상", "term_vi": "Bỏng", "def_ko": "열에 의해 피부가 손상되는 것을 의미합니다.", "def_vi": "Là sự tổn thương da do nhiệt."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (503, '14', '치매 대상자가 알 수 없는 약물을 먹고 의식이 없을 때 응급대처 방법으로 옳은 것은?', '["즉시 가족에게 사실을 알린다.", "우유를 먹여 구토하게 한다.", "천장을 바라보는 자세로 눕히고 고개를 옆으로 돌린다.", "복용한 것으로 의심되는 용기는 시설장에게 전달한다.", "의식이 돌아올 때까지 어깨를 두드린다."]'::jsonb, 3, NULL, NULL, '{"1": "즉시 가족에게 사실을 알리는 것은 중요하지만 응급처치의 적절한 순서가 아닙니다.\n[정답]", "3": "천장을 바라보는 자세로 눕히고 고개를 옆으로 돌리는 것은 기도를 확보하고 질식을 방지하기 위한 올바른 응급처치입니다.", "2": "우유를 먹여 구토하게 하는 것은 위험할 수 있으므로 피해야 합니다.", "4": "복용한 것으로 의심되는 용기를 시설장에게 전달하는 것은 중요한 절차이나, 응급처치와는 직접적인 연관이 없습니다.", "5": "의식이 돌아올 때까지 어깨를 두드리는 것은 효과적이지 않으며, 오히려 추가적인 위험을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 인지 능력이 저하되는 질환", "def_vi": "Bệnh lý giảm khả năng ghi nhớ hoặc nhận thức"}, {"term_ko": "알 수 없는", "term_vi": "Không rõ", "def_ko": "신원이나 상태가 명확하지 않은", "def_vi": "Không xác định được danh tính hoặc tình trạng"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자아나 환경을 인식하는 상태", "def_vi": "Trạng thái nhận thức về bản thân hoặc môi trường"}, {"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "즉각적인 치료 또는 도움을 제공하는 것", "def_vi": "Cung cấp sự điều trị hoặc giúp đỡ ngay lập tức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (502, '14', '대상자가 약물 중독으로 쓰러졌을 때 대처방법으로 옳은 것은?', '["겉으로 드러난 증상이 없다면 지켜본다.", "복용하고 남은 약을 119대원에게 전달한다.", "손가락을 넣어 구토를 유발한다.", "의식이 없더라도 물을 조금씩 먹인다.", "입에서 거품이 나오면 깨끗이 닦아준다."]'::jsonb, 2, NULL, NULL, '{"1": "겉으로 드러난 증상이 없다면 지켜보는 것은 위험할 수 있습니다. 상황에 따라 즉시 조치를 취해야 합니다.\n[정답]", "2": "복용하고 남은 약을 119대원에게 전달하는 것은 중요한 정보 제공으로, 향후 치료에 도움이 됩니다.", "3": "손가락을 넣어 구토를 유발하는 행위는 상황에 따라 위험할 수 있으므로 지양해야 합니다.", "4": "의식이 없더라도 물을 먹이는 것은 호흡기로 물이 들어갈 위험이 있으므로 안전하지 않습니다.", "5": "입에서 거품이 나더라도 수동적으로 닦아주는 것은 불필요하며, 적절한 응급조치가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (501, '14', '프로그램에 참여하던 대상자가 쓰러져 경련을 할 때 응급처치 방법으로 옳은 것은?', '["손가락으로 입을 벌려 약을 먹인다.", "안전을 위해 조용한 방으로 옮긴다.", "대상자의 머리 아래에 딱딱한 것을 대어준다.", "경련이 멈출 때까지 양쪽 어꺠를 꽉 잡아준다.", "고개를 가만히 옆으로 돌려준다."]'::jsonb, 5, NULL, NULL, '{"1": "손가락으로 입을 벌려 약을 먹인다: 이는 매우 위험한 방법으로, 환자가 기도 폐쇄가 발생할 수 있다.\n[정답]", "2": "안전을 위해 조용한 방으로 옮긴다: 조용한 환경을 제공하는 것은 좋지만, 근처에서 안전하게 경련이 멈추길 기다려야 한다.", "3": "대상자의 머리 아래에 딱딱한 것을 대어준다: 부상의 위험이 있으므로 적절하지 않다.", "4": "경련이 멈출 때까지 양쪽 어깨를 꽉 잡아준다: 이는 환자에게 추가적인 부상을 초래할 수 있다.", "5": "고개를 가만히 옆으로 돌려준다: 이는 환자의 기도가 확보되고 안전하게 경련이 멈추도록 도와줄 수 있는 방법이다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "emergency treatment", "def_vi": "điều trị khẩn cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (500, '14', '대상자가 날카로운 물체에 찔려 팔에 출혈이 있을 때 응급처치 방법으로 옳은 것은?', '["맨손으로 지혈하고 수돗물에 닦는다.", "멸균거즈를 이용하여 상처를 압박한다.", "대상자를 절대 안정시키고 움직이지 않게 한다.", "상처부위에 냉찜질을 한다.", "압박붕대를 이용하여 꽉 조이게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "맨손으로 지혈하고 수돗물에 닦는 것은 비위생적이며 상처에 감염의 위험이 있습니다.\n[정답]", "2": "멸균거즈를 이용하여 상처를 압박하면 출혈을 효과적으로 지혈할 수 있습니다.", "3": "대상자를 안정시키고 움직이지 않게 하는 것이 중요하지만 응급처치 방법이 아닙니다.", "4": "냉찜질은 부기에는 도움이 될 수 있으나 출혈을 멈추는 데는 직접적인 효과가 없습니다.", "5": "압박붕대를 이용하여 꽉 조이게 하는 것은 적절한 방법이지만, 멸균거즈를 우선 사용하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (499, '14', '급성 저혈압 증상에 관한 설명으로 옳은 것은?', '["혈압이 과도하게 높아져 혈액순환이 이루어지지 못한다.", "피부색이 하얗거나 파랗다.", "손발이 따뜻하다.", "호흡수가 감소한다.", "맥박수가 감소한다."]'::jsonb, 2, NULL, NULL, '{"1": "급성 저혈압에선 혈압이 낮아 혈액순환이 원활하지 않다.\n[정답]", "2": "급성 저혈압 환자는 피부색이 창백하거나 청색증을 보인다.", "3": "손발은 차갑고, 따뜻하지 않다.", "4": "호흡수가 일반적으로 증가한다.", "5": "맥박수는 보통 증가한다."}'::jsonb, '[{"term_ko": "급성 저혈압", "term_vi": "증상", "def_ko": "급성 hạ huyết áp", "def_vi": "triệu chứng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (497, '14', '인절미를 먹던 대상자가 목을 움켜잡고 괴로운 표정을 지을 때 응급처치 방법으로 옳은 것은?', '["대상자의 뒷목을 주먹으로 두드린다.", "물을 먹여 이물질이 내려가도록 한다.", "손가락을 입에 넣어 구토를 유발한다.", "음식물이 보이면 젓가락으로 꺼낸다.", "대상자를 등 뒤에서 안아 상복부를 후상방향으로 힘차게 밀어 올린다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자의 뒷목을 주먹으로 두드리는 것은 비효율적이며 위험할 수 있습니다. \n[정답]", "5": "대상자를 등 뒤에서 안아 상복부를 후상방향으로 힘차게 밀어 올리면 기도를 확보하는 효과가 있습니다.", "2": "물을 먹이는 것은 이물질을 더욱 밀어넣을 수 있어 위험합니다.", "3": "손가락을 입에 넣어 구토를 유발하는 방법은 위험하며 바람직하지 않습니다.", "4": "음식물이 보일 때 젓가락으로 꺼내는 것은 추가적인 상해를 발생시킬 수 있습니다."}'::jsonb, '[{"term_ko": "목", "term_vi": "Cổ", "def_ko": "목(한국어)", "def_vi": "Cổ họng (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (496, '14', '올바른 손씻기 방법으로 옳은 것은?', '["요양보호사는 정해진 시간에 손을 씻는다.", "흐르는 물로만 손을 씻는다.", "근무 중 반지나 팔찌를 착용하지 않는다.", "손톱은 길고 뾰족하게 다듬는다.", "대상자의 집을 떠난 후 씻는다."]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사는 정해진 시간에 손을 씻는 것은 중요하지만, 손씻기는 상황에 따라 필요할 때 해야 합니다.\n[정답]", "3": "근무 중 반지나 팔찌를 착용하지 않는 것이 올바른 손씻기 방법이며 감염 예방을 위한 중요한 수칙입니다.", "2": "흐르는 물로만 손을 씻는 것은 권장되지 않으며, 비누와 함께 씻는 것이 중요합니다.", "4": "손톱을 길고 뾰족하게 다듬는 것은 오히려 세균이 쌓이기 쉬우므로 권장되지 않습니다.", "5": "대상자의 집을 떠난 후 손을 씻는 것은 올바른 방법이지만, 그 전에 손을 씻는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "손씻기", "term_vi": "Rửa tay", "def_ko": "손을 깨끗하게 하는 방법", "def_vi": "Phương pháp làm sạch tay"}, {"term_ko": "근무", "term_vi": "Làm việc", "def_ko": "일하거나 활동하는 것", "def_vi": "Làm hoặc hoạt động"}, {"term_ko": "반지", "term_vi": "Nhẫn", "def_ko": "손가락에 끼는 장식구", "def_vi": "Đồ trang sức đeo trên ngón tay"}, {"term_ko": "팔찌", "term_vi": "Vòng tay", "def_ko": "손목에 착용하는 장식구", "def_vi": "Đồ trang sức đeo trên cổ tay"}, {"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "병원균", "def_vi": "Mầm bệnh"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병을 유발하는 과정", "def_vi": "Quá trình gây bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (495, '14', '대상자를 도울 때 감염이 전파될 수 있는 상황으로 옳은 것은?', '["장갑을 착용하고 분비물을 처리하였다.", "배설물이 묻은 의류를 분리하여 세탁하였다.", "분비물에 오염된 일회용 장갑을 깨끗이 씻어 재사용하였다.", "일회용 방수가운을 입고 대상자의 분비물을 처리하였다.", "혈액이 묻은 물품을 찬물로 씻어낸 후 더운 물로 헹구었다."]'::jsonb, 3, NULL, NULL, '{"1": "장갑을 착용하고 분비물을 처리하는 것은 감염 전파를 예방하는 행동으로 바른 방법이다.", "2": "배설물이 묻은 의류를 분리하여 세탁하는 것은 감염 전파를 예방하는 올바른 방법이다.\n[정답]", "3": "분비물에 오염된 일회용 장갑을 깨끗이 씻어 재사용하는 것은 감염 전파 위험이 높아지므로 잘못된 행동이다.", "4": "일회용 방수가운을 입고 대상자의 분비물을 처리하는 것은 감염을 예방하는 방법이다.", "5": "혈액이 묻은 물품을 찬물로 씻어낸 후 더운 물로 헹구는 것은 감염 전파에 도움이 되지 않으므로 잘못된 방법이다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm", "def_ko": "전염병이 퍼지는 것", "def_vi": "sự lây truyền của bệnh truyền nhiễm"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "보호를 위해 착용하는 장비", "def_vi": "thiết bị bảo vệ được đeo"}, {"term_ko": "분비물", "term_vi": "Dịch tiết", "def_ko": "신체에서 나오는 액체", "def_vi": "chất lỏng tiết ra từ cơ thể"}, {"term_ko": "일회용", "term_vi": "Dùng một lần", "def_ko": "한 번 사용하고 버리는 것", "def_vi": "dùng một lần và vứt đi"}, {"term_ko": "방수가운", "term_vi": "Áo chống thấm", "def_ko": "물을 막는 장비", "def_vi": "thiết bị ngăn nước"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "신체의 액체", "def_vi": "chất lỏng trong cơ thể"}, {"term_ko": "배설물", "term_vi": "Phân", "def_ko": "몸에서 나오는 노폐물", "def_vi": "chất thải từ cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (494, '14', '전기 콘센트에 감전되어 쓰러진 대상자를 돕기 위한 우선순위로 옳은 것은?', '["119에 신고한다.", "호흡과 맥박을 확인한다.", "누전기 이상 여부를 확인한다.", "119가 올 때까지 지켜본다.", "전류가 차단될 때까지 접촉하지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "119에 신고하는 것은 중요하나, 우선순위가 아니다.\n[정답]", "5": "전류가 차단될 때까지 접촉하지 않는 것이 가장 우선적으로 해야 할 행동이다.", "2": "호흡과 맥박을 확인하는 것은 감전 후 상태를 확인하기 위해 필요하지만, 안전이 확보된 후 해야 한다.", "3": "누전기 이상 여부를 확인하는 것은 나중에 할 일이며, 우선적으로 전류를 차단해야 한다.", "4": "119가 올 때까지 지켜보는 것은 도움이 된다 하더라도 우선적인 조치는 아니다."}'::jsonb, '[{"term_ko": "전기", "term_vi": "Điện", "def_ko": "전기의 힘(한국어)", "def_vi": "Sức mạnh của điện"}, {"term_ko": "콘센트", "term_vi": "Ổ điện", "def_ko": "전기 기구가 연결되는 소켓(한국어)", "def_vi": "Ổ cắm cho thiết bị điện"}, {"term_ko": "감전", "term_vi": "Điện giật", "def_ko": "전기로 인해 생기는 부상(한국어)", "def_vi": "Chấn thương do điện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (493, '14', '태풍 예보를 듣고 대비하는 방법으로 옳은 것은?', '["주유되어 있는 자동차의 연료를 비운다.", "오염에 대비해 욕조에 물을 미리 받아둔다.", "지하 주차장에 주차한다.", "전기 차단기를 내린다.", "통신 기기는 꺼 놓는다."]'::jsonb, 2, NULL, NULL, '{"1": "주유된 차량의 연료를 비우는 것은 태풍에 대비하는 방법으로 옳지 않다.\n[정답]", "2": "오염에 대비해 욕조에 물을 미리 받아두는 것은 재난 발생 시 유용하게 사용될 수 있다.", "3": "지하 주차장에 주차하는 것은 안전을 보장하지 않으므로 바람직하지 않다.", "4": "전기 차단기를 내리는 것은 오히려 불필요한 조치가 될 수 있다.", "5": "통신 기기를 꺼 놓는 것은 연락이 불가능해질 수 있어 위험할 수 있다."}'::jsonb, '[{"term_ko": "태풍", "term_vi": "Bão", "def_ko": "폭풍 nhiệt대 지역에서 발생하는 강한 바람과 비가 동반된 기상현상", "def_vi": "Hiện tượng khí tượng mạnh với gió và mưa xảy ra ở vùng nhiệt đới"}, {"term_ko": "대비", "term_vi": "Chuẩn bị", "def_ko": "미리 준비함", "def_vi": "Sẵn sàng trước"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "욕실에서 사용하는 큰 통", "def_vi": "Bể tắm lớn dùng trong phòng tắm"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더럽혀짐, 영향을 받음", "def_vi": "Bị bẩn, bị ảnh hưởng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (492, '14', '지진 발생 시 대처방법으로 옳은 것은?', '["신속히 엘리베이터로 이동한다.", "건물 바로 밑에서 주위를 살핀다.", "운동장이나 공원 등은 피한다.", "탁자 아래로 들어가 몸을 보호한다.", "전기와 가스를 차단하고 출구를 차단한다."]'::jsonb, 4, NULL, NULL, '{"1": "신속히 엘리베이터로 이동하는 것은 위험합니다. 지진 시 엘리베이터 사용은 피해야 합니다.\n[정답]", "4": "탁자 아래로 들어가 몸을 보호하는 것이 올바른 대처 방법입니다. 이는 낙하물로부터 몸을 보호할 수 있습니다.", "2": "건물 바로 밑에서 주위를 살핀다는 것은 안전하지 않으며, 보호를 받지 못할 가능성이 높습니다.", "3": "운동장이나 공원은 개방된 공간이지만, 움직이지 말고 안전한 장소에서 대기하는 것이 좋습니다.", "5": "전기와 가스를 차단하는 것은 중요하지만, 출구를 차단하는 것은 문제가 많습니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "신속히", "def_ko": "지진(động đất)", "def_vi": "빠르게(nhanh chóng)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (491, '14', '홍수로 인해 수해가 발생했을 때 대처방법은?', '["양초에 불을 붙여 실내를 밝게 한다.", "물이 집 안으로 밀려들어오는 경우 모래주머니로 막는다.", "밀려온 물이 집 안에서 빠진 직후 전기차단기를 올린다.", "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는다.", "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다."]'::jsonb, 2, NULL, NULL, '{"1": "양초에 불을 붙이는 것은 화재를 유발할 수 있으므로 위험합니다.\n[정답]", "2": "물이 집 안으로 밀려들어오는 경우 모래주머니로 막는 것이 올바른 대처 방법입니다.", "3": "밀려온 물이 집 안에서 빠진 직후 전기차단기를 올리는 것은 전기 사고를 유발할 수 있어 위험합니다.", "4": "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는 것은 상황 대처와는 관련이 없습니다.", "5": "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다는 것은 매우 위험한 행동입니다."}'::jsonb, '[{"term_ko": "홍수", "term_vi": "대처", "def_ko": "침수(홍 lũ)", "def_vi": "대응(ứng phó)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (490, '14', '시설에서 화재가 발생했을 때 대처방법으로 옳은 것은?', '["승강기를 이용하여 대피한다.", "최대한 허리를 세워 움직인다.", "실내에 불이 나면 전화를 걸어 알린다.", "아래층으로 이동할 수 없다면 옥상으로 이동한다.", "방향을 알기 힘들 때에는 양쪽 손으로 벽을 번갈아 짚으며 나간다."]'::jsonb, 4, NULL, NULL, '{"1": "승강기는 화재 시 사용할 수 없으므로 잘못된 답변입니다.\n[정답]", "4": "상황에 따라 옥상으로 이동하는 것이 안전할 수 있습니다.", "2": "허리를 세우는 것보다 더 낮은 자세로 이동하는 것이 안전합니다.", "3": "실내에 불이 난 경우 즉시 대피하는 것이 중요하며 전화를 걸 시간이 없습니다.", "5": "벽을 짚고 나가는 것은 좋은 방법이지만, 이 경우 방향을 알기 힘들다고 하여 지체할 필요는 없습니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "Hỏa hoạn", "def_ko": "불이 나는 현상", "def_vi": "Hiện tượng lửa bùng lên"}, {"term_ko": "승강기", "term_vi": "Thang máy", "def_ko": "건물 내부에서 이동할 때 사용하는 기계", "def_vi": "Thiết bị sử dụng để di chuyển trong tòa nhà"}, {"term_ko": "대피", "term_vi": "Tản ra", "def_ko": "안전한 장소로 이동하는 것", "def_vi": "Di chuyển đến nơi an toàn"}, {"term_ko": "옥상", "term_vi": "Mái nhà", "def_ko": "건물의 가장 높은 부분", "def_vi": "Phần cao nhất của tòa nhà"}, {"term_ko": "전화", "term_vi": "Điện thoại", "def_ko": "소통에서 사용하는 장비", "def_vi": "Thiết bị liên lạc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (489, '14', '실내에서 화재가 발생했을 때 소화기를 사용하는 순서로 옳은 것은?(그림) #311', '["가 → 나 → 다 → 라", "가 → 다 → 나 → 라", "나 → 가 → 라 → 다", "나 → 다 → 가 → 라", "라 → 나 → 가 → 다"]'::jsonb, 5, NULL, NULL, '{"1": "먼저 점검 후 처치하는 순서로 맞지 않음.\n[정답]", "5": "화재에 대처하는 올바른 순서가 포함되어 있음.", "3": "적절한 대응 방법이 아님.", "4": "순서가 잘못되어 효과적인 소화가 불가능함.", "2": "올바른 소화 순서가 아님."}'::jsonb, '[{"term_ko": "실내", "term_vi": "화재", "def_ko": "실내(한국어) / Trong nhà(베트남어)", "def_vi": "화재(한국어) / Hỏa hoạn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (488, '14', '가스레인지 불을 끄는 것을 자주 잃어버리는 대상자를 위한 돕기 방법으로 옳은 것은?', '["휴대용 가스레인지를 사용한다.", "배달음식 메뉴로 식단표를 작성한다.", "휴대전화기를 보면서 조리한다.", "음식을 조리하는 중에 주방을 떠나지 않는다.", "미리 얼려둔 음식을 전자레인지에 해동한다."]'::jsonb, 4, NULL, NULL, '{"1": "휴대용 가스레인지를 사용한다. - 이 방법은 불을 잊어버리는 것과 관련이 없어 적절하지 않습니다.\n[정답]", "4": "음식을 조리하는 중에 주방을 떠나지 않는다. - 주방에 계속 머무는 것이 불을 끄는 것을 잊지 않도록 도와줍니다.", "3": "휴대전화기를 보면서 조리한다. - 음식을 조리하는 것에 집중하지 못하게 하며, 위험할 수 있습니다.", "2": "배달음식 메뉴로 식단표를 작성한다. - 조리와 관련이 없으므로 오답입니다.", "5": "미리 얼려둔 음식을 전자레인지에 해동한다. - 이 방법은 전혀 관련이 없습니다."}'::jsonb, '[{"term_ko": "가스레인지", "term_vi": "Bếp gas", "def_ko": "가스를 연료로 사용하는 조리 기구", "def_vi": "Thiết bị nấu ăn sử dụng khí gas"}, {"term_ko": "불", "term_vi": "Lửa", "def_ko": "타오르는 상태", "def_vi": "Tình trạng đang cháy"}, {"term_ko": "배달음식", "term_vi": "Thức ăn giao hàng", "def_ko": "음식을 집으로 배달해 주는 서비스", "def_vi": "Dịch vụ giao thức ăn đến nhà"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식을 준비하고 요리하는 것", "def_vi": "Chuẩn bị và nấu thức ăn"}, {"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "음식을 조리하고 준비하는 공간", "def_vi": "Không gian để nấu và chuẩn bị thức ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (487, '14', '의학적 위기상황에 대한 대처 방법으로 옳은 것은?', '["가장 먼저 기관장에게 보고한다.", "대상자의 의식이 돌아올 때까지 기다린다.", "대상자의 호흡불안정, 심한 통증이 있다면 119에 신고한다.", "뚜렷한 위기징후가 없더라도 반드시 119에 신고한다.", "상황이 종료되면 요양보호사의 주관적 느낌도 기록한다."]'::jsonb, 3, NULL, NULL, '{"1": "기관장에게 보고하는 것은 중요하지만, 응급 상황에서는 환자의 상태를 먼저 파악해야 합니다.\n[정답]", "3": "호흡 불안정이나 심한 통증을 느끼는 경우에는 즉시 119에 신고해야 합니다.", "2": "의식이 돌아올 때까지 기다리는 것은 필요한 응급조치를 지연시킬 수 있습니다.", "4": "뚜렷한 위기징후가 없더라도 신고하는 것은 오히려 자원의 낭비로 이어질 수 있습니다.", "5": "요양보호사의 주관적 느낌을 기록하는 것은 중요하지만, 우선적인 조치는 아닙니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학의 관련된", "def_vi": "liên quan đến y học"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (486, '13', '사전연명의료의향서에 관한 설명으로 옳은 것은?', '["본인 의사에 상관없이 대리작성이 가능하다.", "사전연명의료의향서 등록기관에 등록해야만 효력이 있다.", "연명의료 중단은 의사의 도움에 의한 적극적 안락사와 같다.", "효력이 발생하여 연명의료가 중단되어도 심폐소생술은 실시된다.", "의료행위와 영양분, 산소의 단순 공급은 보류하거나 중단할 수 있다."]'::jsonb, 2, NULL, NULL, '{"1": "본인 의사에 반하여 대리작성을 할 수 없습니다.\n[정답]", "2": "사전연명의료의향서는 등록기관에 등록해야 효력이 발생합니다.", "3": "연명의료 중단은 의사의 도움으로 이루어진 안락사와는 다릅니다.", "4": "효력이 발생하여 연명의료가 중단된 경우에도 심폐소생술은 실시되지 않습니다.", "5": "의료행위 및 영양분, 산소의 공급은 상황에 따라 중단할 수 있습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Văn bản ý kiến về y tế trước khi tử vong", "def_ko": "죽기 전에 의사 결정을 미리 기록한 문서", "def_vi": "Tài liệu ghi lại quyết định y tế trước khi chết"}, {"term_ko": "대리작성", "term_vi": "Viết thay", "def_ko": "다른 사람을 대신하여 작성하다", "def_vi": "Viết thay cho người khác"}, {"term_ko": "효력", "term_vi": "Hiệu lực", "def_ko": "법적으로 효력이 있다", "def_vi": "Có hiệu lực pháp lý"}, {"term_ko": "연명의료", "term_vi": "Điều trị y tế kéo dài sự sống", "def_ko": "생명을 연장하기 위한 의료행위", "def_vi": "Hành vi y tế để gia tăng sự sống"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡을 재개시키기 위한 의료행위", "def_vi": "Hành động y tế để hồi phục tim và hô hấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (485, '13', '사전연명의료의향서를 등록한 대상자가 임종을 앞두고 있을 때 제공 받을 수 있는 것은?', '["산소 공급", "혈액 투석", "항암제 투여", "기관지확장제 투여", "심폐소생술"]'::jsonb, 1, NULL, NULL, '{"1": "산소 공급은 임종 환자에게 제공할 수 있는 기본적인 치료입니다.\n[정답]", "2": "혈액 투석은 임종 환자에게 권장되지 않습니다.", "3": "항암제 투여는 통상적인 경우엔 적합하지 않으며 비특정 치료입니다.", "4": "기관지확장제 투여는 필요한 경우일 수 있으나, 임종 시기에는 우선순위가 낮습니다.", "5": "심폐소생술은 사전연명의료의향서 등록 시 대부분의 환자가 원하지 않는 치료입니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Di chúc y tế trước", "def_ko": "환자의 의사를 사전에 문서화한 것", "def_vi": "Tài liệu ghi lại ý chí của bệnh nhân trước đó"}, {"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "환자의 치료 방법", "def_vi": "Phương pháp điều trị cho bệnh nhân"}, {"term_ko": "공급", "term_vi": "Cung cấp", "def_ko": "드리는 것, 제공하는 것", "def_vi": "Cung cấp, đưa cho"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명에 필요한 기체", "def_vi": "Khí cần thiết cho sự sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (484, '13', '말기환자 또는 19세 이상의 성인이 치료효과 없이 임종과정의 기간만을 연장하는 의학적 시술에 대한 본인의 의사에 대해 명시하는 서류로 옳은 것은?', '["호스피스", "호스피스 이용동의서", "사전연명의료의향서", "임종 관리서", "통증완화 동의서"]'::jsonb, 3, NULL, NULL, '{"1": "호스피스는 환자가 말기 상태에서 삶의 질을 향상시키기 위한 돌봄 서비스입니다.\n[정답]", "3": "사전연명의료의향서는 환자가 치료효과 없이 임종과정의 기간만을 연장하지 않겠다는 본인의 의사를 명시하는 서류입니다.", "2": "호스피스 이용동의서는 호스피스 서비스를 이용하기 위한 동의를 기록한 문서입니다.", "4": "임종 관리서는 임종기간 동안의 관리에 대한 내용을 담고 있습니다.", "5": "통증완화 동의서는 통증 완화를 위한 치료에 관한 내용입니다."}'::jsonb, '[{"term_ko": "말기환자", "term_vi": "Bệnh nhân giai đoạn cuối", "def_ko": "말기 상태의 환자", "def_vi": "Bệnh nhân ở giai đoạn điều trị cuối"}, {"term_ko": "의사", "term_vi": "Ý chí", "def_ko": "본인의 의사", "def_vi": "Ý kiến của bản thân"}, {"term_ko": "서류", "term_vi": "Tài liệu", "def_ko": "법적 문서", "def_vi": "Tài liệu pháp lý"}, {"term_ko": "사전연명의료의향서", "term_vi": "Tuyên bố mong muốn điều trị trước khi mất", "def_ko": "사전의료의향에 대한 문서", "def_vi": "Tài liệu về ý chí điều trị trước khi mất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (483, '13', '임종 대상자의 가족을 돕는 방법으로 옳은 것은?', '["요양보호사만 대상자와 있을 수 있게 한다.", "대상자가 의사소통이 있을 때 사진촬영 등을 금한다.", "분노 반응을 보이는 가족에게는 적대적으로 대한다.", "가족이 스스로 감정을 표현하도록 지지한다.", "1개월 이상의 애도반응은 자연스러운 일임을 알려준다."]'::jsonb, 4, NULL, NULL, '{"1": "요양보호사만 대상자와 있을 수 있게 하는 것은 가족의 정서적 지지를 받지 못하게 할 수 있습니다. \n[정답]", "4": "가족이 스스로 감정을 표현하도록 지지하는 것은 그들의 심리적 안정을 돕고 필수적입니다.", "2": "대상자가 의사소통이 있을 때 사진 촬영 등을 금하는 것은 비생산적이며, 상호작용의 기회를 줄이게 됩니다.", "3": "분노 반응을 보이는 가족에게 적대적으로 대하는 것은 감정을 상처 주고 더욱 부정적인 상황으로 이어질 수 있습니다.", "5": "1개월 이상의 애도반응은 사람마다 다를 수 있으므로, 그것이 자연스럽다고 단정짓는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 단계", "def_vi": "Giai đoạn mà con người sắp đến lúc qua đời"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "당사자의 친족", "def_vi": "Người thân của đối tượng"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "심리적 반응", "def_vi": "Phản ứng tâm lý"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "도움이 되거나 힘을 주는 것", "def_vi": "Giúp đỡ hoặc mang lại sức mạnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (482, '13', '임종을 앞둔 대상자가 음식을 섭취하는 데 어려움이 있을 때 돕기 방법으로 옳은 것은?', '["억지로라도 먹을 수 있게 한다.", "오심, 구토가 있다면 소화제를 준다.", "대상자가 좋아하는 따뜻한 차를 준비하여 준다.", "구토가 심할 경우 주스 얼린 것 등을 입안에 넣어준다.", "위관영양으로 음식을 대체하도록 한다."]'::jsonb, 4, NULL, NULL, '{"1": "억지로 먹게 하면 스트레스를 유발할 수 있다.\n[정답]", "2": "오심과 구토의 원인을 치료하는 것이 우선이다.", "3": "따뜻한 차는 도움이 될 수 있지만, 모든 환자에게 적합하지 않다.", "4": "구토가 심할 경우 주스를 얼린 후 입안에 넣어주면 구토 완화에 도움이 된다.", "5": "위관영양은 마지막 단계에서 고려해야 할 방법이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Tình trạng gần chết"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "구역질의 느낌", "def_vi": "Cảm giác buồn nôn"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "음식을 토하는 행위", "def_vi": "Hành động nôn thức ăn"}, {"term_ko": "위관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "위를 통해 영양분을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua ống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (481, '13', '임종을 앞둔 대상자가 심리적으로 불안해 할 때 돕기 방법으로 옳은 것은?', '["만나고 싶어 하는 사람을 만나게 해준다.", "곧 회복할 수 있다며 격려하고 지지한다.", "조용히 혼자 있는 시간을 준다.", "요양보호사의 희망하는 종교의식을 알아본다.", "장례절차는 가족의 의견을 반영한다."]'::jsonb, 1, NULL, NULL, '{"1": "만나고 싶어 하는 사람을 만나게 해준다. 당연히 그들의 심리적 안정에 도움이 됩니다.\n[정답]", "2": "곧 회복할 수 있다며 격려하고 지지한다. 현실적이지 않은 위로는 오히려 불안감을 증가시킬 수 있습니다.", "3": "조용히 혼자 있는 시간을 준다. 대상자의 상황에 따라 불안감이 증가할 수 있습니다.", "4": "요양보호사의 희망하는 종교의식을 알아본다. 이는 대상자의 심리적 안정과는 관련이 없습니다.", "5": "장례절차는 가족의 의견을 반영한다. 이는 지원의 내용이 아닙니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "삶의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "마음의 상태와 감정", "def_vi": "Tình trạng tâm trí và cảm xúc"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "마음의 괴로움", "def_vi": "Sự lo lắng"}, {"term_ko": "격려", "term_vi": "Khích lệ", "def_ko": "힘을 줌", "def_vi": "Tạo động lực"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "지원하다", "def_vi": "Giúp đỡ"}, {"term_ko": "종교", "term_vi": "Tôn giáo", "def_ko": "신념 체계", "def_vi": "Hệ thống niềm tin"}, {"term_ko": "장례", "term_vi": "Tang lễ", "def_ko": "사망한 사람을 위한 의식", "def_vi": "Nghi thức cho người đã mất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (480, '13', '임종을 앞둔 대상자를 도울 때 마지막까지 남아 있는 감각을 고려하여 돕는 방법으로 옳은 것은?', '["손을 잡아 준다.", "조명을 밝게 켜둔다.", "가족사진을 보여준다.", "좋아하는 음악을 들려준다.", "즐겨 쓰던 아로마 향을 맡게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "손을 잡아 주는 것은 감정적인 지지를 제공하지만, 감각적 방법으로는 부족하다.\n[정답]", "4": "좋아하는 음악을 들려주는 것은 청각적 자극을 제공하여 안정감을 줄 수 있다.", "2": "조명을 밝게 켜두는 것은 오히려 불안감을 줄 수 있으므로 적절하지 않다.", "3": "가족사진을 보여주는 것은 시각적 자극이지만, 임종 시점에서는 기억이나 인식을 하기 어려운 경우가 많다.", "5": "즐겨 쓰던 아로마 향을 맡게 하는 것은 추가적인 감각적 자극을 제공할 수 있지만, 음악에 비해 효과성이 떨어질 수 있다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "끝, 죽음의 과정", "def_vi": "Kết thúc, quá trình chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (479, '13', '임종이 임박한 대상자의 신체적 변화로 옳은 것은?', '["동공이 축소된다.", "소변량이 증가한다.", "잠자는 시간이 짧아진다.", "손과 발에서 열감이 느껴진다.", "무호흡과 깊고 빠른 호흡이 교대로 나타난다."]'::jsonb, 5, NULL, NULL, '{"1": "동공이 확장되는 것이 일반적이다.\n[정답]", "5": "무호흡과 깊고 빠른 호흡이 교대로 나타나는 현상은 임종에 가까운 생리적 변화로 관찰된다.", "2": "소변량은 감소하는 경향이 있다.", "3": "임종 직전에는 수면 상태가 길어질 수 있다.", "4": "손과 발은 차가워지는 것이 일반적이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 가까워짐", "def_vi": "Gần đến cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (478, '13', '임조에 대한 요양보호사의 상담기술 방법으로 옳은 것은?', '["임종 경험 유무에 상관없이 획일적인 상담을 지원한다.", "보호자의 임종에서 마주하는 감정표현을 자제시킨다.", "평소 신뢰하는 종교 지도자와 만남을 주선한다.", "죽음을 앞둔 모든 사람은 죽음에 대해 ''좋은 죽음''이라고 생각한다.", "대상자와 가족이 임종에 이르는 다음 단계에로의 진입에 강요한다."]'::jsonb, 3, NULL, NULL, '{"1": "임종 경험 유무에 상관없이 획일적인 상담은 맞지 않습니다. 상담은 개인의 상황에 맞춰야 합니다.\n[정답]", "3": "평소 신뢰하는 종교 지도자와 만남을 주선하는 것은 적절한 상담 기술입니다.", "2": "보호자의 임종에서 마주하는 감정표현을 자제시키는 것은 비정상적인 접근입니다.", "4": "죽음을 앞둔 모든 사람이 ''좋은 죽음''이라고 생각하는 것은 일반화의 오류입니다.", "5": "대상자와 가족이 임종에 이르는 다음 단계에로의 진입을 강요하는 것은 부적절한 방법입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Thời điểm hưu", "def_ko": "죽음을 맞이하는 시기", "def_vi": "Thời điểm đối diện với cái chết"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "조언 또는 도움을 주는 행위", "def_vi": "Hành động tư vấn hoặc trợ giúp"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "감정이나 느낌", "def_vi": "Cảm giác và cảm xúc"}, {"term_ko": "종교", "term_vi": "Tôn giáo", "def_ko": "신앙이나 교리", "def_vi": "Tín ngưỡng hoặc giáo lý"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc trợ giúp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (477, '13', '임종을 맞이하는 대상자의 임종 적응단계의 순서로 옳은 것은?가.분노 나.부정 다.우울 라.타협 마.수용', '["가 - 나 - 다 - 라 - 마", "나 - 가 - 다 - 라 - 마", "나 - 가 - 라 - 다 - 마", "다 - 가 - 나 - 라 - 마", "다 - 나 - 가 - 라 - 마"]'::jsonb, 3, NULL, NULL, '{"1": "가 - 나 - 다 - 라 - 마: 이 순서는 임종 적응단계를 올바르게 반영하지 않습니다.\n[정답]", "2": "나 - 가 - 라 - 다 - 마: 이 순서가 임종 적응단계의 올바른 순서입니다.", "3": "나 - 가 - 다 - 라 - 마: 이 순서에서도 임종 적응단계를 올바르게 반영하지 않습니다.", "4": "다 - 가 - 나 - 라 - 마: 이 순서는 임종 적응단계를 올바르게 반영하지 않습니다.", "5": "다 - 나 - 가 - 라 - 마: 이 순서에서도 임종 적응단계를 올바르게 반영하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음의 순간", "def_vi": "Khoảnh khắc của cái chết"}, {"term_ko": "적응단계", "term_vi": "Giai đoạn thích nghi", "def_ko": "상황에 적응하는 단계", "def_vi": "Giai đoạn thích ứng với tình huống"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 것", "def_vi": "Sự chấp nhận"}, {"term_ko": "분노", "term_vi": "Tức giận", "def_ko": "화를 내는 것", "def_vi": "Cảm xúc tức giận"}, {"term_ko": "부정", "term_vi": "Phủ nhận", "def_ko": "인정하지 않는 것", "def_vi": "Không chấp nhận"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬프고 우울한 상태", "def_vi": "Trạng thái buồn và suy sụp"}, {"term_ko": "타협", "term_vi": "Thỏa hiệp", "def_ko": "중간 지점을 찾는 것", "def_vi": "Tìm kiếm điểm trung gian"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (476, '13', '다음에 해당하는 임종적응 단계로 옳은 것은?• 평화로운 마음 속에서 마지막 정리의 시간을 보내기도 한다. • 재산관리, 상속 관련 상담이 포함된다. • 가족들과 종교적 예식을 준비하는 경우도 있다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 5, NULL, NULL, '{"1": "부정: 개인이 죽음을 인정하지 않으려는 단계입니다.", "2": "분노: 자신의 상황에 대한 분노와 불만을 표현하는 단계입니다.", "3": "타협: 죽음을 피하기 위해 거래하거나 조건을 제시하는 단계입니다.", "4": "우울: 자신의 상황을 받아들이기 어려워 슬픔에 잠기는 단계입니다.\n[정답]", "5": "수용: 죽음을 자연스럽게 받아들이고 마지막 정리를 하는 단계입니다."}'::jsonb, '[{"term_ko": "임종적응", "term_vi": "Giai đoạn thích nghi với cái chết", "def_ko": "죽음을 받아들이는 과정", "def_vi": "Quá trình chấp nhận cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (475, '13', '대상자가 자신이 더 이상 회복 가능성이 없다고 생각하게 되면서 침울해지는 임종의 적응단계로 옳은 것은?', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 4, NULL, NULL, '{"1": "부정: 처음에는 사실을 부정하는 단계입니다.\n[정답]", "4": "우울: 회복할 수 없다는 인식을 하게 될 때 자연스럽게 느끼는 슬픔과 침울함의 단계입니다.", "2": "분노: 대개 자신이나 주변에 대한 분노를 느끼는 단계입니다.", "3": "타협: 증상이 악화되거나 상태가 심각해질 때, 다른 방법을 찾으려는 시도입니다.", "5": "수용: 마지막 단계로, 사실을 받아들이고 평화를 찾는 단계입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 병자를", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (474, '13', '임종을 앞둔 대상자가 다음과 같이 말할 때의 임종적응 단계로 옳은 것은?대상자: 내게 이런 일이 벌어졌어. 그렇지만 우리 아이가 결혼할 때까지만 살게 해주세요.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 3, NULL, NULL, '{"1": "부정: 자신의 상태를 인정하지 않으려는 감정 단계이다.\n[정답]", "3": "타협: 상대방이나 상황을 고려하여 조건을 제시하며 수용하려는 단계이다.", "2": "분노: 상황에 대한 분노와 불만을 표현하는 단계이다.", "4": "우울: 미래에 대한 무력감을 느끼고 슬픔에 잠기는 단계이다.", "5": "수용: 자신의 운명을 받아들이고 평온하게 임종을 준비하는 단계이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 과정", "def_vi": "Quá trình chuẩn bị cho cái chết"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "부정", "term_vi": "Phủ định", "def_ko": "상황을 인정하지 않으려는 감정", "def_vi": "Cảm xúc không chấp nhận hoàn cảnh"}, {"term_ko": "분노", "term_vi": "Phẫn nộ", "def_ko": "화내는 감정", "def_vi": "Cảm xúc giận dữ"}, {"term_ko": "타협", "term_vi": "Thỏa thuận", "def_ko": "조건을 제시하는 것", "def_vi": "Đưa ra điều kiện"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬픔에 잠기는 상태", "def_vi": "Trạng thái buồn bã"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 과정", "def_vi": "Quá trình chấp nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (473, '13', '다음 내용을 읽고 임종의 적응단계로 옳은 것은?이씨는 "나는 아니야. 왜 하팔이면 나야, 왜 지금이야."라고 화를 내며 어디에서나 누구에게나 불만스러운 면만을 찾으려고 한다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 2, NULL, NULL, '{"1": "부정: 환자가 상황을 인정하지 않으려는 단계입니다.\n[정답]", "2": "분노: 환자가 상황에 대해 화를 내고 불만을 표현하는 단계입니다.", "3": "타협: 환자가 현재 상황을 받아들이기 위해 타협하려는 단계입니다.", "4": "우울: 환자가 상황을 심각하게 받아들이고 슬픔을 느끼는 단계입니다.", "5": "수용: 환자가 상황을 받아들이고 평화롭게 있는 단계입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 시기", "def_vi": "Thời điểm đối mặt với cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (472, '13', '다음에 해당하는 임종적응 단계로 옳은 것은?• 충격적으로 반응하며 이를 사실로 받아들이려 하지 않는다. • 다시 회복할 수 있다는 비현실적인 믿음을 갖는다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 1, NULL, NULL, '{"1": "''부정'' 단계는 충격적으로 반응하며 사실로 받아들이지 않으려는 특성이 있습니다.\n[정답]", "2": "''분노'' 단계는 상황에 대한 반발감이나 분노가 나타나는 것입니다.", "3": "''타협'' 단계는 회복의 가능성을 믿고 이를 통해 개인의 감정을 조절하려고 시도하는 과정입니다.", "4": "''우울'' 단계는 슬픔과 무력감을 느끼는 상태를 말합니다.", "5": "''수용'' 단계는 상황을 받아들이고 평온한 마음을 갖는 단계를 의미합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "말기(한국어)", "def_vi": "Giai đoạn cuối của cuộc sống"}, {"term_ko": "적응", "term_vi": "Thích ứng", "def_ko": "적합해지다(한국어)", "def_vi": "Để phù hợp"}, {"term_ko": "충격", "term_vi": "Sốc", "def_ko": "갑작스러운 감정(한국어)", "def_vi": "Cảm xúc bất ngờ"}, {"term_ko": "부정", "term_vi": "Phủ nhận", "def_ko": "사실을 받아들이지 않음(한국어)", "def_vi": "Không chấp nhận sự thật"}, {"term_ko": "분노", "term_vi": "Nổi giận", "def_ko": "화난 상태(한국어)", "def_vi": "Tình trạng tức giận"}, {"term_ko": "타협", "term_vi": "Thương lượng", "def_ko": "서로의 의견을 조정하는 것(한국어)", "def_vi": "Điều chỉnh ý kiến của nhau"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬퍼하는 상태(한국어)", "def_vi": "Tình trạng buồn bã"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 것(한국어)", "def_vi": "Sự chấp nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (471, '12', '중증 인지기능 장애 대상자 활동으로 스트레스를 해소하고, 사람들과의 관계를 통해 사회적 상호작용이 증가하는 활동 내용으로 옳은 것은?', '["얼굴 삼행시 짓기", "물건 보며 회상하기", "악기 연주하기", "날짜 계산하기", "뇌 건강 일기 쓰기"]'::jsonb, 3, NULL, NULL, '{"1": "얼굴 삼행시 짓기는 언어적 상호작용을 요구하지만, 관계 형성에는 한계가 있을 수 있다.\n[정답]", "3": "악기 연주하기는 다른 사람과 함께 하는 활동으로, 사회적 상호작용을 증진시키고 스트레스 해소에 도움이 된다.", "2": "물건 보며 회상하기는 개인적인 회상 활동으로 사회적 상호작용을 제한할 수 있다.", "4": "날짜 계산하기는 인지적인 활동이나, 사회적 상호작용과는 거리가 먼 개인적인 작업이다.", "5": "뇌 건강 일기 쓰기는 개인의 내면적인 활동으로, 사회적 상호작용을 증진시키는데 직접적인 도움을 주지 않는다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nghiêm trọng", "def_ko": "심각한 상태", "def_vi": "Tình trạng nặng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (470, '12', '중증 인지기능 장애 대상자와 프로그램 진행 시 주의사항으로 옳은 것은?', '["간단한 일상생활도 모두 도움을 준다.", "아침잠이 많은 대상자라도 일찍 깨워 운동하게 한다.", "주방일을 해본 적 없는 대상자에게 요리활동을 제안한다.", "대상자의 익숙한 물건을 버리고 인테리어를 새로 한다.", "배변 실수를 하여도 따뜻한 말로 위로해준다."]'::jsonb, 5, NULL, NULL, '{"1": "간단한 일상생활도 도움을 주지만, 모든 것을 대신해주어서는 안 된다.\n[정답]", "5": "배변 실수를 하더라도 따뜻한 말로 위로하는 것이 중요하다.", "2": "아침잠이 많은 대상자는 억지로 일찍 깨우기보다는 자연스럽게 일어나도록 유도해야 한다.", "3": "주방일을 해본 적 없는 대상자에게는 적합한 활동을 제안해야 하며, 요리활동은 신중하게 접근해야 한다.", "4": "대상자의 익숙한 물건을 버리는 것은 불안감을 유발할 수 있으며, 변경이 필요하더라도 점진적으로 진행해야 한다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nghiêm trọng", "def_ko": "심각하다(한국어)", "def_vi": "Nghiêm trọng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (469, '12', '다음과 같이 책이나 신문을 읽다가 숫자와 음이 같은 글자가 나오면 낭독을 하다가 손동작으로 숫자를 함께 표시하는 활동의 목표로 옳은 것은?문제 1. 아래 신문 기사를 읽다가 숫자와 음이 같은 글자가 나오면 손가락으로 숫자를 나타내세요.문제 2. 집에 있는 신문 기사나 책을 읽으며 해당 동작을 취해보세요.(그림)#290', '["집행 기능", "공감능력", "계산능력", "실행능력", "주의집중력"]'::jsonb, 5, NULL, NULL, '{"1": "집행 기능: 계획, 조직, 실행의 기능으로 본 문제와는 관계가 적습니다.", "2": "공감능력: 다른 사람의 감정을 이해하고 공감하는 능력으로 본 문제와 관련이 없습니다.", "3": "계산능력: 숫자를 계산하는 능력으로 이 문제의 핵심은 아닙니다.\n[정답]", "4": "실행능력: 의도한 동작(손 동작)을 실현하는 데 필요한 능력입니다.", "5": "주의집중력: 주어진 과제를 수행하기 위해 집중하는 능력이므로 이 문제의 정답입니다."}'::jsonb, '[{"term_ko": "집행 기능", "term_vi": "Chức năng điều hành", "def_ko": "계획, 조직, 실행의 기능(한국어)", "def_vi": "Chức năng lập kế hoạch, tổ chức và thực hiện(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (468, '12', '신문, 드라마, 새로 만난 주변인의 이름을 다음과 같은 네모 안에 기입하고 첫 글자로 삼행시를 짓는 활동 목표로 옳은 것은?문제 예시홍:길:동:', '["창의력", "공감능력", "계산능력", "실행능력", "억제력"]'::jsonb, 1, NULL, NULL, '{"1": "창의력: 삼행시를 짓는 활동은 창의력을 요구합니다.\n[정답]", "2": "공감능력: 공감능력과는 관련이 적습니다.", "3": "계산능력: 계산능력은 해당 활동과 무관합니다.", "4": "실행능력: 실행능력의 요소가 포함되지만, 주된 목적은 아니므로 부적합합니다.", "5": "억제력: 억제력과 관계가 없습니다."}'::jsonb, '[{"term_ko": "창의력", "term_vi": "Sáng tạo", "def_ko": "창의적으로 생각하고 새로운 것을 만들어내는 능력(한국어)", "def_vi": "Khả năng tư duy sáng tạo và tạo ra cái mới(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (465, '12', '치매 대상자의 인지자극을 위해 다음과 같은 문제를 내었을 때 향상될 수 있는 것은?(그림)#289• 오늘 날짜를 양력으로 적어보세요, ( )월 ( )일•연도, 양력 날짜, 음력 날짜를 해당란에 적고 덧셈, 곱셈을 표기된 대로 하세요.', '["지남력, 의사표현", "계산력, 기억력", "주의집중력, 억제력", "독립성, 활동수행능력", "언어의 유창성, 자발성"]'::jsonb, 2, NULL, NULL, '{"1": "지남력과 의사표현이 향상될 수 있으나, 이 문제의 중점은 수학적 과제에 있다.\n[정답]", "2": "계산력과 기억력은 주어진 문제를 통해 직접적으로 향상될 수 있다.", "3": "주의집중력과 억제력도 중요하지만, 이 문제에서는 특정 수학적 과제가 더 강조된다.", "4": "독립성과 활동수행능력은 간접적으로 영향을 받을 수 있지만 주된 목표는 아니다.", "5": "언어의 유창성은 이 활동과 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력, 사고, 의사소통에 영향을 주는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ, suy nghĩ, và giao tiếp."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (464, '12', '치매 대상자를 위한 인지자극 훈련에 관한 설명으로 옳은 것은?', '["가족의 수발 부담을 증가시킨다.", "치매의 진행을 늦추는 약물요법에 해당된다.", "''맨손체조하기''는 지남력을 향상시킨다.", "인지자극훈련 대상자는 혼자서 움직일 수 있어야 한다.", "인지기능에 대한 기본적인 인식이 있는 숙련된 요양보호사가 담당한다."]'::jsonb, 5, NULL, NULL, '{"1": "가족의 수발 부담을 증가시키는 것이 아니라, 오히려 경감시키는 것이 목적입니다.", "2": "약물요법이 아닙니다. 인지자극 훈련은 비약리적 접근입니다.", "3": "맨손체조는 몸의 운동능력에 도움을 주지만, 지남력을 향상시키는 것과는 직접적인 관련이 없습니다.", "4": "인지자극훈련을 받는 대상자는 움직일 수 있는 능력뿐만 아니라 지원과 관리가 필요합니다.\n[정답]", "5": "인지기능에 대한 인식과 이해가 있는 숙련된 요양보호사가 이 과정을 담당해야 합니다."}'::jsonb, '[{"term_ko": "인지자극 훈련", "term_vi": "치매", "def_ko": "기억 và khả năng nhận thức", "def_vi": "bệnh suy giảm trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (463, '12', '단기 기억을 향상하기 위한 프로그램으로 적절한 것은?', '["뇌건강 일기 쓰기", "악기 연주하기", "선 따라 그리기", "물건 값 계산하기", "좋아하는 음식 말하기"]'::jsonb, 1, NULL, NULL, '{"1": "뇌의 기능을 자극하고 사고를 정리하는데 도움이 된다.\n[정답]", "2": "악기를 연주하는 것은 단기 기억뿐만 아니라 전반적인 집중력을 향상시킬 수 있다.", "3": "선을 따라 그리기는 집중력을 요구하지만 단기 기억에는 적합하지 않다.", "4": "물건 값을 계산하는 것은 실생활에 유용하지만 단기 기억을 향상시키는 데는 한계가 있다.", "5": "좋아하는 음식을 말하는 것은 대화의 일부일 수 있지만 단기 기억 향상에는 기여하지 않는다."}'::jsonb, '[{"term_ko": "단기 기억", "term_vi": "Trí nhớ ngắn hạn", "def_ko": "짧은 기간 동안 정보를 기억하는 능력", "def_vi": "Khả năng ghi nhớ thông tin trong thời gian ngắn"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "특정 목표를 위해 체계적으로 구성된 활동", "def_vi": "Hoạt động được tổ chức có hệ thống để đạt được mục tiêu cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (462, '12', '빗소리, 개굴 울음소리 등 청각적 자극을 활용한 인지자극 훈련으로 기대할 수 있는 효과로 옳은 것은?', '["집행기능 향상", "지남력 자극", "친화력 확대", "공감능력 향상", "계산능력 향상"]'::jsonb, 2, NULL, NULL, '{"1": "집행기능 향상은 다양한 인지 훈련의 결과로 나타날 수 있지만, 청각적 자극과의 직접적인 연관성은 낮다.\n[정답]", "2": "지남력 자극은 환경 인식을 증가시키고 방향 감각을 향상시키는 데 도움이 된다.", "3": "친화력 확대는 주로 사회적 상호작용에 따른 결과로, 청각적 자극과는 관련이 적다.", "4": "공감능력 향상은 대인 관계에 영향을 미치는 측면으로, 청각적 자극이 직접적인 영향을 주는 것은 아니다.", "5": "계산능력 향상은 주로 수리적 사고와 관련이 있으며, 청각적 자극과의 직접적인 연결이 없다."}'::jsonb, '[{"term_ko": "청각적 자극", "term_vi": "Kích thích thính giác", "def_ko": "귀로 감지할 수 있는 자극", "def_vi": "Các kích thích có thể được phát hiện bằng tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (461, '12', '요양보호사가 치매말기 대상자에게 어르신, 점심 드셨어요?라고 했을 때 대상자의 반응으로 옳은 것은?', '["\"거기에 언제 갈 거야?\"라며 대화의 주제가 바뀐다.", "\"어제 먹었어.\"라며 올바른 시제 사용이 어렵다.", "\"그거 있잖아.아니, 그것 말이야.\"라며 올바른 지칭을 사용하지 못한다.", "\"응, 많이 먹었어요.\"라며 인사를 건넨다.", "\"점심 드셨어요?\"라고 하면 앵무새처럼 따라 한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자가 주제를 바꾸는 것은 치매의 일반적인 반응이다.\n[정답]", "5": "치매환자가 이전에 들었던 질문을 어투를 따라서 반복하는 경향이 있다.", "2": "치매환자는 종종 시제를 혼동할 수 있다.", "3": "올바른 지칭을 사용하지 못하는 것은 치매환자의 일반적인 특징이다.", "4": "간혹 치매환자는 긍정적인 반응을 보이기도 하지만, 정확한 대답은 아닐 수 있다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문직", "def_vi": "Nghề chăm sóc bệnh nhân"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하", "def_vi": "Sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "대답이나 행동", "def_vi": "Trả lời hoặc hành động"}, {"term_ko": "어르신", "term_vi": "Người lớn tuổi", "def_ko": "존경하는 어른", "def_vi": "Ông bà, người lớn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (460, '12', '치매 대상자가 의사표현을 하도록 돕는 방법으로 옳은 것은?', '["큰소리로 톤을 높여 말한다.", "\"이것은 해도 되고, 저것은 안 된다\"라고 표현한다.", "\"아! 그 사람이요? 네? 왜요?\"라고 질문한다.", "대상자의 주의를 끌 때 요양보호사의 소개는 생략한다.", "친근함을 위해 고향 사투리 말을 걸어본다."]'::jsonb, 5, NULL, NULL, '{"1": "큰소리로 톤을 높여 말하는 것은 대상자가 불안감을 느낄 수 있어 좋지 않다.\n[정답]", "5": "친근함을 위해 고향 사투리 말을 건네는 것은 대상자가 편안함을 느끼고 의사표현을 더 잘 할 수 있도록 도와줄 수 있다.", "2": "''이것은 해도 되고, 저것은 안 된다''라고 표현하는 것은 선택의 제한을 둘 수 있어 바람직하지 않다.", "3": "''아! 그 사람이요? 네? 왜요?''라는 질문은 대화를 흐트러뜨릴 수 있다.", "4": "대상자의 주의를 끌 때 요양보호사의 소개는 상황에 따라 필요할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력, 사고력 및 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ, khả năng tư duy và chức năng"}, {"term_ko": "의사표현", "term_vi": "Thể hiện ý kiến", "def_ko": "자신의 생각이나 감정을 전달하는 것", "def_vi": "Truyền đạt suy nghĩ hoặc cảm xúc của bản thân"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스의 혜택을 받는 사람", "def_vi": "Người nhận lợi ích từ dịch vụ"}, {"term_ko": "주변", "term_vi": "Môi trường xung quanh", "def_ko": "가까운 환경", "def_vi": "Môi trường gần gũi"}, {"term_ko": "친근함", "term_vi": "Sự thân thiện", "def_ko": "관계가 가까워서 편안한 느낌", "def_vi": "Cảm giác thoải mái vì mối quan hệ gần gũi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (459, '12', '치매 대상자와의 의사소통 기본 원칙으로 옳은 것은?', '["눈을 맞추고 미소를 지으며 이야기한다.", "어린아이 대하듯 친근하게 말한다.", "\"왜\"라는 질문을 하여 대화를 지속시킨다.", "TV를 켜고 화면에 나오는 내용으로 대화한다.", "목소리의 톤을 높여 집중하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "눈을 맞추고 미소를 지으며 이야기하는 것은 치매 환자의 정서적 안정감과 관계 형성에 중요합니다.\n[정답]", "2": "어린아이 대하듯 친근하게 말하는 것은 부적절할 수 있으며, 존중이 필요합니다.", "3": "\"왜\"라는 질문을 자주 하는 것은 혼란을 줄 수 있습니다.", "4": "TV를 켜고 대화하는 것은 분산 집중을 유발할 수 있으므로 바람직하지 않습니다.", "5": "목소리의 톤을 높이는 것이 오히려 스트레스를 줄 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (458, '12', '시설 치매 대상자가 담당 요양보호사를 애인이라고 하면서 다음과 같은 행동을 할 때 돕는 방법으로 옳은 것은?• 담당 요양보호사가 다른 대상자를 돌보지 못하게 한다.• 담당 요양보호사가 올 때마다 가슴을 만진다.', '["보호자에게 알리고 퇴소절차를 밟는다.", "성희롱이라고 하면서 성폭력 상담소에 신고한다.", "담당 요양보호사의 변경을 요청하겠다고 경고한다.", "어르신을 돌보는 전문가라고 권위적으로 말한다.", "치매 대상자에게 나타나는 증상이라고 이해하고 모른 척한다."]'::jsonb, 3, NULL, NULL, '{"1": "보호자에게 알리고 퇴소절차를 밟는 것은 상황을 더 악화시킬 수 있습니다.\n[정답]", "2": "성희롱이라고 하면서 성폭력 상담소에 신고하는 것은 문제를 해결하기보다는 복잡하게 만듭니다.", "3": "담당 요양보호사의 변경을 요청하겠다고 경고하는 것은 최선의 대처 방법으로, 상황을 개선할 수 있습니다.", "4": "어르신을 돌보는 전문가라고 권위적으로 말하는 것은 상황을 더욱 긴장하게 만들 수 있습니다.", "5": "치매 대상자에게 나타나는 증상이라고 이해하고 모른 척하는 것은 문제를 방치하는 것입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Người chăm sóc", "def_ko": "시설(시설물)", "def_vi": "Có chăm sóc cho người trong một cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (457, '12', '기저귀를 차고 있는 치매 대상자가 기저귀 안으로 손을 자주 넣어 성기에 상처를 낼 때 돕는 방법으로 옳은 것은?', '["손톱을 짧게 깎고, 청결을 유지한다.", "부끄러운 행동이라고 비난한다.", "하의를 벗겨 시원하게 해준다.", "상·하의가 붙은 옷으로 갈아입힌다", "서비스를 중단하겠다고 말한다."]'::jsonb, 1, NULL, NULL, '{"1": "손톱을 짧게 깎고, 청결을 유지함으로써 상처를 방지할 수 있습니다.\n[정답]", "2": "부끄러운 행동이라고 비난하는 것은 대상자의 자존감을 해칠 수 있어 바람직하지 않습니다.", "3": "하의를 벗겨 시원하게 해주는 것은 상황에 따라 불편할 수 있습니다.", "4": "상·하의가 붙은 옷으로 갈아입히는 것은 불편함을 줄이기 위한 방법이지만, 기저귀 착용 문제에 대처하기에는 적합하지 않습니다.", "5": "서비스를 중단하겠다고 말하는 것은 극단적인 대응으로, 문제 해결에 도움을 주지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "아기 또는 노인이 비뇨를 하거나 대변을 눌러도 옷이 더럽혀지지 않도록 해주는 제품", "def_vi": "Sản phẩm giúp cho trẻ em hoặc người già không làm bẩn quần áo khi đi tiểu hoặc đại tiện"}, {"term_ko": "성기", "term_vi": "Cơ quan sinh dục", "def_ko": "남성 또는 여성의 생식 기관", "def_vi": "Cơ quan sinh sản của nam hoặc nữ"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억을 잃거나 혼란스러운 상태", "def_vi": "Tình trạng mất trí nhớ hoặc gây nhầm lẫn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (456, '12', '치매 대상자가 바지를 내리고 성기를 노출하고 있을 때 돕는 방법으로 옳은 것은?', '["\"창피한 것도 모르세요?\"", "\"이러시면 퇴소조치를 하겠어요.\"", "\"제가 옷을 다시 입혀드릴게요.\"", "\"어린아이처럼 행동하지 마세요!\"", "\"지금 저에게 성희롱하는 거예요!\""]'::jsonb, 3, NULL, NULL, '{"1": "''창피한 것도 모르세요?''는 대상자의 행동을 비하하는 표현으로, 적절하지 않습니다.\n[정답]", "3": "''제가 옷을 다시 입혀드릴게요.''는 대상자의 존엄성을 존중하며 상황을 적절히 처리하는 방법입니다.", "2": "''이러시면 퇴소조치를 하겠어요.''는 협박으로, 부적절한 반응입니다.", "4": "''어린아이처럼 행동하지 마세요!''는 대상자를 비하하며 문제가 해결되지 않습니다.", "5": "''지금 저에게 성희롱하는 거예요!''는 상황을 악화시킬 수 있는 발언입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 질병", "def_vi": "Sự suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (455, '12', '치매 대상자가 프로그램 활동 중 자주 옷을 벗는 행동을 할 때 돕는 방법으로 옳은 것은?', '["편안한 옷으로 갈아입게 한다.", "벗은 상태에서 활동하게 한다.", "성희롱으로 신고하겠다고 말한다.", "스스로 옷을 입을 때까지 기다린다.", "시설장과 의논하여 가족에게 퇴소를 권고한다."]'::jsonb, 1, NULL, NULL, '{"1": "편안한 옷으로 갈아입게 함으로써 치매 대상자가 상황에 편안하게 적응할 수 있도록 도와주는 것이 올바른 방법입니다.\n[정답]", "2": "벗은 상태에서 활동하게 하는 것은 적절하지 않습니다. 치매 대상자를 존중하고 안전하게 보낼 수 있는 환경을 조성해야 합니다.", "3": "성희롱으로 신고하겠다고 말하는 것은 치매 대상자의 행동에 대한 이해가 부족한 모습이며, 적절한 대처가 아닙니다.", "4": "스스로 옷을 입도록 기다리는 것은 상황을 악화시킬 수 있으며, 더 이상적이지 않습니다.", "5": "가족에게 퇴소를 권고하는 것은 문제의 근본적인 해결이 아니라 상황을 회피하는 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Quên", "def_ko": "기억력과 인지능력의 저하(치 Dementia)", "def_vi": "Sự suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (454, '12', '시설 대상자가 하루 종일 콩 고르기를 하다가 해질녘이 되면 오늘은 이만 하고 돌아가겠습니다. 하면서 밖으로 나가려고 할 때 돕기 방법으로 옳은 것은?', '["자녀분이 데리러 올 거라고 기다리라고 한다.", "여기가 집이라며 집에 갈 수 없다고 설득한다.", "조명을 소등하여 밤이라는 것을 알린다.", "할 일이 더 있으니 갈수 없다고 말한다.", "반찬거리를 사오자며 함께 산책을 나간다."]'::jsonb, 5, NULL, NULL, '{"1": "자녀분이 데리러 올 거라고 기다리라고 한다. - 대상자의 의사를 존중하지 않는 방식입니다.\n[정답]", "5": "반찬거리를 사오자며 함께 산책을 나간다. - 대상자가 활동을 지속할 수 있도록 유도하며 외부로 나가는 대신 긍정적인 활동을 제안합니다.", "3": "조명을 소등하여 밤이라는 것을 알린다. - 대상자의 인지적 혼란을 초래할 수 있습니다.", "4": "할 일이 더 있으니 갈 수 없다고 말한다. - 강제적인 대처로 대상자의 감정을 해칠 수 있습니다.", "2": "여기가 집이라며 집에 갈 수 없다고 설득한다. - 잘못된 정보 제공으로 대상자를 혼란스럽게 할 수 있습니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (453, '12', '치매 대상자가 해질녘이 되면 불안하고 우울증상을 보일 때 돕는 방법으로 옳은 것은?', '["낮 동안 충분한 수면을 취하게 한다.", "텔레비전을 끄고 소음을 차단한다.", "조용히 혼자 있도록 배려한다.", "복잡한 소일거리를 제공한다.", "따뜻한 음료수를 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "낮 동안 충분한 수면을 취하게 한다. -> 낮 동안 수면을 취하는 것이 아닌 저녁 시간에 안정감을 주는 방법이 필요하다.\n[정답]", "5": "따뜻한 음료수를 제공한다. -> 따뜻한 음료는 정서적 안정에 도움을 줄 수 있다.", "3": "조용히 혼자 있도록 배려한다. -> 혼자 있도록 할 경우 불안감이 증가할 수 있다.", "4": "복잡한 소일거리를 제공한다. -> 복잡한 활동은 오히려 스트레스를 유발할 수 있다.", "2": "텔레비전을 끄고 소음을 차단한다. -> 소음 차단은 필요할 수 있으나, 정서적 지원이 더 중요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력의 감소로 일상 생활에 지장을 주는 질환", "def_vi": "Bệnh gây ảnh hưởng đến trí nhớ và khả năng tư duy của người bệnh"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "정서적으로 고통받는 상태", "def_vi": "Trạng thái tinh thần khó chịu"}, {"term_ko": "우울증상", "term_vi": "Triệu chứng trầm cảm", "def_ko": "슬픔과 무기력 등을 나타내는 증상", "def_vi": "Các triệu chứng thể hiện sự buồn bã và không có động lực"}, {"term_ko": "정서적 안정", "term_vi": "Sự ổn định cảm xúc", "def_ko": "정신적인 편안함", "def_vi": "Sự thư giãn về tinh thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (452, '12', '치매 대상자가 갑자기 분통을 터뜨리며 요양보호사에게 침을 뱉고, 주먹으로 치며 신체적인 폭력을 가할 때 돕는 방법으로 옳은 것은?', '["갑자기 화가 난 이유를 물어본다.", "입을 막아 침을 뱉지 못하게 한다.", "행동이 멈출 때까지 그 자리를 피한다.", "진정될 때까지 신체적으로 구속시킨다.", "화가 난 것을 이해한다고 말하며 진정시킨다."]'::jsonb, 5, NULL, NULL, '{"1": "갑자기 화가 난 이유를 물어보는 것은 상황을 악화시킬 수 있기 때문에 부적절하다.\n[정답]", "5": "화가 난 것을 이해한다고 말하며 진정시킨다. 이는 대상자의 감정을 인정하고, 안정감을 주기 위한 적절한 방법이다.", "3": "행동이 멈출 때까지 그 자리를 피하는 것은 문제를 회피하는 것으로, 바람직하지 않다.", "4": "신체적으로 구속시키는 것은 폭력을 유발할 수 있고, 대상자의 불안감을 더욱 키울 수 있다.", "2": "입을 막는 것은 대상자의 권리를 침해할 수 있으므로 피해야 한다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 인지 기능의 저하", "def_vi": "Suy giảm chức năng nhớ và nhận thức"}, {"term_ko": "신체적인 폭력", "term_vi": "Bạo lực thể chất", "def_ko": "신체에 대한 공격적인 행동", "def_vi": "Hành vi tấn công vào cơ thể"}, {"term_ko": "진정시키다", "term_vi": "Làm dịu", "def_ko": "안정시키다", "def_vi": "Trấn an"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (451, '12', '시설 치매 어르신이 같은 방을 사용하는 노인에게 저 사람은 남의 집에 세들어 살면서 방세도 내지 않는다. 라고 큰소리로 불만을 말할 때 돕는 방법으로 옳은 것은?', '["누가 그런 말을 했는지 물어본다.", "다 같이 지내는 시설임을 수시로 알려준다.", "요양보호사가 방세확인서를 임의로 만들어 보여준다.", "상대 노인에게 귓속말로 신경 쓰지 않아도 된다고 말해준다.", "고향에 관한 대화를 나누어 관심을 돌린다."]'::jsonb, 2, NULL, NULL, '{"1": "누가 그런 말을 했는지 물어보는 것은 상황을 더 혼란스럽게 할 수 있다.\n[정답]", "2": "시설에서 함께 지내는 것임을 상기시킴으로써 불만의 원인을 완화할 수 있다.", "3": "방세확인서를 임의로 만들어 보여주는 것은 믿음을 줄이지 않을 수 있다.", "4": "고령자에게 귀속말로 이야기하는 것은 오히려 상황을 악화시킬 수 있다.", "5": "고향에 관한 대화를 나누는 것은 좋지만, 이는 불만에 대한 직접적인 대처가 아니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "공간(한국어)", "def_vi": "Nơi chốn"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증(한국어)", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "어르신", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}, {"term_ko": "방세", "term_vi": "Tiền thuê phòng", "def_ko": "방세(한국어)", "def_vi": "Chi phí thuê phòng"}, {"term_ko": "귓속말", "term_vi": "Nói thì thầm", "def_ko": "작은 소리로 말하다(한국어)", "def_vi": "Nói nhỏ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (450, '12', '치매 대상자가 아무도 없는 방 안을 보며 우리 손주가 벌써 왔네? 맛있는 거 가져올게. 라고 할 때 돕는 방법으로 옳은 것은?', '["\"방 안에 아무도 없어요.\"라며 방문을 닫는다.", "\"손주가 많이 보고 싶군요.\"라며 어깨를 안아준다.", "\"방 안에 사람이 있는지를 눈을 크게 뜨고 보세요\"라고 말한다.", "\"기력이 없으셔서 헛것이 보이나 봐요.\"라며 보호자에게 연락한다.", "\"손주는 지금 학교에 가서 없어요.\"라며 하던 일을 계속한다."]'::jsonb, 2, NULL, NULL, '{"1": "치매 대상자가 현실을 인식할 수 있도록 돕는 것이 아니라 그들을 혼란스럽게 할 수 있습니다.\n[정답]", "2": "대상자의 감정을 인정하고 지지해 주는 방법입니다.", "3": "치매 대상자에게는 적극적인 지시보다 부드러운 대화가 효과적입니다.", "4": "기력 부족을 판단하기보다 정서적 지지를 우선해야 합니다.", "5": "대상자의 관심사를 무시하는 것이기 때문에 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 감퇴된 상태", "def_vi": "Trạng thái suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (446, '12', '다음 상황을 읽고 요양보호사의 적절한 반응으로 옳은 것은?• 치매 대상자 : 누가 날 죽이려고 내 밥에 독약을 넣었어! 안 먹어. 저리 치워!• 요양보호사 : ________________________________________________', '["\"왜 독약을 넣었다고 생각하세요?\"", "\"정말요?누가 넣었는지 아세요?\"", "\"경찰에 신고해서 누가 그랬는지 알아볼게요\"", "\"아무도 안 넣었으니 걱정 말고 드세요.\"", "\"제가 먼저 먹어볼 테니 저와 같이 드셔요.\""]'::jsonb, 5, NULL, NULL, '{"1": "환자의 불안을 더욱 키울 수 있는 질문이며, 상황을 진지하게 받아들이지 않는 인상이다.\n[정답]", "5": "요양보호사가 먼저 음식을 먹어보임으로써 환자의 불안감을 덜어주고 신뢰를 쌓을 수 있는 방법이다.", "2": "불안을 유발할 수 있는 질문으로, 환자의 정서적 안정에 도움이 되지 않는다.", "3": "즉각적인 신고는 상황을 악화시킬 수 있으며, 환자를 더욱 불안하게 만들 수 있다.", "4": "불안감을 무시하고 대처하는 방식으로, 환자의 감정을 존중하지 않는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억이나 사고에 문제가 생기는 질병", "def_vi": "bệnh có vấn đề về trí nhớ hoặc suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (445, '12', '치매 대상자가 자신의 목걸이를 누군가 훔쳐갔다고 말하며 딸을 의심할 때 요양보호사의 적절한 반응으로 옳은 것은?', '["\"어르신, 따님이 목걸이를 왜 훔쳐갔을까요?\"", "\"어르신, 귀한 목걸이를 잃어버려서 많이 속상하시겠어요.\"", "\"어르신, 다른 데다 두시고 잊어버리신 것 아니에요?\"", "\"어르신, 또 엉뚱한 사람 의심하고 그러세요.\"", "동료 요양보호사에게 귓속말을 하며 하소연을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "어르신의 감정을 무시하는 질문입니다.\n[정답]", "2": "어르신의 기분을 공감하고 위로하는 적절한 반응입니다.", "3": "어르신의 불안감을 덜어주기보다는 오히려 불안하게 만드는 질문입니다.", "4": "어르신의 감정을 깎아내리고 불쾌감을 줄 수 있는 반응입니다.", "5": "동료에게 불만을 토로하는 것은 프로페셔널하지 못한 행동입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 감소하는 질환", "def_vi": "Bệnh giảm khả năng ghi nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (444, '12', '다음과 같은 상황에서 요양보호사의 돕는 방법으로 옳은 것은?시설치매 대상자가 사망한 남편의 이름을 부르며 허공에 손짓을 하며 "여보, 나 여기 있어요!"라며 하고 있다.', '["남편이 무슨 옷을 입었는지 물어본다.", "남편은 오래전에 돌아가셨다고 말해준다.", "\"지금은 밤이니 내일 오실 거에요.\"라며 말한다.", "낮에 사온 과일이 맛있는지 먹어보자고 한다.", "병세가 심해서 헛것이 보이는 것이라고 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "남편의 옷차림에 대한 질문은 현재 상황과 관련이 없고 대상자를 혼란스럽게 할 수 있다.\n[정답]", "2": "남편이 돌아가셨다는 사실은 대상자에게 상처를 줄 수 있기에 적절하지 않다.", "3": "현재 상황을 무시하면서 내일 올 것이라는 말은 상황을 더욱 어렵게 만들 수 있다.", "4": "환자의 감정을 존중하고 긍정적으로 반응하는 것은 요양보호사가 가지고 있어야 할 중요한 태도다.", "5": "병세를 설명하는 것으로는 환자의 감정을 고려하지 않은 답변이 된다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 사람", "def_vi": "Người chăm sóc người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (443, '12', '다음과 같은 상황에서 요양보호사의 적절한 반응으로 옳은 것은?• 치매 대상자 : 나만 빼고 너희끼리 고기 구워 먹었지? 나도 얼른 구워 줘!• 요양보호사 : ________________________________________________', '["\"무슨 고기 냄새가 난다고 그러세요?\"", "\"조금 전에 고기반찬 드셨잖아요.\"", "\"고기가 드시고 싶으세요? 같이 사러 가요\"", "\"어르신은 치아가 나빠서 못 드세요.\"", "\"무슨 말씀이세요? 아무도 고기 먹지 않았어요.\""]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사가 치매 대상자의 감정을 무시하는 반응입니다.\n[정답]", "3": "치매 대상자의 요구를 인정하고, 긍정적인 방향으로 대화를 이끌어가는 반응입니다.", "2": "과거의 기억을 언급하며 대상자를 혼란스럽게 할 수 있습니다.", "4": "치아 문제를 언급함으로써 대상을 불편하게 만드는 대답입니다.", "5": "대상자의 말을 무시하는 반응이며, 부정적인 인터랙션을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억이나 인지 능력을 상실하는 질병", "def_vi": "Bệnh mất trí nhớ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "사람의 행동에 대한 대답", "def_vi": "Đáp lại hành động của người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (442, '12', '내가 살던 집이 아니라며 자주 집 주변을 돌아다니는 치매 대상자를 돕는 방법으로 옳은 것은?', '["집 주소와 보호자의 전화번호를 외우게 한다.", "텔레비전을 크게 틀어주어 집중하게 한다.", "대상자의 신분증을 보호자가 소지하게 한다.", "외출할 때 입을 겉옷을 문 입구에 걸어준다.", "주소, 전화번호가 적인 이름표를 옷에 꿰매어준다."]'::jsonb, 5, NULL, NULL, '{"1": "집 주소와 보호자의 전화번호를 외우게 한다. - 치매 환자는 기억력이 떨어지므로 외우는 것이 어렵다.\n[정답]", "5": "주소, 전화번호가 적인 이름표를 옷에 꿰매어준다. - 이 방법은 대상자가 스스로 정보에 접근할 수 있게 도와주므로 유용하다.", "3": "대상자의 신분증을 보호자가 소지하게 한다. - 신분증을 소지하는 것만으로는 치매 환자의 불안감을 해소할 수 없다.", "4": "외출할 때 입을 겉옷을 문 입구에 걸어준다. - 환자의 혼란을 일으킬 수 있는 방법이다.", "2": "텔레비전을 크게 틀어주어 집중하게 한다. - 집중력이 떨어진 환자에게 효과적인 방법이 아니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이 쇠퇴해 일상생활에 어려움을 겪는 상태", "def_vi": "Tình trạng suy giảm trí nhớ gây khó khăn trong sinh hoạt hàng ngày"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "신분증", "term_vi": "Thẻ căn cước", "def_ko": "개인 정보를 확인할 수 있는 증명서", "def_vi": "Giấy xác nhận thông tin cá nhân"}, {"term_ko": "주소", "term_vi": "Địa chỉ", "def_ko": "거주하는 장소를 나타내는 정보", "def_vi": "Thông tin về nơi cư trú"}, {"term_ko": "전화번호", "term_vi": "Số điện thoại", "def_ko": "전화로 연락할 수 있는 번호", "def_vi": "Số để liên lạc qua điện thoại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (441, '12', '야간에 집 안에서 목적 없이 이곳저곳 배회하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["취침 전에 따뜻한 녹차를 제공한다.", "현관문을 열어 공기를 환기시킨다.", "함께 자리에 누워 고향에 관한 이야기를 한다.", "배회 동선을 차단하여 낙상 위험을 줄인다.", "거실을 어둡게 하여 방에서 나오는 것을 방지한다."]'::jsonb, 3, NULL, NULL, '{"1": "취침 전에 따뜻한 녹차를 제공하는 것은 수면에 도움이 될 수 있으나, 카페인이 포함되어 있을 경우 오히려 수면을 방해할 수 있다.\n[정답]", "3": "함께 자리에 누워 고향에 관한 이야기를 하는 것은 치매 대상자의 정서적 안정감과 기억 회상에 도움이 된다.", "2": "현관문을 열어 공기를 환기시키는 것은 이렇다 할 효과가 없으며 안전에도 문제가 될 수 있다.", "4": "배회 동선을 차단하여 낙상 위험을 줄이는 것은 필요할 수 있으나, 치매 대상자의 자유를 과도하게 제한할 수 있다.", "5": "거실을 어둡게 하여 방에서 나오는 것을 방지하는 것은 대상자를 불안하게 만들 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고 기능이 저하되는 질환", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "일정 시간 동안 의식이 없는 상태", "def_vi": "Trạng thái không có ý thức trong một khoảng thời gian"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "불안이 없는 상태", "def_vi": "Trạng thái không có sự lo lắng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (440, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 서성이며 안절부절못할 때 돕는 방법으로 옳은 것은?', '["대·소변이 보고 싶은지 물어본다.", "소등하여 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, NULL, NULL, '{"1": "대·소변이 보고 싶은지 물어본다. (치매 대상자가 불안해할 때, 신체적 욕구를 확인하는 것이 중요합니다.)\n[정답]", "2": "소등하여 실내를 어둡게 한다. (어두운 환경은 더 불안감을 조성할 수 있습니다.)", "3": "그대로 놔둔 채 프로그램을 진행한다. (대상자의 안전과 안정을 우선시해야 합니다.)", "4": "조용한 방으로 데려가 혼자 있게 한다. (대상자가 더 불안해할 수 있으므로 혼자 두지 말아야 합니다.)", "5": "프로그램에 집중하라고 권유한다. (대상자가 안절부절 못 할 때는 집중하기 어려울 수 있습니다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "뇌의 기능 저하로 인한 인지능력 감소, 나이를 먹는 것과 관련됨", "def_vi": "Giảm khả năng nhận thức do suy giảm chức năng não, liên quan đến tuổi tác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (439, '12', '낮 동안 계속 졸고, 밤에는 거실을 서성거리는 치매 대상자를 돕는 방법으로 옳은 것은?', '["낮 동안 좋아하는 커피를 제공한다.", "낮잠으로 부족한 잠을 보충한다.", "산책과 가튼 야외활동을 하게 한다.", "저녁 식사 후 고강도 근력운동을 하게 한다.", "잠들기 전까지 좋아하는 드라마를 보게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "커피는 카페인이 포함되어 있어 졸음을 유발할 수 있다.\n[정답]", "3": "야외활동은 신체 활동을 통해 낮 동안의 졸림을 줄이고, 야간에 안정된 수면을 도울 수 있다.", "2": "낮잠을 보충하는 것은 문제를 해결하기보다는 수면 리듬을 더 흐트러뜨릴 수 있다.", "4": "고강도 근력운동은 밤에 긴장을 유발할 수 있으므로 추천하지 않는다.", "5": "좋아하는 드라마는 수면 유도보다는 오히려 각성 상태를 유지하게 할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "산책", "term_vi": "Đi dạo", "def_ko": "신체적 활동의 일환으로 걷기", "def_vi": "Hình thức hoạt động thể chất đi bộ"}, {"term_ko": "고강도", "term_vi": "Cường độ cao", "def_ko": "강도가 높은", "def_vi": "Mức độ cao"}, {"term_ko": "근력운동", "term_vi": "Tập thể dục cường độ cao", "def_ko": "근육을 강화하는 운동", "def_vi": "Tập luyện để tăng cường cơ bắp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (438, '12', '치매 대상자의 수면장애 증상으로 옳은 것은?', '["밤낮 없이 일어서서 돌아다닌다.", "초저녁에 자고 새벽에 일어난다.", "밤낮으로 자다 깨다를 반복한다.", "밤에 잠을 자고 낮 동안에 활동이 많아진다.", "2~3일간 잠을 자지 않고 2~3일 뒤에 계속 잠을 잔다."]'::jsonb, 5, NULL, NULL, '{"1": "야경증의 전형적인 증상으로 볼 수 있으나, 잠을 자지 않는 것이 아님\n[정답]", "5": "치매 환자는 주기적으로 수면 패턴의 변화가 있으며, 2~3일째 잠을 자지 않다가 그 뒤에 많은 시간 잠을 자는 경우도 있다.", "3": "경우에 따라 나타날 수 있지만, 전형적인 증상은 아님", "4": "일반적으로 치매 환자는 밤에 활동이 적고 낮에 더 활동적인 경우가 많다.", "2": "치매에 해당하는 전형적인 수면 패턴은 아님"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 상실되는 질환", "def_vi": "Bệnh mất khả năng nhớ và tư duy"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "수면의 질과 양에 문제가 발생하는 증상", "def_vi": "Triệu chứng liên quan đến chất lượng và số lượng giấc ngủ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "환자의 상태를 나타내는 신호", "def_vi": "Dấu hiệu biểu thị tình trạng của bệnh nhân"}, {"term_ko": "전형적인", "term_vi": "Điển hình", "def_ko": "대표적인", "def_vi": "Đại diện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (437, '12', '치매 대상자가 식사를 거부할 때 돕는 방법으로 옳은 것은?', '["꾸짖거나 잔소리를 하여 음식을 먹게 한다.", "대상자 몸의 상태를 충분히 살펴본다.", "가볍게 먹을 수 있는 컵밥 등을 준비해준다.", "다른일에 지나치게 몰두하고 있다면 그대로 둔다.", "기분전환을 할 수 있도록 산책 후 식사하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "꾸짖거나 잔소리를 하여 음식을 먹게 한다는 것은 대상자의 심리적 상태를 악화시킬 수 있다. \n[정답]", "2": "대상자 몸의 상태를 충분히 살펴보는 것은 올바른 접근법이다.", "3": "가볍게 먹을 수 있는 컵밥 등을 준비해주는 것도 좋은 방법이지만, 신체 상태를 우선적으로 고려해야 한다.", "4": "다른일에 지나치게 몰두하고 있다면 그대로 둬서는 안 된다. 대상자가 식사를 해야 하므로 주의를 환기시켜야 한다.", "5": "기분전환을 할 수 있도록 산책 후 식사하게 하는 것은 좋은 방법이다. 그러나 우선은 몸 상태 체크가 필요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억 및 사고에 영향을 주는 질환", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료 또는 돌봄을 받는 사람", "def_vi": "Người nhận điều trị hoặc chăm sóc"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "사람의 생명을 유지하는 물질", "def_vi": "Chất duy trì sự sống của con người"}, {"term_ko": "양식", "term_vi": "Cách ăn", "def_ko": "먹는 방법", "def_vi": "Cách thức ăn"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인 상태와 관련된", "def_vi": "Liên quan đến trạng thái tinh thần"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "사람의 신체적 상태", "def_vi": "Tình trạng thể chất của con người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (436, '12', '치매 대상자가 제공된 음식을 못 먹고 쳐다 보고만 있을 때 돕는 방법으로 옳은 것은?', '["요양보호사가 직접 입에 넣어준다.", "계속 거부하면 음식을 치운다고 말한다.", "식사하는 방법을 순서대로 가르쳐준다.", "식사를 거르면 건강에 해롭다고 설명한다.", "스스로 먹을 때까지 음식을 그대로 둔다."]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사가 직접 입에 넣어주는 것은 대상자의 자존감을 해칠 수 있습니다.\n[정답]", "3": "식사하는 방법을 순서대로 가르쳐주는 것은 올바른 지원 방법입니다.", "2": "계속 거부하면 음식을 치운다고 말하는 것은 강압적일 수 있습니다.", "4": "식사를 거르면 건강에 해롭다고 설명하는 것은 대상자가 받아들이기 어려울 수 있습니다.", "5": "스스로 먹을 때까지 음식을 그대로 둬서는 적절한 지원이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고 능력이 감소하는 질병", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "도움을 주는 행동", "def_vi": "Hành động giúp đỡ"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신의 가치를 아는 감정", "def_vi": "Cảm giác biết giá trị bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (435, '12', '치매 대상자가 방금 식사한 것을 잊어버리고 밥을 또 달라고 할 때 돕는 방법으로 옳은 것은?', '["요구할 때마다 좋아하는 음식을 준다.", "먹고 난 빈 식기를 그대로 둔다.", "다음 식사 시간까지 기다리라고 한다.", "자꾸 먹으면 살이 찐다고 설득한다.", "다른 요양보호사를 데려와 확인시켜준다."]'::jsonb, 2, NULL, NULL, '{"1": "요구할 때마다 좋아하는 음식을 준다. - 이 방법은 치매 환자에게 혼란을 줄 수 있다.\n[정답]", "2": "먹고 난 빈 식기를 그대로 둔다. - 빈 식기를 두는 것은 이미 식사가 이루어졌음을 명확히 인식하게 도와준다.", "3": "다음 식사 시간까지 기다리라고 한다. - 이 방법은 환자에게 스트레스를 줄 수 있다.", "4": "자꾸 먹으면 살이 찐다고 설득한다. - 치매 환자는 이러한 논리를 이해하기 어려울 수 있다.", "5": "다른 요양보호사를 데려와 확인시켜준다. - 이 방법은 환자에게 혼란을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능이 저하되는 질환", "def_vi": "Là căn bệnh suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행위", "def_vi": "Hành động tiêu thụ thực phẩm"}, {"term_ko": "빈", "term_vi": "Trống", "def_ko": "내용물이 없는 상태", "def_vi": "Tình trạng không có nội dung"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (434, '12', '치매 대상자가 비누를 입에 넣으려 하며 빼앗기지 않으려고 할 때 돕는 방법으로 옳은 것은?', '["비누를 쥔 손을 꼬집어 빼앗는다.", "먹으면 안 된다고 설득한다.", "대상자가 좋아하는 호떡을 주며 비누와 바꾼다.", "비누라고 설명하면 냄새를 맡아 보게 한다.", "음식물인지 아닌지 잘 구분해 보라고 말한다."]'::jsonb, 3, NULL, NULL, '{"1": "비누를 쥔 손을 꼬집어 빼앗는다. - 폭력적인 방법으로 해서는 안 된다.\n[정답]", "3": "대상자가 좋아하는 호떡을 주며 비누와 바꾼다. - 대상자의 기분을 고려한 긍정적인 접근 방법이다.", "2": "먹으면 안 된다고 설득한다. - 설득이 잘 안 되는 경우가 많으므로 효과적이지 않다.", "4": "비누라고 설명하면 냄새를 맡아 보게 한다. - 설명은 효과적이지 않을 수 있다.", "5": "음식물인지 아닌지 잘 구분해 보라고 말한다. - 혼란을 줄 수 있는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력이 감소하는 질환", "def_vi": "Bệnh mà khả năng ghi nhớ và tư duy giảm sút"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 필요로 하는 사람", "def_vi": "Người cần sự giúp đỡ"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "세정제로 사용되는 물질", "def_vi": "Chất được sử dụng để tẩy rửa"}, {"term_ko": "호떡", "term_vi": "Bánh hồ tịch", "def_ko": "한국의 전통 간식", "def_vi": "Đặc sản truyền thống của Hàn Quốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (433, '12', '치매 대상자가 밤에 자지 않고 베개 솜을 뜯어 먹고 있을 때 돕는 방법으로 옳은 것은?', '["손모아장갑을 끼고 자게 한다.", "처방받은 수면제를 먹여 재운다.", "솜을 먹으면 안 된다고 설명한다.", "가족에게 새 베개를 사오게 한다.", "솜 대신 두꺼운 수건을 넣어둔다."]'::jsonb, 5, NULL, NULL, '{"1": "손모아장갑을 끼고 자게 한다. - 안전을 고려했지만, 실제로 수면을 취하게 하는 방법이 아닙니다.\n[정답]", "5": "솜 대신 두꺼운 수건을 넣어둔다. - 치매 대상자가 베개 솜을 뜯어먹지 않도록 안전한 대체물을 제공하는 방법입니다.", "3": "솜을 먹으면 안 된다고 설명한다. - 치매 환자는 이해하기 어려워 설명이 효과적이지 않을 수 있습니다.", "4": "가족에게 새 베개를 사오게 한다. - 단순히 새로운 베개를 제공하는 것은 문제 해결에 직접적인 도움이 되지 않습니다.", "2": "처방받은 수면제를 먹여 재운다. - 약물 사용은 의사 처방이 필요하며, 수면제를 사용하는 것이 적절하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 인지 기능에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (432, '12', '과식하는 치매 대상자의 일상생활을 돕는 방법으로 옳은 것은?', '["칼로리가 높은 음식을 제공한다.", "체중계의 체중을 직접 확인시킨다.", "금방 식사했음을 반복해서 알려준다.", "기분을 다른 곳으로 돌릴 수 있도록 산책을 유도한다.", "포만감이 오래 가도록 한꺼번에 많은 음식을 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "칼로리가 높은 음식을 제공하면 과식을 조장할 수 있다.\n[정답]", "4": "기분을 다른 곳으로 돌릴 수 있도록 산책을 유도하는 것은 치매 대상자가 과식하지 않도록 도와줄 수 있다.", "2": "체중계의 체중을 직접 확인시켜도 치매 대상자가 인지하지 못할 수 있다.", "3": "금방 식사했음을 반복해서 알려주는 것은 혼동을 줄 수 있다.", "5": "포만감이 오래 가도록 한꺼번에 많은 음식을 제공하는 것은 오히려 문제를 심화시킬 수 있다."}'::jsonb, '[{"term_ko": "과식", "term_vi": "Ăn quá nhiều", "def_ko": "많이 먹는 것", "def_vi": "Ăn quá nhiều"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (431, '12', '치매 대상자가 자신이 즐겨 입는 꽃무늬 원피스를 접었다 폈다 하느라 잠을 자지 않을 때 돕는 방법으로 옳은 것은?', '["처방받은 수면제 제공한다.", "원피스를 입고 자자며 다독인다.", "그런 행동을 하는 이유를 묻는다.", "세탁해 주겠다며 원피스를 가져간다.", "수건으로 바꾸어 주고 계속하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "처방받은 수면제 제공은 약물 의존을 초래할 수 있어 권장되지 않습니다.\n[정답]", "2": "원피스를 입고 자자며 다독이는 방법은 치매 대상자의 안정과 위안이 될 수 있습니다.", "3": "그런 행동을 하는 이유를 물어보는 것은 불안감을 증가시킬 수 있습니다.", "4": "세탁해 주겠다며 원피스를 가져가는 것은 대상자의 정서적 불안을 유발할 수 있습니다.", "5": "수건으로 바꾸어 주고 계속하게 하는 것은 원피스에 대한 집착을 더욱 심화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지기능의 저하가 나타나는 질환", "def_vi": "Bệnh suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (430, '12', '시설 치매 대상자가 요양보호사를 따라다니며 다음과 같이 반복적으로 질문할 때 요양보호사의 적절한 반응으로 옳은 것은?• 대상자 : 내가 고향에 갈 날이 얼마나 남았어요?• 요양보호사 : ________________________________________________', '["\"어르신은 며칠 남으신 것 같으세요?\"", "\"저와 달력을 보면서 확인해 봐요.\"", "\"아까도 알려드렸잖아요. 몇 번째에요?\"", "\"고향에 가셔도 아는 분이 없을 거에요.\"", "\"저는 어르신과 같이 있고 싶은데 고향에 가고 싶으시군요.\""]'::jsonb, 2, NULL, NULL, '{"1": "''어르신은 며칠 남으신 것 같으세요?''는 환자의 질문에 대한 답변이 아니라 되묻기 때문에 적절하지 않습니다.\n[정답]", "2": "''저와 달력을 보면서 확인해 봐요.''는 환자에게 시각적인 도움을 주어 기억을 도와주는 좋은 반응입니다.", "3": "''아까도 알려드렸잖아요. 몇 번째에요?''는 환자를 혼란스럽게 할 수 있는 반응입니다.", "4": "''고향에 가셔도 아는 분이 없을 거에요.''는 부정적인 반응으로서 적절하지 않습니다.", "5": "''저는 어르신과 같이 있고 싶은데 고향에 가고 싶으시군요.''는 요양보호사의 감정을 드러내지만, 환자의 질문에 대한 직접적인 답변은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고에 능력이 줄어드는 질환", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và suy nghĩ"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc người già", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người cao tuổi"}, {"term_ko": "고향", "term_vi": "Quê hương", "def_ko": "태어난 곳, 자란 곳", "def_vi": "Nơi sinh ra, nơi lớn lên"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 기록한 종이", "def_vi": "Giấy ghi lại ngày tháng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (429, '12', '먼저 사망한 아들이 있는 치매 대상자가 오늘따라 아들이 왜 이렇게 안 오지?라며 반복적으로 물으며 밖으로 나가려고 할 때 돕기 방법으로 옳은 것은?', '["아들을 기다리는 이유를 물어본다.", "조용해질 때까지 하던 일을 모른 척한다.", "아들이 먼저 사망했다는 사실을 알려준다.", "좋아하는 가요 프로그램을 함께 보자고 한다.", "아들이 내일이면 올 거라며 기다리지 말라고 설득한다."]'::jsonb, 4, NULL, NULL, NULL, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (428, '12', '재가 치매 대상자의 부엌을 안전하게 관리하는 방법으로 옳은 것은?', '["채소 모양의 자석은 냉장고에 붙인다.", "유리그릇은 보관장에 넣고 자물쇠로 채워둔다.", "부엌과 거실이 구분되도록 문턱을 설치한다.", "노출된 온수파이프는 주방용 랩으로 감싸둔다.", "음식물이 담긴 쓰레기봉투는 부엌 안쪽에 둔다."]'::jsonb, 2, NULL, NULL, '{"1": "채소 모양의 자석은 장식용일 뿐, 안전과는 관련이 없다.\n[정답]", "2": "유리그릇은 위험할 수 있으므로 안전하게 잠구는 것이 옳다.", "3": "문턱을 설치하는 것은 안전성을 높일 수 있지만, 치매 대상자에게 불편할 수 있다.", "4": "노출된 온수파이프는 감싸는 것이 좋지만, 주방용 랩은 안전한 방법이 아닐 수 있다.", "5": "음식물이 담긴 쓰레기봉투는 부엌 밖에 두어야 한다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 요양 보호를 받는 것", "def_vi": "Nhận sự chăm sóc trong gia đình"}, {"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억력과 인지기능이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "부엌", "term_vi": "Nhà bếp", "def_ko": "음식 준비와 조리를 하는 장소", "def_vi": "Nơi chuẩn bị và nấu nướng thực phẩm"}, {"term_ko": "자물쇠", "term_vi": "Khóa", "def_ko": "잠기는 장치", "def_vi": "Thiết bị đóng lại"}, {"term_ko": "온수파이프", "term_vi": "Ống nước nóng", "def_ko": "핫워터 파이프", "def_vi": "Ống nước nóng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (427, '12', '거울만 보면 욕설을 하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["대상자와 함께 거울을 보며 욕을 한다.", "집안의 거울에 덮개를 씌워 놓는다.", "무슨 이야기를 하는지 자세하게 들어본다.", "거울 속에 있는 사람이 누구인지 물어본다.", "흥분이 가라앉을 때까지 기다렸다가 욕하는 이유를 물어본다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자와 함께 거울을 보며 욕을 한다: 이 방법은 적절하지 않습니다. 대상자의 행동을 부추기는 결과를 초래할 수 있습니다.\n[정답]", "2": "집안의 거울에 덮개를 씌워 놓는다: 이 방법은 대상자가 거울을 보지 않게 하여 욕설을 방지하는 효과가 있습니다.", "3": "무슨 이야기를 하는지 자세하게 들어본다: 이야기를 듣는 것은 중요하지만, 욕설에 대한 즉각적인 대처에는 도움이 되지 않습니다.", "4": "거울 속에 있는 사람이 누구인지 물어본다: 대상자의 불안감을 조정할 수 있지만, 더 이상 욕설을 하는 것을 막는 것은 아닙니다.", "5": "흥분이 가라앉을 때까지 기다렸다가 욕하는 이유를 물어본다: 이 방법은 상황을 진정시키는 데는 시간이 걸릴 수 있습니다."}'::jsonb, '[{"term_ko": "거울", "term_vi": "대상자", "def_ko": "거울(giấy gương)", "def_vi": "대상자(bệnh nhân)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (426, '12', '시설치매 대상자를 위해 화장실의 환경을 안전하게 조성하는 방법으로 옳은 것은?', '["화장실 가는 복도에 화분을 둔다.", "대상자의 눈높이에 맞추어 ''화장실''표시를 한다.", "프라이버시를 위해 화장실 안에 잠금장치를 설치한다.", "펌프식 세정제보다 고형의 비누를 이용한다.", "세면대 위에 큰 거울을 설치하여 자신의 모습을 보게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "화분은 장애물로 작용할 수 있어 안전에 좋지 않습니다.\n[정답]", "2": "눈높이에 맞춘 표시는 대상자가 화장실을 쉽게 인식하는 데 도움이 됩니다.", "3": "잠금장치는 설치할 수 있지만, 긴급 상황에서의 접근을 방해할 수 있으므로 신중해야 합니다.", "4": "고형 비누는 세정에 있어 더욱 위생적이지 않을 수 있으며, 펌프식 세정제가 더 안전합니다.", "5": "큰 거울은 혼란을 줄 수 있어 권장되지 않습니다."}'::jsonb, '[{"term_ko": "시설치매", "term_vi": "Bệnh nhân mất trí", "def_ko": "시설에서 치료받는 치매환자", "def_vi": "bệnh nhân được điều trị tại cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (425, '12', '치매 대상자의 안전을 고려하여 방을 관리하는 방법으로 옳은 것은?', '["침대 밑 방바닥에 두꺼운 요를 깔아둔다.", "큰 유리창을 투명하게 하여 밖이 잘 보이게 한다.", "통일감을 주기 위해 난간과 출입구를 같은 색으로 한다.", "다른 사람의 눈에 잘 뛰지 않는 방으로 배정한다.", "난방을 위해 대상자 옆에 난로를 켜둔다."]'::jsonb, 1, NULL, NULL, '{"1": "방바닥에 두꺼운 요를 깔아두면 넘어짐 사고를 예방할 수 있다.\n[정답]", "2": "큰 유리창을 투명하게 하면 외부를 잘 볼 수 있지만, 외부의 소음이나 자극으로 인해 오히려 불안감을 초래할 수 있다.", "3": "난간과 출입구를 같은 색으로 하는 것은 통일감을 줄 수 있으나, 치매 대상자가 혼란스러울 수 있다.", "4": "다른 사람의 눈에 잘 뛰지 않는 방에 배정하는 것은 고립감을 느끼게 할 수 있어 바람직하지 않다.", "5": "난로를 켜두면 화재의 위험이 있어 안전하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 기능의 저하로 인한 질병", "def_vi": "Bệnh gây suy giảm trí nhớ và chức năng tư duy"}]'::jsonb) on conflict (id) do nothing;
